insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2018-03-20','(Pedro)Reunión con Ildefonso en el día de hoy. +++SITUACIÓN PERSONAL:esta viviendo en un piso de alquiler en Zafra (ver dirección en apunte anterior), donde ha "acogido" a dos personas para ayudarles a salir de la droga (¿?). Llevan unos meses juntos (no ha querido concretar más). +++SALUD: Dr. Leandro (Médico de Familia)///Dr. Zamora (Psiquiatra). +++FUTUEX +++++No les cobra nada por el alquiler porque dice que quiere ayudarles a salir del problema como él salió "sin ayuda de nadie". +++++Está acudiendo al CEDEX de Zafra. "NO CONSUMO NADA". +++ALQUILER: paga en mano 300€/mes. A la propuesta de domiciliar el pago dice qu el propietario no quiere: debería haber tráido el contrato a la reunión pero no se ha acordado (dice): lo enviará y nos mandará el teléfono del propietario. +++BANCO:PLANTEA LA SIGUIENTE PROPUESTA: +++++Restringir la posibilidad de reintegro a la siguiente cantidad mensual: 600€. Conceptos que incluye: • Pago de alquiler………….:300€ (lo paga en mano porque el propietario así lo exige. Tiene que enviar el contrato y teléfono del propietario). • Medicinas………………….:10€ • Alimentación……………… el resto. SE ACEPTA LA PROPUESTA que se hará efectiva a partir Autorización del 1 de abril de 2018. +++DEUDAS reconocdidas por él: +++++EDITORES JM: compró ordenador, colchón y colección Capitán Trueno. No quiere devolver nada. Averiguar: • Cantidad que se adeuda y hasta cuando ha de pagar. • Actualmente paga 73.80/mes, pero quiere volver a la cuota inicial de 144€/mes para pagar menos intereses. ORANGE: tiene la línea bloqueada por impago. Dice que no le dieron la clave. Averiguar: • Deuda actual para activar la línea. Está abonando 7.74€/mes. • Quiere seguir con contrato. Convendría domiciliar el pago. BBVA: dice tener una línea de crédito de la que parece ser le quedan pendientes 2 ó 3 plazos. Actualmente paga 22.53€/mes. Averiguar: • Deuda pendiente y forma de pago en su caso.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA EUGENIA'and edp.apellido1='MOLANO'and apellido2='CAMBERO'),'2018-03-21','-AMALIA : NOS LLEGA ESCRITO DEL JUZGADO QUE AUTORIZÓ EL INTERNAMINTO PARA QUE INDIQUEMOS EL CENTRO DÓNDE VA A IR . MANUELA ( DISCAPACIDAD ) ME INFORMA QUE TIENE 70%G.DISCAPACIDAD POR RM MODERADO + ALT CONDUCTUALES VALORADO EN 2004. EN 2006 HAY UN ESTUDIO DE INGRESO EN CENTRO PERO NO SE VE EL RESULTADO . LLAMO A DOMINGO DTROR. DEL CADEX CC Y QUEDA PTE. VERME ESTE RESULTADO ,PERO CRRE QUE ES NEGATIVO PARA ACCESO A CENTRO DISCAPACIDAD. POR DEPENDENCIA FUE VALORADA EN 2012 CON UN G. 1 . ETÁ PTE. LA NEGOCIACION PIA AL PARECER PTE. DEL ESTUDIO ECONOMICO. TRAS HABLAR POR TF CON DEPEP. CC , ME INDICAN QUE ESCRIBA A LA JEFA DE SECCION SOLICITANDO PRIORIZAR EL EXPEDIENTE. LA IDEA ES NEGOCIAR EL INGRESO EN CENTRO POR PIA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MEJIAS'and apellido2='DE LA MORENA'),'2018-03-20','(Pedro)Asistencia en Juicio en el Juzgado de 1ª Instancia e Instrucción nº 1 de Zafra.Pieza Situación Personal Orden de Protección 0000062/2018. +++AUTO: SE DENIEGA la Orden de protección solicitada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GERMAN JOSE'and edp.apellido1='MONTERO'and apellido2='MORENO'),'2018-03-21','-AMALIA: PEDRO HA HABLADO CON DTRO CADEX CC PARA QUE ADELANTEN LA CITA PARA VALORAR EL PERFIL . EL CENTRO VA A INTENTAR LLEVARLO DESDE ALLI.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUADALUPE'and edp.apellido1='BARRAGAN'and apellido2='GARCIA'),'2018-03-21','-HABLO CON SONIA DEPENDENCIA DE PLASENCIA , NEGOCIO PLAZA RESIDENCIAL MAYORES POR PIA .ME LO ENVIARA AL EMAIL Y SE LO REENVIARÉ POR CORREO ORDINARIO.','2');
