insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='RODRIGUEZ'and apellido2='CALERO'),'2018-03-19','Se envía a D. Juan carta en relación a su demanda para que se le entregue la documnetación existente en su expediente respecto a la tutela que se dió a la Comisión. +++En ella se le indica que lo solicite a través del Juzgado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='RODRIGUEZ'and apellido2='CALERO'),'2018-03-22','(Pedro)Conversación con Carmen Díaz, T. Soc. ESM Valdepasillas. +++Refiere amenazas de denuncia por parte de D. Juan ante su solictud de documentación. Se le informa de la carta que se le ha enviado en este sentido.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2018-03-22','-AMALIA: HABLO CON DEPEND. BROZAS ,HA DADO UN G.1 PROPONEN SAD . ENVIARAN LA SOLCIITUD PIA Y FIRMAREMOS LA NO ACEPTACION. ACTUALMENTE YA SE BENEFICIA DEL SAD DEL SSB Y ES MEJOR MANTENER ESA AUXILIAR QUE ADEMÁS INFORMARÁ A LA TS DEL SSB DEL AYTO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='DOMINGUEZ'and apellido2='GARCIA'),'2018-03-22','-AMALIA.NOS LLEGA DOCUMENTO ACEPTACION PIA DE SAD QUE RECHAZAMOS PARA PODER SEGUIR EN LA PLAZA RESIDENCIAL QUE NO ES PLAZA PUBLICA. ADEMAS SE HA PRESENTADO REVISION PIA POR EMPEORAMIENTO .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EVA MARIA'and edp.apellido1='FERMOSELLE'and apellido2='TEJADA'),'2018-03-22','(Pedro)Conversación con Eva Álvarez, T. Soc. (Plena Inclusión Montijo) (924-454727): +++Solicitan saber si con la autorización general pueden permitir la salida de Eva a pasar unos días con su novio y la los padres de éste en Cordovilla de Lácara.Se trata de un chico que también está en el Centro y quieren pasar unos días en el pueblo. +++El centro valora como positiva esta salida, que ya se produjo en Nochebuena sin que hubiese ninguna incidencia. +++ENVIARÁN notificación indicando con quién va a estar, dónde y los días, haciéndose responsable de sus cuidados las personas con las que esté durante su estancia. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con Irene (Plena Inclusión Montijo). +++JUICIO POR SUPUESTOS ABUSOS: está ARCHIVADO PROVISIONALMENTE POR FALTA DE PRUEBAS. +++++Acudieron a declarar al Juzgado el Pasdo 30 de enero Mª Ángeles, Irene y una de las Cuidadoras de Plena Inclsusión. +++Eva NO SABE NADA NI DE DICHA DECLARACIÓN NI DEL ARCHIVO DE LA CAUSA: solamente si ella pregunta se lo dirán.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2018-03-22','(Pedro)Conversación con María, T. Soc. ESM de Zafra. +++Le informo de la reunión mantenida con Ildefonso el pasado 20 de marzo. +++NO ha acudido a la cita para ponerse el inyectable porque no tiene dinero, aunque comenta que no pasa nada porque se retarse unos días.','2');
