insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SOFIA FLORENTINA'and edp.apellido1='COLLADO'and apellido2='ESTEBAN'),'2018-03-22','(Pedro)Llamada de Juan Carlos, T. Soc. de la Residencia de Deleitosa (927-540149). +++Dª Sofía quiere hablar conmigo: "¿Qué pasa con mi sobrina, que hace mucho que no me llama..." NO SABE QUE SU SOBRINA HA FALLECIDO. Se considera contraproducente el decírselo, POR EL RIESGO que la noticia puede suponer para su bienestar.','2');
