insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2018-03-23','Iciar: HAblo con Orange (TLF. 1470). El móvil 625 245 891 está bloqueadopor impago de factura de septiembre 2017 por un importe de 53,69. Nos facilitan en el móvil de la comisión mensaje con el nº de cuenta del BBVA donde poder hacer la transferencia. Esperaremos a que ingresen la pensión este mes para abonarlo. El contrato de móvil es de 8´95 €/mes con 300 mg de datos y llamadas a 1ct/minuto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JONATHAN'and edp.apellido1='RAMIREZ'and apellido2='JUAREZ'),'2018-03-16','(Pedro)Visita de Jonathan a la CTAEx. +++Comunico con Mara (J. Penal nº 1 de Mérida), por la ejecutoria 16/2016 que tiene pendiente. Intento que se le cite para hoy mismo ante la posibilidad de que vuelva a estar no localizable. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Le citan del Juzgado de lo Penal nº 1 de Mérida, mediante Fax dirigido a la Comisión, que es firmado por él y remitido nuevamente al Juzgado al fax de origen. +++CITA:4 DE ABRIL a las 12:00h.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BARTOLOME'and edp.apellido1='ALBA'and apellido2='GRAGERA'),'2018-03-23','(Pedro)Visita de D. Bartolomé (no programada). +++ACOMPAÑADO por D. Alonso Rodríguez Tiburcio (687-133325) +++Dice tener un abogado para recuperar su "independencia". Se le da el correo de la Comisión para que ese abogado se ponga en contacto con nosotros. +++REclama más dinero para sus gastos (según el SSB no se le debe ampliar).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUIS MIGUEL'and edp.apellido1='MUÑOZ'and apellido2='SANCHO'),'2018-03-23','(Pedro)Conversación con Cristina, Departamento de T. Soc. del C. Penitenciario de Badajoz. +++De 1-2 meses para clasificar la situación de Luis Miguel y valorar la psoibilidad de traslado a otro centro que se comnsidere más adecuado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='GONZALEZ'and apellido2='JIMENEZ'),'2018-03-26','Enviamos a la Oficina de Gestión Tributaria de la AEAT, en Navalmoral de la Mata, Recurso de Reposición contra la Resolución 2016CMP303M983900013X, por la que le imponen 398,95 euros, en concepto de impago del iva correspondiente al alquiler de un local sito en C/. Alfonso XI, de Guadalupe (Cáceres). Este local lo arrendó su madre el 18/7/2014 y los ingresos de la renta se hacen en una cuenta nº Swift Code e Iban 20481006193000026914,titular de la parte arrendadora dice el contrato de arrendamiento. Este contrato lo firmaron también dos de los hermanos de Tomás, Isabel y Lino. Hay otro hermano, Pascual (927367079), con el que hablamos y tampoco recibe la renta de este alquiler, me dijo que la reciben sus dos hermanos, Isabel y Lino. Sin embargo la liquidación del iva impagado hacienda la ha hecho a los cuatro hermanos, reclamándoles el 25% a cada uno. Al parecer parte del alquiler lo pagan al banco ya que hay una hipoteca sobre ese inmueble y la otra se la quedan Isabel y Lino. Hablamos con Isabel y así me lo reconoció, argumentando que Tomás no pagaba nunca nada. No especificó qué. Si le indicamos que cualquier cosa que ellos estimaran que debía pagar Tomás, en concepto por ejemplo de IBI, o cualquier impuesto municipal, nos lo hicieran llegar.--------------------------------------------------- Aquí hay un problema entre los hermanos por la herencia de sus padres fallecidos, no se ponen de acuerdo, porque tanto Isabel como Lino, quieren hacer un reparto desigual de la herencia, en lugar de hacerla tal y como vienen en los testamentos de sus padres y tanto la notaría de Guadalupe como nosotros queremos que se realice según los testamentos de sus padres, o en su caso, si algún hermano quiere hacer un reparto desigual, que compense al resto. La herencia no se ha hecho.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIO'and edp.apellido1='VAQUERO'and apellido2='PEREZ'),'2018-03-26','-MANDAMOS FIRMADO EL CONSENTIMIENO INFORMADO PARA INTERVENCION QUE NOS HA LLEGADO HOY. CONTACTO CON JUANI , AUX. SAD , ME INFORMA QUE LA FAMILIA HARÁ ACOMPAÑAMIENTO LOS PRIMEROS DIAS. ELLA NO PUEDE HACERLO. SI DESPUES LO NECESITARA SE LE PUEDE PEDIR A LA FAMILIA QUE NOS PASEN CONTACTO DE ALGUNA AXILIAR O BUSCAMOS POR EMPRESA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PILAR'and edp.apellido1='ORTIZ'and apellido2='GERMAN'),'2018-03-26','-AMALIA: NOS LLEGAN LAS ACEPTACIONES PIA DE LOS 3 HERMNANOS PARA 70H SAD DE 677€ CADA UNO . SEGÚN CONVERSACIONES CON ROSA , TS DEL SSSB Y QUE TIENE UNA VISIÓN MÁS CERCANA AL CASO , HAY UNAS AUXILIARES SAD DEL SSB QUE ESTÁN ASISTIENDO ESTA CASA Y ESTÁN INTERESADAS EN REALIZAR ESTE SERVICIO. SE PONDRÁN EN COTNACTO CON EMPRESAS ACREDITADAS PARA QUE NOS HAGAN EL CONTRATO . ENVIO LOS PIA A ROSA . EN EL MOMENTO QUE ESTE SERVICIO SE EMPIEZE SE LLAMARÁ A LA SOBRINA QUE ACUDE AL DOMCILIO PARA DECIRLE QUE SE PRESCINDE DE SUS SERVICIOS , SEGUN ROSA POR MOTIVOS FAMILIARES YA NO LOS ATIENDE COMO ANTES.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUADALUPE'and edp.apellido1='BARRAGAN'and apellido2='GARCIA'),'2018-03-26','-AMALIA: ENVIO A PAULA DEL CRR UNA AUTORIZACION PARA PEDIR INFORMES A SALUD MENTAL .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO MANUEL'and edp.apellido1='ALVAREZ'and apellido2='HIDALGO'),'2018-03-26','(Pedro)Conversación con María Zapata (T. Soc. ESM de Zafra) (45970). +++PSIQUIATRA: Dra. Leticia Tolosa Gutiérrez. +++ÚLTIMA CITA EN ESM..................: 17-NOV-2017. +++PRÓXIMA CITA PROGRAMADA EN ESM......: 16-NOV-2018. +++solicitamos informe a ESM de Zafra. +++FAX ESM: 924-552012 Y 924-553208.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='CONTADOR'and apellido2='MATEOS'),'2018-03-27','(PEDRO)REUNIÓN con Manuel hoy a las 10:00h. +++ALQUILER: se le informa de que desde FUTUEX se están haciendo las gestiones pertinentes para la búsqueda de un piso que se adapte a sus necesidades. Se sigue en contacto con la inmobiliaria que ofertó el piso por primera vez y la semana que viene han quedado con otra. +++VIVIENDA FAMILIAR (PISO): +++++dirección: Avda. Antonio Masa Campos 16. +++++GASTOS: hasta ahora se ha encargado Manuel de todos ellos, pero SOLICITA que a partir de que esté de alquiler dichos gastos (desde 2018) sean compartidos con sus hermanas Isabel, Mª José y Natalia (esta última viv ene Madrid desde hace 30 años y cree que tampoco es cuestión de obligarla a ello). ++++++++++GASTOS COMUNES: COMUNIDAD (122.44€/MES); ENDESA ( 15€/MES); SEGURO DE HOGAR (CASER): 300€/AÑO, 150€/SEMESTRAL). +++Retomaremos este tema UNA VEZ ESTÉ DEFINITIVAMENTE DE ALQUILER. +++UNA VEZ DE ALQUILER: +++++Hacer PRESUPUESTO de GASTOS, limitar a él la cuenta y planificar visitas de Futuex.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISIDORA'and edp.apellido1='LEAL'and apellido2='ROMAN'),'2018-03-27','Enviamos a la Abogacía General, por conducto de la Secretaría General de la Consejería, expediente para que la Abogacía solcite aprobación judicial de la herencia del marido de Isidora, así como autorización judicial para vender la parte de la vivienda que aparece en el inventario uno de la herencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VICHO'and apellido2='ALFONSO'),'2018-03-27','(Pedro)Conversación con Rosa (Admón. CSS Plasencia). +++Nos ha enviado por fax la carta que José Mª ha remitido al CSS de Plsencia EN LA QUE SE AMENAZA a varios profesionales de ese centro, así como a mí (Jefe de Sección de Ctaex). REMITIRÁ esta carta al Juzgado de Guardia de Plasencia para quew quede constancia de la misma, ante la próxima excarcelación de José María el próximo mes de octubre. +++Por parte de la Comisión, también remitiremos la copia de esta carta a dicho Juzgado, así como la pondremos en conocimiento del Servivio de Prevención de Riesgos Laborales de la Junta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA EUGENIA'and edp.apellido1='MOLANO'and apellido2='CAMBERO'),'2018-03-27','(Pedro)Recibido Informe del ESM de Cáceres. +++Conversación con Pilar (T. Soc.). Hablará con la Dra. Ríos (Peñita) para saber si el recurso adecuado es de la red de Discapacidad o de la de Salud Mental. +++ÚLTIMAS CONSULTAS: +++++15 DE MAYO DE 2017 (NO PRESENTADA); 09 DE AGOSTO DE 2017 (C. PSIQUIATRÍA); 16 DE OCTUBRE DE 2017 (C. ADMVA.); 08 DE MARZO DE 2018 (C. PSIQUIATRÍA).','2');
