insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2018-03-28','(Pedro)Conversación con el Dr. Juan Pedro Jiménez Cano, Psiquiatra del ESM de Cáceres (54610). +++Mantiene su opinión de que el CRR es el recurso adecuado para José Manuel y que debe ser en el propio Centro donde se trabajen esas actitudes y comportamientos.','2');
