insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN GABRIEL'and edp.apellido1='SOBRINO'and apellido2='TARDIO'),'2018-04-02','Correo-e de Asindi (28-03-2018): +++Buenos días, quería comentaros que según nos indica la familia de Juan Gabriel se irá a casa el domingo día 1 de abril a pasar una semana con ellos. Ahora en Semana Santa no podrán atenderle por trabajo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VANESA'and edp.apellido1='FERNANDEZ'and apellido2='GOMEZ'),'2018-04-02','Enviamos contrato de arrendamiento a la sobrina de la parte arrendadora, Maci (juanfco.tadeo@gmail.com), correspondiente al piso donde está Vanesa, en Miajadas, C/. Donoso Cortés, 23, 2º, para que lo firme. Una vez lo recibamos, lo firmaremos y se lo devolveremos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EVA MARIA'and edp.apellido1='FERMOSELLE'and apellido2='TEJADA'),'2018-03-23','Correo-e de Plena Inclusión Montijo: +++Tras conversación mantendida en el día de ayer, en referencia a la solicitud de salida de Eva Fermoselle al Cordobilla de Lácara, para pasar unos días en la casa de la familia de su pareja os comento, el novio de Eva se llama José Antonio Moreno González, sus padres son Leandro y Josefa. Los números de teléfonos que nosotros tenemos en sus expedientes son 619.978263 y 618.946389 Viven en la C/ Colón, 8 de Cordobilla de Lácara. No obstante a nuestro regreso de vacaciones hablaremos con los padres de José Antonio para hacer un documento en el que ellos se compromentan a hacerse cargo de Eva cuando ella los visite.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='AYALA'and apellido2='NUÑEZ'),'2018-04-02','(Pedro)Conversación con el H. Virgen del Puerto (927-428300). Para ver qué pasa con la operación ocular que Francisco tiene pendiente.Me pasan con la extensión 78070. +++Hablo dos veces con Secretaría de Quirófano y quedan pendientes de devolver la llamada una vez tengan la información.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='BLANCO'and apellido2='TAMAYO'),'2018-03-31','TRASLADO El 31/03/2018. "Se comunica a esa Comisión Tutelar de Adultos que el interno Juan José..., ingresado en este Centro y tutelado por esa Comisión, será trasladado al Hospital de Mérida, en fecha 31/03/2018."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='MURILLO'and apellido2='DELGADO'),'2018-04-02','Toni (Madex) nos comunica que desde la Jefatura de Policía de Badajoz están tratando de comunicar con la Comisión para que les digamos la dirección actual de María. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++(Pedro)Llamo a Carmen (ESM Valdepasillas): no tiene la dirección de María. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++(Pedro)Llamo en dos ocasiones a Dª Marisol, madre de María. NO COGE EL TELÉFONO. +++Llamo a Niobe, abogada que ha defendido a María en el último procedimiento: tras ponerse ella en contacto con Dª Marisol confirma que la dirección actual es: GRUPO JOSÉ ANTONIO nº 25, 2A (BADAJOZ), con teléfono de contacto 665-036664. +++++Nos enviará la SENTENCIA dejando sin efecto la pena impuesta. +++Llamo a Romero (Pol. Nacional/ 924-205516): le proporciono dichos datos y él me indica el Juzgado que reclama los mismos: JUZGADO DE 1ª INSTRUCCIÓN Nº 3 DE BADAJOZ (924284265). DILIGENCIAS PREVIAS P.A. 1343/17 (Delito de Hurto). Está pendiente de tomarle declaración. Cuando fijen el día, nos lo comunicarán, vía fax. También he pedido que todas las notificaciones nos las hagan a nosotros.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONCEPCION'and edp.apellido1='ALEJANDRO'and apellido2='DIAZ'),'2018-04-02','Correo-e del CRR: +++"...para informarles que Concha se encuentra ingresada en el hospital Infanta Cristina nuevamente por el cuadro de Neumología."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='CONTADOR'and apellido2='MATEOS'),'2018-04-03','(Pedro)Conversación con Asunción (24025). +++Se informa de la reunión mantenida con Manuel el pasado día 27 de marzo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='AYALA'and apellido2='NUÑEZ'),'2018-04-03','(Pedro).Conversación con Secretaría de Quirófano del H. Virgen del Puerto (78268). +++Ayer no pudieron obtener la información solicitada. A lo largo de la mañana de hoy tratarán de facilitarla.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2018-04-02','(Pedro)Tras la petición formulada por la Comisión a la DG Infancia y Familia sobre el régimen de visitas a seguir entre beatriz y su hija, nos inoforman por correo-e, que han dado traslado del protocolo al Punto de Encuentro Familiar (PEF)de Don Benito desde donde se pondrán en contacto con nosotros.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2018-04-03','(Pedro)Contacto con el PEF de Don Benito y me informan de que solamente atienden los miércoles, por lo que quedo en llamar mañana entre las 10:30 y las 11:00h. Contactos:Patricia y Mª Isabel (924-114074). ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Llamo a Mercedes, T. Soc. Plena Inclusión. +++Le informo de las gestiones realizadas y quedamos pendientes de lo que me digan mañana en el PEF.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MEJIAS'and apellido2='DE LA MORENA'),'2018-04-03','Iciar: Hemos recibido dos citaciones del nº 5 de Mollet para la videoconferencia de Beatriz, la primera el 19 de abril y la segunda para el 27 de junio de las mismas diligencias previas 400/2015. Hablo con el juzgado y nos aclaran que al no disponer de sala para el 19 de abril lo han pospuesto al 27 de junio a las 9:15.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARGARITA'and edp.apellido1='ANTICH'and apellido2='ARROYO'),'2018-04-03','(Pedro)Llamada de Soraya, Directora CSS Plasencia (24104). +++El traslado de Margarita se va a realizar el 10 de abril a las 10:30h. +++++No se quiere ir: ha iniciado una relación de pareja con otra interna (no están permitidas las relaciones de pareja) y no le conviene, por otra parte, seguir prolongando su estancia en un entorno hospitalario. +++Llamaré mañana a margarita al Pabellón de Larga estancia (24233).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VALLE'and apellido2='SIMON'),'2018-04-03','(Pedro)Llama la hermana de José María: +++Le ha llegado un certificado de "donativos" realizados a Cáritas durante un periodo de tiempo en el que ya estaba viviendo de alquiler. +++Lo remitirá por correo electrónico y lo comprobará Alberto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2018-04-03','Correo-e del ESM de Caceres: +++"Pedro me dice Jose Manuel que ayer sacó del cajero 740 eros, no me explico como en el banco pudo pasar eso, bueno te lo digo para que hagas lo que consideres con sus cuentas. De todas formas intenta llamarme al movil para ver la notificación que hiciste al Ministerio Fiscal por ver si tenemos que cursar nosotros de nuevo la solicitud de CRR o no es necesario y se solicita a través de ellos." ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++(Pedro) Llamada de José Luis, hermano de José Manuel: +++"Ayer me dijo que había sacado más de 700€ y que ya se los había gastado: había comprado un móvil para su hijo y otro para él de 200€ cada uno..." +++++NUEVO Nº TELÉFONO DE JOSÉ MANUEL: 634-288736 ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CUEVAS'and apellido2='LOPEZ'),'2018-04-03','Recibimos Auto del Juzgado de Primera Instancia e Instrucción nº 2 de Villanueva de la Serena, DPAPA 583/2015. Creemos que ha habido un error en el nombre del Acusado, Francisco Pérez Cuevas. Los denunciantes dson Pablo Gutiérrez Milán y Cristina Moraga Severo. Este Auto decreta la apertura de juicio oral y el pago de una fianza de 1525 euros. Debido al error del nombre y que el Juzgado debe entregar el Auto también a Francisco, en el caso de ser él, no pagamos nada. El Juzgado se encargaría de pedir Abogado de Oficio.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='PEREO'and apellido2='REBOLLO'),'2018-04-03','Recibimos Ejecutoria 87/2017, Auto de Medidas de Libertad Vigilada, dictado por el Juzgado de Instrucción nº 4, de Badajoz, por el que se le imponen medidas DE LIBERTAD VIGILADA, por 6 meses: - Prohibición de salir del Sociosantario. - Prohibición de acercarse a Sofía Lajas Montero a una distancia inferior a 500 metros. Se le prohíbe el uso de terminales fijos, móviles, SALVO MOTIVO DE ESTRICTA NECESIDAD Y CON SUPERVISIÓN DE DICHAS COMUNICACIONES, así como el acceso a cualquier dispositivo electrónico (tablets, ordenadores, etc) - Sometimiento a tratamiento terapeútico específico y en RÉGIMEN CERRADO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='BERGANTIÑO'and apellido2='GONZALEZ'),'2018-04-03','(Pedro)Llamada de Juan José (924-255792): +++Su hermana le ha dicho que ella podría hacerse cargo de sus cuentas y él quiere que sea así, aunque siguirea siendo lsu tutora la Comisión. +++Se le explica que eso no es así, que si su hermana quiere solicitar su tutela lo puede hacer dirigiéndose al Juzgado y luego será el Juez el que determine si es posible o no.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA EUGENIA'and edp.apellido1='MOLANO'and apellido2='CAMBERO'),'2018-04-04','(Pedro)Conversación con Mónica Gallego, Tec. PIA (Dependencia I)927-270466. +++Quedamos con ella en ponernos en contacto cuando tengamos los Informes del Cadex para valorar PIA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONCEPCION'and edp.apellido1='ALEJANDRO'and apellido2='DIAZ'),'2018-04-04','(Pedro)Conversación con Gisela (CRR Mérida). +++Informa que: la madre de Concepción llamó el lunes para decir que le habían dado el alta a su hija. +++++Llegó al CRR el martes 3 de abril, en bastantes malas comndicones: falta de higiene, con apariencia de haber consumido alcohol. Se pasó toda la tarde durmiendo, despertándose solamente para tomar la medicación. +++++HOY se ha levantado como si tuviera "resaca", pidiendo dinero y tabaco. "He llegado a dudar de que realmente hubiese estado ingresada en el HIC...Voy a llamar a su madre para ver qué ha ocurrido." ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++(Pedro)Conversación con Loli, T. Soc. del H.I.C (48991): +++CONFIRMA el INGRESO el 31 de MARZO y ALTA el 02 de ABRIL: al parecer se marchó voluntariamente y sin firmar el alta. Envirá informe de alta. +++Planteo si no existe en la Hª Clínica ningún apartado donde se refleje la situación de Tutela, a la hora de facilitar el alta voluntaria: lo va a consultar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANGELES'and edp.apellido1='SANTOS'and apellido2='URBANO'),'2018-04-04','(Pedro)Llamada de Emiliana Cáceres, T. Soc. SSB de Coria (927-510637): +++Ha recibido la petición de informe y documentación para hacer el inventario. Plantea que sea alguine de la Comisión la que vaya a hablar con el padre y pida esa documentación. Se le explica el procediemineto. +++PROPUESTA: ingreso en CRR. Ya lo planteo cuando inofrmó al Juzgado de la situación. +++ESM DE CORIA: Psiquiatra Dr. Mora y T. Soc. Marisa Olivera.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='RUBIO'and apellido2='GONZALEZ'),'2018-04-04','Nos llama la hermana de Javier, Rosa María (952238383). Nos comenta que sigue pendiente nuestra firma por una venta de un local en Cañamero, que todos los hermanos tienen por herencia de la muerte de su padre. No sabe darnos más datos. Tan solo que llamemos a Notaría de Logrosán (927360053-Pedro). Tras hablar con él, indica que el expediente es del año 2014, que va a rescatarlo. En cuanto disponga de el se pone en contacto con nosotros.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARGARITA'and edp.apellido1='ANTICH'and apellido2='ARROYO'),'2018-04-04','(Pedro)Llamo a Larga Estancia (24233) del CSS de Plasencia para hablar con Margarita, pero no ateinden la llamada. +++Llamo a Soraya, pero tampoco puedo contactar con ella.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BARTOLOME'and edp.apellido1='ALBA'and apellido2='GRAGERA'),'2018-04-04','(Pedro) Llamada de D. Bartolomé. +++"Alguien" responde al descolgar "...Se va a poner el interesado..." +++D. Bartolomé llama para pedir cita para el próximo lunes para hablar con Consolación de su situación económica. Se le indica que desde la reunión que tuvimos el pasado 23 de marzo no tenemos nada nuevo que decirle, y que si quiere desplazarse va a ser para volver a decirle lo mismo. +++Le recuerdo que su abogado (si lo tiene) no se ha puesto todavía en contacto con la Comisión: "...Es que yo para hablar con su secretaria necesito 30€..." +++Le propongo, para evitarle desplazaminetos innecesarios, que nos mande, al correo-e que le dí en la reunión, el nombre y teléfono del abogado para ponernos en contacto con él: "...Sí, vale, pero es que es de fuera y para desplazarme necesito 100€...','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2018-04-04','(Pedro)Conversación con Patricia,del PEF de Don Benito (924-114074). +++Comenta que no han recibido, como a la Comisión habían informado, el protocolo para iniciar el régimen de visitas para Beatriz. +++Le explico las circuentancias y la necesidad de agilizarlo todo lo posible y quedamos en que se pondrán en contacto con la D.G. de Infancia y Familia para verlo lo antes posible.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BARTOLOME'and edp.apellido1='ALBA'and apellido2='GRAGERA'),'2018-04-04','(Pedro)Llamada de D. Bartolomé: +++"Alguien" responde al descolgar: "...le pongo con el interesado..." +++Quire pedir cita para venir el próximo lunes para hablar con Consolación. Se le indica que ya estuvimos hablando hace unos días y que, si quería venir, podía hacerlo, pero que no le íbamos a decir nada nuevo sobre su petición de dinero. +++Le digo que su abogado (si lo tiene) no se ha puesto en contacto con nosotros y dice que para hablar con él primero necesita 30€ para hablar con su secretaria, sin indicar nombre de bufete ni de teléfono...Por detrás se oye a ese "alguien" que dice algo. +++Le propongo que, en lugar de venir aquí, que nos envíe, al correo-e que le dí en la entrevista, el nombre de su abogado y teléfono para ponernos en contacto nosotros con él: "...Bueno, es que es de fuera y para ir a verlo necesitaría dinero, 100€...','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='PEREO'and apellido2='REBOLLO'),'2018-04-04','(Pedro)Se envía Auto de Medidas al CSS de Mérida por FAX.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='MURILLO'and apellido2='DELGADO'),'2018-04-04','(Pedro)Conversación con Carmen Díaz. +++Le enviaremos por fax (924-218005) la citación del Juzgado de Instrucción nº 3 de Badajoz (día 8 de mayo de 2018 a las 09:30h) para que se lo entreguen a María el día 12 de abril en la consulta que tiene con su Psiquiatra actual el Dr. Antonio Glez.Glez. +++POSIBLE TELÉFONO DE SU MADRE: 696-266658.LLAMAR TAMBIÉN PARA COMUNICAR CITACIÓN Y TAMBIÉN ENVIAR A ÚLTIMO DOCICILIO DE MARÍA.','2');
