insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN BAUTISTA'and edp.apellido1='RAMIREZ'and apellido2='DE LA ROSA'),'2018-04-04','TRASLADO El 04/04/2018. "Se comunica a esa Comisión Tutelar de Adultos que el interno Juan Bautista..., ingresado en este Centro y tutelado por esa Comisión, será traslado al Hospital de Mérida-Urgencias, en fecha 04/04/2018."','2');
