insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONCEPCION'and edp.apellido1='ALEJANDRO'and apellido2='DIAZ'),'2018-04-05','(Pedro)Llamada de Gisela. +++Se inofrma de la gestión realizada con el HIC. +++Desde el CRR consideran que Pipi no debe volver a casa de su madre de momento, y pide que le mandemos un correo con nuestra opinión al respecto que refuerce, ante ella, dicha postura. Se envía dicho correo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2018-04-05','(Pedro)Conversación con Francisco Caldera, Letrado de la Abogacía de la Junta (924-003951 y 640039468). +++Mañana se reunen los abogados de las partes en el procedimiento en curso sobre posibles abusos sexuales para tratar de llegar a un acuerdo tanto sobre la pena a imponer al acusado como sobre la posible indemnización a recibir: +++++Fiscalía propone 15000€, Abogacía 90.000 y pedir responsibilidad civil subsidiaria al centro (quien no la admite). +++++RELACIÓN CAUSA-EFECTO entre abusos e infección: tanto el Forense como la Abogacía se han puesto en contacto con los especialistas correspondientes, manifestando que no existe literatura científica que permita establcer dicha relación de manera inequívoca. +++Mañana nos informará sobre si se ha llegado a acuerdo alguno o no y, el día 16, irá a Jucicio con un representante de la Comisión para su ratificación en su caso o bien para proceder al juicio','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GERMAN JOSE'and edp.apellido1='MONTERO'and apellido2='MORENO'),'2018-04-05','PENSIÓN Recibida notificación, fechada el 26/03/2018, aprobando la PF por importe de 554.90€.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADOLFO'and edp.apellido1='FAGUNDEZ'and apellido2='CORTES'),'2018-04-05','(Pedro)A fecha de hoy, Maribel entrega en la Comisión la Resolución PIA por cambio de perfil de D. Adolfo en la USAD del CAMP de Don Benito.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DANIEL'and edp.apellido1='MONTAÑO'and apellido2='RANGEL'),'2018-04-05','Procedemos al pago del principal en relación con el juicio verbal 684/2017, por el accidente que tuvo con el repartidor de burger king, 884,40 euros. Faltan por determinar los intereses procesales.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='MURILLO'and apellido2='DELGADO'),'2018-04-05','(Pedro). Comunica Carmen (ESM Valdepasillas) que María ha ingresdo nuevamente ayer en el HIC. +++Hablo con Loli, T. Soc. HIC:le envío por fax la citación del Juzgado para que la comunique a María.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA EUGENIA'and edp.apellido1='MOLANO'and apellido2='CAMBERO'),'2018-04-05','(Pedro)Conversación con Domingo (Cadex) +++Informe de 2011 para ingreso en centro se desetimó por NO dar el perfil debido a los Trastornos Garves de Conducta. +++Habría que solicitar un nuevo estudio de perfil al cadex. +++ACCESO A CENTRO POR DEPENDENCIA?','2');
