insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GERMAN JOSE'and edp.apellido1='MONTERO'and apellido2='MORENO'),'2018-04-06','(Pedro)Llamada de Domingo (CAdex): +++Hoy tiene cita Germán para revición Cadex.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='ARNOSI'and apellido2='PEREZ'),'2018-04-09','-PASA DEL MODULO FAMILIAR A LA PLAZA DE RAE. SE FIRMA EL CONTRATO DE ADMISION AL MISMO . ASI MISMO SE FIRMA LA BAJA DE LA PLAZA EN EL MODULO FAMIL.','2');
