insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SONIA'and edp.apellido1='VALCARCEL'and apellido2='VIDAL'),'2018-04-09','-baja en Vitalia tramitada .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DOLORES'and edp.apellido1='FERNANDEZ'and apellido2='BAEZ'),'2018-04-06','(Pedro)Me encontré con Mariloli en el C.Salud. Ella tenía consulta con el Psiquiatra Dr. Isaac.Me pidió que hablara con él.Acudí a su consulta. +++Conversación con Isaac: +++++Quería conocer la opinión de la Ctaex de cara al alta que constantemente le está pidiendo. +++++Se inofrmó al Psiquiatra que el alta clínica era una cuestión diferente de la recuperación de la capacidad con la que ella parece confundirse, a pesar de las numerosas ocasiones en las que se le ha explicado.La Comisión tiene claro que Mariloli no puede vivir sola. +++++CONCLUSIÓN: esperar al ingreso en centro residencial de mayores antes de dar ningún alta. Es más, le explico a Isaac que el estar en la residencia no quiere decir que se le deba dar el alta, como de hecho creo que no será.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='POBLADOR'and apellido2='FERNANDEZ'),'2018-04-11','SALIDA Entre el 11/04/2018 y el 13/04/2018. "..para participar en el 22º Encuentro Extremeño de grupos de Autogestores."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUIN'and edp.apellido1='GONZALEZ'and apellido2='MILLON'),'2018-04-06','SALIDA El 06/04/2018. "Me comenta Joaquín que quiere ir a visitar a una amiga a Pueblonuevo del Guadiana. Lo llevaría la madre de otra amiga que es de aquí de Montijo. Sería este viernes día 6, se irían sobre las 18:00 horas y volverían sobre las 00:00 horas."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VERA LUCIA'and edp.apellido1='DA CONCEIÇAO'and apellido2='BEZERRA'),'2018-04-10','En relación con el Juicio Verbal nº 606/2017, el Juzgado de primera instancia e instrucción nº 2, de Mérida, va a enviarnos una Diligencia de Ordenación declarando a Vera Luzía en Rebeldía, al no personarse en el Juzgado (En cédula de emplazamiento dictada el 20/9/2017, recibida, al parecer, el 9 de marzo de 2018, sin sello de registro de entrada, anotada a mano). En esa Diligencia sólo nos comunican esta circunstancia, a la espera de que resuelva su Señoría.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUIN'and edp.apellido1='GONZALEZ'and apellido2='MILLON'),'2018-04-02','CURSO Entre el 02/04/2018 y el 03/07/2018. "Nos ponemos en contacto con vosotros para informaros que Joaquín ha empezado una formación para el empleo de un proyecto de la ONCE que ha solicitado plena inclusión Montijo. Este proyecto consta de parte teórica y práctica en empresa. Las empresas son de Montijo, por lo q no sale de la localidad Y, siempre están acompañados por técnicos del centro. Dicha formación ha comenzado el 2 de abril y finaliza el 3 de julio."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JORGE'and edp.apellido1='FERNANDEZ'and apellido2='CERECINOS'),'2018-04-12','SALIDA El 12/04/2018. "Me pongo en contacto con vosotros desde el CRF de Nuñomoral, para comunicar la salida de Jorge Fernández Cerecino (como tutelado vuestro) junto a su hermana, el Jueves 12 de Abril. Rosario vendrá a buscarlo sobre las 12.30 horas y nos comunica que pasarán el día en Plasencia, regresando sobre las 18.30 horas de la tarde."*****************************************************El centro informa el 11/04/2018: "La vuelta al Centro lo hará con nosotros, puesto que tenemos una actividad programada por la tarde con los chicos en Plasencia y lo recogeremos allí. De esta manera facilitamos también a su hermana la vuelta a casa."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIO'and edp.apellido1='VAQUERO'and apellido2='PEREZ'),'2018-04-10','-alta hospitalaria tras su operacion de cáncer.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2018-04-10','-AMALIA: LLAMA SU MADRE ( TF JULIA 688381229) PARA COMUNICAR Q ESTÁ INGRESADO EN EL HOSPITAL SAN PEDRO DE CC POR PROBLEMAS RESPIRATORIOS. SOLICITA DINERO PARA GASTOS DE DESPLAZAMIENTO. DE MOMENTO NO SE LE CONCEDEN , SI PERMANECE MUCHOS DIAS INGRESADOS SE PUEDE MIRAR DARLES ALGUN EXTRA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JACINTO'and edp.apellido1='DIAZ'and apellido2='BOZA'),'2018-04-10','En relación con la aceptación de herencia, una vez presentado el expediente por la abogada (Guadalupe Mena Hernández-Huertas), ante el Juzgado de primera instancia e instrucción nº 5 de Mérida, éste se declara incompetente a favor de los Juzgados de Zafra, al residir Jacinto en Aprosuba de Zafra. Una vez nos lo comuniquen, la Abogada va a solicitar la suspensión, hasta que se designe nuevo abogado del turno de ofcio correspondiente a la demarcación judicial de Zafra y continúe la tramitación del expediente.','2');
