insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2018-04-11','Iciar: Recibido el mail de Julián de Cocemfe, le llamo para indicarle que el contrato que nos ha enviado firmado Tomás con Simyo no es válido pues tiene que estar firmado por Consolación. Me indica que en la teienda de telfonía no le dejan realizar el contrato si mo se firma allí mismo. Acordamos que lo anule y busque otra compañía en la quepueda enviárnoslo para su firma.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='SANCHEZ'and apellido2='PANIAGUA TRENADO'),'2018-04-11','Enviamos documentación relacionada con la herencia de su abuela al abogado Miguel Ángel Asensio Muñoz 924861123, 3243@icaba.com, para que solicite autorización judicial de aceptación de herencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='MURILLO'and apellido2='DELGADO'),'2018-04-16','Iciar: Hablo con Loli, nos mandará esta mañana la copia firmada por fax. MAría see ncuentra más tranquila y receptiva. Tiene conciencia de que está en libertad condicionada. En breve se le dará el alta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUANA'and edp.apellido1='GONZALEZ'and apellido2='NARANJO'),'2018-04-11','-AMALIA: SE HA RENOVADO EL CONTRATO DE ALQUILER DE UNA CASA SITO EN LA BARRIADA DE LAS 800 EN BADAJOZ PROPIEDAD DE ESTAS HNAS A EMILIO TARANCO. TINE PTE. DEUDAS DE ALQUILER HEMOS HECHO UN CONTRATO EN EL QUE SE PRORRATEA LA DEUDA. AL VENIR A FIRMAR ME COMENTA QUE ESTÁ INTENTANDO AHORRAR PARA MEJORAR LA FONTANERIA Y EL SISTEMA ELECTRICO DE LA CASA . HAGO UNA VISITA DOMICILIARIA CON LA DELEGADA TUTELAR PARA CORROBORAR LAS CONDICIONES DE LA VVDA. EFECTIVAMENTE EL CABLEADO ESTÁ MUY MAL Y TB LA FONTANERIA. SE LE PIDE QUE CONTACTE CON ALGUNA EMPRESA PARA QUE NOS PASEN PTOS. ACUDE HOY A LA OFICINA PQ LOS PTOS QUE HA PEDIDO NO SE LOS FACILITAN. CONTACTO CON FONTANERIA PAJUELO EN BDJOZ Y QUEDO PTE. PARA QUE NOS PASEN PTOS. VALORAREMOS SI ARREGLAR LA VIVIENDA O CANCELAR CONTRATO SI FUERA PRECISO , NO PODEMOS ALQUILAR UNA VVDA QUE NO REUNE CONDICIONES DE HABITABILIDAD . EN LA MISMA VIVE UNA FAMILIA CON HIJOS MENORES.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MERCEDES'and edp.apellido1='PEREZ'and apellido2='PINNA'),'2018-04-11','AMALIA.QUEDO CON ELLA MAÑANA EN LA OFINA PARA CONCRETAR GASTOS MENSUALES . VENDRÁ CON SU PRIMO JESUS TF647758555','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARGARITA'and edp.apellido1='ANTICH'and apellido2='ARROYO'),'2018-04-10','(Pedro). +++Acompaño a Margarita, junto con Mariví (T. Soc. del CSS de Plasencia) a su nueva plaza residencial en el Hogar "San Vicente de Paul", gestionado por las Hijas de la Caridad. +++DIRECCIÓN: calle Los Naranjos nº 16, Bajo A. 10.600.Plasencia. +++TELÉFONOS: 927-419971 (HOGAR). 654-748564 (SOR Mª FE). 671-016615 (PILAR, T. SOCIAL). +++TRASLADO. Aunque Margarita estaba previamente avisada de que su estancia en el CSS de Plasencia era temporal, no dejaba de llorar, de manera pausada, al tener que marcharse y dejar a las compañeras con las que había establecido una fuerte relación, especialmente con su "pareja" Puerto,relación que, según los compañeros del centro, tampoco le convenía. Le ayudamos a hacer la maleta y la acompañamos al Hogar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSO'and edp.apellido1='MARIN'and apellido2='DE CACERES'),'2018-04-12','Iciar: Hablamos con Toni de futuex después de hablar con la madre de Alfonso, Isabel 680784490. Van a realizar una visita para ver las condiciones en las que se encuentra. LA madre dice que no sale de casa, fuma mucho y está engordando con lo que ha pensado que comprarle una bicicleta sería una buena opción pues él en alguna ocasión lo ha propuesto. Esperamos el informe de futuex para tomar una decisión','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='GUILLEN'and apellido2='ROMAN'),'2018-04-13','Tras fallecer su madre, que tenía el usufructo de la vivienda sita en Avda. Hernán Cortés, 16, entrada en C/. Espadán, de Cáceres, enviamos al hermano, Francisco Javier para que presente la liquidación del Impuesto de Transmisiones Patrimoniales y Actos Jurídicos Documentados, para adquirir el pleno dominio de la vivienda. Él pagará en ventanilla la parte correspondiente a todos los propietarios y en cuanto a José María, nos enviará la factura para hacerle la transferencia. Posteriormente a esto se hará la venta.','2');
