insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2018-04-16','INFORME CEDEX ZAFRA "Que el paciente D. Ildefonso..., con DNI 80044285F reinicia tratamiento en este Cedex el Día 05/02/2018. Acude derivdo de la consulta de enfermería de la Unidad de Salud Mental de Zafra. Actualmente realiza controles de consumo para la detección de sustancias tóxicas en orina. Se adjunta resultados de dichos controles."********************El informe da NEGATIVO en todo entre el 26/02/2018 y el 19/04/2018. Excepto el 12/04/2018, que da POSITIVO en Cannabis.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2018-04-17','(Pedro)Asistencia a Juicio/Diligencias Urgentes/Juicio Rápido 0000034/2018. del Juzgado de 1ª Instancia e Instrucción nº 6 de Cáceres. +++QUEBRANTAMINETO de las medidas cautelares indicadas el día 13 de abril de 2018. +++DISPOSICIÓN:PRISIÓN PROVISIONAL COMUNICADA Y SIN FIANZA. Estas medidas se acumulan al procediemiento origen. +++ABOGADA asignada: Dª Ana Iglesias Ávila. 927-210029 y 620-111918. Correo-e: anaiglesias@icac.es +++++++++++++++++++++++++++++++ (Pedro)Conversación con José Luis, hermano de José Manuel: +++Se le informa de su ingreso en C. Penitenciario de Cáceres esta mañana. +++Se le pide que le lleven ropa y que den una vuelta al piso. +++Intentaremos que esté el menor tiempo posible en prisión y puda cumplir en CSS Plasencia. +++HABLAR CON SU ABOGADA PARA RECURRIR EL AUTO Y SOLICITAR TRASLADO. +++Hablo y envió correo-e a su abogada,Dª VERÓNICA MORENO DURÁN (927-371136 y 666-990426).Correo-e: veronicamoreno@icac.es, para que recurra en el sentido de que cumpla la sentencia en CSS.','2');
