insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSARIO'and edp.apellido1='SOLIS'and apellido2='BERMEJO'),'2018-03-22','SALIDA El 22/03/2018. Participación en la Marcha Antibarreras en Cáceres.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='DEBON'and apellido2='CHENIQUE'),'2018-03-23','SALIDA Entre el 23/03/2018 y el 31/03/2018. El 19/03/2018 plantea nuevamente la residente la psobilidad de realizar un viaje a Don Benito con el objeto de pasar unos días con Juan Martín Isidoro y familia, del 23/03/2018 al 31/03/2018. Su pareja sentimental desde abril de 2017. Para ello, realizaría los desplazamiento en el cohe particular de su pareja. Se trata de un vehículo que no es necesario disponer de carnet de conducir por lo que la residente llevará una silla de ruedas manual prestada en Terapia Ocupacional.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='DEBON'and apellido2='CHENIQUE'),'2018-03-01','SALIDA Entre el 01/03/2018 y el 05/03/2018. El 01/03/2018 plantea nuevamente la residente la posibilidad de realizar un viaje a Don Benito con el objeto de pasar unos días con Juan Martín Isidoro y familia, del 01/03/2018 al 05/03/2018. Su pareja sentimental desde abril de 2017. Para ello, realizaría los desplazamientos en el coche particular de su pareja. Se trata de un vehículo que no es necesario disponer de carnet de conducir por lo que la residente llevará una silla de ruedas manual prestada en Terapia Ocupacional.************************************************En la anterior salida de la residente, la misma acompañada de su pareja fueron a Liberbank en Don Benito a realizar un reintegro bancario. La cantidad que retiraron está dentro del límite establecido por la Comisión Tutelar de Adultos, pero se le recordó a Isabel que está tutelada y los reintegros bancarios sólo puede realizarlos con la supervisión del Centro. Se realizará seguimiento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='VAZQUEZ'and apellido2='DIAZ'),'2018-04-19','Con motivo de la excarcelación de Jesús para el próximo día 25/4/2018, realizo las siguientes actuaciones: 1.- Hablo con el Juzgado nº 4 de Badajoz, que es quien incapacita a Jesús, al que le enviamos escrito, poniéndole en antececentes y solicitándoles colaboración para el traslado de Jesús al CSS de Mérida. Me indican que han recibido el escrito, vía fax, pero que no son competentes, porque se inhibieron a los Juzgados de Segovia. Compruebo que efectivamente, enviamos las rendiciones de cuentas al Juzgado de Primera Instancia e Instrucción nº 4 de Segovia. 2.- Hablo con el Juzgado de Primera Instancia e Instrucción nº 4 de Segovia y me dicen que, aunque en las rendiciones de cuentas hacemos mención a que Jesús está ingresado en el Centro Penitenciario de Badajoz y que recupera la libertad, en la rendición de noviembre de 2017, en enero de 2018, no lo han leído... Me dicen que les envíe un fax diciéndoles el domicilio actual de Jesús, para que se inhiban a favor de los Juzgados de Badajoz, al estar en el Centro Penitenciario a fecha de hoy, o bien, a los Juzgados de Mérida, en el caso que ingrese en el CSS de Mérida. Hasta el 25/4/2018, no le enviaré el fax, en función de donde se encuentre. 3.- Hablo con el Juzgado de Primera Instancia e Instrucción nº 1 de Mérida, para preguntar si nos sirve la Autorización judicial de ingreso involuntaria dictada por ese Juzgado el 3/1/12. Me dicen que no, que habría que solicitarlo de nuevo, o bien intentar un internamiento por la vía de urgencia, a través del Juzgado de Guardia de Mérida. 4.- Hablo con el Juzgado de Guardia de Mérida y me dicen que solicitemos el internamiento urgente en el CSS de Mérida, para que una vez se ingrese en el centro, en el plazo de 24 horas lo pongan en conocimiento del Juzgado, para que se ratifique en el ingreso. Pero como actualmente reside en el Centro Penitenciario de Badajoz, debo consultarlo con el Juzgado de Guardia de Badajoz. 4.- Llamo al Juzgado Decano de Badajoz, porque allí las Guardias se gestionan de otra manera a Mérida. Me pasan con el Juzgado de Instrucción nº 2, que es quien está de guardia, desde el 18 al 24 de abril de 2018. Me dicen que eso allí no se tramita, al ser un Juzgado de Instrucción (penal), y que debo consultarlo con Fiscalía Civil. 5.- Llamo a Fiscalía civil de Badajoz, hablo con el Fiscal, Miguel, me indica que efectivamente hay dos opciones para ingresarlo, o bien el urgente o el ordinario solicitando autorización judcial, como siempre. Sin embargo le hago saber que el urgente no es viable, porque la propia fiscalía envió escrito a los centros indicándoles que sin autorización judicial, no podían recibir a ninguna persona, con lo que esa vía está inoperativa en realidad. La otra vía la ordinaria, solicitar autorización judicial de internamiento involuntario no nos da tiempo a realizarla y que emitan la autorización. 6.- No obstante todo lo anterior, ni el Juzgado de Badajoz, ni el de Mérida, ni la Fiscalía pueden ayudarnos en el traslado de Jesús desde el penitenciario de Badajoz al CSS de Mérida. Todos me indican que debemos ser nosotros quienes convenzamos a Jesús para que ingrese en el CSS de Mérida.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VANESA'and edp.apellido1='FERNANDEZ'and apellido2='GOMEZ'),'2018-04-19','Hablamos con Toni de Futuex para que concierten visita con Vanesa y ver cómo se desenvuelve en el piso de alquiler de Miajadas','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='VAZQUEZ'and apellido2='DIAZ'),'2018-04-20','(Pedro) Amalia y Pedro visitan a jesús en el C. penitenciario de Badajoz para comunicar su traslado al CSS de Mérida el próximo día 25 de abril, fecha en la que se va a producir su excarcelación. +++Hablamos con Beatriz y Paula (depto. de Trabajo Social) y con Víctor, Psicólogo. En su opinión, un C.para personas con discapacidad no es el lugar adecuado para Jesús. +++ACTITUD DE JESÚS:NO QUIERE IR AL CSS de MÉRIDA, Y MENOS EN AMBULANCIA. SE QUIERE IR CON "SU GENTE" Y "YA ESTÁ".','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='BRUNO'and apellido2='SAAVEDRA'),'2018-04-23','ICiar: Llama Pilar Salguero, Jefa de Sección de Menores 64574, indica que Felisa se encuentra en centro especial de menores de Málaga, Dulce Nombre de María. En principio en el centro una vez que Felisa ya es mayor de edad podría estar hasta el 12 de mayo, habría que buscarle un recurso en Extremadura. Nos enviarán el expediente. La técnico que lleva el expdte de Felisa en menores es Isabel, 64577, por si tenemos alguna duda.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='POBLADOR'and apellido2='FERNANDEZ'),'2018-04-23','SOLICTUD Sale en el correo solicitud de PFHC tras subsanar la anterior. Se remite al CAISS de Mérida.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='VAZQUEZ'and apellido2='DIAZ'),'2018-04-23','(Pedro) Solicito por correo-e transporte de Cruz Roja para el traslado de Jesús Vázquez el próximo día 25 de abril al CSS de Mérida. Centralita: Juan Pérez (607-504280). +++CONTACTO: Víctor (659-312234) +++CORREO-e: ssee.extremadura@cruzroja.es','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='VAZQUEZ'and apellido2='DIAZ'),'2018-04-20','+++CONTACTOS CENTRO PENITENCIARIO DE Badajoz:**** VÍCTOR (Subdirector de Tratamiento): 924-289102 y 617-604460. CORREO-e: subtratamiento_badajoz@dgip.mir.es////Beatriz (T. Social): 924-289174 y 924-289117. CORREO-e: beatriz.barras@dgip.mir.es.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUGENIA'and edp.apellido1='PACHECO'and apellido2='VICENTE'),'2018-04-23','(Pedro)Conversación con Carmen Jerez, miembro permanente de la Subcomisión de Casos). +++PRÓXIMA CONVOCATORIA del 25 de abril. Considero que la CTAEx no es necesario que acuda dado que solamente tiene la curatela de carácter económico (por encima de los 300€) y patrimonial de Dª Eugenia. +++Acudirá Eva, de la Sección de Salud Mental del Sepad: se le da la inofrmación disponible en la CTaex, así como los teléfonos de Amalia y el móvil de la Comisión por si tiene que contactar con nosotros.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='AYALA'and apellido2='NUÑEZ'),'2018-04-23','(Pedro)Hablo con Toni, de Futuex, para que acompañen a Francisco a la intervenbción ocular que tendrá lugar mañana, 24 de abril de 2018, a las 15:00h en el H. Virgen de Puerto. +++Lo acompañará Alicia y estrá pendiente de las indicaciones que le den para el postoperatorio así como de su seguimeinto en los priemros días del mismo. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con Francisco: está muy nervioso por la operación de mañana.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='ANTUNEZ'and apellido2='SANZ'),'2018-04-23','(Pedro)Informa Toni (Futuex), que hay un vecino de la casa propiedad de Josefa que está produciendo desperfectos en en la de aquel. Me deja el teléfono. +++Le paso el caso a Alberto para que se ponga en contacto con el vecino.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUGENIA'and edp.apellido1='PACHECO'and apellido2='VICENTE'),'2018-04-23','(Pedro)Conversación con Carmen','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN GABRIEL'and edp.apellido1='SOBRINO'and apellido2='TARDIO'),'2018-04-23','(Pedro)Acude a la CTAEX Dª Araceli, hermana de Gabriel. +++Dice que tenemos una cuenta en la que su padre estaba como titular con gabriel y en la que había 25.000€ que eran de su padre. +++Se le explica que Gabriel solamente tiene una cuenta en al que figuara él y la CTAEx. +++Si su padre no ha cancelado la cuenta que refeiere seguirá abierta en su banco, donde deberá pedir esa información yendo su padre con su DNI (al no estar incapacitado). +++La CTAEx envío escrito al banco autorizando el desbloqueo de dicha cuenta y que el padre de gabriel dispusiese del dinero que en ella hubiese.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JONATHAN'and edp.apellido1='RAMIREZ'and apellido2='JUAREZ'),'2018-04-23','(Belén y Pedro) Varias llamadas al teléfono de Jonathan. Siempre salta el contestador. Se deja mensaje con fecha para sacar el DNI y que pase por la CTAEx a recoger las fotografías.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='ARNOSI'and apellido2='PEREZ'),'2018-04-17','CADEX Se recibe resolución del CADEX indicando la nueva valoración (modifica la de la resolución de 26/08/2005) de Juan José. Grado: 81% (anteriormente 71%). D.T.F.: RETRASO MENTAL SEVERO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='DOMINGUEZ'and apellido2='BLANCO'),'2018-04-25','iCIAR, llama Isabel, Psicóloga tlf 924 50 30 92, comunica que Josefa suele dar paseos por la mañana acompañada pero hoy ha querido dar el paseo sola y ha salido del centro en dirección al pueblo sin permiso. En este tipo de situaciones se le plantea la cuestión de si esperar a que Josefa vuelva, como ha ocurrido otras veces, o llamar a la Guardia Civil. Josefa es bastante autónoma y podría pensarse en dejarle dar esos paseas sin acompañamiento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='DOMINGUEZ'and apellido2='BLANCO'),'2018-04-25','Nos informa Isabel que Josefa ha vuelto al Centro. Nos enviará por correo electrónico el informe de lo ocurrido y la sugerencia de posible autorización de pequeñas salidas, así como cambio de recurso.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2018-04-25','Iciar: Llama el hermano de José Manuel , José Luis 687 58 10 61, comenta que ha pasado 50€ a su hermano a la cárcel para que compre tabaco, quiere saber si hay pensado mandarle dinero a José Manuel a la cuenta peculio del centro p. Comentado con Amalia y Alberto: se esperará a que cobre la pensión pues a día de hoy su saldo es casi nulo. Si después de pagar lo que debe le reta alguna cantidad se le ingresará een la cuenta de la cárcel.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='VAZQUEZ'and apellido2='DIAZ'),'2018-04-25','(Pedro).Excarcelación de Jesús Vázquez del C. Penitenciario de Badajoz por cumplimiento de condena. +++Se traslada al CSS de Mérida (UME) en ambulancia de Cruz Roja contratada para el traslado. +++Sin incidencias durante el mismo. +++Un avez en el CSS y durante la entrevista con la Médico asignada (Taciana), el Psicólogo (Juan Pedro) y otros profesionales, se niega a cumplir con las normas de las que s ele inoforma: pijama, entrega de dinero y dni. Se al tera bastante, profiriendo amenazas antes hipotéticas situaciones que él anticipa. +++Ante esta situación, llamp a Mª José, hermana de Jesús, quien acudirá a visitarle a partir de las 17:00h de hoy mismo, con el visto bueno para ello de Taciana. +++ENtre el personal que lo ha atendido parace haber unanimidad de que el CSS no es el adecuado para él, dada su agresividad manifiesta y la preocupación existenmte por el resto de los pacientes.SE plantea la derivación a UDAC.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2018-04-26','(Pedro)Llamada al Juzgado de 1ª Instancia nº 6 (Penal) de Cáceres (927-620175). +++Diligencias Previas 320/18. +++Citado para reconocimeinto forense el 3 de mayo: no es necesraio que vaya CTAEx porque lo acompañarán desde prisión. +++Envío correo-e a su abogada, Verónica. +++Confirman que su abogada ha presentado recurso al auto de prisión dictado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='BERGANTIÑO'and apellido2='GONZALEZ'),'2018-04-26','Iciar: HAblo con María la psicóloga del CRR. Considera que no es necesario darle a Juan José los 70€ que demanda para ir a Cáceres a visitar a su familia. El mes pasado también pidió dinero para lo mismo y al final no fue gastándoselo en otras cosas. Según MAría se está tranbajando con él el tema de la responsabilidad con dinero, por lo tanto podría gestionarse el viaje con su asignación semanal.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='LEAL'and apellido2='BENITO'),'2018-04-26','Iciar: Llaman desde el CADEX de BAdajoz porque se ha presentado allí CArmen diciendo que no puede sacar dinero del banco. Carmen no tiene autorización para hacer ningún reintegro. Se habla con BAnkia para que puntualmente le puedadn dar 350€ en el día de hoy, y nos manden todos los datos de CArmen que ya enel mes de marzo le habíamos solicitado. Volvemos a hablar con el Cadex para que le diga a Carmen que vaya a retirar el dinero.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2018-04-26','(Pedro)Se envía correo-e a D. Juan Manuel solicitando inofmración de la situación de Dª Manuela,','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='MARTIN'and apellido2='MARTIN'),'2018-04-26','TRASLADO DE CENTRO Llama Isabel, TS del CSS de Plasencia. José Antonio será trasladado al CRF de Nuñomoral (Mensajeros de la Paz)el 02/05/2018. Se queda con ella que si necesitamos algo, llamaremos al CSS.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSARIO'and edp.apellido1='CABEZAS'and apellido2='MAZON'),'2018-04-27','ICiar: Llama el yerno de Rosario (t/c 609 674 558 - 679 48 52 11 hija). Quiere autorización para que pueda viajar a Madrid para la comunión de la nieta. Nos ponemos en contacto con la Residencia para conocer si sería conveniente. La trabajadora social nos enviará por correo electrónico un informe. HAblamos con Manolo, "adjunto" a la dirección del centro.','2');
