insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SEBASTIAN'and edp.apellido1='PAREDES'and apellido2='DICHA'),'2018-05-03','REGRESO FUGA El 03/05/2018. "Se comunica a esa Comisión Tutelar de Adultos que el paciente Sebastián..., ingresado en este Centro y tutelado por esa Comisión, regresa de su fuga a las 12:15 Hs. del día de hoy".','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='GAMERO'and apellido2='GOMEZ'),'2018-05-03','FUGA Y REGRESO DE FUGA El 03/05/2018. "Se comunica a esa Comisión Tutelar de Adultos que el paciente Miguel Ángel..., ingresado en este Centro y tutelado por esa Comisión, se ha fugado del mismo a las 18:45 Hs. del dia de ayer, regresando el mismo día a las 22:20 Hs." +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++(Pedro)Conversación con Carmen Franco (CSS Mérida): +++Pendiente de las inidcaciones de la Unidad de Programas para traslado nuevamente a Zaragoza y acercamiento progresivo posterior según evolución a Extremadura, con fines de semna largos,etc. valorando evolución.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AGUSTIN'and edp.apellido1='RASTROLLO'and apellido2='BARRAGAN'),'2018-05-04','FUGA El 03/05/2018. "Se comunica a esa Comisión Tutelar de Adultos de que el paciente Agustín..., que se encontraba de permiso terapéutico en su domicilio, tendría que haber regresado en el día de ayer y al no hacerlo se activo el protocolo de fuga."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AGUSTIN'and edp.apellido1='RASTROLLO'and apellido2='BARRAGAN'),'2014-05-07','REGRESO DE FUGA El 04/05/2018. "Se comunica a esa Comisión Tutelar de Adultos que el paciente Agustín..., al cual se le activo protocolo de fuga por no haber regresado de permiso domiciliario, regresó a este Centro el día 4 de los corrientes a las 16:00 Hs."','2');
