insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIX'and edp.apellido1='GARCIA'and apellido2='AMBROSIO'),'2018-04-16','SALIDA Sale todos los días al pueblo, solo o con algún compañero. El 25 de febrero participa en la salida para visitar la FIO en Monfragüe. El sábado, 24 de marzo, acude a la fiesta tradicional de la Matanza Hurdana en Caminomorisco. El día 27 de febrero participa enla salida a Coria y a Montehermoso para comprar material para los talleres ocupacionales.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARCOS'and edp.apellido1='GARRIDO'and apellido2='PEREZ'),'2018-04-16','SALIDA Todos los días va de paseo con los compañeros y participa en salidas ocasionales por el pueblo. El 25 de febrero participa en la salida para visitar la FIO en Monfragüe. El sábado, 24 de marzo, acude a la fiesta tradicional de la Matanza Hurdana en Caminomorisco.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LAZARO'and edp.apellido1='LUBIAN'and apellido2='SANTANO'),'2018-04-16','SALIDA Sale esporádicamente por el pueblo y a dar algún paseo por los alrededores con los compañeros. El sábado, 24 de marzo, acude a la fiesta tradicional de la Matanza Hurdana en Caminomorisco.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='DOMINGUEZ'and apellido2='BLANCO'),'2018-05-09','(Pedro)Llamada de Isabel (Plena Inclusión de Zafra). +++Nos envía inoformes de ingreso y alta en UHB de Llerena. +++Enviará inofrmes de incidencias. +++Correo-e: +++++Buenos días, Josefa Domínguez Blanco ha sido dada de alta ayer día 8 de mayo. Les adjunto informe médico de alta y trato de ponerme con contacto con ustedes vía telefónica. Les adjunto también desarrollo del incidente que motivó el ingreso. Muchas gracias de antemano. Un saludo, Isabel Puerto Psicóloga Plena Inclusión Zafra','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='DOMINGUEZ'and apellido2='BLANCO'),'2018-05-07','Correo-e: +++Me pongo en contacto con vosotros para informaros que ayer domingo 6 de mayo, nuestra usuaria y tutelada vuestra Josefa Domínguez Blanco, fue ingresada en la Unidad de hospitalización Breve de Llerena debido a una importante alteración conductual con intento de suicidio. Adjunto incidencia. Aún no disponemos de informe médico ya que no fue facilitado por el psiquiatra que se encontraba en urgencias. He intentado ponerme en contacto con vosotros vía telefónica durante la mañana a los diferentes teléfonos de los que disponemos pero me ha sido imposible. Mañana lo intentaré de nuevo. Muchas gracias de antemano. Un saludo, Isabel Puerto Psicóloga Plena Inclusión Zafra','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2018-04-26','Contactos nieta y nieto. +++Dª Mª Carmen, sita en la calle Gaviota 5-portal 2-1ª de la localidad de El Viso de San Juan, en la provincia de Toledo. Los teléfonos de contacto son los siguientes: 620-673371 (D. José Manuel) y 671-438716 y 925-502182 (Dª Mª Carmen).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2018-05-10','(Pedro)Conversación con las T. Sociales del SSB (Pilar,927-580326, ext.8)y del C. Salud de Valencia de Alcántara (Lidia,54209). +++Ninguna de las dos tienen conocimineto de los supuestos desperfectos en tejado de la vivienda. +++Solicito al Aparejador Municipal Informe Técnico al respecto.Correo-e: trabajadorasocial@valenciadealacantara.es','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONCEPCION'and edp.apellido1='ALEJANDRO'and apellido2='DIAZ'),'2018-05-09','(Pedro)Llamada de Mª Antonia, Psiquiatra de la UHB de Mérida. +++Concepción está ingresada en la UHB y se plantea derivación a UME','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PAULA'and edp.apellido1='SOLANA'and apellido2='GUERRA'),'2018-05-10','ICiar: llama Valentina t.s., t/c 52515, del centro salud de Aldea moret. nos eviará mañana por fax el informe donde ratifica la no necesidad de internamiento en centro de paula.','2');
