insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='MURILLO'and apellido2='DELGADO'),'2018-05-11','(Pedro)Conversación con Carmen Franco, Directora CSS de Mérida (24003). +++CONCLUSIONES DE LA SUBCOMISIÓN: tenía ya previsto el ingreso en Comunidad Terapéutica para el 23 DE MAYO. Una vez que salga de ella se prevé su ingreso en UME de Mérida. +++Ruego nos envíe el Informe de la Subcomisión. Lo enviará.','2');
