insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2018-04-12','(Pedro) Reunión con la Abogacía de la Junta para valorar posible acuerdo con Novaforma (previamente planteo la situación a Consolación para ver hasta dónde se puede acordar).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2018-04-16','(Pedro)Asisto al Juzgado de lª Instancia e Instrucción Nº 2 de Cáceres. +++Se llega a un acuerdo con Novaforma y no se celabra juicio. +++En espera de la Sentencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='RUIZ'and apellido2='LARENA'),'2018-05-11','(Pedro)Llamnada de Gregorio, Alcalde de Valdecaballeros. +++Los vecinos acudieron a solicitar un acto de conciliación con Carmen, pero el Juzgado de Talarrubias no lo admitió por estar carmen viviendo en Mérida. +++Dice que el Arquitecto Municipal ya nos mandó el informe técnico, pero no consta tal Informe en la Comisión. Se le reuega lo vuelva a enviar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EVA MARIA'and edp.apellido1='FERMOSELLE'and apellido2='TEJADA'),'2018-05-15','-AMALIA: CONFIRMO CON AP.8 QUE EVA TIENE UN CONTRATO INDEFINIDO Y ES PERCEPTORA DE PFHC CON UNA NOMINA DE MÁS DE 600€.LA PNC LA TIENE SUSPENDIDA DESDE EL 2001 , ENVIO A PNC EL DOCUMENTO DE OPCION ELIGIENDO PFHC.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADELA'and edp.apellido1='LOPEZ'and apellido2='CASTAÑARES'),'2018-05-15','PENSIÓN Se recibe resolución, de 03/05/2018, por la que se modifica la cuantía de la PNC. Al morir su hermana Cristina, le elevan la cantidad a 369,90 (E/ eccos. desde 01/08/2017). Percibirá atrasos, por seis meses de 2017, de 331,98€; y para 2018 de 4 meses por un total de 221,92€. Total atrasos: 553,90€.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARGARITA'and edp.apellido1='ANTICH'and apellido2='ARROYO'),'2015-05-15','TRASLADO EXPTE. Recibido oficio, de 07/05/2018, de comunicación de traslado del expte. de PNC a Extremadura. Nº. Expte.: 05/0004514-I/2014.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='BRUNO'and apellido2='SAAVEDRA'),'2018-05-15','(Pedro)Conversación con Isabel Carrasco,T. Soc. de la D.G. Infancia y Familia en Badajoz (64577). +++Dice que nos ha enviado por correo ordinario carta solcitando información sobre la disponibilidad de plaza para Dª Felisa: NO NOS HA LLEGADO DICHO CORREO. Me pasa con Pilar Salguero, Jefa de Sección (924-010060 y 64574). +++Conversación con Pilar Salguero. Dice haber estado tratando de hablar conmigo y con Amalia en numerosas ocasiones, también por correo-e. SE le explica la situación: +++++SE le explica que se ha aceptado el cargo el pasado 10 de abril y que ahora estamos en fase de elaboración del inventario para presentarlo al Juzgado. +++++En estos momentos no podemos saber qué plaza se le va a adjudicar ni cuándo. Plantea que hablará con Juan Gordillo, Director del Centro "Ana Bolaños" (924-013640), para ver la posibilidad de que pueda ser trasladada allí hasta que obtenga plaza. +++++Hablaré también con el Director para informarnos de las características del caso.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADRIAN'and edp.apellido1='ORTIGOSA'and apellido2='FUENTES'),'2018-05-15','-AMALIA: SOLICITO POR FAX AL CADEX DE BADAJOZ NUEVA CITACION . LA ANTERIOR SE ENVION AL CAM ANA BOLAÑOS Y NO SE RECIBIÓ A TIEMPO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='VAZQUEZ'and apellido2='DIAZ'),'2018-05-15','Reunión de la subcomisión de casos para valorarla situación de Jesús. Presentes: Soraya (Jefa de Unidad Programas Asistenciales), Isabel (Psiquiatra UME), María (T. Soc. UHB), María (Jefa de Enfermería del CSS de Mérida), Juan José (Psicólogo UME), Pedro (Jefe de Sección de CTAEX)y ¿.......? +++CONCLUSIONES: +++++ Es necesario intentar atender a Jesús en los recursos de los que la Comunidad dispone, antes de valorar la necesidad de canalizarlo fuera de ella. +++++ Dado que no se puede establecer en qué periodo de tiempo se pueda plantear dicha posibilidad, en el caso de que su atención en los recursos de la Comunidad no den resultado alguno, se solicita que se refuercen las medidas de seguridad habituales en el CSS de Mérida, dada la insuficiencia de las acttuales para atender un caso como el de Jesús.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='CONTADOR'and apellido2='MATEOS'),'2018-05-15','(Amalia y Pedro). Reunión con Manuel. +++SE valora la relación de gastos/ingresos en base al presupuesto presentado por Asunción Cabrera de acuerdo con Manuel y con el, elaborado por Alberto en base a los datos obrantes en la Comsión. +++Se establece una limitación permanente de 144€/semana (semanalmente a petición de Manuel, que a los técnicos nos parece también más oportuna). En total, 576€/mes, en los que se incluye, comida, tabaco, móvil y dinero de bolsillo). +++SE prevé también una extra de 100€ para ropa y otra de 150€ para menaje del hogar y prodcutos de limpieza. +++SE le recuerda la necesidad de que tenga siempre la nevera llena, la casa en condiciones adecuadas de higiene al igual que su persona. +++SE le insiste en la NECESIDAD DE REALIZAR EL TRATAMIENTO DE MANERA CORRECTA Y CONTINUADA, ADEMÁS DE ACUDIR A LAS CONSULTAS PROGRAMADAS. Además, se le recuerda que en caso de "recaída" o "bajón" acuda a Asun y a la Comisión. +++INICIO DE SU ESTANCIA DE ALQUILER: 16 de MAYO de 2018.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='GOZALO'and apellido2='CALDERON'),'2018-05-15','PENSIÓN Se recibe resolución de 02/05/2018 sobre modificación de la cuantía de la PINC. Con E/ de 01/09/2017, pasa a cobrar 554,85€. La pensión incluye 369,90€ de cuota + 184.95€ de complemente ayuda 3ª persona. Percibirá retrasos, comprendidos entre el 01/09/2017 y el 30/04/2018, por importe de 1662,05€.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='RUBIO'and apellido2='TRINIDAD'),'2018-05-15','(Pedro)Conversación con Mercedes, T. Soc. Ayto. de Trujillo (927-659391). +++Nos ha enviado el pasado lunes el siguiente correo-E: Buenos días. Os informo de que la madre de D. Antonio Rubio Trinidad, que está tutelado por vosotros, ingresó ayer en el Hospital San Pedro de Alcántara de Cáceres. En estos momentos, según sabemos, Antonio está en el Hospital como acompañante. Aún desconozco el diagnóstico ni las condiciones en que será dada de alta, pero hay también un expediente de incapacitación de la madre pendiente de resolución y, en la medida de lo posible, vamos a intentar que ingreso en Centro Residencial al alta hospitalaria. Os informo para que estéis al día de las circunstancias de Antonio. Si es posible, me gustaría poder hablar con vosotros en algún momento. Gracias y un saludo. Mercedes Prieto Sánchez Trabajadora Social del Ayuntamiento de Trujillo ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Le pido qu etodo lo que me está contando me lo ponga en un correo porque en estos momento mi cabeza no puede abarcar más...LO enviará a ctutelar y al mío corporativo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='BERGANTIÑO'and apellido2='GONZALEZ'),'2018-05-16','(Pedro)Llamada de Juan José (924-255792). +++Quiere saber si lo del CRR de Cáceres va a tardar mucho, porque también se había planteado una vivienda social, aunque él se está portando bien para demostrar que puede vivir independiente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUADALUPE'and edp.apellido1='BARRAGAN'and apellido2='GARCIA'),'2018-05-16','(Pedro)Llamada de José Manuel Rubio, Fiscal de Plasencia (924-427379). +++Se ha derumbado una parte de la vivienda que tiene en Guijo de Granadilla, afectando al vecino. +++El hermano, D. Pedro Barragán, que se venda lo antes posible, porque al parecer, si no se vende pronto los gastos van a superar lo que se saque de la venta. +++ACTUACIÓN: solicitar abogado de oficio para que valore la situación y se encargue de la venta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO MANUEL'and edp.apellido1='ALVAREZ'and apellido2='HIDALGO'),'2018-05-16','Iciar: llama Silvia de Futuex, Antonio Manuel fue al la asociación de Zafra y aunque al pricipio se mostró reticente a visitarla, una vez que estuvo allí se mostró encantado con monitores y compañeros. Hoy, sin previo aviso, se ha presentado en un taxi en el centro. No hay transporte entre Valencia de Ventoso y Zafra con lo que pide se gestione de alguna manera la posiblilidad de que Antono se desplaze a ZAfra swegún su disponibilidad económica aunque fuera tres veces por seman y no todos los días. Llama tb la T.S del centro de salud de zafra, maría t/c 45970,por el mismo motivo. Cree que es muy positivo para Manuel que acuda a la asociación para que salga de su entorno familiar pero expone la falta de ransporte público para ir de Valencia del Ventoso a zafra.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='GAMERO'and apellido2='GOMEZ'),'2018-05-11','REGRESO DE FUGA El 11/05/2018. "Se comunica a esa Comisión Tutelar de Adultos que el Paciente Miguel Ángel..., ingresado en este Centro y tutelado por esa Comisión, regresa de fuga al Centro en fecha 11/05/2018, a las 13.30 Hs."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN MANUEL'and edp.apellido1='GONZALEZ'and apellido2='VICENTE'),'2018-05-17','Recibimos citación del Juzgado de 1ª. Instancia e Instrucción nº 1 de Trujillo, para el día 4/6/18, a las 10:15 horas, en relación al Juicio Verbal 33/2018, por la demanda de recuperación de la patria potestad de la madre, María Dorotea Vicente Parras. En su día, enviamos Informe a la Abogacía General, comunicándoles nuestro parecer. El Juzgado también ha comunicado la citación a la Abogacía General, para que vayan ese día, junto con nosotros.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='MURILLO'and apellido2='DELGADO'),'2018-05-21','(Pedro)Conversación con Loli, T. Social de la UHB del Infanta Cristina (924 218100 y extensión 31806 o 48330). +++TRASLADO DE MARÍA AL CEDEX Mérida: se hará con ambulancia y acompañamiento por Celador desde el H. Infanta Cristina. Una vez allí, la ambulanci y el Celador se marcharán. +++TRASLADO DEL CEDEX A COMUNIDAD TERAPÉUTICA "LA GARROVILLA". Por protocolo del CEDEX, se le pondrá un taxi para dicho desplazamiento pagado por el SES. +++++POSIBIBLE INCIDENCIA: si el test que le realicen en el CEDEX da positivo en consumo de laguna sustancia, NO LA DERIVARÁN A COMUNIDAD TERAPÉUTICA: en la UHB no se tiene constancia de que haya consumido, pero compartió tiempo de ingreso con su "pareja" Antonio y es posible que éste le haya dado algo...En la UHB no le quieren repetir el test "por si acaso...". Le indico que eso sería lo más conveniente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='GOZALO'and apellido2='CALDERON'),'2018-05-21','-AMALIA: SUBIDA DE LA PNC CON CPTO A 554.85€/MES +1662€ DE ATRASOS. LE PASO A LA PARTE EC. EL EXPEDIENTE PARA QUE ACTUALIZE EL ABONO DE LA PLAZA EN CAMP.','2');
