insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GERMAN JOSE'and edp.apellido1='MONTERO'and apellido2='MORENO'),'2018-05-21','-AMALIA: HABLO CON TS CAMP PLASENCIA DONDE SE LE HA CONCEDIDO PLAZA RAL . EL DIA 28 MAYO SERÁ EL INGRESO . LE PIDO CON PLACEAT PARA ORGANIZARLO . EN PRINCIPIO IRIA DE SU CASA A PLACEAT COMO UN DIA NORMAL PARA EVITAR QUE LA MADRE LE IMPIDA SALIR . DE ALLÍ ANDANDO PQ ESTÁ A 5 MINUTOS SE IRÁ AL CAMP. UNA DELEGADA TUTELAR IRÁ A COMPRARLE ROPA Y ENSERES PQ NO LLEVA NADA .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='BRUNO'and apellido2='SAAVEDRA'),'2018-05-21','(Pedro) Llamada de Maribel, Psiquiatra de la Subdirección de Salud Mental (22611). +++La han llamado del "Dulce Nombre de María" para saber cómo iba el trámite del traslado en vistas a darle el Alta allí.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='BRUNO'and apellido2='SAAVEDRA'),'2018-05-21','(Pedro)Conversación con Pilar Salguero (D.G. Infancia y Familia). +++Ha hablado con Juan, Director del "Ana Bolaños": NO ES POSIBLE que Felisa se quede temporalmente allí mientras se le busca un recurso adecuado dado que en el centro HAY NIÑOS MUY PEQUEÑOS y su agresividad y alteraciones de conducta hacen inviable que pueda permanecer allí. SÍ SE OFRECEN, p.e, para el traslado al centro que se le asigne y para cualquier cosa en relación a Felisa "...porque todos en el Centro al quieren mucho, pero su agresividad fue la causa de derivarla al "Dulce Nombre de María".','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='FERNANDEZ'and apellido2='GARCIA'),'2018-05-21','-AMALIA . SE PROCEDE AL CAMBIO DE PERFIL EN RAE , ELIGO EL CAMP LAS CRUCES PARA QUE PERMANEZCA ALLÍ. PONGO EL DOCUMETNO DE ELECCION EN LA FIRMA .','2');
