insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSARIO'and edp.apellido1='CABEZAS'and apellido2='MAZON'),'2018-05-21','DISCAPACIDAD CADEX de CC y BA comunican que no hay expediente a nombre de Mª. Rosario.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2018-05-16','Subcomisión de casos. Presentes: Rosa (Psicóloga CADEX), Domingo (Director Cadex), Maribe (Psiquitra Subdirección de SM), Betariz (Subdirectora de SM), María (Jefa de Enfermería de la UME), Soraya (Jefa Unidad de Programas) y Pedro (Jefe de Sección de CTAEx). +++CONCLUSIONES: +++++Esperar a ver qué resolcuión de toma en el Juicio que tiene pendiente José María. +++++Realizar una actualización diagnóstica en el ESM de Plasencia y, sin cambiar la resolución del CADEx, sí "adaptarla" para que de manera temporal pudiese seguir en Centro de Discapacidad.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUISA'and edp.apellido1='REY'and apellido2='CAMPON'),'2018-05-21','AMALIA. NOS LLAMA SOLEDAD TS DEL HOSP. DE LA MONTAÑA , PARA INFORMAR QUE ESTÁ INGRESADA N LA UHB DESDE LA SEMANA PASADA. NO TIENE PENSION PQ CONVIVE CON SUS HNOS Y SUPERAN EN RENTA. SIN EMBARGO SE PODRIA PEDIR LA PFHC . NO TIENE GRADO DE DISCAPACIADA , LE ENVIO A SELEDAD EL DOCUMENTO PARA QUE APORTE EL I.MEDICO Y LO ENTREGUE EN EL CADEX .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PETRA'and edp.apellido1='COSTA'and apellido2='RODRIGUEZ'),'2018-05-18','PENSIÓN El INSS informa que percibe una PENSIÓN DE VIUDEDAD por 935.15€.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='VAZQUEZ'and apellido2='DIAZ'),'2018-05-21','(Pedro) Llamada de Taciana (Psiquiatra de la UME Mérida) (24065). +++SALIDA del 17 al 18 de mayo."Ha regresado muy bien. No ha consumido (ha dado negativo en tóxicos) y la hermana dice que se ha portado bien. Durante el fin de semana se le ha tenido que realizar contención verbal y también química. Se altera especialmente por las tardes." +++Taciana considera que se ha de establcer con él un programa terapéutico a medio-largo plazo en modificación de conducta, para lo cual también necesita tener la mayaor estabilidad posible. Taciana no ve tampoco conveninete sacarlo en estos momentos de la C.A., porque lo que requiere es preceisamente dicha estabilidad. +++SE ha negociado con él que en función de su comportamineto las salidas serán de 1 día o para pasar fuera una noche, pudiéndose ampliar a todo un fin de semana llegado el caso. +++ALTERNATIVAS: +++++Como se quedó en la Subcomisión, AMPLIAR LAS MEDIDAS DE SEGURIDAD CON AL MENOS 1 GUARDIA DE SEGURIDAD FIJO en todo momento en la UME. +++++UN REFUERZO DE AUXILIARES, de al menos 2 en cada turno, ya que la atención que requiere Jesús es permanente. +++CONVERSACIÓN CON JESÚS: a pesar de haberlo pactado así con Taciana, insiste en querer salir todo un fin de semana completo, de viernes a lunes.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='RUBIO'and apellido2='TRINIDAD'),'2018-05-18','(Pedro)Se envía nota interior a la Gerencia informando de la situación de D. Antonio.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='HERMENEGILDO'and edp.apellido1='RUIZ'and apellido2='ROMERO'),'2018-05-16','FUGA Y REGRESO Entre las 07:50 Hs. y las 22:15 Hs. del 12/05/2018. "Por la presente se comunica que D. Hermenegildo... residente de este centro y tutelado por la Comisión Tutelar de Adultos, seha fugado del centro el día 12/05/2018 a las 7:50 Hs. de la mañana. Se interpone denuncia sobre las 11:19 Hs. ante el Cuerpo Nacional de Policía. Por la tarde se recibe llamada de la Guardia Civil en Cabeza del Buey. Una educadora sale del centro a las 19:45 Hs. en taxi para ir a recoger a Hermenegildo regresando de nuevo al centro a las 22:15 Hs. No opone resistencia para regresar de nuevo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='BRUNO'and apellido2='SAAVEDRA'),'2018-05-22','(Pedro) Conversación con Jesús Porras Quiñero, T. Soc. "Dulce Nombre de María" (Málaga). 952-290499///653985002. FAX:952-206060. Correo-e: dulcenombre@vnet.es +++Se le informa de que en estos momentos estamos elaborando el inventario y que no le podemos decir cuándo vamos a traer a Felisa.','2');
