insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='MONTERO'and apellido2='VAZQUEZ'),'2018-05-14','SALIDA Entre el 14/05/2018 y el 16/05/2018. "Me pongo en contacto con vosotros para informaros que Crístofer se irá el próximo lunes a casa de su tía Belén, de Lácara, y volverá el miércoles, aprovechando el puente de San Isidro. El viaje lo hará en el transporte del centro."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JONATHAN'and edp.apellido1='RAMIREZ'and apellido2='JUAREZ'),'2018-05-22','(Pedro)Visita de Jonathan sin cita previa. Trae la siguinete documentación del Juzgado de 1ª Instancia e Instrucción nº 5 de Mérida: +++DPA Diligencia Previas Poc. Abreviado 0000101/2018. AUTO de 3 de mayo.DELITO de LESIONES.PARTE DISPOSITIVA: obligación apud-acta de comparecer los días 1 y 15 de cada mes y cuando se le requiera en el juzgado, comunicar cualquier cambio de domicilio. +++ DPA Diligencia Previas Poc. Abreviado 0000062/2018. AUTO de 30 de marzo.DELITO de VIOLENCIA en el ÁMBITO FAMILIAR. PARTE DISPOSITIVA: obligación de comparecer ante el Juzgado cuantas veces fuere llamado y comunicar cualquier cambio de domicilio. +++DOMICILIO: DICE CARECER DE ÉL EN ESTE MOMENTO, PORQUE EN EL DE SU PADRE NO PUEDE NI QUIERE ESTAR. SE LE DIRIGE AL cENTRO "Padre Cristóbal", de Mérida, pero no quiere ir. +++SE LE ENTREGA FOTOCOPIA DEL DNI, que porenésima vez dice haber perdido. Pedirá cita nuevamente y cuando la tenga vendrá para hacerle la extra para sacarlo y ENTREGARLE LAS FOTOGRAFÍAS.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='FRAILE'and apellido2='SALAMANCA'),'2018-05-22','(Pedro) Conversación con Asun (Psicóloga CSS Mérida) (24025). +++Javier pasará a los chalets de la entrada del CSS el próximo lunes 28 de mayo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='CONTADOR'and apellido2='MATEOS'),'2018-05-22','Llega el Informe de Alta del CSS de Mérida. Conversación con Asun: +++En el informe enviado al ESM (Dr. Samino) ya se incluye la propuesta de que sea derivado, si se considera oportuno, al CRPS, si bien Manuel no está por la labor en estos momentos.','2');
