insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='MURILLO'and apellido2='DELGADO'),'2018-05-23','(Pedro)Ingresa en Comunidad Terapéutica "La Garrovilla", tras ser derivada desde la UHB del Infanta al CEDEX de Mérida donde ha sido vista por la Enfermera, Mª Carmen y la Médico, Mª Ángeles Piriz. +++En la C. Terapéutica la recibe Carmen, Psicóloga (85705).','2');
