insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='DOMINGUEZ'and apellido2='PALENCIA'),'2018-05-24','Los familiares no saben nada acerca del paradero de Martín. Investigamos sus cuentas y vemos que ha realizado un reintegro el día 22 de mayo en la oficina de su banco en Ayamonte.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='VAZQUEZ'and apellido2='DIAZ'),'2018-05-23','-LLAMADA DE SU HNA Mª JOSÉ , NO HA PODIDO COGER LA ASIGNACION MENSUAL DE 40€/SEMANALES PARA EL PAGO DE GASOLINA . SOLICITA ALGO MÁS DE DINERO . LE DIGO QUE NO ES POSIBLIE AUMENTAR LA ASIGNACION .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='MURILLO'and apellido2='DELGADO'),'2018-05-28','-AMALIA: LLAMA AGUSTINA PSIQUIATRA DE LA UHB DE MERIDA , DONDE ESTÁ MARIA INGRESADA DESDE EL VIERNES . QUIERE SABER SI MANTIENE LA PLAZA EN LA C.TERAPEUTICA PARA VOLVER A DERIVARLA ALLÍ. 8tf81620) LLAMA LA PSICOLOGA DE LA C. TERAP " LA GARROVILLA " (85705) CONSIDERA QUE MARIA NO PUEDE ESTAR EN ESE RECURSO . NO QUIERE PARTICIPAR EN LAS ACTIVIDADES Y AMENAZA CON INTENTOS AUOTILICITOS . LE DOY EL TF DE AGUSTINA PARA QUE HABLEN ENTRE ELLAS Y LLEGUEN A UN ACUERDO . VUELVE A LLAMARME PARA DICIRME QUE HAN ACORDADO QUE PASE DE 8 A 10 DIAS EN LA UHB Y DESPUÉS VOLVERÁN A VALORAR . AGUSTINA TAMPOCO LA VE EN C. TERAP.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='HERMENEGILDO'and edp.apellido1='RUIZ'and apellido2='ROMERO'),'2018-05-28','INTERNAMIENTO INVOLUNTARIO Se recibe Auto nº. 35/18, de 2 de marzo, proc. Int. 237/17, por el cual se autoriza el internamiento de Hermenegildo en la UDAC.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='VAZQUEZ'and apellido2='DIAZ'),'2018-05-28','(Pedro)FALLECIMIENTO DE JESÚS VÁZQUEZ DÍAZ EN LA MAÑA DE HOY. +++DESCANSE EN PAZ. +++Avisamos a su hermana Mª José del fallecimiento. Juan, su marido, nos dice que se desplazan en ese mismo momento a Mérida. +++El dinero que el CSS había sacado para los gastos de Jesús (380€ "creo recordar") los volverán a ingresar en su cuenta. +++Nos trasladamos Soraya y yo al CSS donde también acude el Médico-Forense. +++Se le pide al Forense si es posible esperar a que lleguen los familiares para trasaladr el cuerpo al Instituto dse Meidicina Legal: +++++No es posible esperar. Además me informa de que no lo van a poder ver en el día de hoy. Ya mañana por la mañana sí lo podrán ver y a partir de medio día hacerse cargo del cuerpo. +++Llamo nuevamente a Mª José para informarles de lo dicho por el Forense para que decidan si llegar a Mérida y hablar con nosotros o bien regresar a Badajoz. Deciden llegar al CSS a donde ya están de camino. +++Reunión de la Directora del CSS, la Jefa de Unidad de Programas del SEPAD, el Jefe de Sección de la Comisión TUtelar, Mª José y Carlos (hermanos de Jesús), la madre de éste y su sobrina Fátima. La reunión ha transcurrido por unos cauces de completa noramlidad a pesar de las circunstancias. +++++Se les explica las circusntancias en que se han prodcuido los hechos, sin saber las causas ( a la espera de lo que el Forense determine). +++++Sí se han mostrado bastante molestos por no poder ver a su hermano y velarlo hasta mañana, al respecto de lo cual se les indica que es el protocolo que el Forense nos ha comentado. Se les da el teléfono del IML por si quieren llamar en el día de hoy. +++++Preguntan por los gastos del entierro, si su hermano tenía seguro de deceso: se les informa de que Jesús tiene suficiente dinero para costear el entierro. Se encargará la familia de hablar con la funeraria y luego pasarán la factura a la Comsiión. +++++Se les explica cuáles son los trámites que ahora debe acometer la Comsión Tutelar. +++++Se les entregan las pertencias de Jesús.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='RUBIO'and apellido2='TRINIDAD'),'2018-05-28','(Pedro) Hablo con Domingo en el día de hoy y me informa de que han vuelto a citar a D. Antonio el próximo 30 de mayo. Han contactado con una prima suya que se ha ofrecido a acompañarlo a la cita.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONCEPCION'and edp.apellido1='BARBERO'and apellido2='SANCHEZ'),'2018-05-29','-AMALIA PENDIENTE RECIBIR FE DE VIDA Y ESTADO DE LA R.M. PARA ACTIVAR PENSION DE FRANCIA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GERMAN JOSE'and edp.apellido1='MONTERO'and apellido2='MORENO'),'2018-05-28','AMALIA: SE REALIZA EL TRASLADO DESDE PLACEAT ( C.DIA ) A RAE EN CAMP DE PLASENCIA. SE AVISA A LOS PADRES QUE NO REGRESARA A CASA ( TF 927416248), NO SE AVISO CON ANTELACION PARA EVITAR QUE LA MADRE NO LO DEJASE IR . EL PADRE SE LO TOMA BIEN , LA MADRE DICE QUE ACUDIRÁ AL CENTRO CON LA G.CIVIL. DESDE EL CENTRO LE COMPRARÁN LA ROPA QUE NECESITE.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2018-05-28','AMALIA: LLAMA CEFE PARA INFORMAR QUE SE VA IR A VIVIR A LOGROSAN A UN PISO DE ALQUILER CON SU NOVIA. QUE TANTO ANA DELFA COMO MARIA CLAROS LE DAN EL VISTO BUENO . LE COMENTO QUE DESDE LA CTAEX NO ESTAMOS DE ACUERDO EN ESTE ALTA , QUE TIENE QUE PERMANECER EN EL CENTRO . RENUNCIA A LA PERMUTA A CRR DE MERIDA. QUIERE QUE RENUNCIE TB A LA SOCILICITUD PARA EL DE PLASENCIA ,SOLO SE IRA A CC. NO HAGO TAL RENUNCIA DE SOLICITUD, CAMBIA DE OPINION CONSTANTEMENTE.','2');
