insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA EUGENIA'and edp.apellido1='MOLANO'and apellido2='CAMBERO'),'2018-05-28','-A TENER EN CUENTA INFORME DE PSIQUIATRIA EN EL QUE INDICAN QUE BAJO SU CRITERIO ,NO ES PERFIL DE LA RED DE SALUD MENTAL . ( FECHA 9 DE MARZO 2018)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='VAZQUEZ'and apellido2='DIAZ'),'2018-05-29','(Pedro)Convesración con D. Félix Sánchez, Médico Forense del IML de Badajoz (924-286959. Coge el teléfono el Guardia de Seguridad y pasa la llamada) +++A la hora en que he llamado, sobre las 9, estaban a punto de empezar la autopsia. El Forense me informa de que no es necsario que la Comisión se persone allí, que podemos llamar en tre shoras y nos inofrmarán de los resultados de la autopsia. +++La familia ya estaba en el Instituto de Medicina Legal cuando he llamado. +++FUNERARIA que traslado el cuerpo al IML: "Reina de los Ángeles" (la del propio IML). Teléfono 619-831499. Contacto: Ángel. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Nueva conversasción con Félix, el Forense. +++AUTOPSIA: EDEMA PULMONAR (posible causa del fallecimiento). Probablemenmte causas naturales, pero han pedido análisis toxicológicos y estudio cardíaco para descartar otras alternativas. Los resultados pueden tardar varios meses. +++La familia ha sido informada de todo ello y su actitud ante estas circusntancias ha sido de completa colaboración. +++Solicitamos al Juzgado nº 3 de Mérida el Informe Forense cuando este esté disponible.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2018-05-29','(Pedro)Conversación con Mercedes, T. Social Plena Inclusión Llerena (924871037). +++SE ha pagado ya el taxi del primer viaje al Punto de Encuentro Familiar de Don Benito. +++Los 50€ por el acompañamineto no se ha podido abonar porque la persona que lo realizó ha tenido un problema familiar y no ha podido firmar el recibo. +++Para el día 1 de junio (viernes) seguramente tendrá que ir otra persona. Se procederá de la misma manera. +++INFORMACIÓN: Según refiere mercedes, Antonio (padre de la niña) está enviando fotos a Beatriz de la niña cuando se encuentra con ella (cosa que no está permitida en el punto de encuentro), diciéndole además que ya está con ella y con su abuela. +++++Respecto de las fotos, se le indica que las pongan en conocimineto del Punto de Encuentro (que ya avisó de que no estabn permitidas) para que tomen las medidas oportunas). +++++Respecto del nuevo número de telefóno de Beatriz, se le propone bloquearlo (al parecer Antonio lo consiguió a través de una amiga de Beatriz.).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA SOLEDAD'and edp.apellido1='ACEVEDO'and apellido2='GALLEGO'),'2018-05-29','iCIAR: Llama Clemencia Carmona León del CAmp de Don BEnito para informar que Soledad lleva 3 semanas ingresada en el Hospital de Don BEnito. Ella ha contratado un acompañamiento 24 hs para Soledad. Se ha puesto en contacto con la empresa y a día de hoy la factura asciende a 6000 €.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINA'and edp.apellido1='VELASCO'and apellido2='CAPERUZA'),'2018-05-29','-AMALIA.PONGO PARA FIRMA LAS DECLARACIONES ANUALES DE PNC DE 2017 Y 2018 PARA PODER ACTIVAR NUEVAMENTE LA PENSION. CUANDO ESTE FIRMANDO ENVIAR A PNC','2');
