insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CANDIDO'and edp.apellido1='BAS'and apellido2='GONZALEZ'),'2018-05-30','(Pedro)Llamada de la Guardia Civil de Vva. del Fresno.Julio (Cabo) (924-427013). +++Ha habido una denuncia por amenazas a un vecino, pero no lo han detenido. +++No se explica como una persona así, que está tutelada, puede estar viviendo en estas condicones y con la inseguridad que genera en los vecinos, a los que amenza. +++"Pero cuando se lo lleven tiene que ser SIN AVISARLE, PORQUE SI NO VA A DESAPARECER O VA A ESTAR PREPARADO, porque ya lo ha dicho: si alguien quiere entrar en mi casa o llevarme de ella lo mato..." +++++Cuando se produzca el traslado, AVISAR A AYTO, POLICÍA LOCAL Y GUARDIA CIVIL CON AL MENOS UN DÍA DE ANTELACIÓN PARA SEGUIRLO y que en el momento de efectuarlo esté localizado. +++++Se Informa a Julio de que se ha solictado autorización judicial para ingreso en Centro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CANDIDO'and edp.apellido1='BAS'and apellido2='GONZALEZ'),'2018-05-18','Visita de Amalia y Pedro a la T. Social de Vva. del Fresno. +++Se había pedido unos días de vacaciones. +++Hablamos con una vecina de Cándido. +++++AmenAzas, miedo en los vecino, ruidos por la noches. HACE CUCHILLOS. +++++Cuando su hermana era la tutora le traía la comida en una lata y se la dejaba en la ventana. Ahora la familia hace lo mismo. +++Policía local.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='DOMINGUEZ'and apellido2='GARCIA'),'2018-05-30','LA TRABAJADORA SOCIAL DE MEDINA DE LAS TORRES NOS INFORMA DE LA RESOLUCIÓN DEL PIA, NO ESTA APROBADA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='CALZAS'and apellido2='SANCHEZ'),'2018-05-30','(Pedro)Llamada de Dª Florencia Calzas (hermana)927-416618. 50 años en Alemania y ha vuelto ahora. +++Preocupada por la situación de su hermana. +++Se le informa de que estamos pendientes de obtener plaza residencial.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORA'and edp.apellido1='GUTIERREZ'and apellido2='GARCIA'),'2018-05-30','RECIBIMOS REQUERIMIENTO DEL JUZGADO Nº 3 DE PLASENCIA PARA ACLARAR LA FORMA EN QUE FLORA ADMINISTRA SU DINERO Y SI TIENE ACCESO A LAS CUENTAS. ESTE REQUERIMIENTO TIENE SU ORIGEN EN UNA DENUNCIA QUE FLORA PUSO A UN TAXISTA PORQUE LE PIDIÓ 300 € PRIMERO Y DESPUES 400€ PARA SUPUESTAMENTE PAGAR UN ABOGADO QUE LA SACARA DEL CENTRO. ACLARAMOS AL JUZGADO QUE LA FECHA A QUE SE REFIEREN LOS HECHOS LA COMISIÓN TUTELAR TODAVÍA NO HABÍA TENIDO ACCESO A SUS CUENTAS POR LO QUE ELLA SACABA LIBREMENTE Y NO PODEMOS DETERMINAR SI EFECTIVAMENTE HIZO ENTREGA DE ESE DINERO, SI APARECEN REINTEGROS POR LOS IMPORTES QUE ELLA REFIERE POR LO QUE SE ENVÍA AL JUZGADO EXTRACTO DE MOVIMIENTOS DE SU CUENTA. MJGH','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2018-05-30','(Pedro)Conversación con María Isabel, del PEF de Don Benito. +++Confirma que este viernes es la próxima visita de Beatriz a su hija. +++Se les informa de las incidencias puestas en conocimineto de la Comisión ayer desde Plena Inclusión de Llerena.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CANDIDO'and edp.apellido1='BAS'and apellido2='GONZALEZ'),'2018-05-30','Iciar. Después de conversación con el juzgado nº 1 de Olivenza, adelantamos por fax la solicitud de ingreso involuntario. Enviamos también por correo postal.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='HIDALGO'and apellido2='ROMO'),'2018-05-30','RECIBIMOS LLAMADA DEL CENTRO PENITENCIARIO DE CÁCERES (MAITE 927181407) PARA CONFIRMAR SI TENEMOS TUTELADO A ANTONIO HIDALGO ROMO, LE COMENTO QUE ES UNA CURATELA. ME INFORMA QUE ESTÁ EN PRISIÓN DESDE FEBRERO DE ESTE AÑO PROCEDENTE DEL SOCIOSANITARIO DE PLASENCIA. ACTUALMENTE NO COBRA NINGUNA PENSIÓN, HASTA AGOSTO DE 2017 PERCIBÍA RENTA BÁSICA. DESDE PRISIÓN LE VAN A SOLICITAR GRADO DE DISCAPACIDAD Y POSTERIORMENTE VALORAREMOS CUAL ES LA MEJOR OPCIÓN. DE MOMENTO NO TIENE NADA DE DINERO Y SU FAMILIA NO QUIERE SABER NADA DE EL, DE HECHO PARECE SER QUE SE ENCUENTRA EN PRISIÓN POR AMENAZAS A SUS HERMANOS. MAITE TAMBIÉN NOS TRANSMITE LA NECESIDAD DE ANTONIO DE QUE LA COMISIÓN TUTELAR VAYA A VISITARLO Y EXPLICARLE EN QUE CONSISTIRÁ NUESTRA GESTIÓN. MJGH','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CANDIDO'and edp.apellido1='BAS'and apellido2='GONZALEZ'),'2018-05-31','(Pedro)Intento de hablar con el cabo de la G.Civil Julio. la llamada se deriva a la Guardia Civil de Olivenza al estar e estos momentos cerrado el Cuartel de Vva. del Fresno. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Correo-e enviado a Soraya. En relación al caso de D. Cándido B. G., de Vva. del Fresno, ayer llamó la Guardia Civil como creo que ya os conté a tí y a Consolación. Y esta mañana ha llamado una de las hermanas, la anterior tutora, preguntando quién se va a ocupar ahora de "su" hermano, quién le va a dar de comer, etc... En este caso considero que el paso previo por la red de Salud Mental (UHB) es imprescindible antes dedetrminar cualquier recurso. La cuestión es cómo accede a esa red, porque al parecer (estamos en periodo de inventario) no ha pasado hace tiempo por el ESM que sepamos y el único Informe del que se dispone es de septiembre de 2013, en el que se diagnóstica retraso metal no especificado leve-moderado. Tampoco creemos que esté siguiendo el tratamiento desde hace mucho tiempo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUIS MIGUEL'and edp.apellido1='MUÑOZ'and apellido2='SANCHO'),'2018-05-31','-AMALIA: CONTACTO CON PAULA ( CTRO PENIT. ) SOLICITA 150€ PARA ROPA ,ELLA SE ENCARGA DE COMPRARLA FUERA . VAN A TRASLADARLO A UNA CARCEL DE MADRID O SEGOVIA , NOS AVISARÁ.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MERCEDES'and edp.apellido1='PEREZ'and apellido2='PINNA'),'2018-05-31','-AMALIA : DESDE HACE MES Y MEDIO SE LE ATIENDA EN OFICINA TODAS LAS SEMANAS , NOS TRAE DATOS SOBRE SU PATRIMONIO , DEUDAS.. Y GESTIONES ECONOMICAS. CON RESPECTO A SU SEGUIMIENTO DE LA SALUD , YA SE HA DADO DE BAJA EN SANITAS Y VA AL CENTRO DE SALUD DE LA ZONA CENTRO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TERESA'and edp.apellido1='MANGAS'and apellido2='DE LA CRUZ'),'2018-05-31','(Pedro) Converación con Ana, T. Soc. de la Residencia de Torre de Don Miguel (638-658981). +++Le llegó ayer la sentencia de incapacitación de Dª Teresa de fecha 23 de mayo.No nos consta todavía a nosotros. +++SE le explica el proceso a seguir a partir de cuando nos llegue. +++Refiere que Dª Teresa INGRESÓ EN LA RESIDENCIA en JULIO DE 2017. Desde entonces NO HA ABONADO DINERO ALGUNO ni para el pago de la plaza ni para sus gastos. +++ANA va a estar de VACACIONES hasta el 18 de junio.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2018-05-31','(Pedro)Conversación con Pablo (676-783101) y su mujer sobre la situación de las visitas a Dª Manuela. +++"Es José Manuel la que se niega a cualquier tipo de acuerdo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUANA'and edp.apellido1='NIETO'and apellido2='LABRADOR'),'2018-05-31','(Pedro) Conversación con D. Candelario, agente de la Guardia Civil de Zafra.924-550124. +++Solicita permiso para incluir una fotrografía de Dª Juana en la base de datos de la G.C. para v´citimas de Violencia de Género. +++Lo pedirá por correo-e. +++Podemos recurrir a él en otros posible casos de V.G. con otras tuteladas, aunque no sean de la localidad.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VICHO'and apellido2='ALFONSO'),'2018-05-31','Iciar: Desde JDo nº 4 de plasencia nos solicitan les comuniquemos en qué centro se encuentra José María. Les enviamos fax.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO MANUEL'and edp.apellido1='ALVAREZ'and apellido2='HIDALGO'),'2018-05-31','-AMALIA: ESTOY VALORANDO NUEVA PRESTACION POR DEDPEND. PERCIBE PECE , SU MADRE NO LO ATIENDE ADECUADAMENTE , ELLA TIENE DELIRIO COMPARTIDO SEGUN INFORMACION DEL SSASB. HE SOLICITADO INFORMES AL ESM Y AL CADEX , PARA VALORAR DENTRO DE QUÉ RED PROCEDE SU INGRESO . SEGUN SENTENCIA DE INCAP SU DIAGONOSTICO ES R.M. LIGERO +TNO CDTA+TNO PSICOTICO+LIMIACION FUNCIONAL EN UN PIE . NO SE HAN RECIBIDO LOS INFORMES SOLICITADOS. EN PIA ME CONFIRMAN QUE EL PRIMERO DE ELLOS SE RESOLVIO CON C.DIA EN APROSUBA 1 DE ZAFRA.ÉL SE NIEGA A IR Y POR ESO SE CAMBIA A PECE. HABLO CON OLGA M. TS DE VALENCIA DEL VENTOSO , ME VA A ENVIAR INFORME , SU PROPUESTA ES INGRESO EN CENTRO . FINALMENTE VALORANDO LA OPINION DE TODOS LOS AGENTES IMPLICADOS ( INCLUIDO FUTUEX ) NEGCIO POR PIA PETICION DE C.DIA Y / O R.A.E . ELLOS LO ENVIAN A DISCAPCIDAD Y MAYTE AL CADEX PARA QUE VALORE PERFIL. HAY QUE SOLICITAR INTERN. INVOLUNTARIO A NIVEL JUDICIAL PARA SU POSIBLE INGRESO . ALICIA ( DEPENDENCIA ) ME ENVIARÁ EL PIA Y SE LO REEENVIARÉ FIRMADO , REGISTRADO DE ENTRADA Y POR CORREO POSTERIORMENTE.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JORGE'and edp.apellido1='MARTIN'and apellido2='BLANCO'),'2018-05-31','-AMALIA : JORGE VIVE EN LA CASA FAMILIAR CON SUS PADRES SITO EN C/PLASENCIA , BLOQUE 7 , PORTAL A BAJO B . ACUDE AL C.E.E. CASA DE LA MADRE EN MERIDA (924009556)PERO LA EDAD MAXIMA ESTABLECIDA ES HASTA 21 AÑOS Y LOS CUMPLE ESTE JUNIO . DESDE DEPENDENCIA NOS LLAMAN PARA NEGOCIAR PIA. HABLO CON SU PADRE QUE NO QUIERE QUE LO LLEVEMOS A PLAZA RESIDENCIAL Y SÍ ESTÁ DE ACUERDO EN UN RECURSO DE DÍA . PIDO INFORMES AL C.E.E. PARA VALORAR EL RECURSO MÁS ADECADO . INFORMO A PEPA UGALDE DE LA SITUACIÓN ACTUAL Y DE QUE VAMOS A ESPERAR A QUE NOS LLEGUE ESE INFORME PARA DECIDIR. EN PRINCIPIO OPTO POR C.O. EN MERIDA , SI LOS INFORMES LO AVALARAN PEDIRIA RAL.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CANDIDO'and edp.apellido1='BAS'and apellido2='GONZALEZ'),'2018-06-01','Correo-e de Clara (dependencia): +++Hola Pedro, se trata de BAS GONZALEZ, CANDIDO, BJE-09910-11, Grado I. Este expediente está inactivo por No aprobación PIA, es decir le ofrecimos 20 horas de ayuda a domicilio y 98 € al mes porque tiene capacidad económica y rechazó. Se puede revisar si lo considerais. Ahora la hermana ha llamado al call center como lees más abajo. Les pongo en copia para que tengan conocimiento de que os hemos pasado la información. Saludos -------- Mensaje reenviado -------- Asunto: BJE-09910-11 Fecha: Thu, 31 May 2018 12:08:52 +0200 De: INES FLORES TAPIA >ines.flores@fitex.net> Para: Clara Isabel Gómez Nestares >clara.gomez@salud-juntaex.es> Hola Clara: La hermana de este chico que ha dejado de ser su tutora legal, para pasar a serlo según le ha informado el juzgado la Junta de Extremadura, nos llama ya que no consigue hablar con la comisión tutelar de adultos y en espera de internamiento en un centro por su fuerte agresividad ,manifiesta que nadie le está llevando la comida, y a ella la ha amenazado y le pide dinero. La chica se llama Mª José y su teléfono es el 605129003 Un saludo Ines Flores Tapia Gestora Telefónica Serv.Att.Dependencia Fitex Ilunion Tel:901.12.14.16 ines.flores@fitex.net Descripción: Descripción: Descripción: Descripción: Ilunion Fitex','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN FRANCISCO'and edp.apellido1='OSORIO'and apellido2='CALDERON'),'2018-05-30','-LO ATIENDO EN OFICINA , QUIERE REMOVER LA TUTELA PARA QUE LA COGA UN AMIGO SUYO , TESTIGO DE JEHOVÁ Y QUIERE BAUTIZARSE EN ESA RELIGIÓN . LE EXPLICO LAS OPICONES LEGALES QUE TIENE , ASÍ COMO DE LAS POCAS PROBABILIDADES QUE TIENE . SU MADRE ESTÁ INGRESADA EN R.M. DESDE QUE FALLECÍO EL MARIDO. SU HNO , SOLTERO , VIVE EN LA CASA . LO LLAMA ESTANDO CONMIGO REUNIDO Y LE DICE QUE LA MADRE LE ESTÁ PIDIENDO IR A LA CASA Y QUÉ NO SABE QUÉ VA A HACER , QUE SE VA A SUICIDAR . ÉL LE DICE Q NO LA PUEDE LLEVAR PQ PUEDE CAERSE COMO LE OCURRIÓ A SU PADRE Y LO TRANQUILIZA.','2');
