insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUISA'and edp.apellido1='RODRIGUEZ'and apellido2='GRAGERA'),'2018-06-06','En relación con la herencia de la madre, solicitamos abogado de oficio para solicitar la autorización judicial de aceptación de la herencia. A día de hoy no hemos recibido la designación del Colegio de Abogados, ni la confirmación de la Comisión. Sin embargo, llama Estefanía dándonos un teléfono de un abogado que al parecer es el que ha sido designado. Se llama José Moreno Ávila (697441072-jmoreno@icaba.com). Él ha recibido la designación el 4/6/18. Hasta que no recibamos la designación, ni la confirmación nosotros, no enviamos documentación alguna.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2018-06-06','(Pedro)Reunión NO programada con Ildefonso. +++Trae el contrato de alquiler (se lleva la copia), un informe del ESM de Zafra de 2017 y certificado de empadronamineto. +++DEBE EL MES DE MAYO de alquiler: nos pondremos en contacto con el dueño para insistir en que el pago se haga por transferencia. +++ALQUILER +++++Dirección: Avda. de la Estación nº 14, 2ºD de ZAFRA. +++++PROPIETARIOS: D. Juan antonio Serrano Murillo y Dª Mª Dolores Zambrano Vázquez. +++++TELÉFONO: 608-703345. +++Dice haberse gastado le pasado mes el dinero (600) en "mantener" a las dos personas que conviven con él y que por eso no ha podido pagar el alquiler (¿?) +++SE le da extra para pagar farmacia( y otros gastos): Ldo. Rafael Augustino Fernandez. Calle Huelva, 25. Zafra. teléfono: 924-550791.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AGUSTIN'and edp.apellido1='RASTROLLO'and apellido2='BARRAGAN'),'2018-06-05','FUGA El 05/06/2018. "Se comunica a esa Comisión Tutelar de Adultos que el interno Agustín..., ingresado en este Centro y tutelado por esa Comisión, no acude al CSS, tras disfrutar de permiso de ocio, e fecha 05/06/2018. Se activa protocolo de fuga."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADOLFO'and edp.apellido1='GARCIA'and apellido2='CRUZ'),'2018-06-06','PENSIÓN Se recibe certificado del INSS para inventario. Percibe PNC Incapacidad por un importe de 369.90€.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='MURILLO'and apellido2='DELGADO'),'2018-06-06','(Pedro) María tenía cita en el CEDEX hoy a las 11:00h. +++Contacto con UHB para informar de ello. Me comentan que nunca se ha llevado a nadie que estuviese ingresado al CEDEX. +++Contacto con el CEDEx (924-300862). Intento hablar con Mª Ángeles (84758)pero no coge el teléfono. Hablo con Fabián para que le informe de que la consulta no se va a poder realizar por estar ingresa en UHB. Volveré a llamar. +++Informo a MªÁngeles de la situación.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CANDIDO'and edp.apellido1='BAS'and apellido2='GONZALEZ'),'2018-06-05','(Pedro) Acompañamineto a D. cándido al Juzgado de 1ª Instancia nº 1 de Olivenza. +++MOTIVO: CITADOS PARA RECONOCIMINETO FORENSE. +++RECURSOS MOVILIZADOS: el Cuartel de la Guardia Civil, 4 Agentes con 2 vehículos, el Conductor de la Consejería y el representenate de la Comisión Tutelar. +++RESULTADO: NO ESTABA EL FORENSE. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Desde la semana pasada en que se puso en contacto la Guardia Civil de Villanueva del Fresno con esta Comisión para inofrmarnos de la denuncia interpuesta por un vecino contra D. Cándido por amenzas se solict','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='BRUNO'and apellido2='SAAVEDRA'),'2018-06-06','(Pedro) Acuden a la Comisión Maribel (Psiquiatra) y Rocío (t. Social) de la Subdiercción de Salud Mental. +++Están presionando desde el "Dulce Nombre de María" para que se haga el traslado de Felisa a un centro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CANDIDO'and edp.apellido1='BAS'and apellido2='GONZALEZ'),'2018-06-06','(Pedro)Conversación con María, T. Social del SSB de Vva. del Fresno. +++Se informa de las gestiones realizadas ayer. +++++++++INTERVENCIONES PLANTEADAS+++++++++++++++++++++++ +++Se le pide que solicite cita en la Médico de Familia para Cándido para que lo derive a Salud Mental. +++Dada la colaboración que planteó su hermana María josé, será ella la encargada de acompañarlo al médico y, en su caso, al ESM. Si ello no fuera posible finalmente se trataría de que lo acompañara FUTUEX (Cándido ayer no quiso ir al juzgado si su hermana MªJosé no lo acompañaba, ni quería otra comida que la que le llevara ella). +++Una vez visto por el ESM, valorar ingreso en UHB para estabilizar e instaurar tratamiento y, en su caso, derivar a UME si da perfil. +++++Si no es así, solcitar ingreso en Centro para Personas con Discapacidad. +++ALIMENTACIÓN: se compromete su hermana a llevarle la comida, al menos hasta que sepamos si puede ingresar en algún centro. Para ello, se compromete a enviarnos un presupuesto de los gastos que su hermano le pueda ocasionar y en función de ingresos pagarle los mimsos. +++++Parece ser que hay una deuda pendiente con la ermpresa que le ha estado llevando la comida durante algún tiempo (Hablar con teresa sobre ello).Una vez abonada, se puede contactar nuevamente con ella y que sea la que le lleve la comida. +++LIMPIEZA: el SAD, según María, no puede intervenir en estos monemtos. Ya hablé con la hermana para ver si ella podría tratar de adecentar la casa... +++RELACIONES ENTRE HERMANAS: según María no son buenas y María José "malmete" a Cándido contra sus otras dos hermanas (Isabel y manoli), pero quizá sea con Isabel con la que más se puede contar. Teléfono de Isabel: 669-539304) +++Si se comprueba que la colaboarción con la (las) hermanas no es la adecuada, solamente queda el seguimiento con Teresa (Futuex) que, de cualquier manera, se ha de mantener.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA SOLEDAD'and edp.apellido1='ACEVEDO'and apellido2='GALLEGO'),'2018-06-06','(Pedro)Conversación con Victoria, T. Social de Atención al paciente del Hospital de Don Benito (86643 y 924-386812). +++El Dr. Galán quiere hablar presencvialmente con alguien de la Comisión para explicar en qué va a consitir la intervención, riesgos, etc. +++Hace unos días, las hermanas de Dª Soledad fueron a visitarla y dijeron que se encargarían ellas de acompañrla, pero al parcer la situación ha cambiado por que una alega que tiene una niña pequeña y la otra un comercio, por lo que nuevamente se va a recurrir a la Empresa que realizó días atrás el acompañamineto: 4 horas/día de 10 a 14 h. +++Acudiré mañana al hospital para entrevistarme con el médico.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALMUDENA'and edp.apellido1='CORREYERO'and apellido2='PAREJO'),'2018-06-07','NOS LLAMA ANTONIO, HERMANO DE ALMUDENA , PARA DECIRNOS QUE HA CAMBIADO DE COMPAÑÍA DE SEGURO DE DECESOS. ACTUALMENTE TIENEN DE COMPAÑIA CASER, ES UNA POLIZA PARA LOS 3 HERMANOS PERO CADA UNO ABONA SU PARTE. ALMUDENA CONCRETAMENTE PAGARÁ 37,12€ ANUALES, COMO SE YA SE LE DA A ANTONIO EL DINERO PARA LOS GASTOS, NO ES NECESARIO ABONARLE NADA. (MJGH)','2');
