insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA SOLEDAD'and edp.apellido1='ACEVEDO'and apellido2='GALLEGO'),'2018-06-07','(Pedro)Acudo a la entrevista solicitada por el Dr. Galán para informar de la sitaución de Soledad. +++Al no aceptar la sonda oral hay que intervenir para implantar sonda direcytamente eal estómago, evitando así, si no totalmente, sí en buena medida el problemna de aspiraciones que tiene a la hora de comer by que le pueden provocar axfisia. +++Se encontraba allí la aompañante de la >empresa a la que se le ha solcitado el sewrvico. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Visito tamnbién el CAMP y me reuno con Clemen, su Directora.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='MONTAÑA'and apellido2='ALISEDA'),'2018-06-07','(Pedro) Hablo con Rosa, T. Soc. del SSB de Don Benito sobre la situación de María Luisa. +++Solicitamos autorización judicial de ingreso involuntario +++Solicitar plaza en residencia de mayores POR EMERGENCIA SOCIAL, una vez hecha la solcicitud anterior para adjuntarla.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CANDIDO'and edp.apellido1='BAS'and apellido2='GONZALEZ'),'2018-06-07','(Pedro) Conversación con la Dra. Paqui Vizcaino, del C. Salud de Vva. del Fresno (924-427512)y(42918).DIRECTO: (42904). +++Mañana tendrá el volante de derivación al ESM y quizá también la cita. +++Ha hablado conb el Dr. Samino, el cual se encuentra ya al tanto de la situación. +++OBJETIVO: valorar la salud mental en el momento actual, actualizar el diagnóstico y, en base a ello, proponer cuál sería el recurso más adecuado para Cándido.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='VAZQUEZ'and apellido2='DIAZ'),'2018-06-07','-AMALIA: RECIBO DOS VECES LA VISITA DE SU HERMANA M. JOSÉ EN OFICINA. ME TRAE LOS ALBARANES DE LA FUNERIARI Y DE LA LAPIDA . HABLO CON AMBOS PARA PEDIRLES QUE NOS ENVIEN LAS FACTURAS Y Nº DE CUENTA. SE LO PASO A ALBERTO PARA QUE PROCEDA AL ABONO EN CUANTO LLEGUEN. DESPUES QUEDA LA D.FINAL DE CUENTAS Y NO QUIERO Q SE PASE EL TIEMPO LEGAL PARA EL TEMA DE LA HERENCIA. COMUNICO A PNC LA BAJA DE LA PENSION, YA TENIAN EL COMUNICADO DE LA S.S. . SE PROCEDE A LA BAJA , EN JUNIO YA NO LA VA A PERCIBIR.','2');
