insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='BUENO'and apellido2='FERNANDEZ'),'2018-06-11','José Antonio fue sanacionado con amonestación verbal por falta leve, basado en el Decreto 83/2000, de 4 de abril por el que se regula el estatuto de los Centro de Mayores de la Consejería, por agresión verbal con otros residentes. Igualmente se le sancionó con la retirada del dinero de bolsillo semanal (se le estaban reponiendo 20 € semanales). Hace un par de semanas vino a decirme que ya había transcurrido un tiempo y quería nuevamente su asignación semanal.Le informo que se realizará de forma gradual y en principio le asigno 10€, cosa qe no acepta con actitud poco decorosa me indica " que quién me he pensado que soy yo.. y que el dinero es suyo...que ya me enteraré..."... de lo que os informo para que tengais conocimiento como tutores de Jose Antonio. El incidente protagonizado por Jose Antonio fue consecuencia de la ingesta de alcohól, motivo por el que se le retira la asignación semanal para evitar que compre vino.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUSTINO'and edp.apellido1='DE SANDE'and apellido2='CHAPARRO'),'2018-06-13','FALLECIMIENTO Se recibe, el 12/06/2018, DIOR del Jzdo. nº. 1 de Plasencia solicitando informe de Justino. Al mismo tiempo nos comunica su fallecimiento. Tras comunicación telefónica con el CSS de Plasencia, donde residía, averiguamos que el óbito tuvo lugar el 01/06/2018.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN PABLO'and edp.apellido1='BUENO'and apellido2='SANTOS'),'2018-06-13','(Pedro) Llamada de Dª Carri, hermana de Juan Pablo (608-236411). +++"Hace dos años que no voy a verlo por mis circusntancias...y vaya, si mi madre pidió la tutela para ingresarlo rápido cuando fuese necesario, pero si hubiera sabido esto..." Se le inofrma de que puede solicitar la remcoión de la tuetela si lo desea. "A mi no me llamaron en el juicio...-a preguntas mías-..." +++Quiere saber qué dinero tiene para saber si le pueden pagar los implantes que él se quiere poner. " A mí me han dicho que para estas personas no es bueno que se los pongan y que es más barato un puente..." +++Quiere también que le suban de 4€/día a 6€/día porque cada vez que va su madre le tiene que pagar más de 100€ a otro paciente que le presta...LO ha comentado con las cxompañeras del CSS y le ha dicho, como yo, que todos sus necesidades están cubiertas y que 120€/mes, fuera de ellas, es una cantidad considerable.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CANDIDO'and edp.apellido1='BAS'and apellido2='GONZALEZ'),'2018-06-13','(Pedro) +++Conversación con Carmen, T.Soc. ESM Valdepasillas (42853/42897/ 924-218004). +++++CITADO para el 17 DE OCTUBRE de 2018 a las 10:30h en consulta de Psiquiatría (Dr. Samino). Insisto en la posibilidad de adelantarlo por la urgencia del caso (todos lo son) y, al parecer, ha habido una baja en agosto: NUEVA cita el 27 de AGOSTO a las 9,10H (LOS NUEVOS SE CITAN A PRIEMRA HORA). +++CONVERSACIÓN CON Mª JOSÉ, hermana de Cándido. RELATO DEL FIN DE SEMANA: "Cada vez que le he llevafdo la comida me está esperando a mí o a mi hija o a mi yerno con un a navaja enorme, amenazándonos porque nos pide dinero y no se lo damos (estamos en periodo de inventario). A mí me amenzáo el sábado con unas tijeras. Pedimos ayuda a la Polciía Local para llevarle la comida pero dijeron que eso no era comepetencia suya..." Imposible plantear que mañana, 14 de junio, colabore para llevar a su hermano al forense en Olivenza.Ya me dice que bajo ningún concepto. +++++Al parecer también ha roto la luna de un vehículo en estos días... +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++CONVERSACIÓN CON EL CABO DE LA GUARDIA CIVIL, Julio (924-427013 y, solo en caso necesario, el corporativo 680-430974): corrobora todo lo que dice Mª José. En cuanrto a la luna del coche, también son sabedores de ello, pero al parecer todo el mundo piensa que ha sido él pero nadie lo ha visto... +++Comenta que hace unos días castró a un perro que se metíacon los suyos, dejándole los genitales colgando...Al parecer el Alcalde está pensando intervenir, porque además es el veterinario. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con ALMA, del Juzgado de Olivenza (924-492834). +++Se le pone al tanto de las últimas informaciones, de la impossibilidad de llevar a Cándido de nuevo a Olivenza y de la conveniencia de que sea el Forense el que se traslade a Vva. del Fresno. Inclsuo le planteo, para que lo hable con su Señoría, la posibilidadde que el propio Forense, si el Juzgado da la Oreden de ingreso, pueda activar el 112 para ingreso en UHB del Infanta. +++Llama una vez inofarmada su Señoría: "no es preciso que la Comisión esté presente en el reconocimineto y, si mañana a las 10:00 h, hoara de la cita, Cándido no está allí (ya le indico que no va a estar), dará orden a la G. C. para que acompañen al Forenese a su casa. +++Le informo que la intención de etsa Comisión es estar presente en ese momento, pero que en estos momentos carecemos de vehículo disponible para ello. Mañana a primera hora volveremos a plantearlo y llamaremos nuevamente al Juzgado. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Nueva llamada al cabo de la G.Civil para ponerle qal tanto de las nuevas circunstancias. Dará parte a su superior para que haya efectivos disponibles al efecto (insisto en tener localizado a Cándido una vez que el Forenese llegue).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='RODRIGUEZ'and apellido2='CACERES'),'2018-06-14','Recibimos citación del Juzgado de Instrucción nº 2 de Badajoz, procedimiento abreviado 665/2016, para el día 19/6/2018, a las 10:00 horas, para práctica de prueba preconstituida. Es una declaración ante el Juez, con la asistencia de una psicóloga. Ésta quiere reunirse con nosotros antes de la celebración de la prueba, a las 9:00 horas. La acompañan desde Aprosuba 3.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LIBERTAD'and edp.apellido1='GARCIA'and apellido2='MARQUEZ'),'2018-06-16','SALIDA Entre el 16/06/2018 y el 17/06/2018. Fin de semana en su casa de Badajoz.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BARTOLOME'and edp.apellido1='ALBA'and apellido2='GRAGERA'),'2018-06-14','(Pedro)Conversación con D.Bartolomé. Ha estado esta mqañana en la Comisión hablando con Alberto. +++MAÑANA INGRESA en el "Perpetuo Socorro" a las 19:30h para ser intervenido en un dedo del pie (¿para amputar?). +++Llamaré mañana a Rosa para inoformarnos porque desconocíamos esta situación.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CANDIDO'and edp.apellido1='BAS'and apellido2='GONZALEZ'),'2018-06-14','(Pedro). Nueva visita a Vva del Fresno, citados por el Juzgado para reconocimineto Forense: +++Convresación con la G. Civil. +++Convresación con el Forense: no ha considerado necesario acudir a la localidad tras informarle de los últimos acontecieminetos del pasado 5 de junio y de este fin de semana (amenaz>as a la hermana, rtotura de luna de un coche, "castración" de un perro supuestamente achacada a él...". +++++Emitir´ña informe para internamineto inmediato. Dudas sobre la foerma de articular el traslado. +++SE INFORMA DE TODO ELLO A LA T. SOCIAL Y AL ALCALDE DE VvA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='MURILLO'and apellido2='DELGADO'),'2018-06-08','(Pedro)Visita a María en la UHB. Hablo con ella y con Agustina, su Psiquiatra (81620). +++Está prevista su derivación a UME para el próximo 20 de junio. +++Coincide Agustina en que es un caso muy difícil.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='MURILLO'and apellido2='DELGADO'),'2018-06-15','(Pedro)Convresación con Agustina, Psiquiatra UHB. +++El pasado vierens, 8 de junio, María se tomó unas pastillas que cogió de otra paciente y se las tomó. Se le hizo un lavado de estómago por precaución, porque','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUISA'and edp.apellido1='REY'and apellido2='CAMPON'),'2018-06-15','(Pedro)Llmada de Soledad (56950), T. Soc. HIC.. Correo-e remitido: +++Soy Soledad, Trabajadora Social del H. Ntra. Sra. Montaña de Cáceres, ayer os llame en varias ocasiones al tlfo corto el 68590 y 68504; no he sido capaz de constastar con vosotros y tengo necesidad de hablar de la Tutelada vuestra, LUISA REY CAMPON, está pendiente que el equipo de valoración de Dependencia la pueda valorar, han ido en varias ocasiones al domicilio y no les abre la puerta. El médico me dice que no viene nadie a interesarse por esta Señora y últimamente ha tenido varios ingresos en la UHB, por que no realiza el tratamiento, no tiene red primaria de apoyo y esta Señoria se le deberia solicitar un ingreso por Emergencia en un Centro de la Junta de Extremadura, para asegurar sus cuidados y atenciones. Sin mas y esperando os pongais lo antes posible en contacto conmigo al Tlfo: 56950. Un Saludo ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Nuevo ingreso en HIC el pasado 10 de junio Soledad +++Llamada: +++++el lunes, Alberto acudirá al HIC para hacer la valoración de dependencia. +++++solicitar por emergencia ingreso en centro de mayores.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2018-06-15','(Pedro)Conversación con María, T. SOc. ESM de Zafra, enrelación a visita/informe de futuex del 4 de junio (ver expediente). +++Consideran que Ildefonso debería pasar una temporada ingresado, pero cuando acude a la consulta lo hace tranquilo y, si bien se altera en algunos momentos, cosnideran que derivarlo a UHB sin una clara desestabiloización no va a faciliatr su infgreso. +++María manifiesta que, como también se opina desde la Comisión, este paciente debería estar ingresado ya que no existen los medios ni recurosos para garantizar de forma aedecuada el día a dí: control de tratamineto, asistencia a consultas, alimentación, higiene, vestido, compañías...Si no existe ese control diario, se condena a una situación de ingresos repetitivos entre los cuales, con este paciente u otros, pueden surgir problemas importante tanto para ellos vcomo para terceros.','2');
