insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DESIDERIA'and edp.apellido1='BARBERO'and apellido2='BUENO'),'2018-06-18','(Pedro)Llamada de Rosa (CSS de Plasencia). Se pone al teléfono D. Ángel Pérez Manzano, marido de Dª Desideria. +++Están pagando cla hipoteca de la casa en la que están viviendo (quedan unos 14.000€), pero la quieren vender y ya la tienen "apalabrada". Quiere saber si tiene que "firmar" la Junta para venderla. +++SE le informa que sí, que la Comisión tiene que ver la conveninecia o no de la venta y soplcitar en su caso al Juzgado autorización para la misma. +++ACEPTACIÓN del CARGO: 26 de ABRIL. SIN INVENTARIO TODAVÍA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='BRUNO'and apellido2='SAAVEDRA'),'2018-06-18','-AMALIA: SOLICITADA PLAZA PARA CENTRO DE DISCAPACIDAD','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2018-06-19','-AMALIA: BEATRIZ GASTA 150€ AL MES EN LA VISITA QUE HACE A SU HIJA EN CC, 100 DE TAXI Y 50 DE CUIDADORA . SOLICITO A FUTUEX QUE VIRGINIA LE ACOMPAÑE EN CC CUANDO VAYA Y REDUCIMOS ESE COSTE . LO COMUNICO A APROSUBA LLERENA .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LIBERTAD'and edp.apellido1='GARCIA'and apellido2='MARQUEZ'),'2018-06-19','-VA MEJORANDO SU ADAPTACION , HAN ENVIADO DESDE APROSUBA UNA INSCRIPCION PARA UN MODULO , ENVIAR LAS 3 COPIAS.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUISA'and edp.apellido1='REY'and apellido2='CAMPON'),'2018-06-19','-HABLO CON SOLEDAD , ME CONFIRMA QUE ALBERTO DEPEND Y LA DELEGADA TUTELAR ESTUVIERON EL LUNES ALLÍ . LA IDEA ES QUE PASE DE LA UHB A RESIDENCIA DE MAYORES . LE HAN DADO UN GRADO II , HAN SOLICITADO LA CAPACIDAD EC. EN ESTA SEMANA ENVIARÁN EL PIA . HAY QUE PEDIR AUTORIZACION JUDICIAL PQ PUEDE QUE NO QUIERA INGREASAR VOLUNTARIAMENTE ( SE LO DERIVO A ANGEL ) . UNA VEZ QUE SOLICITEMOS PLAZA RESIDENCIAL HABRIA QUE HABLAR CON MARIA LEON PARA INTENTAR PLAZA EN CC , POR LA CERCANIA A LA UHB. TIENE UN DELIRIO RESIDUAL , NO ALTERACIÓN CONDUCTUAL. CUANDO INGRESE HAY QUE TRAMITAR PNC , ACTUALMENTE NO LA PERCIBE PQ SUPERAN INGRESOS CON LOS HERMANOS.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CACHO'and apellido2='GARRIDO'),'2018-06-18','-SOLICITO AL HOSPITAL DE C.REAL INFORMACION DE FCO, ME INFORMAN QUE EL 13 DE JUNIO FUE DERIVADO AL H.V.DE LA MONTAÑA DE CC. ME MANDA INFORME PSIQUIATRICO .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CACHO'and apellido2='GARRIDO'),'2018-06-19','-ME PONGO EN CONTACTO CON ISABEL ( TS DEL H. V.MONTAÑA ) YA HA SIDO DADO DE ALTA . ME VA A ENVIAR INFORMACION SOBRE ESTE CASO , MUY CONOCIDO POR ELLA. SOLICITA UNA SUBCOMISION DE CASOS , DONDE ESTEN UHB, SUBDIRECCION SALUD MENTAL , C.S.SANTIT. , ... EN SU OPINION EL RECURSO SERIA LARGA ESTANCIA , PERO PARA INGRESAR ALLÍ NO PUEDE IR DERIVADO DESDE LA UHB SINO DESDE EL PROPIO CSS. LE COMENTO QUE DERIVEN ENTENCES A UME Y LUEGO ELLOS VALOREN , NO DA PERFIL PARA ESA DERIVACIÓN. SE COMPENSA RAPIDAMENTE . TENDRIAMOS QUE PEDIR UN INTERN INVOLUN. JUDICIAL . NO TIENE RESIDENCIA FIJA , VAGABUNDEA , SE VA CON ALGUN AMIGO ... ACTUALMENTE EN PARADERO DESCONOCIDO. SIN PENSION , HA INTENTADO SOLICITARLE PNC PERO AL NO TENER RESIDENCIA FIJA NO HA PODIDO . LA MADRE ( ADOPTIVA ) ESTÁ ESCONDIDA EN UNA RESIDENCIA DE MAYORES , POR TEMOR A SU HIJO , LE PIDE DINERO . CONSUME TÓXICOS CUANDO DISPONE DE ÉL . TIENE UNA HIJA DE 8 AÑOS QUE TIENE ACOGIDA UNA PRIMA HERMANA ( CARGO DE LA JUNTA ) A LA QUE RESPETA Y NO MOLESTA PARA NADA. SOLICITO A LA TS ,INFORME DE ALTA DE ESTE INTERNAMIENTO , UN INFORME DONDE MOTIVE AL INGRESO EN CSS PARA PEDIR LA AUTORIZACION JUDICIAL , INFORMACION RELATIVA AL DOMICILIO DE LA MADRE PARA EMPADRONARLO ALLI Y PEDIR PENSION ( PNC ? PFHC? P.ORF? . QUEDO PENDIENTE DE SU RESPUESTA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='RODRIGUEZ'and apellido2='CACERES'),'2018-06-19','(Pedro). Acudimos al Juzgade de Instrucción nº 2 de Badajoz. Finalmente se suspende por no haber sido avisado el Mº Fiscal de la citación para hoy. +++PRESENTES: Los Letrados D. José Antonio Romero Porro (Aprosuba 3), D. Francisco Espada Guerrero (Futuex), D. Tomás Sala Chaves (Defensa); Dª Emilia Rodríguez Cáceres (Curatelada); Dª Lourdes Corrales Isaac (Psicóloga del IML de Badajoz).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CATALINA'and edp.apellido1='MIRANDA'and apellido2='ROSADO'),'2018-06-19','(Pedro)Visita no programada de Catalina. +++Acude tranquila, serena. +++Plantea nuevamente si la Comisión cree que sería buena para ella volver a compartir piso, porque a veces se siente un poco sola.Le comento que eso es algo que debería hablar con Asun, para conocer su opinión. +++Quire un extra de 60€ para comprarse ropa, que se le autoriza (consulto a Alberto). +++Finalemnte plantea la cuestión de si ella podría voluntariamente volver al CSS o a los Pisos Supervisados. Se le explica que, en caso de recaída -como ella dice-debería avisarnos si fuera posible o acudir voluntariamente a la UHB del Hospital, donde la atenderían y decidirían si derivarla o no al CSS. +++++Consulto con Asunción Cabrera este último aspecto, dado que me ha generado cierta sorpresa su planteamiento dado el aparente buen estado en que se encuentra. Asun también considera que su deseo repetivtivo y con arrepentimientos suscesivos de compartir su vida con alguien a la hora de ejecutarlo quizá deba de ser valorado en estos momentos. Redactará inoforme para el ESM en el sentido de valorar la posibilidad de derivación a pisoso o CRR por parte del Equipo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='VAZQUEZ'and apellido2='DIAZ'),'2018-06-20','-TF DE MARIA JOSÉ 627386178','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='MURILLO'and apellido2='DELGADO'),'2018-06-20','(Pedro)Llamada de Agustina, Psiquiatra UHB de Mérida. TRasladan a María a UME a las 10:30h. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++(Pedro). Presente en el ingreso junto con su madre, María Soledad. Psiquiatra: Isabel. +++Pido a Alberto que envíe autorización general.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='SANCHEZ'and apellido2='BELLO'),'2018-06-20','(Pedro)Nueva llamada de Dª María Rodríguez Tello. +++Pregunta por si vamos a hacer alguna intervención en la casa e insiste en que a ella no le importaría alquilar la vivienda e incluso inciar alguna pequeña reforma en ella que trata de explicar. +++++Le propongo nos envíe un correo electrónico explicándonos dicha propuesta para valorarla en la Comisión. Le parece bien y nos enviará su propuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='RODRIGUEZ'and apellido2='BONILLA'),'2018-06-20','NO SE PRESENTA DECLARACIÓN DE LA RENTA PORQUE UNA VEZ SOLICITADOS LOS DATOS FISCALES VEMOS QUE NO ESTÁ OBLIGADO. MJGH','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO'and edp.apellido1='SUDON'and apellido2='HERNANDEZ'),'2018-06-20','(Pedro)Se presentan en la Comisión una de la hermanas y el gerente de la inmobiliaria con la que se ha firmado un pre-contrtao de compra supeditado a la autorización judical de venta de la casa. +++No constaba en el expediente la soclicitud formulada por la hermana, a pesar de que tenbía registro de entrada del 11 de mayo. +++Le paso la documentación a Ángel y queda pendiente el tema de la deuda que los hermanos tienen con Pedro al haberse hecho cargo de los gastos de la casa al 100% cuando su cuota de participación es del 10%.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='HIDALGO'and apellido2='ROMO'),'2018-06-21','-AMALIA : ANTONIO SE ENCUENTRA ACTUALMENTE EN EL C.PENITENCIARIO DE CC. PERCIBIÓ RENTA BÁSICA HASTA AGOSTO DEL AÑO PASADO . ACTUALMENTE SIN INGRESOS. LE HE GESTIONADO PNC INVALIDEZ , LLEVO SOLICITUD, OFICIO Y DOCUMENTACION PARA ENTREGAR EN MERIDA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CANDIDO'and edp.apellido1='BAS'and apellido2='GONZALEZ'),'2018-06-20','Llega Auto del Juzgado de 1ª Inst. e Instrucción nº 1 de Olivenza: +++AUTORIZA ..."el internaminento no voluntario de en la Unidad de Psiquiatría por razón de trastorno psíquico de D. Cándido Bas González para estudio, control y tratamineto". +++++Inclusye Informe Médico Forense y acuerdo de la Fiscalía. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Llamamos la Juzgado para saber si desde él se van a disponer los medidos necesarios para su traslado. La Secretaria lo hablará con el Juez y nos llamará.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CANDIDO'and edp.apellido1='BAS'and apellido2='GONZALEZ'),'2018-06-21','(Pedro)Llamada al Juzgado de Olivenza. Hablo con Alma. +++El Juez ha determinado que sea el tutor el que habilite los medios necesarios para ejecutar el ingreso de D. Cándido. Se le explica que la Comisión carece de los medios para ello y de las competenmcias para la activación del 112, por lo que nos pondremos en contacto con el C. salud de Vva. del FResno para dicha activación. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con la Dra. Paqui Vizcaíno, del C. Salud de Vva. de la Serena (FAX: 924-427082): SE LE ENVÍA AUTO DE INTERNAMINETO NO VOLUNTARIO emitido por el Juzgado de 1ª instancia nº 1 de Olivenza. Activará 112 para su traslado. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Informo de todo ello a María, T. Social del SSB de VVa. del Fresno y a la Guardia Civil de la localidad.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA SOLEDAD'and edp.apellido1='ACEVEDO'and apellido2='GALLEGO'),'2018-06-21','(Pedro)Conversación con Fausti, T. Soc. Hospital Don Benito-Vva. +++En contacto con ella para conocer la evolución del estado de Soledad a través de los correos electrónicos compartidos entre el día 11 (intervención) y el 20 de junio. +++Correo de ayer 20 de junio:Buenos días Pedro, acabo de ver a Soledad, ayer vino el cirujano, tenia los puntos infectados, de ahí la inflamación, lo raro es que la infección no ha dado la cara, y no le ha dado fiebre. El cirujano actuó en el momneto y le limpio toda la infección, sin anestesia ni nada, la cuidadora que está ahora, lo tuvo que presenciar todo, porque el cirujano le dijo que se quedará en representación, por si hubiera alguna complicación. Le han puesto de comer por vía intravenosa, la recuperación va ser más lenta de lo previsto, porque le han dejado la herida abierta para que cicatrice de dentro a fuera, de todas formas luego busco al médico y hablo también con él. Ella tiene buena cara, a ver si ya no hay más complicaciones y se mejora pronto. Con respecto a la familia, no hemos vuelto a tener noticias de nadie, menos mal que le habeis puesto la cuidadora sino la pobre esta sola. Un saludo, Fausti.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA SOLEDAD'and edp.apellido1='ACEVEDO'and apellido2='GALLEGO'),'2018-06-11','Intervención quirúrgica de Soledad en el día de hoy, comunicada por correo-e por Fausti T. Soc. del Hospital D. Benito-Vva (mariafa.barrena@salud-juntaex.es).','2');
