insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CACHO'and apellido2='GARRIDO'),'2018-06-21','(Pedro)Conversación con Pilar, T. Soc. ESM de Cáceres. +++Ha gestionado la estancia de D. Francisco en un Hostal de Cáceres a través de Cáritas hasta que el día 27 de junio lo vea Juan Pedro (Psiquiatra) en su consulta. +++Alternativas: +++++convocar una Subcomisión de Casos para tratar la situación de D. Francisco, convocatoria que le comento a Pilar la Comsión no tiene competencias para realizar. +++++Valorar la posibilidad de ingreso voluntario en UHB por parte de D. Francisco o bien derivarlo desde el ESM. +++++Otra alternativa sería pedir internamiento involuntario por orden judicial, lo que conllevaría un mayor retraso y tener que activar el 112 para su traslado, activación que tampoco esta Comisión es competente para iniciar, deviéndolo hacer los servicios médicos. +++Pilar cree que podría ser un paciente de larga estancia, dadas sus caraterísticas. +++Planteará todas estas alternativas en el ESM.','2');
