insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUGENIA'and edp.apellido1='PACHECO'and apellido2='VICENTE'),'2018-06-22','-AMALIA: DESDE EL CRR DE PLASENCIA SOLICITAN QUE ALGUIEN DE CTAEX PUEDA HABLAR CON ELLA PARA EXPLICARLE LAS MEDIDAS IMPUESTAS EN LA ULTIMA SUBCOMISIÓN. HABLAR CON PAULA DEL CRR. LO DERIVO A FUTUEX PARA QUE HAGAN LA VISTA.','2');
