insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DOLORES'and edp.apellido1='MARAVER'and apellido2='NORIEGA'),'2018-06-22','-AMALIA : ME REUNO CON SU SOBRINA ELISABETH , PARA HABLAR DE ELLA . CONSIDERAN QUE NO SE LE ESTÁ CUIDANDO BIEN EN EL RECURSO DONDE ESTÁ. CREE QUE NO TIENE DEPENDENCIA SOLICITADA, CONFIRMO QUE SÍ , ESTÁ EN FASE DE GESTION DE CITA. SE LE PODRIA PONER ESTIMULACIÓN COGNITIVA. ENVIO A FUTUEX A SEGUIR CON ESTAS VISITAS PARA QUE NOS CUENTEN CUAL ES LA SITUACIÓN . DE MOMENTO NO SE VA A SOLICITAR CAMBIO DE RECURSO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA SOLEDAD'and edp.apellido1='ACEVEDO'and apellido2='GALLEGO'),'2018-06-22','(Pedro)Visita a Soledad en el Hospital Don Benito-Vva. +++En estos momentos le están dando alimentación parenteral. Previsto empezar con aporte de agua a lo largo del día de hoy y valorar como acepta la alimentación a través de sonda gástrica. +++Evolución adecuada de la infección de la herida, que quedo a nivel subcutáneo sin afectar a zona muscular. +++Según evolución, posible alta la semana que viene.','2');
