insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CANDIDO'and edp.apellido1='BAS'and apellido2='GONZALEZ'),'2018-06-25','(Pedro)Convresación con Paqui Vizcaíno. +++Se realizó el ingreso de D. Cándido en la UHB del HIC el pasado viernes por la tarde, acompañado de la Guardia Civil. +++Llegó tranquilo, se duchó y durmió bien. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Llamo a Mª José (605-129003).Le informo de la situación y quedo en llamarla nuevamente cuando sepa algo desde la UHB. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Hablo con Loli, T. Soc. UHB del HIC: tienen una reunión a mitad de mañana. Me llamará para informarme. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++SE comunica a Carmen, T. Soc. del ESM de Valdepasillas, el ingreso en UHB de D. Cándido. +++Al igual que la Comisión, Carmen plantea la conveninecia de que desde la UHB pueda ser derivado a UME para tener más tiempo en su estabilización. Le pido que si pueden hacer algo en ese sentido la Comisión apoyaría la medida.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIPE'and edp.apellido1='BLANCO'and apellido2='GUISADO'),'2018-06-08','SALIDA El 08/06/2017. "Buenos días, informo que hoy Felipe Blanco va a participaren en una formación de la Federación Plena Inclusión Mérida, sobre accesibilidad cognitiva.************Va a formar parte de un grupo de trabajo de accesibilidad cognitiva."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RICARDO'and edp.apellido1='ROCHA'and apellido2='BARCO'),'2018-06-25','SE ENVIA CORREO A FUTUEX PARA QUE PIDA DOS PRESUPUESTOS A EMPRESAS PARA LIMPIAR LA VIVIENDA DE RICARDO. EN PRINCIPIO NO ES NECESRIA LA DESINSECTACIÓN DE LA VIVIENDA.','2');
