insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='RODRIGUEZ'and apellido2='BONILLA'),'2018-06-25','-AMALIA: HABLO CON YOLANDA ( MENSAJEROS DE LA PAZ ) 927673047 PARA ESTABLECER PROTOCOLO EN CASO DE FALLECIMIENTO ,PADECE UN CANCER Y ESTÁ EN PROCESO TERMINAL . NO TIENE SEGURO DE DECESOS PERO TIENE DINERO , LE INSTO A QUE AVISE A LA FUNERARIA DE REFERNCIA LLEGADO EL CASO Y NOS ENVIEN FACTURAS. SE ENTERRARÁ EN SU PUEBLO . HAY DOS PRIMOS QUE PASAN A VERLO Y SON LOS HEREDEROS , LE COMENTO QUE PREGUNTE TB A ELLO POR SI CONOCEN SUS DESEOS PARA SER ENTERRADO.','2');
