insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VICENTE'and edp.apellido1='ROJO'and apellido2='CARRASCO'),'2018-06-26','-AMALIA: ENVIO AL CADEX REVISION DE GRADO POR AGRAVAMIENTO Y SOLICITUD DE TRASLADO DE EXPEDIENTE DESDE EL DE CC.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CANDIDO'and edp.apellido1='BAS'and apellido2='GONZALEZ'),'2018-06-26','(Pedro). Conversación con Loli, T. Soc. HIC (48330). +++Psiquiatra:Dr. Ingelmo (48538).UHB:48320 +++SITUACIÓN: al poco de examinar al paciente ya informó al la T. Social de que en unos días se iba de alta y que se hiciera un seguimiento de su tratamineto. +++++Actualmente está tranquilo, administrándosele "ceprium" intramuscular. +++++En conversación que Loli mantuvo con María (T. Soc. del SSB), esta le dijo que si se garantizaba que Cándido estaba tranquilo se podía quedar en los pisos tutelados de la localidad. La opinión de la Comisión en este sentido es que no solamente ha de esstar tranquilo, sino querer quedarse allí y no irse a su casa. Además, está la dificultad de hacer un seguimiento en el día a día. +++Inoformo a Loli de que la idea de la Comisión erea que desde UHB se derivara a UME para ver su evolución en el tiempo y valorar el recurso más adecuado para él, que la Comisión considera, en este momento, es la red de salud mental. Se le informa de los riesgos que en estas condidicones existen si vuelve a su domicilio, dada la alarma social creada en la localidad desde hace años.ME PROPONE HABLAR CON EL DR. INGELMO Y ME PASA CON ÉL, PERO NO COGE EL TELÉFONO. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Vuelvo a hablar con Loli: llamaré mañana a primera hora al Dr. Ingelmo y, caso de que no puieda comunicar con él, Loli se encargará de hacerle llegar el punto de vista de la Comisión. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con Mª José, hermana de Cándido. SE le inofrma del estado tranquilo en que se encuentra su hermano. Volveré a llamarla una vez haya hablado con el Médico. +++Ayer llamó a la Unidad y le dijeron que podía ir a vistarlo por la tarde, pero que por teléfono no le podían dar inofrmación alguna. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con María, T. Soc. del SSB de Vva del FResno. +++Preocupada por si regresa pronto al pueblo, para que en caso de que ocurra su casa pueda estar en mejores condiciones. Plantea que autoricemos a las hermanas entrar a limpiar, pero se le propone que la limpieza la haga el ayuntamineto: nos enviará solcitud de autorización para dicha limpieza. +++Su idea es que D. Cándido, si vuelve a la localidad, pueda residir en los pisos tutelados, acudsiendeo a su casa durante el día, o bienm que, en condiciones adecuadas, pueda vivir en ella volviendo a solictar la ayda a domicilio: SE DEJÓ DE PRESTAR ESTE SERVICIO POR IMPAGO de varias mensulaidades por parte de la hemana que lo tuteló: al parecer se denbunció a la hermana por ello al Juzgado pero parece ser que nos se hizo nada al respecto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONCEPCION'and edp.apellido1='BARBERO'and apellido2='SANCHEZ'),'2018-06-26','-AMALIA : ENVIO FE DE VIDA A SS DE FRANCIA . DESCONOZCO LA DIRECCIÓN , LO ENVIO A LA DIRECCION DE SORIA ORTIZ .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALBERTO'and edp.apellido1='RAMOS'and apellido2='BLANCO'),'2018-06-26','-AMALIA : CONTACTO CON SU HNA ANA PARA QUE NOS ACOMPAÑE A LA PRIMERA VISITA PERO NO PUEDE VENIR . ME DICE QUE HACE TIEMPO QUE NO SABE NADA DE ÉL . CONTACTO CON SU PADRE ( 619782212) NOS ACOMPAÑARÁ EL VIERNES . ME CUENTA QUE ALBERTO VIVE AHORA CON UNA CHICA , PERO QUE EN LA FERIA LO HA VISTO VESTIDO DE MUJER . TIENE UNA PLANTA DE MARIHUANA EN CASA . LO HA QUITADO YA DE LA CUENTA BANCARIA , PQ LE ESTÁ PIDIENDO DINERO CONSTANTEMENTE.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSARIO'and edp.apellido1='BARROSO'and apellido2='DORADO'),'2018-06-26','-AMA: ENVIO A FUTUEX NEGOCIACION PIA PARA PODER ELEGIR LO QUE MEJOR CONVENGA . EL EMAIL DE DEPENDENCIA ES DEL DIA 26 DE JUNIO Y QUEDA PTE. DE ESTA GESTION','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAIRO'and edp.apellido1='PUERTAS'and apellido2='MARTIN'),'2018-06-26','(Pedro)Conversación con Jairo, a petición de Isabel, T. Soc. del CSS de Plasencia. +++Quiere ser independiente.Considera que se ha cometido una conspiración contra él. +++Quiere ir a la Universidad, etc. Estáfuera de la realidad. +++SE le propone que nos envíe un escrito con todas sus quejas, planteaminetos de futuro, qué medios para llevarlos a cabo, etc.y la Comisión se lo hará llegar al Juzgado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA SOLEDAD'and edp.apellido1='ACEVEDO'and apellido2='GALLEGO'),'2018-06-27','Alta hospitalaria hoy, 27 de junio.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CANDIDO'and edp.apellido1='BAS'and apellido2='GONZALEZ'),'2018-06-28','(Pedro)Llamada del Dr. INgelmo, Jefe de Psiquiatría del HIC (48538//48073). +++"Aquí D. Cándido se comporta como un "corderito": acepta la medicación, tiene una buena actitud, dócil...No da problema alguno. Tampoco veo que se pueda diagnosticar de esquizofrenia como aparece en el Informe Médico Forense. El tiene diagnóstico de retarso mental leve-moderado. Ahora le vamos a hacer un test de CI". +++Le pongo al día de los sucesos ocurridos últimamente en la localidad y de la alarma que hay generada en ella desde hace tiempo. Choca este comportamineto con el que demuestra en la UHB. +++Planteamiento de la CTAEx: mantener su internamiento durante unos meses en UME y durante ese tiempo, ver comó evolciona. De volver en estos momentos a la localidad existe el riesgo de que tienda a buscar al responsable de este ingreso. +++++El Dr. Ingelmo duda de que vaya a ser admitido en UME y plantea la posibilidad de solicitar URH o bien tanto UME como URH.Hará la solicitud.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIX'and edp.apellido1='GARCIA'and apellido2='AMBROSIO'),'2018-06-28','(Pedro)Conversación con Alicia, DUE de la Casa de la Misericordia (0927-674303): +++Solicitan autorización de la Comisión para pruebas diagnósticas por dolor abdominal y pérdida de peso que no remite. +++Solicito nos envíen por fax consentimineto inofrmado para su firma. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Se envía Consentimiento Informado a Ana Marta, T. Soc. del H. Virgen del Puerto (78471), al fax nº 927-428332.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CACHO'and apellido2='GARRIDO'),'2018-06-27','-AMALIA : HABLO CON ISABEL , LA TS DE LA UHB DEL HOSPITAL VIRGEN DE LA MONTAÑANA DE CC . FCO. ESTÁ NUEVAMENTE INGRESADO EN LA UHB . QUERÍA QUE LA CTAEX CONVOCASE UNA SUBCOMISION DE GESTION DE CASOS PARA BUSCAR UN RECURSO RESIDENCIAL . LE COMENTO QUE ESA SUBCOM. TIENEN QUE PROGRAMARLA DESDE S.MENTAL , ASÍ COMO LA DERIVACIÓN A UN RECURSO DENTRO DE ESA RED Y QUE NOSOTROS ASISTIRIAMOS COMO PARTE. LO HABLARÁ CON PILAR DEL ESM DE CC . VOY A DERIVAR EL CASO A FUTUEX PARA QUE LA COMPAÑERA PUEDA ACERCARSE Y COORDINAR ESTE CASO . ESTAMOS HACIENDO GESTIONES PARA AVERIGUAR EL EMPADRONAMIENTO DE FCO , APARECE EN VARIOS DOMICILIOS DE DISTINTAS LOCALIDADES PARA TRAMITAR UNA PNC , ACTUALMENTE NO TIENE RECURSOS EC. SU MADRE ADOPTIVA ESTÁ INGRESADA EN R.MAYORES , ESCONDIDA DE ÉL , PQ LA ACOSA BUSCANDO DINERO PARA CONSUMO DE DROGAS.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MEJIAS'and apellido2='DE LA MORENA'),'2018-06-28','(Pedro)ASISTENCIA al Juzgado de 1ª Instancia e Instrucción nº 1 de Zafra. +++VIDEOCONFERENCIA con el Juzgado de Instrucción 5 de Mollet del vallés. Previas 400/2015. Informada de la posibilidad de no prestar declaración al comparecer como testigo, Beatriz renuncia declarar alegando que no recuerda los hechos motivo de esta citación.Se acepta por parte del Juzgado su decisión. +++D.P. Procedimineto Abreviado 0000167/2018. Hyabía sido citada para el 20 de junio, pero había perdido la citación y se le había pasado. En el juzgado se le propuso tomarle declaración en ese mismo día y así se realizó. +++D.P. 62/2018 (Violencia de género contra su expareja): plantea que quiere retirar la denuncia. Pregunto si es posible según el momento en que se encuentre el procedimiento y me dice la funcionaria (Mª Eugenia)que sí, es posible hasta que se dicte sentencia.En este caso tampoco establecer orden de protección. +++++Previamente había hablado con Beatriz en el sentido de que, como le han dicho en el CRPS, se lo piense antes de tomar una decisión equivocada. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Visita a Patricia (Psicóloga)y María (T. Social) del CRPS. Informo de la conversación mantenida con Betariz. +++Dejo copia de grado de discapacidad y enviarán presupuesto de las cosas que necesite para el cambio de domicilio.','2');
