insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SEGUNDA'and edp.apellido1='GARCIA'and apellido2='CARRILLO'),'2018-06-28','(Pedro)Conversación con D. Gregorio, hermano de Segunda. +++Preocupado porque, dice, el año pasado no se hizo la declaración de la renta de su hermana y porque en el santander hay 90.000€ "parados". +++Dice que ahora se va a ir a Cataluña.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUANA'and edp.apellido1='GONZALEZ'and apellido2='NARANJO'),'2018-06-28','-AMALIA . ACUDE AL DESPACHO EL INQUILINO . YA NOS DIERON PTO. DE LA REFORMA DE LA CASA . HAY QUE VALORAR CON LA PARTE EC. CÓMO VAMOS A PROCEDER . LO CITO PARA EL JUEVES DE LA SEMANA QUE VIENE PARA DAR UNA RESPUESTA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUISA'and edp.apellido1='REY'and apellido2='CAMPON'),'2018-07-02','-AMALIA: EL 27 DE JUNIO ANGEL ENVIÓ EXPTE.PARA INTERNAMIENTO INVOLUNTARIO EN CENTRO " ADECUADO A SU PATOLOGIA. " ROSA , TS DEL C.SALUD DEL CASAR DE CC NOS ENVIÓ UN INFORME SOCIAL JUSTIFICANDO ESTA MEDIDA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUISA'and edp.apellido1='REY'and apellido2='CAMPON'),'2018-07-02','- Correo enviado por FUTUEX : La delegada acude al hospital a visitar a Luisa, nuevamente en el dia de ayer, 26 de Junio de 2018 en principio se valoró alta para hoy pero van a mantenerla en el hospital hasta final de semana puesto que aún no está estabilizada del todo, el psiquiatra propone que mientras se tramita su ingreso en centro se busque a alguien de la localidad para que acuda al domicilio a administrarle la medicación de forma correcta puesto que continua sin tener adherencia al tratamiento y duda que se tome la medicación pautada de forma correcta. Habla con Sole, TS del hospital Virgen de la Montaña y comenta que esta misma mañana ha estado hablando con la CTAEX para informar de que le han concedido el grado 2 de dependencia y que por el momento no hay plazas disponibles en centro para ingresar a luisa, por lo tanto, se plantea gestionar plaza de emergencia y para ello le han solicitado informe social a la trabajadora social de su centro de salud de referencia. En el momento de la visita no puede ver a Luisa porque en ese momento están comiendo los enfermos de la planta en el comedor, para no interrumpir a Luisa ni al resto de internos, decide acudir por la tarde en el horario oficial de visitas para comprobar su estado actual in situ. Una vez allí la encuentro mejor de ánimo, y comprueba la mejoría de la que nos habla el psiquiatra doctor molina, se observa a Luisa más animada y centrada en la realidad, aunque mantiene discursos en torno a su delirio. Mañana antes del alta de Luisa, 29 de Junio, irá a Casar para tratar de negociar con los dos hermanos, Fermin de 54 y LUis de74, el que puedan de alguna forma estar pendientes de que su hermana se tome la medicación, dado que esta va a ser oral, va a ser complicado en principio que colaboren pero lo vamos a intentar, también cabe la posiblidad que aunque le digan que tiene que tomarlas está no lo haga, dado que no existe conciencia de enfermedad y dice que las pastillas le vienen mal, también hay que tener en cuenta que uno de los hermanos es fuente de sus deliros, en concreto Fermin, Luisa dice constantemente que entra en su cuarto por la noche...','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUISA'and edp.apellido1='REY'and apellido2='CAMPON'),'2018-07-02','-AMALIA : RECIBO DENEGACION DE MARIA LEON DE LA PLAZA RESIDENCIAL DE MAYORES POR EMERGENCIA SOCIAL . HAGO UN ESCRITO A LA UNIDAD Y SOLICITO LOS MOTIVOS POR LOS QUE SE HA DENEGADO . LE PASO EL CASO A SORAYA MAYA QUE ABORDARÁ EL CASO . PTE. DE SU RESPUEESTA.','2');
