insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CANDIDO'and edp.apellido1='BAS'and apellido2='GONZALEZ'),'2018-07-03','-AMALIA: SOLICITO REVISION PIA , SU EXPEDIENTE SE CERRÓ PQ PASARON 3 MESES Y NO ACEPTÓ LO QUE SE LE PROPUSO EN SU DÍA . LO REGISTRO Y ENTREGO A CLARA DEPENDENCIA . TB HE SOLICITADO REVISION GRADO , PENDIENTE QUE ME ENVIEN INFORMES MEDCIOS ACTUALIZADOS. CLARA ME DICE QUE EL EXPTE ES DE PEPA UGALDE Y HASTA SEPTIEMBRE NO LO VAN A VER.','2');
