insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BASILISO'and edp.apellido1='JIMENEZ'and apellido2='HERNANDEZ'),'2018-07-03','-AMALIA. HABLO CON DEPEND PLASENCIA , TS 5 , ME VA A ENVIAR PIA. CREE QUE LA MEJOR OPCION ES PLAZA RESIDENCIAL . LO HA COMENTADO CON EL PADRE FERNANDO , Y OPINA IGUAL. ACUDE A PINO FRANQUEADO PARA COMER Y A VECES DORMIR . LA VVDA. EN CONDICIONES INFRAHUMANAS . ENVIARÁ PIA Y LO ACEPTAREMOS . NECESITAREMOS ORDEN JUDICIAL DE INTERNAMIENTO . PUEDO ENVIAR A FUTUEX POR SI VOLUNTARIAMENTE QUISIERA INGRESAR','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BASILISO'and edp.apellido1='JIMENEZ'and apellido2='HERNANDEZ'),'2018-07-03','- LA OPCION DE RESIDENCIA NO PUEDE SER , CORREO DE LA COMPAÑERA DEPEND . SANDRA RICO 927638026. BUENOS DIAS AMALIA, TE MANDO DOC PIA PARA FIRMA DE BASILIO. NO SE PUEDE TRAMITAR SOLICITUD DE PLAZA PUBLICA DE RESIDENCIA PORQUE ES UN GRADO I. POR LO QUE TE ENVIO AYUDA A DOMICILIO. SI QUEREIS CENTRO RESIDENCIAL, DEBERIAS DE VER EL TEMA DE LOS PISOS TUTELADOS YA QUE CON G.I PODRÍA ACCEDER.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUADALUPE'and edp.apellido1='BARRAGAN'and apellido2='GARCIA'),'2018-07-03','-AMALIA : CORREO DE DEPENDENCIA : EN CUANTO AL TEMA DE GUADALUPE NO ME CONSTA REVISIÓN PIA, PERO DEJAME QUE LO MIRE MÁS DESPACIO YA QUE LA COMPAÑERA QUE LLEVA ESO ESTÁ DE VACIONES HASTA EL DÍA 16 DE JULIO. TE DIGO ALGO. UN SALUDO, SANDRA RICO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='MUÑOZ'and apellido2='CAMACHO GARCIA'),'2018-06-04','- CORREO DE LA RESIDENCIA SAN ROQUE EN TALARRUBIA: Buenas tardes Le informo que D. JUAN MUÑOZ CAMACHO GARCÍA, ha sido diagnosticado de cáncer rectal, sin posibilidad de realizar cirugía. Han considerado una actitud conservadora y paliativa dada la situación de D. JUAN. Está en la unidad de enfermería encamado, con escasos periodos de tiempo sentado en sillón relax. Recibe todos los cuidados para que tenga la mejor calidad de vida en este proceso final. Pendiente de revisión por la unidad de cuidados paliativos del hospital Adjunto informe de cirugía Un cordial saludo RESIDENCIA SAN ROQUE TLF: 924638023/630181685 FAX: 924638024 Correo: gestion@residenciasanroque.org Mª Luisa Nula Navarrete','2');
