insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALBERTO'and edp.apellido1='RAMOS'and apellido2='BLANCO'),'2018-06-06','-AMALIA: REUNION CON EL PADRE Y LA HNA. EN EL SEPAD. ALBERTO TIENE 28 AÑOS , VIVE SOLO EN C/ MACON, 9 EN SAN ROQUE . SON 4 HERMANOS , SU MADRE FALLECIÓ HACE 2. PADRES SEPARADOS. LA CASA ES DE LOS 4 HERMANOS Y ÉL TIEE EL USUFRUCTO. POLITOXICOMANO , 5 BROTES PSICOTICOS CO INGRSOS EN UHB, ULTIMO EN 2017 FUE DERIVADO A UME PERO NO LLEGÓ A INGRSAR POR FALTA DE CAMAS. PACIENTE DEL ESM VALDEPASILLA , EMILIO SALGUERO( E.A.P.) Y ANTONIO GONZALEZ (PSIQUIATRA). tENIA CITA CO EL ENDOCRINO PARA HORMONARSE, TRANSEXUAL ? SE ANULÓ POR EL PADRE . ACUDIÓ TEMPORALMENTE AL CEDEX Y HA PASADO POR VARIAS C. TERAPEUTICAS PERO DURA DIAS. LOS GASTOS DE SUMINISTROS DE LA CASA LOS PAGABA EL PADRE. NO TIENE SEGURO DE DECESOS , GESTIONAR . SOLO COME ARROZ Y PASTA , ACUDE AL COMEDOR SOCIAL CUANDO NO TIENE NADA. HA ESTADO 3 AÑOS EN EL EJERCITO , ESTUDIÓ HASTA 2º BUP PROBLEMAS JUDICIALES : 2 POR RESISTENCIA A LA AUTORIDAD Y POR CONDUCIR EBRIO .ESTO ZANJADO. ULTIMA DENUNCIA POR ROBAR EN UNA TIENDA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUISA'and edp.apellido1='REY'and apellido2='CAMPON'),'2018-07-04','-FUTUEX NOS COMUNICA QUE SUPERVISARÁN LA ADMINISTRACION MAÑANA Y TARDE DESDE LOS PISOS TUTELADOS. EL VIERNES POR LA TARDE LE DIERON EL ALTA EN LA UHB. SE VISITARÁ SEMANALMENTE POR FUTUEX. QUEDAMOS PTE. QUE DESDE EL SEPAD SE NOS ASIGNE PLAZA, DENEGADA PLAZA RESIDENCIAL POR EMERGENCIA SOCIAL . SE COMENTA EL CASO A SORAYA.','2');
