insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN FRANCISCO'and edp.apellido1='VALENCIA'and apellido2='AREVALO'),'2018-07-04','-AMALIA : VUELVE A INGRESAR EN HOSPITAL D.BENITO-VVA. HE SOLICITADO A FUTUEX QUE PIDA I.S +I.MÉDICO QUE JUSTIFIQUE LA SOLICITUD DE PLAZA PUBLICA PARA DEPENDIENTES.CAMBIAR PIA. SE AUTORIZA A LA R.M. A TRAVES DE FUTUEX PARA LA COMPRA DE SILLA DE RUEDAS. SE LLAMA A LA SOBRINA QUE EN SU DIA DIJO QUE LE INTERESABA HACER ACOMPAÑAMIENTO HOSPITALARIO , DECLINA. SE LE PIDE A LOS PISOS TUTELADOS QUE CONTACTEN CON ALGUIEN O CON EMPRESA PARA PONER 3H. AL DIA ( MAX. 10 € HORA )','2');
