insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDREA'and edp.apellido1='GUERRERO'and apellido2='ZAMBRANO'),'2018-07-04','-AMALIA : DESDE LA R.M. SOLICITAN PERMISO PARA ACOMPAÑARA A SU DOMICLIO IDA Y VUELTA . Y UNA SALIDA EN BJOZ PARA COMPRAR ROPA . SE LE AUTORIZA A TRAVES DE FUTUEX . SOLICITARÁN REINTEGRO PARA LAS COMPRAS.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JONATHAN'and edp.apellido1='RAMIREZ'and apellido2='JUAREZ'),'2018-07-05','-AMALIA : CORREO DE ANA TIMON , DEPEND. CC : "Pues la solicitud para valorar a Jonathan debe haber sido desde menores puesto que es un chico que está valorado con grado I desde el 2013. Me aparece el domicilio que tenía en 2013, pero investigando he visto que estuvo también en Plasencia en recurso de salud mental y luego en otra base de datos aparece una dirección de Badajoz. La cuestión a realizar desde dependencia es la misma que con Ventura, gestionar algún recurso de la cartera de servicios de dependencia, lo cual va a ser bastante complicado dada la situación de Jonathan. En definitiva, y una vez confirmado que está Mérida les tengo que derivar el expediente a las compañeras del Equipo de Mérida y se encarguen de contactar y ver si hay algún recurso de dependencia que se adapte a su situación...','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='CUENCA'and apellido2='SILVA'),'2018-07-05','JOSE CUENCA SILVA TIENE DOS CUENTAS EN IBERCAJA, EN UNA SE INGRESA LA ORFANDAD Y EN OTRA LA PF. EL OBJETIVO ES UNIFICAR TODO EN UNA CUENTA POR LO QUE PROCEDEMOS AL CAMBIO DE DOMICILIACIÓN DE LA ORFANDAD. TAMBÍEN SE SOLICITA AL CENTRO SOCIOSANITARIO QUE CARGUEN LOS RECIBOS EN LA CUENTA DE LA PF. QUEDA PENDIENTE CAMBIAR LA DOMICILIACIÓNDE SANTA LUCÍA. UNA VEZ QUE ESTÉ TODO CAMBIADO CANCELAR CUENTA. MJGH','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JORGE'and edp.apellido1='MARTIN'and apellido2='BLANCO'),'2018-07-05','- EN EL INFORME RECIBIDO DE CASA DE LA MADRE , LA PROPUESTA ES DE C.O. HAN ASESORADO A LA FAMILIA PARA QUE ACUDA A INSERTA EMPELO ( ENTIDAD PRA LA FORMACION Y EMPLEO DE PERSONAS CON DISCAPACIDAD ) COMO UNA OCION MAS PARA LA INSERCION SOCILABORAL . PEPA ESTÁ DE VACACIONES , CUANDO VUELVA , NEGOCIARÉ PIA CON C.O. EN MERIDA Y ENVIARÉ A FUTUEX PARA QUE CONTACTEN CON INSERTA EMPLEO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CANDIDO'and edp.apellido1='BAS'and apellido2='GONZALEZ'),'2018-07-05','-AMALIA: RECIBO LLAMADA DE CARMEN DIAZ, COMPAÑERA DEL ESM VALDEPASILLAS. EN COORDINACION CON LA UHB HIC SE VA A PROCEDER A SOLICITAR DERIVACION A UDAC . SOLICITO TB LA POSIBLIDAD DE DERIVACION A CSS POR SI NO HUBIESE OPCION DE INGRESO EN LA UDAC . LE COMENTO LA IMPOSIBILIDAD DE QUE CANDIDO VUELVA AL DOMICILIO . QUEDAMOS EN QUE MAÑANA PASARÁ POR EL SEPAD PARA DEJARME LA SOLICITUD PARA UDAC Y YO LA ENTREGARÉ EL LUNES EN MÉRIDA. LE PIDO QUE COMENTE CON LA UHB , QUE EN EL CASO QUE NO FUESE ATENDIDA SOLICITUD DE INGRESO EN CSS Y ANTES DE PROCEDER A ALTA INFOMEN A ESTA COMISIÓN O A SORAYA MASA . LE TRASLADÉ EL EXPEDIENTE PARA QUE SE ESTUDIASE ESTE CASO .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUANA'and edp.apellido1='GONZALEZ'and apellido2='NARANJO'),'2018-07-05','-AMALIA : HAGO GESTIONES CON LA DELEGACION DE VVDA DEL AYTO BJOZ. TONI SANCHEZ 924210049. ME ENVIA CORREO ELECTRONICO DONDE ME FACILITA INFORMACION PARA LA OPCION DE ALQUILER CON OPCION DE COMPRA Y CONTACTOS DE EMPRESAS PARA OBTENER OTROS PTOS. CONTACTO CON GRUPO MACIAS 619554239 Y CON CONSRUCCIONES JESUS GARCIA 615266257 , ME ENVIARAN PTO. EMAIL DE TONI : "Me dices que la propiedad es de JUANA GONZALEZ NARANJO, que es la madre de Juana y Teresa que son las que tenéis tuteladas. Si la madre no está tutelada tiene que consentir igualmente y tiene el 50% de la propiedad más el usufructo de su marido. Entiendo que la propiedad sería del matrimonio, porque el propietario catastral de la vivienda es ANTONIO GONZALEZ SEÑORON. La referencia catastral es muy importante para identificar la vivienda por eso te la paso 5672303PD7057B0001DJ. Antes de hacer nada habría que confirmar si la vivienda está inscrita en el Reg. de la Propiedad y a nombre de quien. Una vez confirmada la inscripción ya se podría hacer el contrato con opción de compra. He hablado con mi compañero en el Plan General y con los años de las viviendas y los valores catastrales me comenta que al día de hoy la valoración aproximada sería entre 23.000€ y 28.000€ dependiendo del estado interior de la vivienda. Te paso dos teléfonos de contacto de dos empresas que nos trabajan a nosotros, yo me lloro mucho y la verdad que no son altos de precios, claro que todo depende, normalmente yo les digo lo que queremos hacer, les puedes decir que lo más importante es la electricidad y la fontanería que la pongan vista. De todas formas ya les he llamado y les he dicho que te pondrán en contacto con ellos. GRUPO MACIAS ( PREGUNTA POR MARCO)619-554239 COSTRUCIONES JESUS GARCÍA NUÑEZ (JESUS) 615-266257','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUANA'and edp.apellido1='GONZALEZ'and apellido2='NARANJO'),'2018-07-05','-AMALIA: ME REUNO HOY CON EL INQUILINO EN EL SEPAD PARA VALORAR ALTERNATIVAS ( EMILIO 677245567 ) : -ARREGLAR LA VVDA. -ALQUILER CON OPCIÓN A COMPRA , ELLOS SE ENCARGAN DE LAS OBRAS DE LA VVDA. ESTA OPCION LE INTERESA. -SOLICITAR VPO DE VVDA JUNTA Ó DEL AYTO BJOZ , ACTUALMENTE NO HAY NINGUNA DISPONIBLE . EN JUNTA SE LE OFRECIO UNA EN COLORINES PERO LA DECLINARON , NO SE PUEDE ACOTAR ZONAS . EN EL AYTO NO LO HAN SOLICITADO POR DESCONOCIMIENTO. -OTRA VVDA DE ALQUILER , LE INSTO A QUE PREGUNTE POR OTRAS VVDAS PARA TENER OTRA OPCION FACTIBLE. QUEDO PTE. DE LOS NUEVOS PTOS QUE NOS VAN A HACER Y VALORAR.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='MARTIN'and apellido2='MARTIN'),'2018-07-05','-AMALIA : PONGO PARA FIRMA COMUNICACION DE VARIACIONES DE LA PFHC CON VARIACIÓN EN LA DISCAPACIDAD , PARA TRAMITAR EL CPTO. DEL 50%','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO MANUEL'and edp.apellido1='ALVAREZ'and apellido2='HIDALGO'),'2018-07-05','-AMALIA: EN LA REUNION CON TONI FUTUEX VALORO INGRESO ADECUADO. HE PEDIDO INFOMRES A LA TS DEL C.SALUD , INFORME SOCIAL AL SSB , I. MEDICO A LA PSIQUIATRA. EL SSB SE DECANTA POR CENTRO RESIDENCIAL , EL RESTO POR C.O. DISCAPACIDAD. LLAMO A OLGA , TS , PARA VALORAR LA SITUACIÓN , LE EXPLICO QUE SI INGRESARA EN R.A.L. INVOLUNTARIAMENTE AL SER CENTROS ABIERTOS SE IRÍA . LE PROPONGO COMO MEJOR ALTERNITVA PARA EMPEZAR C.O. Y LE PARECE BIEN. LLAMO A MERCEDES , TS DEPENDE. ZAFRA , DESDE MAYO DEL 2017 QUE SOLITÉ REVIÓN PIA NO SE HA CAMBIADO NADA . QUEDO PTE QUE ME LLAME PARA NEGOCIAR PIA. LO VA A COMENTAR CON SU JEFA SECCION.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN FRANCISCO'and edp.apellido1='VALENCIA'and apellido2='AREVALO'),'2018-07-06','-AMALIA: HABLO CON TS DEL H.D.BENTIO DONDE SE ENCUENRA INGRESADO NUEVAMENTE. SE HA CONTRATADO 3H AL DIA CON UNA CUIDADORA , EL CONTACTO LO HA FACILITADO EL HOSPITAL . LES PIDO VALORACIÓN PARA EL ALTA HOSPITALARIA , LOS PISOS TUTELADOS DE HELECHAL DONDE SE ENCUENTRA DICEN QUE ALLI NO PUEDE VOLVER PQ NO SE LE PUEDE ATENDER . SOLICITO VALORACION DE PLAZA SOCIOSANITARIA. QUEDO PTE. RESPUESTA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='POBLADOR'and apellido2='FERNANDEZ'),'2018-07-06','-AMALIA: HABLO CON TS DE APROSUBA 10 . ELLOS ENVIARON PFHC , MODELO NO VALIDO , DENEGADO POR SS Y YO SOLICITÉ NUEVAMENTE LA PFHC. NO ME SABEN DECIR QUÉ PASÓ CON LA P. ORFANDAD, SOLICITO QUE ME ENVIEN SOLICITUD +DOCUMENTACION PARA QUE YO TERMINE DE CUMPLIMENTARLA Y LA REGISTRO EN CAISS. TENGO DE SS EL DOCUMENTO DE OPCION DE PF /PNC , SON INCOMPATIBLES , NO ENVIO NADA HASTA SOLICITAR P. ORFANDAD.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BASILISO'and edp.apellido1='JIMENEZ'and apellido2='HERNANDEZ'),'2018-07-06','-AMALIA : HABLO CON CACERES , TETE NO SE ENCUENTRA Y HABLO CON UN COMPAÑERO . CON G.I NO PUEDE PEDIR PLAZA RESIDENCIAL POR DEPEND. HABRIA QUE PEDIR INTERN. INVOLUNT. ADEMÁS NECESITARIAMOS INFORME DE ESM DONDE SE ESPECIFICARA QUE NO PRESENTA PROBLEMAS CONDUCTUALES . Y ES CONSUMIDOR D ALCOHOL QUE ES OTRO CRITERIO DE EXCLUSIO . ALTERNATIVAS ??? VALORAR CON JEFE DE SECCIÓN . CASA DE LA MISERICORDIA PERO EN REGIMEN RESIDENCIAL ??? PISO TUTELADO ?? PLAZA RESIDENCIAL POR EMERGENCIA SOCIAL ??','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN FRANCISCO'and edp.apellido1='VALENCIA'and apellido2='AREVALO'),'2018-07-06','-AMALIA.RESPUESTA DE LA TS DEL HOSPITAL : "Soy Victoria, he estado hablando la facultativa esta mañana, respecto de Juan Francisco Arévalo. En conversación con su doctora Lucía Vicente, me comenta que el paciente ingresa por una insuficiencia respiratoria y que los cuidados que va a precisar son los mismos que tenía antes de su ingreso. No tendrá, por tanto, otros cuidados sanitarios adiccionales, con lo cual no es posible tramitar desde el hospital una plaza sociosanitaria al carecer de los mismos. Si su estado cambiase durante su ingreso lo revisaríamos, al día de hoy, los cuidados que necesita son de dependencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='YOLANDA'and edp.apellido1='CALDERA'and apellido2='MARTIN'),'2018-07-06','-AMALIA : ARCHIVO LA DOCUMENTACION ENVIADA POR P.I. VILLANUEVA CON LA DOCUMENTACION ENVIADA AL SEPAD SOLICITANDO PLAZA EN UDAC.','2');
