insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2018-07-06','AMALIA: SE RECIBE INFORME FUTUEX. ATI ESTABA MUY NERVIOSO , NO QUERIA VOLVER A SU PISO EN ZAFRA. MARIA ZAPATA CONSIGUE PLAZA EN C.TRANSEUNTES EN MERIDA PARA EL DIA 9 , PERO QUE SEPAMOS EN CTAEX NO HA VENIDO . LLAMO AL CENTRO PARA PREGUNTAR SI HA INGRESADO PERO NO CONSIGO HABLAR CON NADIE.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MEJIAS'and apellido2='DE LA MORENA'),'2018-07-10','-AMALIA: SOLICITO REACTIVAR EL EXPEDIENTE DE DEPEND. TIENE G.1 , SE DESACTIVÓ AL INGRESAR EN P.SUPERVISADO ZAFRA. ACTUALMENTE EN PISO DE ALQUILER , SOLICITO CAMBIO PIA CON SAD.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='CAMPA'and apellido2='SILGUERO'),'2018-07-10','(Pedro) llamada de María León (68560). +++Comunica que hay plaza para el traslado de Dª Antonia a la Residencia "Patronato de Coria", pero que ha estado hablando con Amparo, directora de "El Cuartillo" y esta no cree que sea conveninete. +++La Comisión Tutelar NO HA SOLICITADO dicho traslado. Comprueba que ha sido la T. Soc. de la Residencia. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con Amparo, Directora de "El Cuartillo". +++Ella no cree que sea conveninete el acercaminerto a su hijo por la relación tan patológica que mantienen entre ellos. Solamente se "desetabiliza" cuando habla con el hijo. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con Montaña. T. Soc.de "EL Cuartillo". +++Planteaba este trasalado en su informe de Junio de este año, porque considera que una madre y su hijo deben estar lo más cerca posible. +++Se le inofrma que dicha solicitud debe partir de la Comisión Tutelar y esta considera que el acercamineto a Cilleros no le conviene a la madre. Que otra cosa es que el hijo pueda ir a verla o pasar algún fin desemna juntos, pero que el riesgo de problemas enntre ellos es muy elevado y la proximidad pouede contribuir a ello. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Nueva converscaión con María León: DE MOMENTO, SE PARALIZA DICHO TRASLADO, lo que también he hablado con Montaña.','2');
