insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='POBLADOR'and apellido2='FERNANDEZ'),'2018-07-10','-AMALIA: DENEGADA LA PFHC PORQUE NO HEMOS ENVIADO LA OPCION ELIGIENDO ESTA Y DEJANDO PNC . NO LA HEMOS ELEGIDO ESPERANDO LA RESPESTA DE P. ORFANDAD , ESTA PRESTACIÓN SE TRAMITÓ DESDE EL CENTRO Y NO APARECE.( EN EL EXPEDIENTE PAPEL ESTÁ GUARDADO EL CORREO DEL CENTRO EN EL QUE SE ENCARGABAN DE TRAMITARLO.HACEN UN MODELO DE PF QUE NO ES EL CORRECTO Y VIENE DENEGADO . Y LA P. ORFANDAD NO APARECE ) CANCELO TODO Y VOLVERÉ A PEDIR PF+P.ORFANDAD. EL CENTRO ENVIARÁ CDO. DEFUNCION Y DEMAS DOCUMENTACION. SERIA CONVENIENTE PRIMERO INTENTAR AVERIGUAR SI EL PADRE COTIZÓ LO SUFICIENTE ANTES DE PEDIR PENSIONES.','2');
