insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO'and edp.apellido1='SUDON'and apellido2='HERNANDEZ'),'2018-07-11','(Pedro)Reunión NO programada de las siguientes personas en relación a la evnta del psio del que Pedro es copropietario con su 9 hermanos: +++Dª Mª Carmen Sudón Hernández (hermana); D. Javier Cacho (inmobiliaria); Dª Mª Luz Carrasco Valle, abogada que ha preesentado toda la documentación y futura compradora de la vivienda (644-784226). +++No les puedeo decir en qué punto están los trámites. Llamaremos la semana que viene para hablar antes sobre el tema. +++PREOCUPADOS POR LOS PLAZOS dada la deuda que se está generando con la vivienda. LES RECUERDO, especialmente a la hermana que DURANTE AÑOS todos esos gastos HAN SIDO COSTEADOS POR D. PEDRO (el agente inmobiliario interviene para decir que desde hace unos meses se han dejado de pagar) a lo que la hermana respeonde que "...claro, porque él estaba viviendo en el piso con la madre y tenía su paga...". Le explico que los gastos de la vivienda corren a cargo de los propietarios, todos, de la misma, según el % de la propiedad de cada una (en este caso todos tienen el mismo) y que de cara a la posible venta del piso tendremos que hablar de ello porque habrá que tener en cuenta lo que ha pagado Pedro durante esos años y no sus hermanos. LA ABOGADA ME DA LA RAZÓN, comentando quew una vez vendida la vivienda habrá que calcular lo que ha cada uno le corresponde teniendo en cuenta que a Pedro le corresponderá más que a los demás por lo ya mencionado. +++La hermana no parecía muy conforme con esta explicación.','2');
