insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2018-07-12','-correo enviado por Futuex , del viernes pasado : A continuación adjunto notificación de Idelfonso García, de Zafra, la ts del centro de salud Maria Zapata, contactó con la compañera de la zona, para comunicar que alli habia vuelto a ir Idelfonso y que se queria ir de Zafra, al parecer esta trató de ver si habia plaza en el centro hermano de Mérida y como a paritr de hoy vuelve, le iba a ayudar con está gestión, le explicamos a María que debía ponerse en contacto con la comisión por la via que prefiriese para comentar dicho situación y que en cualquier caso la decisión del cambio de residencia reside en ellos. Creemos que pudiera estar consumiendo, y que las cuestiones por las que quiera salir de Zafra, tengan que ver con líos o problemas derivados de su adicción. A nivel psicopatológico no está descompensado en el este momento. Un centro de las características al centro hermano de Mérida, entendemos que no puede contemplarse como una solución... no sabemos si el asesoramiento de Maria Zapata para que Ildefonso cuenta con vuestro consenso y visto bueno, de ahi que pongamos esta información en vuestro conocimiento.','2');
