insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='REBOLLO'and apellido2='HERNANDEZ'),'2018-07-16','(Pedro)Conversación con Nieves, T. Soc. CR "Felipe Trigo" (20359). +++Pendiente de intervención por cataratas. El dictamen de oftalmología es contrario a la intervención. La direccción del centro envío escrito a la Unidad de Oftalmología apoyando el desewstimineto de la intervención en base a dicho criterio clínico, al no estar todavía tutelada Dª Josefa. +++Por otro lado, Nieves informa de que Dª Josefa solicita el traslado o acercamineto a Badajoz, donde reside su hija. Hace unos años su relación era ambivalente, la hija no se encuentra bien y no se puede hacer cargo de su madre, pero la compañera cree que el acercamiento sería positivo para ambas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2018-07-13','(Pedro)Visita de Ildefonso. Vino el lunes sin cita y se le indicó que acudiese en el día de hoy. +++Solicita extra de 50€. +++Ha dejado el piso de alquiler de Zafra por desavenencias con su "compañeros" y dice que no quiere volver: refiere amenenazas, etc. Este mes de alquiler ya está pagado, por lo que hay que valorar rescindir el contrato de cara al mes que viene. +++Actualmente esta en el C. "Padre Cristóbal" (desde el día 9 de julio). +++Se plantea la posibilidad de buscar alquiler en Don Benito: "Mérida no me gusta, porque me recuerda a Joaquina..." Se le anima a buscar piso de alquiler bien en Don Benito, bien en Mérida. +++Le PLANTEO LA POSIBILIDAD DE VIVIR EN UN CENTRO (CRR, p.e.) Y APOYA ESTA POSIBILIDAD. Querría ir al CRR de Plasencia pero ya se le dice que, e primer lugar, la derivación la tiene que hacer su Psiquiatra; segundo, que debe dar perfil y tercero, que la plaza que se le pueda proporcionar no es elegible, con el riesgo de que si renuncia a ella perdería su orden el la lista de espera. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Hablo con María Zapata de esta visita y de las conclusiones a las que hemos podido llegar. Quedo pendiente de hablar con Isabel, Enfermera del ESM de Zafra para ver la posibilidad de que el tratamiento lo pueda realizar en Mérida. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Intento hablar con Isabel (45960) pero no consigo contactar. ESM (45991)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2018-07-16','(Pedro)Conversación con Inma, T. Soc. del Centro "Padre Crsitóbal".924-302618. +++Ildefonso les ha informado de que "va a ir al CRR...". Informo de esta posibilidad en las condiciones en las que se le indicó a Ildefonso: es una posibilidad dque debe pasar previamente por la derivación desde el ESM. +++Allí no lo pueden tener, "...como mucho UN PAR DE SEMANAS MÁS...". +++ Se le inofrma de lo hablado en la vista de Ildefonso: posibilidad de que busque alquiler, ya sea en Mérida o Don Benito; psoibilidad de un hosptal hasta nuevo recurso. +++En caso de que se quiera marchar a Don Benito, "Padre CRistóbal" lo derivaría al centro que tienen allí para que fuese buscando piso. +++En caso de que decidiera ir al Hostal, "El Torero" tiene un acuerdo con el Centro por 180€/mes comida aparte. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con Isabel, Enfermera del ESM de Zafra (45960): +++NO HAY PROBLEMA EN QUE SE PONGA EL INYECTABLE EN EL ESM DE MÉRIDA. +++++En cuanto a la posibilidad de CRR, en el ESM ven mejor los Pisos Supervisados (se le indica que el recurso adecuado es el que ellos propongan). LO hablará con Francisco Zamora, Psiquiatra del Equipo (ahora de vacaciones). +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Llamada a Julián Onofre, Enfermero y Cooirdinador del ESM de Mérida (924-487229). +++No hay problema en que acuda el próximo 29 de julio a pomnerse el inyectable. +++Tramitar tarjeta sanitaria para asignación de Médico de familia y posterioermente de Psiquiatra. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Cobnversación con Inma, del "Padre Cristóbal" para que hablen con Ildefonso sobre el próximo inyetable y que solicite tarjeta dsanitaria. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++SE COMUNICA POR FAX AL JUZGADO de 1ª Instancia e Instrucción nº 1 de zafra el cambio de domicilio de Ildefonso. +++SE REMITE por correo-e AL CENTRO "PADRE CRISTÓBAL" EL AUTO DEL Juzgado de 1ª Instancia e Instrucción nº 1 de Zafra para que pueda acudir el día 1 de cada mes a firmar ante el juzgado de Mérida','2');
