insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2018-07-18','(Pedro)Llamada de Cristina (Plena Inclusión Llerena. 677217880). +++Le paso con Juana porque se trata de cuestiones económicas. +++Preguntada por Beatriz, comenta lo siguiente: se va de vacaciones con su padre, su tía y el marido de esta a Toledo el día 3 de agosto, tras ver a la niña en Don Benito, donde la recogerán. Plantea que quizá pasen por Trujillo para recoger algunas pertenencias de Beatriz. Sobre esto le reuego que hablen con la tía para que si es posible, eviten llevar a Beatriz a Trujillo y, caso de ir con ella allí, que no le dejen ver a Antonio ni a su familia. +++Una vez que han hablado con la tía y teniendo en cuenta los deseos de Beatriz, el Centro considera adecuado permitir esta salida, confiando en la buena predisposición de los tío quienes han ido a vistarla alcentro y la han llamado en varias ocasiones preocupándose por ella. +++Beatriz sigue yendo al PEF en Don Benito los primero viernes de cada mes y parece ser que el contacto con Antonio ha disminuido considerablemente.','2');
