insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MAXIMILIANO'and edp.apellido1='BELLO'and apellido2='MIGUEL'),'2018-07-18','-AMALIA: HABLO CON LA TS DE ACEHUCHE , MAXI PAGA IBI DE UNA VVDA EN ESA LOCALIDAD QUE ERA PROPIEDAD DEL PADRE, HAY VARIOS HNOS HEREDEROS Y LA TS CREE Q ÉL ERA USUFRUCTURARIO . SU SOBRINA YOLANDA TIENE CARGADOS A CUENTA DE SU TIO 10 RECIBOS Y SU HNA NATIVIDAD EL DE TF. LES AVISARÁN A TRAVES DEL PROGRAMA FAMILIA PARA QUE CAMBIEN EL Nº DE CUENTA O PROCEDEREMOS A DAR DE BAJA A TODO . LA SOBRINA YA NO VIVE ALLÍ LE HAN DADO UNA VPO. QUEDAMOS A LA ESPERA DE LA RESPUESTA.','2');
