insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BLAS'and edp.apellido1='GUERRERO'and apellido2='ASEGURADO'),'2018-07-18','(Pedro)Conversación con Alfonso (20270), Director en funciones de la residencia. Mario (Director) y Magdalena (T. Social) están de vacaciones. +++Desde que nos enviaron el Informe la sitruación se ha calmado, más a llá de pequeñas discuiones entre D. Blas y otros resiedentes. +++Se le pronpone derivación del médico al ESM para su valoración y, en su caso, tratamineto. Y también consisderar la posibiliadd de llamar al !!" en esas ocasiones (lo que sucecde es que son "explosiones" de unos seinstantes y luegos et tranquiliza). En último caso, valorar psoible denuncia. +++Seles ruega manadr estos informes también a la Unidad de Recursos para su concimiento.','2');
