insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUISA'and edp.apellido1='RODRIGUEZ'and apellido2='GRAGERA'),'2018-07-18','(Pedro)Llamada de Dª Luisa (722-668789). +++ES muy difícil entender lo que dice, por la rapidez con la que habla, la deficiente vocalización y los saltos que da en lo que parecen temas diferentes... +++Dice tener faringistis crónica, de lo poco que soy capaz de comprender. Menciona también a su hermana Estefanía y otros familiares, "aparentemenete" disgustada con ellos... ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Llamo al CRR de Mérida. Hablo con Beatriz (Psicóloga). javier está de vacaciones. +++Le informo de la "conversación" mantenida con Luisa y comenta que lleva unos días, desde que fue a visitarla su hermana Estefanía, un poco "revuelta" con el tema de la casa. Le informo que la venta ya se firmó y que ahora estamos con la herencia de la madre.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VANESA'and edp.apellido1='FERNANDEZ'and apellido2='GOMEZ'),'2018-07-18','-AMALIA: ME LLAMA ELISA , AGENTE DE EMPLEO CON APOYO PARA OFRECER UN CONTRATO LABORAL DE 6M EN EL ECONOMATO BAJOZ PARA LIBERTAD GARCIA. NO ES POSIBLE POR EL TRASLADO DESDE LLERENA PERO SOLICITO LA POSIBILIDAD QUE SEA PARA VANESA. TANTO LA ENTIDAD COMO VANESA NO PONEN OBJECIONES, VANESA SE PONE MUY CONTENTA . SERIA PARA EMPEZAR EN SEPT. , HABRIA QUE AYUDARLA A BUSCAR HABITACION COMPARTIDA ( FUTUEX ) Y PODRIA COMER SOLICITANDO LA EMPRESA DE COMIDA A DOMICILIO O ELABORARSELO ELLA MISMA .HAY QUE AVISAR AL ARRENDADOR PARA DEJAR EL PISO QUE TIENE ALQUILADO . TENGO QUE SOLIICITAR PLAZA DE C.O. EN DOWN PARA QUE ELISA PUEDA APOYAR ESTE EMPLEO . LES INTERESA PQ LAS PLAZAS NO SE CUBREN . MANUELA DISCAPACIDAD ME DA EL OK .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VANESA'and edp.apellido1='FERNANDEZ'and apellido2='GOMEZ'),'2018-07-18','-AMALIA : CONSIGO TRABAJO PARA VANESA A TRAVES DE ELISA DE A. DOWN BADAJOZ. 6MESES EN ECONOMATO BADAJOZ , JORNADA COMPLETO A EMPEZAR 1 SEPTIEMBRE SOLICITO C.O. EN DOWN . HAY QUE AVISAR PARA CANCELAR CONTRATO ALQUILER ACTUAL . BUSCAR HABITACION COMPARTIDA EN BADAJOZ . COMUNICAR A PNC CUANDO SE INICIE EL TRABAJO . TF. ELISA MONITORA DOWN 693754274. empleodownbadajoz@gmail.com TF VANESA 622294398','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='RUIZ'and apellido2='LARENA'),'2018-07-19','-AMALIA: FUTUEX SE VA A ENCARGAR DE SOLICITAR EL COMPLEMENTO DE ALQUILER DE LA PNC . SE LE VA A ENVIAR LA DOCUMENTACION NECESARIA. MINIMOS VITALES NO SE LE PUEDEN TRAMITAR PQ NO DISPONEMOS DE LA DOCUMENTACIÓN SOLICITADA.','2');
