insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='RUBIO'and apellido2='TRINIDAD'),'2018-05-03','-AMALIA : email del ssb trujillo.Pidió plaza en RAL nov-2017 sin embargo le pregunto a Maribel en julio 2018 y no le aparece . Buenos días. Soy Mercedes Prieto, una de las Trabajadoras Sociales del Ayuntamiento de Trujillo. Me pongo en contacto con vosotros porque he recibido vuestra comunicación de designación de la Comisión Tutelar de Adultos de Extremadura como tutores de D. Antonio Rubio Trinidad. Me gustaría poder hablar con vosotros para poder explicaros un poco la situación de esta persona, pero no soy capaz de contactar telefónicamente. El tema que principalmente me urge es el relativo a la solicitud de Centro para Personas con Discapacidad. Se tramitó solicitud el pasado 21 de noviembre. Para poder resolver dicha solicitud era preceptivo que fuera valorado por el CADEX, donde fue citado el pasado 14 de febrero. D. Antonio no acudió a esta cita; yo he tenido conocimiento de esta situación el pasado día 30, pero como ya han pasado casi tres meses el expediente está pendiente de archivo. No sé si habría posibilidad de que Pedro Gracia, contactara con el director del CADEX, Domingo Salas, para paralizar este archiva y promover una nueva citación de tal modo que podamos organizar algún servicio de transporte para que no falte a la cita. Si queréis poneros en contacto conmigo, a través de esta dirección de correo o a través del número de teléfono 927659391. Gracias por todo. Un saludo. Mercedes Prieto Sánchez. Trabajadora Social del Ayuntamiento de Trujillo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='RUBIO'and apellido2='TRINIDAD'),'2018-07-19','-AMALIA: PREGUNTO A MARIBEL MESA CÓMO VA EL EXPETE DE INGRESO EN CENTRO QUE SOLICITÓ LA TS DEL SSB ( INTRANET DEL DIA 3 DE MAYO 2018). ME LO MIRARÁ QUEDO PTE. RESPUESTA .','2');
