insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='MARTIN'and apellido2='MARTIN'),'2018-04-19','-AMALIA: SE RESUELVE PIA CON RAE EN MENSAJEROS DE LA PAZ . SE ARCHIVA LA COMUNICACION .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VANESA'and edp.apellido1='FERNANDEZ'and apellido2='GOMEZ'),'2018-07-19','-AMALIA : Seguimiento Futuex : Hola buenos dias, adjunto el seguimiento que se le hizo a Vanesa en Abril, cuando nos lo comentaste, me parece raro que ella diga que no ha recibido visita, pero bueno igualmente volveremos.. en esa visita, el piso se comprobó que se encontraba en buen estado, estaba (según ella) esperando a ser contratada por el ayuntamiento de Miajadas para operario o peón, en un trabajo temporal, cosa que supongo no habrá sucedido si tiene más dificultades ecónomicas como comentas, también ella manifestó que recibía una ayuda de 100 euros mensuales por participar en un curso, y que a temporadas tenía que ayudar a la madre que no tenía recuros ni para comer.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2018-07-19','(Pedro). En respuesta al correo de Cintia para ver cómo se va a hacer el traslado de José Mª el próximo 3 de septiembre a los juzgados de Plasencia. +++Le comento que lo habitual es que el Centro lleve a José María al Juzgado y nosotros vamos allí. +++Lo cometará con la Directora y nos dirá.','2');
