insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VANESA'and edp.apellido1='FERNANDEZ'and apellido2='GOMEZ'),'2018-07-19','-TF MADRE DE VANESA 633142963 ME COMENTA QUE VANESA TIENE UN NOVIO EN ALMOHARIN Y CREE QUE NO VA A AGUANTAR EN UN PISO COMPARTIDO EN BADAJOZ . HA SOLICITADO ABOGADO DE OFICIO PARA REMOVER LA TUTELA . ELLA VA LOS FS A MIAJADAS , TIENE UN TRABAJO DE FS Y DE L A V ESTÁ CON SU MADRE PQ AHORA MISMO ESTÁ DE MEDICOS. VANESA NO INFORMA DE NADA DE ESTO . AL IGUAL QUE VENIA PERICIBIENDO 100€ EN UN CURSO AL QUE YA NO ASISTE. ME DICE LA MADRE QUE HA CONTRATADO WIFI EN LA CASA. Y SIGUE PIDIENDO DINERO PARA BOMBONAS . QUEDO CON ELLA QUE MAÑANA ME DARÁ LA RESPUESTA DEFINITIVA .','2');
