insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ARTURO'and edp.apellido1='ROCHA'and apellido2='MERCHAN'),'2018-07-19','(Pedro)Conversación con Gema (Admón. "El Péndere"). +++La Directora está de vacaciones. +++Se le inofrma de que la familia puede comprar a D. Arturo llas cosas que considere oportunas, pero si lo hace sin contar con la Comisión no pase luego la factura porque no se le abonarán. +++La Comisión entiende que, como en este caso, si D. Arturo tenía necesidad de comprarse ropa es la resiedencia la que nos lo tiene que comunicar y, adado que no ha sido así, entendemos que no existía tal necesidad. +++El abono de la factura queda pendiente de hablar primero con la Dirección de la Residencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARGARITA'and edp.apellido1='ANTICH'and apellido2='ARROYO'),'2018-07-19','(Pedro)Conversación con Pilar, T.Soc. del Hogar "san Vicente de Paul" y con Margarita. +++Se encuentra muy bien y nos agradece que la hayamos llevado allí. Quiere vernos y le digo que si para septiembre voy para allá si puede le haré una visita. +++Me da su teléfono móvil: 663-676697. En cualquier caso, quedo con Pilar en que cuando queramos hablar con ella lo haremos a través de los teléfonos del Centro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DOLORES'and edp.apellido1='PESADO'and apellido2='ESTEBAN'),'2018-07-20','-AMALIA: AÚN NO SE HA ACEPTADO EL CARGO . HAY SENTENCIA 65/2018 DE 16 DE ABRIL EN LA QUE SE DECLARA SU INCAPACITACIÓN TOTAL POR ESCLEROSIS MÚLTIPLE , DEPENDIENTE PARA LAS ABVD . LA PROPIA SENTENCIA DE INCAPACITACIÓN AUTORIZA AL INTERNAMIETNO EN CENTRO ASISTENCIAL O SOCISANITARIO.PEDRO ME INDICA QUE SOLICITE CENTRO DE DISCAPACIDAD POR REVISIÓN PIA , LE COMENTO LA SITUACIÓN .HABLO CON SECCION DISCAPACIDAD, TENGO QUE SOLICITAR REVISION PIA E INDICAR POR EMERGENCIA SOCIAL , NO ES NECESARIO I.SOCIAL LO TIENEN DEL ANTERIOR INGRESO , A LA SECCION DE DEPENDENCIA DE PLASENCIA , EL CASO LO LLEVÓ PABLO .','2');
