insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VANESA'and edp.apellido1='FERNANDEZ'and apellido2='GOMEZ'),'2018-07-20','-AMALIA : LE PIDO A PEDRO QUE ENTREGUE LA SOLICITUD DE CO EN DOWN REGISTRADA A MARIBEL RAMOS QUE SE LA ENVIARÁ A JULIA DURAN EN CC ( 927004346 ) . VER DOCUMENTO DE COMO GESTIONAR UN TRASLADO DE EXPEDIENTE DE DISCAPACIDAD EN LA CARPETA DE EXPEDIETNES.','2');
