insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN'and edp.apellido1='GUTIERREZ'and apellido2='RONCERO'),'2018-07-23','Hemos firmado la venta de la vivienda perteneciente a la herencia de sus padres, junto con sus hermanos en Plasencia. Recibe 8.000 euros.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO'and edp.apellido1='VAZQUEZ'and apellido2='RODRIGUEZ'),'2018-07-23','(Pedro)Llamada de Carmen Franco: Este fin de semana han ingresado a D. Pedro en el Hospital de Mérida por una obstrucción intestinal. Al no conseguir ponerse en contacto con nadie de la Comisión dirigieron la solicitud de autorización para intervenir al Juzgado. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++(Pedro) Conversación con el Dr. Carlos Jordán (Cirujano): D. Pedro no llegó a ingresar en UCI por no considerarse necesario. En estos momentos se encuentra en Reanimación, donde permanercerá al menos durante el día de hoy. Ha sufrido una rotación de colon (obstrucción intestinal que impedía el riego sanguíneo) y se le ha practicado una ileostomía (bolsa para defecar). ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Llamada de la Dra. Marta Mateo (Médico de la Unidad de Reanimación): La operación se realizó a las 5 de la madrugada del domingo. En estos momentos la infección está controlada, mantiene respiración autónoma (aunque con aporte de oxígeno), con función renal normal y con administración de droga vasoactiva para mantener tensión (permanecerá en Reanimación hasta que se le pueda retirar dicha medicación).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CESAREO'and edp.apellido1='PANIAGUA'and apellido2='CALLE'),'2018-07-23','(Pedro)Conversación con el Padre Miguel (679-077448). +++En una de las revisiones de próstata se le ha detectado una tumoración a nivel renal por la cual ha sido citado para preanestesia el próximo 21 de agosto en el H. "Virgen del Puerto". El consetimineto lo ha firmado él. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++(Pedro)Conversación con Fernando, T. Soc. del H. "Virgen del Puerto" (78206). +++Nos remitirá el consentimiento informado para su firma por la Comisión. SE le deja número de fax y correo-e.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSARIO'and edp.apellido1='BARROSO'and apellido2='DORADO'),'2018-07-23','(Pedro)Conversación con Susana (T. Soc. de Futuex). +++La negociación PIA la lleva Susana, Delegada Tutelar. Hablará con ella y me informará la repecto. +++He hablado previamente con Purificación (Dependencia/924-551798 y 20704) y dice que han de tener el expedeinte cerrado a final de mes. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Nueva conversación con Susana (T:Soc.). Ha hablado con la Delega Tutelar: fue a visitarla la semana pasada y ni la madre ni ella quieren dejar entrar a nadie en casa. Masñana va a verla nuevamente e intentará convencerlas de lo útil de seguir alguno de los trataminetos existentes dentro de la Promcoción de la Autonomía. mañana volveremnos a hablar y, caso de no aceptar PIA algunoi, lllamar a Puri y dejar en suspenso la negociación.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2018-07-23','(Pedro)Conversación con Julian (Cocemfe): +++Tras realizar estudio económico no es viable llevar a cabo la propuesta de salidas planteada por el centro, dada la no disponibilidad económica existente actualmente para soportar el coste de 217€/mes. +++DE cara a septiembre, valorará la posibilidad de pasar de la asignación mensula de 60€ a gestionar directamente lo que resta de la pensión una vez pagada plaza, teléfono y seguro (+/- 137€). +++Pendiente comprobar factura de teléfono de este último mes.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CANDIDO'and edp.apellido1='BAS'and apellido2='GONZALEZ'),'2018-07-23','(Pedro)Intento hablar con Carmen (T. Soc. ESM de Valdepasillas) sin conseguir contactar con ella.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CUEVAS'and apellido2='LOPEZ'),'2018-07-24','Recibimos fax del Sociosanitario comunicándonos la liquidación de condena privativa de libertad correspondiente a la ejecutoria 190/2018 del Juzgado de lo Penal nº 1, de Don Benito. Termina de cumplirla el 30/1/2023. Por esta ejecutoria se le condena al pago de 175 euros, que hemos pagado el 6 de julio.','2');
