insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSARIO'and edp.apellido1='BARROSO'and apellido2='DORADO'),'2018-07-26','REMISIÓN Se pone al correo el PIA de NO ACEPTACIÓN.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA'and edp.apellido1='GOMEZ'and apellido2='NEVADO'),'2018-07-26','(Pedro)Intento llamar a la T. Social de Valencia de Alcántara (927-580326/8)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA'and edp.apellido1='GOMEZ'and apellido2='NEVADO'),'2018-07-27','(Pedro)Conversación con PIlar, T. Soc. del SSB de Valencia de Alcántara. +++Dª Rosa tiene todas las necesidades cubiertas en la Residencia "San Pedro de Alcántara".Lo que ocurre es que durante toda su vida ha gastado el dinero como ha querido y sin control alguno. +++Respecto a su negativa a realizarse las pruebas que sus médicos le han indicado en relación a un tumor de estómago que tiene, pido a Pilar que nos envíen los consentimientos informados para autorizar las mismas.Una vez firmados, remitirlos nuevamente a la Residencia. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Se envía fax al Juzgado de 1ª Instancia e Instrucción nº 1 de Valencia de Alcántara.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='DOMINGUEZ'and apellido2='GARCIA'),'2018-07-27','(Pedro)Llamada de Juan Pedro (Valoración PIA). 924-555480. Alternativas: +++Plaza Pública (ahora está en concertada) y pasar a lista de espera.Dado que es un grado III no tardaría mucho seguramente. +++Plaza concertada: ver el coste de la plaza y valorar si con su pensión y PIA la puede costear. Otras consieeraciones:nivel de adaptación en la actualk residsencia y nivel de cobertura de sus necvesidades actuales(en estos momentos, la residencia actual cubre adecuadamente sus necesidades). +++Averiguará coste de plaza para decidir...','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='IÑIGO'and apellido2='RODRIGUEZ'),'2018-07-27','BAJA Se designa tutor a su hermano D. Antonio Iñigo Rodríguez. Sentencia ya firme en 26/06/2018.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2018-07-27','(Pedro): Llama su madre (655149792) +++Dinero para boda Mari Mar y Pablo. REgalo y ropa.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='DOMINGUEZ'and apellido2='GARCIA'),'2018-07-30','(Pedro)Conversación con Juan Pedro.(Ver correo-e en expedeinte. +++Se envía documentación PIA firmada: +++++Prestación vinculada al servicio residencial (Mientras tierne plaza en la misma residencia para cobertura de la plaza). +++++Plaza de dependiente en la misma residencia, a la espera de vacante. CORREO DE DEPENDENCIA. : Con respecto a la conversacion mantenida esta mañana sobre la tramitación del PIA de Rafael Dominguez Garcia con DNI 08303323R te comento que ya he hablado con Mari Carmen, la directora del centro residencial donde se encuentra actualmente Rafael, en una plaza de autónomos en base al grado I que obtuvo en la valoracion anterior (en Medina de las Torres). La directora considera que el centro entiende que cubre las necesidades de atención de Rafael pero no en el tipo de plaza que ocupa, y que se encuentra muy conforme en el centro por ser la misma localidad donde siempre ha vivido, por lo que conoce al personal del mismo y a muchos de los residentes Por ese mismo motivo, os propongo solicitar la plaza de dependientes de dicho centro (que, en principio debería tardar poco tiempo por ser grado III en la última valoracion realizada y tener pocos ingresos). Por si tardara mas tiempo, tambien propongo una prestación económica vinculada al servicio de atención residencial en el mismo centro (la directora entendiendo la situación económica por la que pasa Rafael, abarataria algo el precio y le cobraría por la plaza 1275 euros al mes con IVA incluido, y nosotros le tramitariamos una cuantía de 715,07, situacion que permite, o al menos así lo he calculado yo, pagar el total de la plaza privada con su pensión y la cuantía que le tramitariamos nosotros). No obstante, y al haber sido una valoración prioritaria, la ayuda de dicha prestacion no corresponderia hasta el 21/09/2018 (6 meses y un dia desde la fecha de revision de grado), independientemente de cuándo se le hiciera el ingreso del dinero. Obviamente, si obtiene plaza residencial concertada antes, se anularía la tramitación del pago de dicha prestacion En este sentido, os mando la documentación PIA tanto de la plaza residencial concertada como de la prestación vinculada. Me haria falta que se firmara y sellara la documentación cuanto antes (si es posible como muy tarde el martes 31 de Julio, ya que asi nos lo exigen por el cambio de declaracion de la renta). Junto a esta documentación me haria falta el alta a terceros a nombre de Rafael pero con el nombre a pie de firma de Maria Consolacion, y firmado por ella misma. El resto de documentación que me haria falta se la solicitaría yo directamente a la directora del centro residencial Para cualquier aclaracion podeis contactar conmigo directamente en el telefono 924555480 Gracias JUAN PEDRO MARTIN ALONSO Terapeuta Ocupacional Seccion de Dependencia de Zafra SEPAD','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUISA'and edp.apellido1='REY'and apellido2='CAMPON'),'2018-07-30','(Pedro)Llamada a Maite, Directora de la Residencia "San Francisco" de Plasencia (927-017340). +++NO se incorpora de las vacaciones hasta el día 1 de agosto (la semana pasada me dijeron que estaría ya hoy, lunes 30 de junio). +++Me pasan con Juan carlos (Admón.)Tartará de averiguar si esp posible hacer el traslado sin que esté la directora en caso de que se realice esta semnana (yo estoy de vacaciones la semana que viene y mi idea era dejarlo ya hecho). Lo consultará con el Coordinador de Enfermería y me llamará. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Llamada de Juan Carlos: me da el teléfono particular de Maite, Directora (619-822390. USAR SOLO EN CASO URGENCIA): intentar que el traslado se haga el miérdcoles 1 o jueves 2 (si se realiza esta semana) para que ella ya se haya reincorporado. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con Eva María, T. Soc. del SSB de Casar de Cáceres (927-291976) +++Le informo del próximo trasalado de Dª Luisa, pendiente de fecha para realizarlo. +++Me comenta que Rosa, T. Soc. del C.Salud está hoy en Cáceres, pero no sabe en qué C. Salud. Me llamará para habalr con ella. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con Rosa, T. Soc. del C. Salud de Casar de Cáceres (927-291531). Va los martes al Casar. Le inoformo de la situación. Hablaré con el Médico de Familia. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con el Dr. José Luis Tello, MÉDICO DE FAMILIA del C. Salud del Casar de Cáceres (50723). CORREO-e: joséluis.tello@salud-juntaex.es +++Está la tanto del caso. +++Activará el 112 para el miércoles 1 de agosto, ya que ese día está de guardia en el Casar. +++LE ENVÍO por correo-e la siguiente documentación: Aceptación y Testimonio de Aceptación del cargo; Testimonio de la Sentencia y Auto de internamiento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIPE'and edp.apellido1='RODRIGUEZ'and apellido2='SOLIS'),'2018-07-30','Iciar: Llama Isabel Pino, T.S. de Miajadas 92734 70 00 ext 3216, para comunicarnos que el hermanod e Felipe que se encontraba eingresado en un centro en Cáceres ha pedido el alta voluntaria y ha vuelto a la casa donde reside Felipe. La convivencia es insoportable y Felipe quiere denunciar a su hermano. la Guardia Civil les dice que para presentar denuncia debe estar su representante legal.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='VAZQUEZ'and apellido2='DIAZ'),'2018-07-30','(Pedro)Conversación con Mª José (llamó ayer). Está en Málaga en estos momentos (951-445161): +++Pregunta si sabemos algo del Forense y que tampoco ha recibido ningún documento de la funeraria. +++Dice haber recibido una carata de un móvil (del 2006¿?)Nos la hará llegar. +++SE le informa de que nosotros tampoco sabemos nada del foerense y que nos pondremos en contacto con ella.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DEL MAR'and edp.apellido1='GORDILLO'and apellido2='SANTANA'),'2018-07-31','Correo-e (31-07-2018) La usuaria María del Mar Gordillo Santana va a disfrutar de 4 días en el domicilio familiar. Se irá el martes 31 de Julio y volverá al piso el viernes 3 de Agosto. Sentimos avisarles con tan poco antelación, pero a su hermana Blanca le han dado días libres y justo se lo han notificado hoy por lo que pese a haberles avisado de que es necesario que me lo comuniquen con antelación no ha sido posible. He intentado que cambiásemos la fecha de permiso pero su padre esta ingresado, y la única hermana que puede quedarse con ella en el domicilio es Blanca durante estos días. Consideramos necesario, y así se lo hicimos llegar a la familia, que disfruten de tiempo de calidad juntos. No obstante, no se están produciendo las salidas porque las condiciones de supervisión no eran las adecuadas. En éste caso Blanca se hará cargo de María del Mar los 4 días y supervisará tanto su dinero, tabaco y medicación, es por ello que consideramos que sería positivo para ella pues no está disfrutando de tiempo en familia con la frecuencia que le gustaría. Para cualquier información pueden llamar a su hermana Blanca (675368468), o al del piso supervisado (660296795) Un cordial saludo. María Molero Sánchez (Coordinadora/Psicóloga del Piso Supervisado de Zafra)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIPE'and edp.apellido1='RODRIGUEZ'and apellido2='SOLIS'),'2018-07-31','(Pedro)Conversación con G. Civil de Miajadas: +++Felipe puede poner la denuncia sin necesidad de nuestra presencia. De momento, no la ha puesto. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con Choni, T. Soc. SAD Miajadas (927-347000. Ext. 3401 y 3402).Me da el contacto Isabel Pino, T. Soc. del SSB de Miajadas (927-347000, Ext. 3216) con la que previamente he hablado. +++Expone la situación: Francisco, el hermano, residía en el CRR de Plasencia. Hace un mes la llamaron porque él quería marcharse y querían saber si las condiciones en casa lo permiotirían (él lleva pañales, pero está bien, le dijeron). Choni les dijo que no creía que fuese buiena idea que volviese a casa (un hijo de Felipe también opinaba así y se le dijo que se encargara de su padre) y que el SAD por Dependencia solamente debía atender a Felipe. Desde su llegada, Felipe ha sufrido una cierta desestabilización en su situación.Comenta que LA CASA EN LA QUE VIVE LA MADRE LA PUSO A NOMBRE DE FELIPE, pero que posteriormente se comprobó que estaba puesta a nombre del hermano : ¿podría haber él cambiado la titularidad cuando era el tutor?. +++Enviará Informe sobre la misma para comunicar a Juzgado. +++Dirá a felipe que ponga la denuncia y caso de hacerlo, nos la enviará.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN MANUEL'and edp.apellido1='GONZALEZ'and apellido2='VICENTE'),'2018-07-31','REHABILITACION PATRIA POTESTAD Y CIERRE EXPEDIENTE Se recibe DIOR de 23/07/2018 confirmando la firmeza de la Sentencia 52/18, de 05/06, por la que se rehabilita la patria potestad en la figura de su madre, Dña. Mª. Dorotea Vicente Parras.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ARTURO'and edp.apellido1='ROCHA'and apellido2='MERCHAN'),'2018-07-31','(Pedro)Conversación con Begoña, Directora de la Residencia de Santiago sobre la factura de ropa enviada por Dª Granada. +++En la Residdencia se comprobó que lo facturado coincidiera con lo entregado, como así fue. +++Por otra parte, Begoña comenta que también la implicación de la familia es necesaria (suelen ir a verlo los viernes) y que, dado que ellos se tienen que desplazar a San Vicente para estas compras, casi les viene mejor que así sea. La Residencia se compromete a verificar todo lo que se compre. +++En cualquier caso, le ruego nos comuniquen culaquier necesidad que tenga D. Arturo independieentemente de que la familia se haga cargo o no de ella.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MINERVA'and edp.apellido1='MARTIN'and apellido2='BLANCO'),'2018-07-31','Nos pasan de Discapacidad la posibilidad de solicitar, además de las ya solicitadas, plaza en Plena Inclusión de Almendralejo, que empezará a funcionar el 1 de octubre. Se hace nueva solcitud incluyendo Almendralejo.SE suprime una de las anteriormente solicitadas (no pueden ser más de cuatro).','2');
