insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MAXIMILIANO'and edp.apellido1='BELLO'and apellido2='MIGUEL'),'2018-08-01','(Pedro)Le paso a Alberto correo electrónico de Yolanda Pizarro (605227479), sobrina de Maximiliano.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CANDIDO'and edp.apellido1='BAS'and apellido2='GONZALEZ'),'2018-08-01','(Pedro)Llamada de Carmen, T. Soc. del ESM de Valdepasillas. +++Comentamos situación de D. Cándido y su próximo traslado al CSS de Mérida. +++También sobre la actitud de la T. Social de Vva. del Fresno al respecto. +++Nos enviará la solcitud de recurso y documentos clínicos actualizados (los tiene Soraya).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CANDIDO'and edp.apellido1='BAS'and apellido2='GONZALEZ'),'2018-08-01','(Pedro) Llamo a María, T. Soc. de Vva. del Fresno (924-427000). +++No cogen el teléfono.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CORAL'and edp.apellido1='NEVADO'and apellido2='NAVARRO'),'2018-07-31','(Pedro)Conversación con Montse, T. Soc. CAMP Don Benito (20110). +++Correo-e (31-07-2018): Buenos días, os informo que Coral se encuentra hospitalizada en el hospital de Don Benito, hemos contratado SAH desde anoche, siendo las tarifas las siguientes: dia completo 140 € noche 70€ hasta el mediodia 105 € precio por hora 10€ La residente esta sufriendo convulsiones, en esta mañana se han vuelto a repetir, mañana estara de guardia nuestro medico del centro, prevee que la hospitalización sea de una semana, pero no podemos asegurarlo. Por favor,contactad conmigo para determinar las horas del acompañamiento externo. Un cordial saludo, Montserrat de Pablos Gómez Trabajadora Social Centro Residencial "Nuestra Señora de las Cruces" Avda. Alonso Martín, 16. 06400, Don Benito (Badajoz) Tlf: 924 021 571 +++Hablo con ella sobre el tema: nos informará sobre evolución y previsión de duración del acompañamineto. +++En estos momentos lo precisa las 24 horas del día por estar convulsionando. +++Paso a Alberto para que contacte con ella.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CORAL'and edp.apellido1='NEVADO'and apellido2='NAVARRO'),'2018-08-01','(Pedro)Conversación con Montse (CAMP). +++Coral está mejor. +++La está acompañando una cuidadadora contratada. +++La familia se ha prestado a realizar el acompañamineto, para cobrarlo, planteando también que se le debe abonar el alojamineto. Se mantendrá el acompañmineto como hasta ahora. +++Montse nos dirá la previsión que hay en cuianto horas/sía de acompañamineto porque el periodo de ingreso no lo pueden precisar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DOLORES'and edp.apellido1='ALFONSO'and apellido2='GARCIA'),'2018-08-01','(Pedro)Se recibe mediante Nota Interior de Víctor Ruiz (Jefe de Gestión de Control de la actividad Asistencial) informando sobre la reserva de plaza residencial en el Centro Residencial "El Prado" de Mérida.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUISA'and edp.apellido1='REY'and apellido2='CAMPON'),'2018-08-01','(Pedro)Conversación con maite, Directora de la residencia "San Francisco": +++Dª Luisa ha ingresado ya en la residencia. Se ha mostrado tranquila. Llevaba 150 € que le han recogido y le han habilitado una habitación para ella sola (de momento), si bien ella pedía tener una compañera. +++Respecto de la visita al CADEx el p´roximo 20 de agosto seguramnente la llevarán en taxi: se le indica que pidan factura a nombre de Dª Lusia y nos la remitan con un nº de cuenta para hacer el ingreso. +++Le envío por fax (927-017361) copia de la tarjeta de la Seguridad Social.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA EUGENIA'and edp.apellido1='MOLANO'and apellido2='CAMBERO'),'2018-08-02','(Pedro)Conversación con Carmen gallego, Jefa de Sección de Dependencia. (927-004339). DIRECCIÓN: SEPAD. Serv. Territorial.DEPENDENCIA. Plaza Hernán Cortés nº 1. 10001. Cáceres. +++rEQUIERE iNFORME DE sALUD PARA DAR TRÁMITE A LA REVISIÓN DE GRADO. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++(Pedro)Conversación con Fátima Díaz Torrado, Médico de Familia de Arroyo de la Luz. +++No recordaba los contactos mantenidos con ella a finales del pasado año, ni el correo en el que se le solicitaba el inofrm de Salud que nuevamente se le solicita por fax (927-271219). +++Citará a Dª Eugenia. Fátima se va de vacaciones la segunda quincena de agosto. Le ruego que nos lo envíe antes si es posible (yo me marcho de vacaciones hasta finales de agosto). +++Enviarlo a la dirección indicada. (Ella no ha tenido constancia de nuestra solcitud hasta hace unos días.)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA EUGENIA'and edp.apellido1='MOLANO'and apellido2='CAMBERO'),'2018-08-02','(Pedro)Conversación con Fátima Díaz Torrado, Médico de Familia','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2018-08-02','(Alberto y Pedro)Entrevista con Ildefonso. +++Se firma compromiso de actuación. Ver expedeinte. +++Transferencia de alquiler y abono de 70€/semana para alimnetación, etc.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2018-08-01','(Pedro)Visita de Ildefonso. Ha estado buscando Hostal pero dice que están todos ocupados. +++Llamo al Hostal Salud y, efectivamente, dicen que está completo por el Festival de Teatro. +++En trámites con Inmobiliaria Ático.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2018-08-03','(Pedro)Visita de Ildefonso. +++Todavía la inmobiliaria nos ha comunicado si acepta las modificaciones del contrato. +++Llamo a Inma, T. Soc. del "Padre Cristóbal" para ver si se puede quedar al menos el fin de semana en el centro. +++++Le propuesieron marcharse al Centro de Don Benito pero no quiso. +++++Para hoy tienen todas las plazas ocupadas, pero mañana creen que se va a marchar una persona. Acudirá mañana al centro y si está libre la plaza pasará en ella el fin de semana. +++A la espera de respuesta por la inmobiliaria.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DOLORES'and edp.apellido1='ALFONSO'and apellido2='GARCIA'),'2018-08-03','(Pedro)Tras conversación con Carmen Torres, T. Soc. del SSB de Cilleros (927-512037), en la que informa de que Dª Dolores está ilocalizable, envío fax al Juzgado de 1ª Instancia e Instrucción de Coria informando de la situación (SE TRATA DE UNA DEFENSA JUDICIAL).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='VALADES'and apellido2='DIAZ'),'2018-08-03','(Alberto y Pedro). Visita de Isabel, sin programar. +++Gafas: se pagarán por transferencia una vez contactemos con la Óptica Barrau. +++No se le proporciona extra dado que sacó sin autorización 315€.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA EUGENIA'and edp.apellido1='MOLANO'and apellido2='CAMBERO'),'2018-08-03','(Pedro)Conversación con Susana, T. Soc. Futuex: +++Pedirán cita en el ESM y acompañarán a Dª Eugenia a la consulta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CANDIDO'and edp.apellido1='BAS'and apellido2='GONZALEZ'),'2018-08-03','(Pedro)Convereación con María, T. Soc. SSB de Vva. del Fresno. Se le informa del ingreso y situación de D. Cándido en estos momentos y de que el recurso actual puede no ser el definitivo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CANDIDO'and edp.apellido1='BAS'and apellido2='GONZALEZ'),'2018-08-02','(Pedro)Conversación con Isabel Álvarez, Psiquiatra de UME Mérida. +++El comportamiento de Cándido es estupendo. +++Le pongo al tanto de la consucta de Cándido en su localidad y de la alarma social que con él ha venido provocando. Se queda muy sorprendida tras esta información: "No te preocupes que lo tendremos en cuenta".','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='MURILLO'and apellido2='DELGADO'),'2018-08-02','(Pedro)Conversacaión con Isabel Álvarez, Psiquiatra UME Mérida. +++El comportamineto de María está seindo bueno. No ha provocado ningún enfrentamiento con nadie. +++La tendrán hasta septiembre/octubre y posiblemnete le den el alta, aunque siempre cabe el riesgo de recaída, con lo cual se empezaría de nuevo el "circuito". +++PROBLEMA: llegado el momento, no ve que su marcha a Monesterio sea algo positivo, tanto más cuanto que allí no conoce a nadie. Su madre muestra una gran ambivalencia respecto a su hija, y no parece querer estar pendiente de ella en caso de alta. +++En cualquier caso, María requiere un recurso dentro de la red de salud mental. +++PLANTEAR CRR DESPUÉS DEL VERANO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='IVAN'and edp.apellido1='MESA'and apellido2='CANDIL'),'2018-08-03','BELEN: NOS INDICA ISABEL, DIRECTORA DE APROSUBA 3 (687 777 282)QUE HASTA HACE 2 SEMANAS NO SE SABÍA NADA DE LA MADRE, AHORA ESTÁ EN CASA.DESCONOCE LA RELACIÓN QUE PUEDA HABER CON IVÁN.PEDIRÁ INFORME SOCIAL.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2018-08-06','Iciar: 6/8/2018. Llama Loli la propietaria porque no se le ha pagado la renta . No tiene constancia de que Ildefonso haya dejado el piso. Esta mañana ha ido y le ha abierto un hombre. Se le informa de que la fianza la puede utilizar para el pago del mes, ella quiere ver cómo está el piso pues igual los desperfectos superan a la fianza. Pide las llaves del piso para poder entrar. Le gustaría que cuando fuera a ver el estado del piso le acompañara alguien de la comisión. Hablamos con Antonio Parra del Hostal El Torero, 924 37 17 89. Tiene habitaciones disponibles para una semana. Nos manda el presupuesto de habitación con pensión completa al mail de la comisión. Ildefonso no se ha pasadopor el Hostal para preguntar','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JONATHAN'and edp.apellido1='RAMIREZ'and apellido2='JUAREZ'),'2018-08-07','Ponen en nuestro conocimiento la Ejecutoria nº 35/2013, dictada por la Audiencia Provincial Sección 3 de Mérida, por la que ponen en libertad a Enrique Merchán Fernández y fija su residencia en C/ San Judas, 11 de Alemendralejo, a los efectos de que lo pongamos en conocimiento de Jonathan.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIPE'and edp.apellido1='RODRIGUEZ'and apellido2='SOLIS'),'2018-08-08','Iciar: Llama Isabel, T.S. de Miajadas. La Guardia Civil sigue sin dejar que Felipe ponga la denuncia al ser una persona tutelada.Sin embargo, la misma G.C. le pide por escrito que le facilite informe del estado de Felipe.Le pedimos a Isabel que Felipe redacte el motivo de la denuncia lo firme y nos lo envie a la Comisión, y desde aquí se lo hacemos llegar por escrito al La G.C.. Además nos enviará escaneado la nota simple del Registro de la Propiedad de Trujillo para que podamos averiguar algo más del supuesto cambio de titularidad de la casa cuando Franciso era tutor de Felipe.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUGENIA'and edp.apellido1='PACHECO'and apellido2='VICENTE'),'2018-08-09','Hemos solicitado al Juzgado de Primera Instancia e Instrucción nº 3, de Plasencia, información relativa al embargo judicial ETJ 35/2018, por la que le reclaman 27.418,91 euros en total, a ella y a Lino Luis Martín. Al mismo tiempo, hemos solicitado aclaración de la sentencia, al haber aceptado el cargo de curador, mientras que en el fallo de la sentencia constantemente hace referencia al cargo de tutor.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONCEPCION'and edp.apellido1='MARTINEZ'and apellido2='VAZQUEZ'),'2018-08-09','Hemos enviado escrito al OAR de Badajoz (924630003), para que, como consecuencia del Testamento otorgado por D. Pedro Pecos García, en el que lega a Dª. Concepción el usufructo universal y vitalicio del inmueble sito en C/. Pizarro, 13, de Talarrubias (Badajoz), le giren los recibos correspondientes al IBI del inmueble, desde el fallecimiento de D. Pedro Pecos GArcía, el 17/2/2017, en adelante. Hemos hablado con la hermana de Pedro, Isabel (662440957-60066118), que reside en Palma de Mallorca, para que sus hijos que son los herederos, procedan a formalizar la herencia. En Ibercaja de Talarrubias (Mª. Luisa, 924630102), D. Pedro dejó un depósito de unos 700 euros aproximadamente. En la herencia hay también un préstamo de unos 1.500 euros aproximadamente, a liquidar entre en el depósito y lo que se obtenga por la venta del inmueble (valorado por la Junta en unos 28.992,83 euros, aunque según la propia Isabel e Ibercaja, el valor pueda ser menor), de lo que Concepción obtendrá el usufructo (35%). Hemos enviado al Registro de la Propiedad de Herrera del Duque (Consoli, 924650054), solicitud para que liquiden el impuesto de sucesiones correspondiente a Concepción, que le sale a pagar 0.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA EUGENIA'and edp.apellido1='MOLANO'and apellido2='CAMBERO'),'2018-08-10','Iciar: Llama Fátima, la médico de familia 52600, nos manda el informe de salud por fax y por correo postal.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VICENTE'and edp.apellido1='MARQUEZ'and apellido2='CABEZA'),'2018-08-16','- INGRESA EL DIA 30 DE JULIO EN CRR BADAJOZ , CORREO DE ANA DELFA , ENVIÓ UNA DOCUMENTACIÓN PARA FIRMAR , NO SÉ SI SE HA ENVIADO . : Os comunico que hoy día 30/07 ha sido entrada en nuestro dispositivo Vicente Márquez Cabezas. Carmen te envío por correo el certificado de provisión de servicio y a vosotros Amalia y Pedro os remitiremos la documentación interna que necesitamos que esté también firmada por vosotros.','2');
