insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2018-08-16','-AMALIA: ENVIAN POR CORREO LA RESOLUCION DE LA NO ACEPTACION.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN FRANCISCO'and edp.apellido1='VALENCIA'and apellido2='AREVALO'),'2018-08-17','-AMALIA: NOS LLAMAN DE LA GERENCIA SEPAD BADAJOZ, SE LE VA ADJUDICAR PLAZA T3 EN EL ENCINAR DE D. BENITO. ENVIARÁ LA RESOLUCIÓN EN UNOS DIAS. CONTACTAREMOS CON HOSPITAL Y EL CENTRO PARA EL TRASLADO CUANDO NOS LLEGUE LA RESOLUCIOÓN . LA PLAZA ES TEMPORAL , REVISABLE CADA 6 MESES.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='RUBIO'and apellido2='TRINIDAD'),'2018-08-17','-AMALIA : LE HAN CONCEDIDO PLAZA RAL EN EL CAMP D.BENITO ,INGRESARÁ EL PROXIMO DIA 21 . LO ACOMPAÑARÁ FUTUEX , VIAJE EN TAXI , LA PRIMA NO PUEDE ACOMPAÑARLO ( TF ESPERANZA 620127798). HAY UNA CHICA QUE VA A ASEARLO POR LAS MAÑANAS A SU CASA , LE HE PEDIDO QUE LO TENGA PREPARADO PARA QUE PUEDAN SALIR DE ALLÍ SOBRE LAS 10.00.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='MACIAS'and apellido2='MARTINEZ'),'2018-08-17','-LLAMA LA DIRECTORA DE NUÑOMORAL , SE LE HA BAJADO LA MEDICACION POR SU PSIQUIATRA Y SE ESTÁ DESCOMPENSANDO . IDEAS DELIRANTES Y AMENAZAS. EL SABADO ACTIVO 112 Y HOY TB VA A HACERLO . SEGUIREMOS VIENDO SU EVOLUCION.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANGELES'and edp.apellido1='SANTOS'and apellido2='URBANO'),'2018-08-17','-AMALIA: FUTUEX ENVIA IMFORMES Y DOCUMENTACION ANEXA. GUARDADO EN SU CARPETA DE " PERSONAL " . ANTE SU PROPUESTA DE SACARLA DEL DOMICILIO PQ NO REUNE CONDICIONES DE HABITABILIDAD LES CONTESTO ESTO : " De la documentación se desprende la idoneidad de sacarla de esa vivienda por sus pésimas condiciones de habitabilidad. Para no desarraigar lo ideal ,si el resto de condiciones ( buena relación con el padre, mantenimiento de la casa , elaboración de comidas , controles sanitarios ... ) se puedieran garantizar sería que ambos se fuesen a una vivienda alquilada que reuniera condiciones óptimas .Solicitar SAD y mantenerlos juntos y en la misma localidad. Si el padre persiste en su negativa de no irse, tendríamos que sacar de allí a Mª Angeles , que es la que está tutelada . El padre tiene libertad de decisión . Proponéis una plaza en Centro Residencial , y al parecer existe voluntariedad por parte de ella para el ingreso . Ahora bien , tiene un Grado I con lo que no reune requisito para solicitar plaza por dependencia . Podriamos pedir P. vinculada a servicio y ayudar al pago de residencia privada junto con la PNC que percibe. Existiría la posibilidad de ingresar en Pinofranqueado , que es un centro no acreditado , y estaría con el hermano ?? Otra opción es pedir plaza residencial por emergencia social , pero en este caso , no podemos elegir centros , dónde surja la plaza vacante tendría que ingresar . Para curarnos en salud, vamos a solicitar autorizacion judicial para el ingreso , el padre puede influenciarla y llegado el día no querer ingresar . Qué alternativa os parece la más idónea tras la visita que habéis realizado ?? Un saludo . Amalia. _ QUEDO PTE. DE LA RESPUESTA . SOLICITO AL AREA JURIDICA SOLICITUD DE INGRESO EN CENTRO .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIPE'and edp.apellido1='RODRIGUEZ'and apellido2='SOLIS'),'2018-08-20','Enviamos al Juzgado Decano de Trujillo denuncia por un posible delito de amenazas del hermano, así como incumplimiento de las obligaciones impuestas en la transmisión de la vivienda familiar.','2');
