insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONCEPCION'and edp.apellido1='ALEJANDRO'and apellido2='DIAZ'),'2018-08-21','-AMALIA: LLAMA MANUEL JESUS , SU EXMARIDO , HAN RETOMADO LA RELACIÓN, QUIEREN VOLVER A CASARSE Y VA A SOLICITAR SER TUTOR. NO ME FACILITA SUS APELLIDOS , VIVE EN UNA VPO EN BADAJOZ Y SE QUIERE LLEVAR ALLÍ A PIPI. SOLICITA AUTORIZACIÓN PARA SACAR DINERO . ME COMENTAN LA PARTE EC. QUE HA SACADO 600€ SIN AUTORIZACIÓN Y NO SE LE VA A DAR NADA DE DINERO SI NO VUELVE AL CENTRO . EL CRR NOS COMUNICA QUE EL DIA 20 DIÓ DE BAJA A LA PLAZA.','2');
