insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTINA'and edp.apellido1='SOLANA'and apellido2='GUERRA'),'2018-08-27','ICiar: llama Juana , T. S., pregunta por el segurod e decesos de Martina. le comento que tiene Santa Lucía. Ella se va a poner en contacto con el seguro para gestionar los trámites tras el fallecimiento de Martina el pasado viernes. Desde la funeraria le preguntan si se procederá a la incineración de Martina pues alhaber pasado 72 horas desde el fallecimiento se debe o bien dar un tratamiento de conservación al cuerpo, algo que no entra en su seguro, o bien proceder a la incineración. Al contar Martina con tan pocos recursos y no tener contacto con famila cercana se les pide que se haga lo que le cubra el seguro, en este caso incineración (Amalia dixit). Se realizará en el crematorio de Plasencia donde ha fallecido, ellos custodian las cenizas durante un tiempo en caso de que algún familiar las reclamen.','2');
