insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DOLORES'and edp.apellido1='ALFONSO'and apellido2='GARCIA'),'2018-08-28','(Pedro)Conversación con Víctor (Jefe Unidad). +++La resolución de ingreso estaba firmada para que se produjese el 31 de julio. No se puedo hacer en esa fecha y se quedó en realizarla el pasado 8 de agosto. Tampoco se puedo hacer porque, según la T.Soc. de"El Prado" decía que faltaba "algún papel" (toda la documerntación estaba completa). +++NUEVA LLAMADA DE VÍCTOR. Le llaman nuevamente de la residencia "El Prado": la T. Soc. de la Residencia (Toni) y la del SSB de Cilleros (Carmen), ante la dificultad de transporte para acudir al ingreso el pasado día 8 decidieron quer, dado que la citación del Forense era para el día 30 de agosto, la llevarían a dicha revisión y tras la misma la llevarían a la residencia. +++HABLAR MAÑANA CON LA t. sOC. DE "EL PRADO", que vuelve de vacaciones.','2');
