insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DOLORES'and edp.apellido1='ALFONSO'and apellido2='GARCIA'),'2018-08-29','(Pedro). Llamada a Toni, T. Soc. de la Residencia "EL Prado". +++En estos momentos no puedo contactar con ella. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Llamo a Carmen, T. Soc. de Cilleros (629-670606). +++Ha hablado con el Juzgado y le han dicho que la solcitud que se formuló era "de reserva " de plaza y que todavía el ingreso o no no estaba decidido. +++No se hacen reservas de plaza, dado la lista de espera que suelke haber en ellas y, que si se ha agilkizado, ha sido con la idea de que hubiese plaza disponible una vez acudiera mañana al Forense. +++Carmen acompañará a Dª María al Forense mañana.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE PEDRO'and edp.apellido1='VILLEGAS'and apellido2='SERRANO'),'2018-08-30','(Pedro)Converación con Encarna, T. Soc. Centro de Salud (Plasencia I)(927-423436y 74439). +++Correo emitido por Encarna en el día de ayer: Hola Pedro, soy Encarna Hurtado del Centro de Salud Plasencia I. Hoy no te escribo por nada de Francisco Ayala si no por un caso que me ha llegado y me dicen que han puesto denuncia a su tutor legal en el Juzgado de Plasencia y creen que sois vosotros los tutores legales actualmente, pero no lo saben. Era por si me puedes confirmar o desmentir lo que ellos creen y así poder saber a quién dirigirme en otras cuestiones que necesitan como el tema de dependencia. Te estoy hablando de los hermanos José Pedro y Cristina Villegas Serrano. Te agradezco de antemano si puedes decirme algo. Besos, Encarna. +++Información recibida de Encarna: +++++D. José Pedro','2');
