insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROBERTO'and edp.apellido1='HERNANDEZ'and apellido2='CASTAÑO'),'2018-09-07','-AMALIA: NOS AVISAN DEL CENTRO QUE AYER ROBERTO NO SE FUÉ. SE PUSO NERVIOSO Y TUVO QUE IR AL C.SALUD A PONERSE UN TRANQUILIZANTE , EL TAXISTA NO SE ATREVIÓ A LLEVARLO. EL CENTRO PROPONE QUE VAYA UN TAXI DE ALCANTAR QUE LO CONOCE CON UN MONITOR DEL CENRO O ESPERAR A QUE VUELVA CRUZ ROJA CON SU HNA. NOS INFORMARÁN CON LA DECISION QUE TOMEN.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='REMEDIOS'and edp.apellido1='CHAVES'and apellido2='MASERO'),'2018-09-07','-AMALIA: DEL CENTRO SAN JAVIER DE APROSUBA 3 NOS INFORMAN QUE EN EL ULTIMO MES SE HA TRAGADO LOS CRISTALES DE LAS GAFAS Y UN TAPÓN . AÚN ASÍ DICEN QUE HA REDUCIDO LOS EPISODIOS DE INGESTA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2018-09-03','(Pedro)Asistencia al Juzgado de lo Penal nº 1 de Plasencia. PROCEDIMIENTO ABREVIADO 0000206/2018. Respecto del juicio de José María la sanción impuesta es la siguiente: +++++++Por cada uno de los dos delitos, medida de internamiento en centro médico adecuado al tipo de anomalía o alteración psíquica por tiempo no superior a 2 años y seis meses. Firme sin posibilidad de recurso. +++++++Prohibición de aproximarse a ambas víctimas ... a una distancia no infererior a 200 m y de comunicarse por cualquier medio con ellos por tiempo de dos años. Según me comentó el abogado, había sido un acuerdo entre Fiscalía y él, preguntándome que si la Comisión estaba de acuerdo, a lo que le comenté que estaba a lo que el tribunal estimase oportuno. Antes de entrar en sala, le comenté al abogado que si la sentencia se podía cumplir en el mismo centro en el que se encontraba actualmente, dadas las incidencias constantes en el mismo y teniendo en cuenta que, no solo éste, sino todos los Centros para personas con discapacidad son centros abiertos. La contestación fue que no se había decidido el lugar, pero que en principio el que fueran centros abiertos no debía ser un problema. A esto le comenté que no podíamos perder de vista el tipo de delito y el tipo de medida (medida de internamiento de carácter judicial), para lo cual los únicos centros "medianamente " habilitados eran los dos CSS, considerando que el de Plasencia no podía ser al estar allí una de la víctimas. La duda fue la única respuesta a ello. Tras entrar en sala y una vez pronunciadas las medidas a tomar, le hice ver al salir al abogado que el internamiento decretado se debía realizar en centro médico, por lo que no era ya posible que la sentencia se ejecutara en el actual centro u otro de discapacidad. El juez comentó, al volver a entrar, que el lugar en el que se ejecutara la sentencia ya se determinaría cuando saliera la Ejecutoria.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LIBERTAD'and edp.apellido1='GARCIA'and apellido2='MARQUEZ'),'2018-09-07','-AMALIA: EL CENTRO LE PONE UNA SANCIÓN DE 3 DIAS DE EXPULSION , SE VA A SU CASA POR CONDUCTA DISRUPTIVA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='CAMPA'and apellido2='SILGUERO'),'2018-09-07','-AMALIA : DESDE EL CUARTILLO NOS COMUNICAN QUE TENDRÁ UNA SALIDA DE 10 DIAS EN SU DOMICILIO . YA SE HIZO EN MAYO Y TODO FUE CORRECTAMENTE.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA FERNANDA'and edp.apellido1='MARQUEZ'and apellido2='GARCIA'),'2018-09-10','DOMICILIO PARA INVENTARIO Se estableció comunicación con el juzgado la semana pasada solicitando la dirección para saber a quién, y dónde, solicitar el IS para el inventario. El juzgado da la dirección C/ Badajoz, 22, de Los Stos. de Maimona. Se le informa que la propia sentencia indica que vive en una residencia. El juzgado no sabe dar otra dirección.***********Se procede a llamar a la R. de los Stos. de Maimona (R. MM. Antonio Zapata), y a dos residencias de zafra. El resultado es negativo. No sabemos dónde reside esta Sra.**************************************Se solicita el IS a los SSB.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANGELES'and edp.apellido1='SANTOS'and apellido2='URBANO'),'2018-09-10','(Pedro)Conversación con Inma, del Juzgado de Coria (927-508158). +++Quería saber el Centro en el que se iba a ingresar a Dª Mª Ángeles. SE le explica que no podemos solicitar plaza hasta que tengamos la Autorización Judicial. +++REVISIÓN MÉDICO-FORENSE: 17 de OCTUBRE de 2018 las 10:00. Enviarán citación a la tutelada y a la CTAEx. +++Insisto en la necesidad de tramitar lo antes posible la autorización para poder solicitar Centro, así como la posibilidad de adelantar reconocimiento médico.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE PEDRO'and edp.apellido1='VILLEGAS'and apellido2='SERRANO'),'2018-09-03','(Pedro)Visita domiliaria a Dª Cristina y D. José Pedro. Acompañado por D. José Miguel Basquero (anterior tutor y abogado) y Dª Charo Hernández (Aux. de Hogar contratada por D. José Miguel. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++D. JOSÉ PEDRO: lo fuimos a ver al centro de Día del Hogar de Nazaret donde nos recibión con Puerto, la Directora (927-416563). +++En silla de ruedas, atendido por una Cuidadora, se mostró amable y educado. Buen aspecto y bien aseado. Mostraba dificuldaes en el habla, propias de la enfermedad, pero que no obstante permitían mantener una conversación con él. De esta forma me dijo que estaba muy contento en el Hogar y que quería seguir estando allí (acude a las 8 de la mañana y vuelve a la 8 de la tarde en un taxi que va a buscarlo). En un pricipio, ante la posibilidad de permanecer en un Centro como resiedente se negó, pero terminó aceptando esta posibilidad si su hermana estaba con él. En ese caso, le gustaría permanecer en el Hogar (Puerto comentó que tenían 70 plazas concertadas y que en esos momentos había alguna vacante). Se le informó de que no se podía garantizar, caso de tomar la decisión, que pudiera permanecer en él...pero que se tendría en cuenta. +++Puerto comentó que en Centro de Día está pagando 700€ y que había algunas deudas, pero que no corría prisa ya que le comenté que se abonarían una vez estuviésemos autorizados en las cuentas y supiésemos el estado de las mismas. +++Según mis acompñaantes, estos hermanos están pagando la hipoteca del piso que ocupan y un préstamos que adquirieron, al parecer, a ponerlos su hermano D. Julián como avalistas. También parece ser que deben en alguna tienda (frutería, farmacia, etc.). +++En cuanto a la relación que mantiene con Dª Charo, parece ser buena tal y como se expresaba durante nuestra visita. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Dª CRISTINA: a ella fuimos a verla en su domicilio, de donde en esos momentos se disponía a salir. Nos recibió con cordialidad. Su aspecto era bueno y aseado, si bien muy delgada pero sin problemas aparentes de movilidad. +++Las condiciones de habitabilidad e higiene de la vivienda que comparte don su hermano eran completamente normales. Sin embargo y a pesar de ñla petición del sr. Basquero, no consintió en mostrarnos el piso de su propiedad que está en el mismo rellano, frente por frente a este en el que nos recibió y que, según el abogado y la auxiliar está en pésimas condiciones. +++Su primer comentario fue el siguiente: "Le voy a ser sincera. Ante todo, mis previsiones son que no me quiero marchar a ninguna residencia, por lo menos de momento. Yo aquí estoy bien, con Charo y con mi hermano. A pesar de exponerle las razones que podrían aconsejar dicho ingreso ella se mantiene firme en su postura: "...Y si le pasa algo por la noche a mi hermano yo llamo al 112 y ya está (¿y si le pasa a usted y su hermano no puede avisar?)..." Esta opción le hizo dudar un instante, para reponerse rápidamente y volever a su postura inicial. +++La relación con Charo también parece buena, si bien el contrato que esta tenía se refería solamente a la atención de D. José Pedro: "...pero bueno, no me importa si le hago la cena a él hacerle también algo a ella...". A Charo le comenté que nos enviase por corre-e el modelo de contrato que había tenido y que al ser removido del cargo el anterior tutor quedó rescindido y que nos dijese también en ese correo las propiedades que tenían los hermanos (se lo pregunté al anterior tutor, pero me dijo que Charo estaba más puesta en ello que él y que toda la docuemntación que había al respecto la tendría D. JUlián, primer tutor de Dª Cristina.). También le dije que, de momento y dado que la relación con ambos hermanos era buena, que se encargase ella de atenderlos y luego se le pagaría lo que fuese necesario, con la posibilidad de contratarla si s econsideraba la opción de permanecer en domcilio. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++CONCLUSIÓN DE LA VISITA: considero que ambos hermanos, con la ayuda de una tercera persona (que si sus ingresos lo permiten, podría estar incluso interna) podrían manternerse en el domicilio mientras sus circunstancias de salud no variasen significativamente. DUDA: la influencia que parece tener D. Julián sobre ellos y que aparentemente, según los datos aportados por D. J.M. Basquero y Dª Charo, no es muy de fiar y que quizá podría justificar un ingreso en centro anticipado. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ANTES DE ESTA VISITA ME REUNO CON LA FISCALÍA, con D. José Manuel R. +++LOs informes que me facilita sobre dos de los hermanos, D. Julián y D. Francisco (Procurador) no son nada buenos, especialmente negativos en el caso del primero y poco recomendable el segundo. +++PLANTEA QUE LA COMISIÓN SOLICITE AMPLIACIÓN DE LA INCAPACIDAD (no se propueso en su momento porque no se consideró necesario entonces). +++OTROS TEMAS: +++++LEXNET: La CTAEx no tiene obligación de requerir Lexnet, ni tampoco la Abogacía. TODO SE TRATMITA CON ABOGADO DE OFICIO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE PEDRO'and edp.apellido1='VILLEGAS'and apellido2='SERRANO'),'2018-09-04','(Pedro). Resumen de las llamadas efectuadas por D. Julián Villegas (927-412660 y 675-695571), hermano de Dª Cristina y D. José Pedro (una de ellas anterior a la presente fecha). +++En todo momento mostró una actitud muy exigente en cuanto a la atención a sus hermanos y un desacuerdo absoluto y completamente negativo en cuanto a la gestión que había realizado el anterior tutor, Sr. Basquero (quien, por otra parte manifestó que el haber asumido la tutela fue por la amistad que le unía a ambos hermanos y uno de los motivos para renunciar a ella el del acoso al que D. Julián le estaba sometiendo, incluso menoscabando su prestigio como abogado)y la atención que Dª Charo prestaba a sus hermanos (Dª Charo confesó que había tenido varios desencuentros serios con él y que incluso había llegado a llevar a otras personas para que hicieran las tareas domésticas...) +++El negó haber sido removido del cargo en su momento ("...a mí nadie me quitó, lo dejé yo...") y dijo que estab dispuesto a hacerse nuievamente cargo de sus hermanos. +++Se le explicó que esta Comisión no iba a entrar en los problemas familiares que pudiesen existir entre ellos; se le recordó que desde el punto de vista legal él no podía tomar decisión alguna sobre sus hermanos y que, al igual que cuando fue tutor tomó las decisiones que consideró oportunas, en estos momentos era la Comisión Tutelar la que debía tomarlas en el mayor beneficio de sus hermanos. +++Ante el desacuerdo manifestado reiteradamente por D. Julián, se le indicó que estaba en su derecho de hacer las reclamaciones/denuncias que considerase oportuno ante el Juzgado correspondiente si estaba en desacuerdo con la gestión de esta Comisión, a lo que RESPONDIÓ: " Pues si esto va a ser así, y esa mujer va a encargarse de mis hermanos, ya me encargaré de sacarlos yo de su casa..." A lo cual se le respondió: "No está usted autorizado a tomar sobre sus hermanos nio esa ni ninguna otra decisión que les afecté, y tal como esto ocurra, esta Comisión dará parte al Juzgado de dicha situación..."RESPUESTA: "...No, si no me los voy a llevar yo, serán ellos lo que se vayan..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CRISTINA'and edp.apellido1='VILLEGAS'and apellido2='SERRANO'),'2018-09-04','(Pedro). Resumen de las llamadas efectuadas por D. Julián Villegas, hermano de Dª Cristina y D. José Pedro (una de ellas anterior a la presente fecha). +++En todo momento mostró una actitud muy exigente en cuanto a la atención a sus hermanos y un desacuerdo absoluto y completamente negativo en cuanto a la gestión que había realizado el anterior tutor, Sr. Basquero (quien, por otra parte manifestó que el haber asumido la tutela fue por la amistad que le unía a ambos hermanos y uno de los motivos para renunciar a ella el del acoso al que D. Julián le estaba sometiendo, incluso menoscabando su prestigio como abogado)y la atención que Dª Charo prestaba a sus hermanos (Dª Charo confesó que había tenido varios desencuentros serios con él y que incluso había llegado a llevar a otras personas para que hicieran las tareas domésticas...) +++El negó haber sido removido del cargo en su momento ("...a mí nadie me quitó, lo dejé yo...") y dijo que estab dispuesto a hacerse nuievamente cargo de sus hermanos. +++Se le explicó que esta Comisión no iba a entrar en los problemas familiares que pudiesen existir entre ellos; se le recordó que desde el punto de vista legal él no podía tomar decisión alguna sobre sus hermanos y que, al igual que cuando fue tutor tomó las decisiones que consideró oportunas, en estos momentos era la Comisión Tutelar la que debía tomarlas en el mayor beneficio de sus hermanos. +++Ante el desacuerdo manifestado reiteradamente por D. Julián, se le indicó que estaba en su derecho de hacer las reclamaciones/denuncias que considerase oportuno ante el Juzgado correspondiente si estaba en desacuerdo con la gestión de esta Comisión, a lo que RESPONDIÓ: " Pues si esto va a ser así, y esa mujer va a encargarse de mis hermanos, ya me encargaré de sacarlos yo de su casa..." A lo cual se le respondió: "No está usted autorizado a tomar sobre sus hermanos nio esa ni ninguna otra decisión que les afecté, y tal como esto ocurra, esta Comisión dará parte al Juzgado de dicha situación..."RESPUESTA: "...No, si no me los voy a llevar yo, serán ellos lo que se vayan..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE PEDRO'and edp.apellido1='VILLEGAS'and apellido2='SERRANO'),'2018-09-07','(Pedro)Conversación con Encarna, T. Soc. del C.Salud Plasencia I (927-423436/Ext 74439). +++Plantea la posibilidad de hacer una visita a los hermanos Villegas, a lo cual le digo que por supuesto que puede (y si lo considera, debe hacerla). +++Le comentó que hable con Radiotaxis para informar a quien recoja a D. José Pedro que puede enviar las facturas a la Comsiión, incluídas las que pudiera haber pendientes. (esto también se lo comenté a Charo, la Auxiliar de Hogar).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CRISTINA'and edp.apellido1='VILLEGAS'and apellido2='SERRANO'),'2018-09-07','(Pedro)Conversación con Encarna, T. Soc. del C.Salud Plasencia I . +++Plantea la posibilidad de hacer una visita a los hermanos Villegas, a lo cual le digo que por supuesto que puede (y si lo considera, debe hacerla). +++Le comentó que hable con Radiotaxis para informar a quien recoja a D. José Pedro que puede enviar las facturas a la Comsiión, incluídas las que pudiera haber pendientes. (esto también se lo comenté a Charo, la Auxiliar de Hogar).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CACHO'and apellido2='GARRIDO'),'2018-09-10','-AMALIA : LA DOCUMETNACION DE LA PNC HA LLEGADO A REGISTRO CC, CREO QUE EN REGISTRO LA HAN SEPARADO DE LA SOLICITUD. LES PIDO QUE LA ENVIEN A PNC CC','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CRISTINA'and edp.apellido1='VILLEGAS'and apellido2='SERRANO'),'2018-09-03','(Pedro)Visita domiliaria a Dª Cristina y D. José Pedro. Acompañado por D. José Miguel Basquero (anterior tutor y abogado) y Dª Charo Hernández (Aux. de Hogar contratada por D. José Miguel. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++D. JOSÉ PEDRO: lo fuimos a ver al centro de Día del Hogar de Nazaret donde nos recibión con Puerto, la Directora (927-416563). +++En silla de ruedas, atendido por una Cuidadora, se mostró amable y educado. Buen aspecto y bien aseado. Mostraba dificuldaes en el habla, propias de la enfermedad, pero que no obstante permitían mantener una conversación con él. De esta forma me dijo que estaba muy contento en el Hogar y que quería seguir estando allí (acude a las 8 de la mañana y vuelve a la 8 de la tarde en un taxi que va a buscarlo). En un pricipio, ante la posibilidad de permanecer en un Centro como resiedente se negó, pero terminó aceptando esta posibilidad si su hermana estaba con él. En ese caso, le gustaría permanecer en el Hogar (Puerto comentó que tenían 70 plazas concertadas y que en esos momentos había alguna vacante). Se le informó de que no se podía garantizar, caso de tomar la decisión, que pudiera permanecer en él...pero que se tendría en cuenta. +++Puerto comentó que en Centro de Día está pagando 700€ y que había algunas deudas, pero que no corría prisa ya que le comenté que se abonarían una vez estuviésemos autorizados en las cuentas y supiésemos el estado de las mismas. +++Según mis acompñaantes, estos hermanos están pagando la hipoteca del piso que ocupan y un préstamos que adquirieron, al parecer, a ponerlos su hermano D. Julián como avalistas. También parece ser que deben en algun