insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE PEDRO'and edp.apellido1='VILLEGAS'and apellido2='SERRANO'),'2018-09-10','(Pedro) Se recibe fax en la CTAEx de la Dirección del Hogar de Nazaret, informando de que D. José no acude al Hogar desde el pasado 6 de septiembre. +++Ya habíamos sido inofrmados previamente por Dª Charo, Auxiliar que lo atiende y que refeiere que ningún taxista quiere hacer el servicio porque no se le paga. Ruego a Charo que nos envíe los teléfonos de los taxistas que coincoen el caso para hablar con ellos y garantizar el pago de dichos servicios. +++SEGÚN LA DIRECCIÓN DEL HOGAR, al parecer D. José suele llegar en condiones poco higiénicas al Centro, debiendo en ocasiones incluso tener que bañarlo...NO FUE ESTA LA IMPRESIÓN QUE ME LLEVÉ EN LA VISITA REALIZADA EL PASADO DÍA 4 (visita NO programada ni concertada). ¿Podemos confiar en la Auxiliar de Hogar? +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con Encarna, T. Soc. C.Salud Plasencia I. +++Le ruego que vaya a visitar a los hermanos los antes posible, en vista de la nueva inofrmación recibida de la dirección del Hogar de Nazaret. Tenía previsto ir mañana. Le propongo acudir con Futuex para iniciar el seguimineto. Le parece oportuno. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con Toni (FUtuex). +++Le pongo al tanto de las circunstancias del caso y le pido que se pongan en contacto con Encarna para la visita de mañana.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DIEGO'and edp.apellido1='RODRIGUEZ'and apellido2='PARRILLA'),'2018-09-10','-AMALIA: PONGO A FIRMA MODIFICACION DATOS ENTIDAD BANCARIA DE LA PFHC. FIRMAR Y REGISTRAR DE ENTRADA AL INSS BADAJOZ.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='SAUCEDO'and apellido2='AGUEDO'),'2018-09-10','-AMALIA : PERCIBE PFHC Y ORFANDAD. LA PFHC HA PASADO DE 380 A 195€. EL CPTO. A MINIMOS ES MENOR CUANDO PASAN A TENER 18 AÑOS. LA SS.NO SE HA DADO CUENTA HASTA AHORA , LO REDUCEN PERO NO VAN A PASAR COBRO INDEBIDO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ESTIBALIZ'and edp.apellido1='MENDEZ'and apellido2='CARRASCO'),'2018-09-10','-AMALIA : COTNRATO DE TRABAJO POR 6 MESES . COMUNICADO A PNC EL CAMBIO POR SOLE , TS DE CTRO LA LUZ.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='QUIROS'and apellido2='SAUCEDA'),'2018-09-11','BELEN:LLAMA CARMEN(686810015) CUÑADA DE JOSE ANTONIO QUIROS, PARA COMUNICAR QUE ESTÁ INGRESADO EN EL HOSPITAL DON BENITO-VILLANUEVA, DESDE EL VIERNES 7/9/2018, INDICANDO QUE VA A NECESITAR ACOMPAÑAMIENTO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CUEVAS'and apellido2='LOPEZ'),'2018-09-11','(Pedro)Llamada de D. Francisco. +++Quiere saber hasta cuando es su condena (se le dice que hasta enero 2023), saber si la puede terminar de cumplir en un CRR (es una medida de internamineto) y problemas con unas pastillas que su médico debe valorar (Dr. Álvaro) en cuanto a su indicación.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GONZALEZ'and apellido2='HERNANDEZ'),'2018-09-11','-AMALIA: SOLICITO ACTIVAR EXPENDIENTE DEPEND , PARA SOLICITAAR PREST. VINCULADA A SAD PEDIDO POR EL C.SALUD Y EL SSASB. EL AYTO . TIENEN PROBLEMAS PARA PRESTARLO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA'and edp.apellido1='GOMEZ'and apellido2='NEVADO'),'2018-09-11','-AMALIA : PIDO A FUTUEX UNA VISITA PARA CONOCER SU SITUACIÓN PERSONAL Y EC. AL PARECER TIEEN DEUDAS EN ESTABLECIMIETNOS.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE PEDRO'and edp.apellido1='VILLEGAS'and apellido2='SERRANO'),'2018-09-12','-AMALIA: SE RECIBE CORREO DE ENCARNA , TS C.SALUD SOBRE LA VISITA QUE REALIZARON AYER CON LA D. TUTELAR : Hola Pedro, vengo de la visita domiciliaria de los Hermanos Villegas. He ido acompañada de Alicia de FUTUEX. Nos ha abierto la puerta Julián (no estaba avisado). Es muy importante que exijas al abogado que te mande el contrato de Charo. José Pedro lleva 10 días sin ir al Centro de día. Te cuento más despacio el jueves porque mañana no vengo a trabajar. He conseguido el teléfono del taxista que llevaba en su día a Pepe al Centro. Se llama Chema: 616-012147.Correo-e: 12diciembre53@gmail.com También me han facilitado el tfno de Patri, una chica que ya cuidó a la madre de ellos y les gusta como trabaja: 655-039831. Es una pena que con 4000 € aproximadamente que entran en esa casa cada mes, vivan como lo están hacciendo. Te lo cuento el jueves. Un abrazo. Encarna.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2018-09-11','(Pedro)Llamada de D. José Luis y José Manuel. Han estado en el Juzgado de lo Penal 1 de Cáceres tras haber cumplido José Manuel los 5 días de arresto domiciliario. José Manuel ha dicho que quiere terminar de pasar la medida en el CRR de Mérida. +++Se les explica que esa elección no le corresponde a él.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2018-09-12','(Pedro)Ángel se pone en contacto con Verónica, abogada de José Manuel. Enviaremos correo-e indicando que él no puede decidir el centro y que tendrá que ser el Juzgado el que lo plantee al SEPAD. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++(Pedro)Hablo con Mari Luz y dejo copia de la Comparecencia de D. José Manuel en el Juzgado. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Envío correo a Verónica (ver expediente).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONCEPCION'and edp.apellido1='ALEJANDRO'and apellido2='DIAZ'),'2018-09-13','iciar: Llama Pipi para pedir 600 € porque se casa con su marido el próximo domingo. Hemos comprobado en su cuenta que a día de hoy ya ha sacado los 300 € que le correspondían por este mes, a pesar de que se dio orden al banco de que pudiera sacar 150 € quincenalmente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='REMEDIOS'and edp.apellido1='CHAVES'and apellido2='MASERO'),'2018-09-13','(Pedro) En el día de hoy se realiza visita a Dª Remedios por parte de Amalia y Pedro en la Residencia San Javier de Aprosuba 3. Están presentes Isabel (Directora), Mª José (Psicóloga) y Eli (voluntaria que sale de paseo con Remedios un día a la semana, habitualmente los jueves). +++Principal problema de Dª Remedios, su comportamineto, que le lleva a tragarse objetos que han provocado en numerosas ocasiones su traslado a urgencias. +++++Al parecer, ella "mide" lo que puede o no puede tragar, siendo una dificultad añadida el que dichas ingestas no se producen en situaciones de especial estrés, sino en cualquier situación, sin haber encontrado hasta este momento causa alguina para tal comportamineto. +++++Al parecer, el fallecimiento de su abuelahace unos años pudo ser el desencadenante de este tipo de comportamiento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='RUBIO'and apellido2='TRINIDAD'),'2018-09-14','(Pedro)Aclaro con Inma, T. Soc. del CAMP de Don Benito el motivo por el que la Comisión no acudió a la cita del 11 de sept en el Juzgado: con fecha de salida del 14 de agosto se envió al Juzgado escrito indicando que D. Antonio estaba tutelado y que por lo tanto estaba excluido como posible tutor de su madre, como así lo indicó el propio Juez la decir que, con un escrito que se le hubiese enviado, dicha comparecencia se podría haber evitado.Evidentemente, el escrito de la Comisión no le había llegado al Juez.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN PABLO'and edp.apellido1='MANZANO'and apellido2='ROBLES'),'2018-09-12','Se comunica desde el CSS de Mérida el traslado a urgencias de D. Juan en el día de hoy.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE PEDRO'and edp.apellido1='VILLEGAS'and apellido2='SERRANO'),'2018-09-14','(Pedro) Conversación con Encarna (T. Soc. del C.S. Plasencia I). +++Planteo posibilidad de residencia, para lo cual necesitaremos Informe de situación de emergencvia social. +++Cree que durante el fin de semana D. Julián se encargará de la alimentación. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ (Pedro)Conversación con Puerto, Directora del Hoagar Nazaret. +++José Pedro ha vueltoa ir al Hogar desde hace dos días y ha llegado en buenas condiciones tanto en el vestir como higiénicas. +++También acude al Hogar los sábados y festivos. Aunque parce ser que durante el fin de semana no les va a faltar alimento, le ruego a Puerto que cuando vuelva José Pedro a casa le dé comida para el fin de semana. Lo advertirá en cocina para que así sea. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++(Pedro)Conversación con José Manuel Rubio, Fiscal de Plasencia (927-422800). +++Plantea que solcitemos, a través de Abogado de Oficio la AMPLIACIÓN de la INCAPACIDAD: no se hizo en su momento porque se consideró que estaba en mejores condiciones. +++Respecto al ingreso en Centro, se puede solcitar la autorización para Dª Cristina, pero no en estos momentos para D. José. Le indico que la Comisión no tiene capacidad para activar el 112.SOLCITAREMOS INFORME MÉDICO QUE CERTIFIQUE EL EMPEORAMINETO DE D. José Pedro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN PABLO'and edp.apellido1='MANZANO'and apellido2='ROBLES'),'2018-09-14','(Pedro)Llamo a Blñanca, T. Soc. del CSS Mérida (24012) para conocer el estado de D. Juan. No contesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN PABLO'and edp.apellido1='MANZANO'and apellido2='ROBLES'),'2018-09-17','(Pedro)Conversación con Blanca. +++El viernes estuvo de permiso. +++Dieron el alta a D. Juan el pasado 14 de septiembre.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TERESA'and edp.apellido1='MANGAS'and apellido2='DE LA CRUZ'),'2018-09-17','-AMALAI: RECIBO LLAMADA DEPEND. ( CRISTINA ) VA A ENVIAR PIA, MANTENIMIENTO PLAZA EN R. MAYORES. ENVIAR REGISTRADO A SECCION DEPED PLASENCIA EN CSS .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2018-09-17','(Pedro)Conversación con Raquel, T. Soc. ESM de TRujillo (va los martes)(C.Salud Mejostilla:53334). +++Está acudiendo a ponerse los inyectables, el último en agosto. Llamar a Nuria, T. Soc. ESM de TRujillo que es quien lleva el seguimiento). +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con Nuria, Enfermera (54508), ESM de Trujillo: Se puso el inyectable el pasado 22 de agosto y el siguiente es el 22 de noviembre: este día se intentará que lo vea también el Psiquiatra. +++SE encuentra más tranquilo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='HIDALGO'and apellido2='ROMO'),'2018-09-17','-APROBADA PNC INV 380€ , EL PRIMER PAGO ES DE 760€ CON ATRASOS. SE PIDE A LA PARTE EC. ABRIR CTA. PECULIO Y ENVIAR UNA ASIGNACIÓN MENSUAL. ADG','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='SANGUINO'and apellido2='LANCHO'),'2018-09-17','-PIA , MANTENIMIENTO PLAZA EN CSS PLASENCIA. LO PONGO PARA FIRMA . LUEGO REGISTRARLO DE ENTRADA A SECCION DEPEN PLASENCIA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='MURILLO'and apellido2='DELGADO'),'2018-09-17','(Pedro)Conversación con Isabel Álvarez, Psquiatra del CSS de Mérida. +++Va a dar ya el alta médica a María: se encuentra en condiciones de recibir dicho alta. Insisto en que si no sería posible una derivación a CRR o Pisos: NO TIENE PERFIL PARA NINGUNO DE ELLOS. +++La posibilidad de que se vaya a vivir al piso que tiene alquilado en Monesterio no parece la mejor opción, dado que no es posible realizar una supervisión pormenorizada del día a día de María, por lo que esta Comisión considera que el riego de recaída es muy alto. +++Esta misma mañana ha llegado a la Comisión un paquete enviado por la madre de María con las llaves del piso de Monesterio (no indica dirección) y el teléfono móvil "...ante la posibilidad de ALTA MÉDICA....."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='PINILLA'and apellido2='PINILLA'),'2018-09-17','SE ARCHIVA EL EXPTE. La Sentencia 181/17, de 24/10/2017, incapacita a D. Antonio y nombra su curador a D. Manuel Pinilla Vázquez.************Se ha solicitado la confirmación de la firmeza al Jzdo. en tres ocasiones (01/12/2017, 14/03/2018, 23/05/2018) no contestando en ningún caso. Puesto que el nombramiento es de un familiar se da por firme y se procede al archivo del expte.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARGARITA'and edp.apellido1='ANTICH'and apellido2='ARROYO'),'2018-09-17','(Pedro)Conversación con Pilar. +++Se le informa de que cualquier gasto extra, fuera de lo habitual (p.e. vacaciones), que pueda tener lo consulten antes con la Comisión.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA EUGENIA'and edp.apellido1='MOLANO'and apellido2='CAMBERO'),'2018-09-19','(Pedro) Llamo al SSB de Arroyop de La LUz (927-640020). +++Eva, T. Soc. , está de baja. Isabel todavía no ha llegado y sandra no está al tanto del caso de Dª Eugenia. +++Volveré a llamar a Isabel.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SAMUEL'and edp.apellido1='BARRADO'and apellido2='SANCHEZ'),'2018-09-19','SENTENCIA APELACION CONTRA INCAPACITACIÓN Curro nos comunica, el 18/09/2018, que D. Samuel no está incapacitado. Que, en su momento, él mismo, apeló, en la Audicienca Provincial, la Sentencia que incapacitaba a D. Samuel. El resultado fue que la Audiencia revocó la susodicha Sentencia de incapacitación.**********************Recurso estimado: Sentencia nº. 137/13, de 30 de mayo, de la Audiencia Provincial de Cáceres, Sección Primera. Rollo apelación nº. 85/13, Autos nº. 400/10. Jzdo. que incapacitó: 1ª. Inst. e Inst. nº. 2, de Cáceres.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROBERTO'and edp.apellido1='HERNANDEZ'and apellido2='CASTAÑO'),'2018-09-19','(Pedro)Conversación con Sonia (927-390193), Directora Asindi. +++En caso de que vuelva a suceder algo así:procurar convencer y si se altera mucho y se pone agresivo valorar llamar al 112. +++En principio no saben qué ha podido motivar este comportamineto, pero cabe la posibilidad de que cuanto más tiempo pase con la familia más le cueste el retorno al centro. +++ALICIENTE: plantear algún incentivo que le motive a regresar al centro. +++MEDIDAS: las próximas salidas sea cortarán y disminuirá su frecuencia, empezando por un día y valorando evolución poder ir ampliando frecuencia y duración.Para Navidad la madre ha pedido que se pueda quedar hasta Reyes, pero se le ha dicho que debe decidir si quiere que sea para Nochebuena o para Reyes. +++Del 23 al 28 de spetiembre se marcha a Marina D´Or.','2');
