insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONCEPCION'and edp.apellido1='ALEJANDRO'and apellido2='DIAZ'),'2018-09-20','(Pedro)Reunión mantienida en el día de hoy con Dª Conecepción y su ex-marido, D. Manuel José Menacho Gómez(anterior tutor) con quien dice habers evueltoi a casar este pasado fin de semana. +++Dicen estar viviendo en Los Colorines, en la PLAZA TOTO ESTIRADO, PORTAL 1, 2ºA. 06007. BADAJOZ. +++No aportaron documento ni información alguna que pudiera corroborar dicho matrimonio, considerando que era una excusa para autorizarles 600€ que necesitan para dicha supesto enlace. +++Tanto en la conversación telefónica del 19 de sept. como en la reunión de ayer, Dª Concepción vertió amenazas de muerte contra los miembros de esta Comisión, amenzas que yahan sido puestas en conocimiento de la Dirección-Gerencia. +++En ningún momento Dª Concepción entendió que ellla seguía estando tuietlaada por la Comisión y que el Alta del CSS de Mérida era solamente clínica. +++D. Manuel José quiere -dice- tutelar nuevamente a Dª Concepción: "...la otra vez dejé el cargo porque ella bebía mucho...". SE le explica el procediemiento para ello.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA EUGENIA'and edp.apellido1='MOLANO'and apellido2='CAMBERO'),'2018-09-21','(Pedro) LLamo a Isabel, T. Soc. de Arroya de la Luz. +++Me pasan con ella pero no coge el teléfono. Volver a llamar.','2');
