insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2018-09-25','(Pedro)Llamada de PIlar, T. Soc.671-016615 (PILAR, T. SOCIAL del Hogar San Vicente de Paul y en el Comedor Social Obra Social La Milagrosa en Cáceres ). +++Ventuira lleva un tiempo yendo a comer de forma habiatual al Comedor: DICE QUE SE LE HA ROTO LA COCINA DE GAS. Pilar le ha pedido que solcite un presupuesto para hacernoslo llegar. +++También quiere dinero para irse de vacaciones. +++Quiere solcitar una ampliación de la capacidad (curatela). Pilar le ha informado de que a efectos prácticos nada iba a acambiar para él. SOLCITAR INFORMACIÓN A FUTUEX.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='AYALA'and apellido2='NUÑEZ'),'2018-09-25','(Pedro)Conversación con Elena, de Elena Farmacia a raiz de su correo-e: +++Buenos días: Soy la farmacéutica de Francisco Ayala, les escribo para comentarles que desde hace un tiempo, su estado se ha deteriorado mucho. Me gustaría hablar con algún responsable para ofrecer nuestros servicios de preparación de medicación (SPD) con el fin de que se tome la medicación correctamente, controlando así , desde la farmacia, la medicación que realmente se toma. Les rogaría que se pusieran en contacto conmigo a la mayor brevedad posible. TF: 927 41 11 97 Móvil: 617622491 Saludos Elena Serrano SPD: Sistema Personalizado de Dosificación. +++Refiere que últimamente Francisco está muy desmejorado, de hace un par de mese a esta parte. Le está controlando la medicación y quiere saber si hay algún proble ma en ello. Francisco está de acurdo y así asegura la correscta administración y adherencia la tratamineto. +++Nos tendrá informados de cualquier incidencia en relación a él. +++PEDIR INFORMACIÓN AL RESPECTO A FUTUEX.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2018-09-25','(Peero)Conversación con Urbano, de la D. G. Infancia y familia en Cáceres. +++Han dado la guarda a la abuela y han retirado la tutela administrativa. +++A la espera de si los letrados van a recurrir. +++Enviará la sentencia. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++PROCEDIMIENTO MEDIDAS DE PROTECCIÓN DE MENORES 0000710/2017..SENTENCIA 190/2018, DE 11 DE SEPTIEMBRE(FALLO): "...acuerdo dejar sin efecto la misma (la resolución administrativa de la Consejería de Sanidad y políticas Sociales...) -y, por ende, las posteriores recaídas- y, en su mérito, acordar el acogimineto familiar de la menor Mª del Rocío B.M. a favor de la abuela paterna Dª Magdalena C.C..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA EUGENIA'and edp.apellido1='MOLANO'and apellido2='CAMBERO'),'2018-09-25','(Pedro)Nuevo intento de hablar con la T. Social, Isabel. NO coge el teléfono. Al parecer, lunes y martes tienen atención al público. Llamar a partir de la 13:00.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='MURILLO'and apellido2='DELGADO'),'2018-09-20','(Pedro)Visita a María en el CSS de Mérida y reunión con Isabel Álvarez y María Barrasa. +++ALTA PREVISTA: 27 DE SEPTIEMBRE.Se encuentra clínicamnet estable y con una gran ilusión por salir del CSS e iniciar una nueva vida. Se le entragan la llaves del piso y móvil enviado a esta Comisión por su madre para entregarlas nosotros. +++DATOS DE CONTACTO: +++++EMPADRONADA EN EL PISO DE ALQUILER: C/. ANTONIO LANCHARRO REYES Nº 16, PLANTA 1, PUERTA 8 EN MONESTERIO. +++++Este piso pertenece, al parecer, a la Obra Social de la Caixa, y lo alquiló la madre sin conocimiento de esta Comisión. +++++TELÉFONO de María MURILLO: 665-064306 +++Por parte de la Comisión Tutelar, se exponen las dudas al respecto por varios motivos, entre otro, la falta de capacidad de supervisión en el día a día en relación a alimentación, adherencia al tratamiento, escasez de recursos económicos, asitencia a Salud mental. +++En la conversación manteenida con María se le hace ver la preocupación d ela Comisión ante el riesgo de recaída, posibilidad que nadie descarta y ante la cual se le comenta que debe solcitar ayuda. +++Sobre todo en los primeros momentos, procuraremos que FUTUEX haga una supervisión de mayor frecuencia para ver cópmo evolcuiona, en coordinación con los SSB y el ESM. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Intento hablar con Ana, T. Soc.de Monesterio, con quien, según María Barrasa me comentó, habían hablado María y su madre en la última salida juntas.NO ME COGEN EL TELÉFONO. +++Hacer seguimeinto y supervisión. +++Registro de razas peligrosas','2');
