insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DEL CARMEN'and edp.apellido1='CASTAÑO'and apellido2='CARDENAS'),'2018-09-25','Iciar. llamo a PNC 924 00 6031, los atrasos que se le han devuelto a M Carmen no son los correctos pues se le ha devuelto lo mismo que a Sandra (1478,10 €) cuando le correspondería 4.058,90 €. Pasan nota al técnico para que lo corrija. El técnico está de vacaciones hasta el día 1 de octubre.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='POBLADOR'and apellido2='FERNANDEZ'),'2018-09-26','-RGTO. ENTRADA AL CAISS MERIDA + DOCUMETNACION PARA SOLICITAR LA P. ORFANDAD. FALTA EL DNI , LO PIDO AL CENTRO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE PEDRO'and edp.apellido1='VILLEGAS'and apellido2='SERRANO'),'2018-09-26','(Pedro)Conversación con Encarna, T. Soc. C.Salud PlasenciaI. +++Solicito Informe Social para valorar posible situación de emergencia y propuesta de recurso a aplicar. +++Llamo a la Dra. Concepción Hernández Moreno, Médico de Familia (74447) de los hermanos Villegas para solcitar Infrome Médico. ESTÁ SALIENTE DE GUARDIA. LLAMAR MAÑANA. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Correo-e de futuex.Aprovecho también para comentarte de la cuidadora de los hermanos Villegas, el lunes no estuvo alli en los horarios que debia, bueno de hecho no fue en todo el dia, porque al parecer estaba en el medico con su padre... Hoy se ha entrevistado con ella la delegada, y tiene una copia del contrato, y algunas facturas q están pendientes de pago, que dice la cuidadora que ya hablo contigo que se las iba a mandar, queda pendiente una de farmacia y alguna otra. Sobre el contrato ella dice que no se ajusta a la realidad porque se lo hicieron mal. En el pone que trabaja de lunes a domingo y son 40 horas semanales que cobra 700 y algo, aunque en realidad dice que a ella le pagan 900 euros. Y que va aproximadamente 4 horas al día lo que serían 20 semanales. Aunque a veces dice que es mas. Dice que lo hicieron rápido y corriendo y por eso está asi, no se porque no lo han cambiado... pero hombre cobrar 900 euros por entre 20-30 horas y que encima tanto Cristiana, como desde el hogar, como Julián se hayan quejado que aveces Pepe no va asesado , nos parece mucho... Tal y como comentastes, es un lío con lo que dicen unos y otros q no veas, con Julián el hermano se lleva fatal por lo que es normal que hable fatal de ella, pero eso de que hayan dicho en hogar de nazaret q a veces a llegado sin asear etc... nos hace sospechar, ella a primera vista parece todo bien, pero creemos que se lo toma con mucha tranquilidad y habrá visto que nadie la controlaba en si hacia o no o llegaba a una hora u otra y se ha aprovechado de eso. Sinceramente serguro que hay profesionales que esa precio están dispuestos a ser más constantes y profesionales, consideramos que se deberia valorar un cambio de cuidadora. +++ALTERNATIVAS: SOLICITARÁN PRESUPUESTO EN VARIAS EMPRESAS DE SERVICIOS DE PLASENCIA para valorar el mantenimineto de los hermanos en domicilio con una atención adecuada en cuanto a aseo personal, limpieza del hogar, alimentación, medicación y traslado al Hogar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CRISTINA'and edp.apellido1='VILLEGAS'and apellido2='SERRANO'),'2018-09-26','(Pedro)Conversación con Encarna, T. Soc. C.Salud PlasenciaI. +++Solicito Informe Social para valorar posible situación de emergencia y propuesta de recurso a aplicar. +++Llamo a la Dra. Concepción Hernández Moreno, Médico de Familia (74447) de los hermanos Villegas para solcitar Infrome Médico. ESTÁ SALIENTE DE GUARDIA. LLAMAR MAÑANA. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Correo-e de futuex.Aprovecho también para comentarte de la cuidadora de los hermanos Villegas, el lunes no estuvo alli en los horarios que debia, bueno de hecho no fue en todo el dia, porque al parecer estaba en el medico con su padre... Hoy se ha entrevistado con ella la delegada, y tiene una copia del contrato, y algunas facturas q están pendientes de pago, que dice la cuidadora que ya hablo contigo que se las iba a mandar, queda pendiente una de farmacia y alguna otra. Sobre el contrato ella dice que no se ajusta a la realidad porque se lo hicieron mal. En el pone que trabaja de lunes a domingo y son 40 horas semanales que cobra 700 y algo, aunque en realidad dice que a ella le pagan 900 euros. Y que va aproximadamente 4 horas al día lo que serían 20 semanales. Aunque a veces dice que es mas. Dice que lo hicieron rápido y corriendo y por eso está asi, no se porque no lo han cambiado... pero hombre cobrar 900 euros por entre 20-30 horas y que encima tanto Cristiana, como desde el hogar, como Julián se hayan quejado que aveces Pepe no va asesado , nos parece mucho... Tal y como comentastes, es un lío con lo que dicen unos y otros q no veas, con Julián el hermano se lleva fatal por lo que es normal que hable fatal de ella, pero eso de que hayan dicho en hogar de nazaret q a veces a llegado sin asear etc... nos hace sospechar, ella a primera vista parece todo bien, pero creemos que se lo toma con mucha tranquilidad y habrá visto que nadie la controlaba en si hacia o no o llegaba a una hora u otra y se ha aprovechado de eso. Sinceramente serguro que hay profesionales que esa precio están dispuestos a ser más constantes y profesionales, consideramos que se deberia valorar un cambio de cuidadora. +++ALTERNATIVAS: SOLICITARÁN PRESUPUESTO EN VARIAS EMPRESAS DE SERVICIOS DE PLASENCIA para valorar el mantenimineto de los hermanos en domicilio con una atención adecuada en cuanto a aseo personal, limpieza del hogar, alimentación, medicación y traslado al Hogar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2018-09-26','(Pedro)Conversación con Encarna, T. Soc. C.Salud PlasenciaI. +++Solicito Informe Social para valorar posible situación de emergencia y propuesta de recurso a aplicar. +++Llamo a la Dra. Concepción Hernández Moreno, Médico de Familia (74447) de los hermanos Villegas para solcitar Infrome Médico. ESTÁ SALIENTE DE GUARDIA. LLAMAR MAÑANA.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2018-09-26','Correo-e de Futuex: Ventura Gómez Las citas con Ventura continúan siendo con una frecuencia semanal, incluso dos veces a la semana si su agenda y la de la delegada lo permite, aunque es difícil debido a todas las actividades en las que participa y a su actitud esquiva en numerosas ocasiones, en las últimas citas se ha insistido en la pertinencia de visitarlo en domicilio con la excusa de poder comprobar que efectivamente se han muerto las cucarachas (tenía una plaga importante que al parecer eran las que habian roto los claves de la placa y por eso no podía cocinar, nosotros nos ocupamos de solicitar la fumigación y esta pendiente ese abono, en cuanto tengamos la factura la pasaremos) y así proceder a realizar la reparación de la vitrocerámica. La última supervisión con Ventura fue el día 21 de sep. fuera del domicilio, como suele ser habitual, en esta ocasión se le vuelve a insistir en que acuda al comprar el menú del catering, hasta que se pueda realizar la reparación (pendiente del procedimiento para exterminar las cucarachas) Mientras está la vitro estropeada se le ha insistido en cada visita que acuda a retirar la comida de algún catering de los que hay disponibles en Cáceres que ofrecen generalmente menús completos por 5,50 € aprox. En algunas ocasiones accede, en otras se le ha acompañado a comprar alimentos saludables en el súper que no necesitan preparación (aprovechando que es verano y apetecen alimentos frescos). No teniamos ni idea que acudia al comedor social. Se desconocía, que estaba acudiendo a un comedor social para comer, puesto que ha evitado dar esta información, es más siempre que se ha intentado indagar sobre este asunto, él ha relatado que estaba comiendo precocinados y recogiendo comida en el catering. Con respecto a la reparación de la Vitrocerámica, la empresa de las cucarachas nos recomendó esperar un tiempo prudencial para proceder a la reparación y dar tiempo a que el producto aplicado haga efecto y mate a todas las cucarachas, se le acompaño la semana pasada a una empresa que ofrece servicio técnico que el conoce, pero estaba cerrada, está planificado con él acudir de nuevo a solicitar presupuesto y fecha para la reparación puesto que se valora urgente. Dicha reparación habría que abonarla porque aunque la vitro está en garantía no cubre avería por plagas de infectos a no ser un defecto de fabricación si no de la propia vivienda.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='AYALA'and apellido2='NUÑEZ'),'2018-09-26','Correo-e de futuex:Francisco Ayala, efectivamente estábamos al tanto de que últimamente se encuentra delicado de salud, la pasada semana estuvo en el hospital, ya que según el no podía orinar, no llegaron a hospitalizarlo, dias atrás se había tomado la pauta mal, puede ser que tuviera que ver con su estado de salud actual, la delegada también constata “que ha dado un bajón físico grande” en estas semanas, ahora anda encorvado porque al parecer se queja de la espalda, hoy ha estado con el, y ha quedado que si sigue así, mañana irá de nuevo al médico. Hoy tenía cita con la psiquiatra, que le han cambiado la medicación, le han bajado y quitado algunas desde el dia que estuvo hospitalizado, ya que al parecer llevaba demasiado tiempo con esa medicación que además de hacer una tolerancia tiene cierta toxicidad. Le deberia funcionar esta pauta, le deberia servir para estabilizarse, pero para eso le ha dado cita de nuevo en noviembre. Lo del control con los pastilleros en la farmacia, pues le ha parecido una fantastica idea, que servira tambie´n para uqe no se equivoque mas en la pauta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='MURILLO'and apellido2='DELGADO'),'2018-09-26','Correo-e de futuex.Maria, Monesterio, no me había llegado a hablar Amalia de este caso, pero no importa, con la información el email, es sufciiente para empezar a trbajar, trazando como plan de actuación visitas en principio semanas para trazar las necesidades que surgan una vez abandone el psiquiatrico, nos pondremos en contacto con los profesionales de su entorno también,. Si le dan el alta el jeuves, pues iremos para principios de la semana que viene,.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE PEDRO'and edp.apellido1='VILLEGAS'and apellido2='SERRANO'),'2018-09-26','Correo-e de futuex.Aprovecho también para comentarte de la cuidadora de los hermanos Villegas, el lunes no estuvo alli en los horarios que debia, bueno de hecho no fue en todo el dia, porque al parecer estaba en el medico con su padre... Hoy se ha entrevistado con ella la delegada, y tiene una copia del contrato, y algunas facturas q están pendientes de pago, que dice la cuidadora que ya hablo contigo que se las iba a mandar, queda pendiente una de farmacia y alguna otra. Sobre el contrato ella dice que no se ajusta a la realidad porque se lo hicieron mal. En el pone que trabaja de lunes a domingo y son 40 horas semanales que cobra 700 y algo, aunque en realidad dice que a ella le pagan 900 euros. Y que va aproximadamente 4 horas al día lo que serían 20 semanales. Aunque a veces dice que es mas. Dice que lo hicieron rápido y corriendo y por eso está asi, no se porque no lo han cambiado... pero hombre cobrar 900 euros por entre 20-30 horas y que encima tanto Cristiana, como desde el hogar, como Julián se hayan quejado que aveces Pepe no va asesado , nos parece mucho... Tal y como comentastes, es un lío con lo que dicen unos y otros q no veas, con Julián el hermano se lleva fatal por lo que es normal que hable fatal de ella, pero eso de que hayan dicho en hogar de nazaret q a veces a llegado sin asear etc... nos hace sospechar, ella a primera vista parece todo bien, pero creemos que se lo toma con mucha tranquilidad y habrá visto que nadie la controlaba en si hacia o no o llegaba a una hora u otra y se ha aprovechado de eso. Sinceramente serguro que hay profesionales que esa precio están dispuestos a ser más constantes y profesionales, consideramos que se deberia valorar un cambio de cuidadora.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='RODRIGUEZ'and apellido2='CACERES'),'2018-09-26','Caty (Aprosuba 3) envía por correo-e reconocimiento de Grado II y solcvitud de Complemento de tercera persona. +++Se pon e a la firma para su envío a PNC.','2');
