insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='YOLANDA'and edp.apellido1='CALDERA'and apellido2='MARTIN'),'2018-09-27','(Pedro)Conversación con Maribel, Directora Aprosuba 9 (VVA. de la Serena). 924-840900. +++El centro no está preaparado para garantizar la seguridad de Yolanda ante sus continuas ingestas de gel, etc. +++Desde enero intentando ingreso en UDAC(ver incidencia del 23 de enero 2018). +++Actualmente ingresa en UHB desde hace alrededor de 15 días (la Comisión lo desconocía): su Psqiquiatra, Mª Antonia, dice que allí no puede estar porque no tienen los recursos necesarios, a pesar de estar con contención mecánica y vigilancia intensiva. Desde la UHB ya hjan hecho, al parecer, gestiones de cara a un ingreso en UDAC. +++Maribel considera que Yolanda ya se ha hecho resistente a cxualquier tipo de tratamiento. +++Han hablado también con Manuela (planteando derivación a CAMP Don Benito)y con la coordinadora del Área de Salud de Mérida. +++ENVIARÁN INFORME A LA COMSIIÓN TUTELAR y se remitirá posteriormente a gerencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='ROLLAN'and apellido2='SUAREZ'),'2018-09-27','(Pedro)Visita programada de Cristopher. Motivo: extra de 150€ para ropa. +++SE LE AUTORIZA. +++Comenta que hace unos días su expareja le denunció por supuetsas amenazas que él niega y que pasó unas hora en los calabozos. Fue interrogado por el Juez y puesto en libertad sin medida alguna hasta que saliera el juicio. +++++Responde que indicó que estaba tutelado por la Comisión, pero que la Policía no tuvo este hecho en consieración. +++++Le pido que nos traiga el docuemnto de su declaración y cuando sea citado que nos traiga la citación por si el juzgado no nos la comunica a nosotros.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA EUGENIA'and edp.apellido1='MOLANO'and apellido2='CAMBERO'),'2018-09-27','(Pedro) Programo visita a Dª Eugenia para el próximo 01 de octubre a las 10:30h en Arroyo de la Luz. +++Asisteremos Soraya (Jefa de Unidad), Virginia (Delegada de Futuex), Isabel (T. Soc. SSB) y yo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TERESA'and edp.apellido1='MANGAS'and apellido2='DE LA CRUZ'),'2018-09-28','-PONGO PIA A FIRMA Y RGTO ENTRADA A DEPEND PLASENCIA. A.D.: Buenos días, soy Cristina Carrón, to. del equipo de valoración de la zona sociosanitaria de Coria. Os hago llegar un PIA correspondiente a TERESA MANGAS DE LA CRUZ, para que sea firmado por la comisión. Se trata de un mantenimiento de plaza, ya que se encuentra ya ocupando una plaza pública de atención residencial en la Residencia de mayores de Torre de Don Miguel.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2018-09-28','(Belén)Llama Enrique, Unidad de Familia (UFAM) de la Policía Nacional de Cáceres (927-626520/4), preguntando por si José Manuel está ingresado en el CSS de Plasencia para cumplir la medida de seguridad impuesta por el Juzgado nº 6 de Cáceres. +++NO TENEMOS CONSTANCIA DE ELLO. Ángel llama a Verónica, Abogada, pero tampoco lo sabe. +++(Pedro) Llamo al CSS de Plasencia (no puedo hablar con T. Sociales, ni con Dirección. Hablo con Adela (Administración) y me confirma que José Manuel está ingresado desde hace aproximadamente una semana. +++++Pido que nos envíen por fax informe de dicho ingreso. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++(Pedro)Hablo con Enrique, de la UFAM, y le informo del ingreso de José Manuel. Quedo en enviarle el informe de ingreso una vez nos llegue a nosotros.LO ENVÍO AL CORREO-E SIGUIENTE: caceres.ufam@policia.es','2');
