insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='ROLLAN'and apellido2='SUAREZ'),'2018-09-28','(Pedro) Crisdtopher trae Auto del Juzgado de 1ª Instancia e Instrucción nº 4 de Mérida: +++++ Pieza de Situación Personal 0000343/2018 0001, de 25 de junio: Libertad provisional a la espera de juicio. +++++Auto Pieza de Situación Personal Orden de Protección 0000037. Se establece orden de protección y prohibición de acercarse a su ex-pareja Sara a distancia mínima de 500m y de comunicación con ella y al hermano de ésta Jesús y a su padrastaro Antonio a distancia mínima de 200m y de comunicación). +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Juan Carlos (Seguridad) le ha dado la dirección y teléfono de la empresa "Granja Cantos Blancos" (924-677432), de Almendralejo, para un posible trabajo en ella.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='FAUS'and apellido2='LEMUS'),'2018-09-27','-SE RECIBE EN EL SEPAD BADAJOZ LA VISITA DE RAFAEL Y SU TIA ASUNCION ( 620436620) . VIENEN DEL CEDEX , QUIERN UNA PLAZA EN COMUNIDAD TERAPEUTICA URGENTE.EL ASPECTO FISICO DE RAFAEL ES MUY MALO , HA PERDIDO MUCHISIMOS KL. ESTÁ MUY DESMEJORADO Y CON UN BRAZO ESCAYOLADO . EL FIN DE SEMANA ESTUVO IMPLICADO EN UAN RELLERTA EN EL GURUGÚ , LE DIERON CON UNA CATANA POR UN AJUSTE DE CUENTAS, ME DICE QUE DE DEBE A UN PRESTAMISTA UNOS 1200€ . HA PERDIDO DOS DEDOS DE LA MANO Y NO HAN PODIDO OPERARLE PQ NO HAN PODIDO ADMINISTRAR LA ANESTESIA QUE NECESITABA POR LA CANTIDAD DE DROGA EN SANGRE. UN SOBRINO ,HIJO DE SU HNA. ANTONIA , DE 22 AÑOS SALIÓ A DEFENDERLE Y ESTÁ EN CTRO. PENITENCIARIO . ANIMICAMENTE DESTROZADO , LLORA DURANTE LA ENTREVISTA , SE SIENTE CULPABLE DE LA SITUACIÓN DE SU SOBRINO Y DE CÓMO ESTÁ HACIENDO SUFRIR A SU TIA . ÉSTA ME CUENTA QUE HACE UNOS MESES LES TIROTEARON LA VIVIENDA DE OTRO DE LOS SOBRINOS , POR AJUSTE DE CUENTAS. ME DICE QUE SE ABRIÓ UNA CUENTA EN SANTANDER POR SU CUENTA Y ES DONDE PERCIBIA EL SUBSIDIO DE EXCARCELACION Y ES DE DONDE HA ESTADO PAGANDO LA DROGA. AL ACABARSE EL MISMO , HA ROBADO... PARA CONSEGUIR EL DINERO. JURIDICAMENTE DEBE TENER VARIAS COSAS PENDIENTES, ME DICE QUE ACUDE LOS DIAS 1 Y 15 DE CADA MES AL JDO. DE BADAJOZ PARA FIRMAR , POR UN ROBO DENTRO DE UNA CASA CON UN MENOR A UNA SEÑORA. ME TRAEN UNOS DOCUMENTOS DE HACIENDA , SE LES PIDE QUE ABONE 601€ POR UNA MULTA IMPUESTA POR HABERLE COGIDO CON 1,28 GRAMOS DE DROGA . SI NO SE ABONA PROCEDERÁN AL EMBARGO DE SUS BIENES. ME DICEN QUE AYER ESTABA CITADO PARA OTRO JUICIO PERO NO SE PRESENTÓ PQ ESTABA HOSPITALIZADO PERO QUE NO LO HA COMUNICADO. HOY TIENE CITA EN LA COMISARIA DE BADAJOZ, EN EL GRUPO 4 ( RAUL ) PERO NO TIENE INTENCIÓN DE IR. ACUDO A CEDEX A INFORMAME SOBRE LA SITUACIÓN DE RAFAEL PARA PLANTEAR LA NECESIDAD DE SACARLO DEL DOMICILIO Y QUE INICIE TTO. DE DESINTOXICACIÓN , DADA LA VOLUNTARIEDAD QUE MUESTR. ME REUNO CON LA TS ( CARMEN MATA 924215368) Y CON EL MÉDICO . ÉSTE ME DICE QUE HAN ACUDIDO SIN CITA Y ME DA UNA NUEVA PARA ÉL EL 31 DE OCTUBRE , SI MANTIENE SU VOLUNTARIEDAD VALORARÁ EL INGRESO EN C. TERAPEUTICA . CON LA PSICOLOGA 20 DE DICIEMBRE Y NINGUNA CON LA TS, HACE ENTREVISTA SI SE LA DERIVA EL MEDICO . A LA ÚLTIMA QUE LE DIÓ HACE MESES RAFA NO ACUDIÓ. DADO QUE POR VIA CONVENCIONAL NO VAMOS A CONSEGUIR PLAZA PROCEDO A LA BUSCA DE RECURSO DE DROGODEPENDENCIA , CONCERTADO O PRIVADO. ME PONGO EN CONTACTO CON LA ASOCIACION SAGUARO 648146322.VAN A VALORAR EL CASO , ME PEDIRÁN INFORMACION VIA EMAIL.','2');
