insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PURIFICACION'and edp.apellido1='GALLARDO'and apellido2='LOPEZ'),'2018-10-04','El 9 de octubre acudimos a la Notaría de Carlos Mateos y Timoteo Díez, en Badajoz, para la firma de la Declaración de Herederos de su hermano, José Gallardo López. Envío documentación por correo electrónico al oficial, José Luis Nogales.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='MONTERO'and apellido2='VAZQUEZ'),'2018-10-05','-LA DRTRA. INFORMA DE UN NUEVO EPISODIO DE FUGA EN LA VIVIENDA TUTELADA AYER POR LA TARDE. LO HAN TRASLADO AL HOSPITAL I.CRISTINA EN BJOZ. Y VA A SER INGRESADO . TIENE DINERO AHORRADO ( 12000) POR SI SE NECESITA CONTRATAR PERSONAL EN EL HOSPITAL , SE LE COMUNICA A LA ENTIDAD. QUIEREN QUE SE LE BUSQUE OTRO PLAZA EN RESIDENCIA, SE LES INFORMA QUE ESO CORRESPONDE A LA UNIDAD DE DISCAPACIDAD Y QUE SU PERFIL ES DE RAL Y NO DE RAE.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADRIAN'and edp.apellido1='ORTIGOSA'and apellido2='FUENTES'),'2018-09-25','-ACUDE AL CADEX A VALORACION DE PERFIL CON DELEGADA TUTELAR .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VICENTE'and edp.apellido1='ROJO'and apellido2='CARRASCO'),'2018-10-03','(Visita al CRR de Amalia y Pedro). +++Desde junio de 2017 que entró en piso supervisado ha ido deteriorándose, hasta volver al CRR en junio de 2018: "Todo parace darle igual..." +++Con controles en CEDEX (negativos) y tto. con Antabux. Él niega consumo, pero creen que sí consume algún porro y alcohol). +++Muy apático. Ya no acude a los talleres de Sorapan. +++En septimebre ha pasado una seman con su hermana Olga (vive en Galicia). Vuelve con el mismo aspecto apático, como si no se hubiera ido. Su hermana está preocupada por ese estado anímico que muestra. +++SE relaciona sobre todo con Juan José B. +++Valorar posible revisión de Cadex y/o traslado. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Entrevista con Vicente. +++Se aprecia la apatía mencionada y solamente pide que se le aumente la asignación diaria que tiene (1.20€).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='BERGANTIÑO'and apellido2='GONZALEZ'),'2018-10-03','(Visita al CRR de Amalia y Pedro).Entrevista con las compañeras y con Juan José. +++Desde la 10h está en la calle. +++Pendiente de cobrar los 40€ "prometidos" por su participación en los talleres de jardinería: Ya ha cobrado los del mes de octubre. Cobrará también noviembre y diciembre (el taller duró tres meses) con la condición de que presente los justificantes de gastro del dinero ya cobrado. Todo ello al margen de los 120+80€/semanales. +++Quiere marcharse a Cáceres, a un psio de alquiler. Se le explica que ya está solcitado traslado al CRR de Cáceres y que el alquiler puede llegar a ser un paso posterior si gana en autonomía. +++Dice llevar mucho tiempo en Badajoz y estar cansado. Negociamos con él la posibilidad de salidas periódicas con su familia en Cáceres (máx. una semana) con la posibilidad de aportar algo de dienero a la familia en esas salidas (20/30€). +++MONTAÑA (hermana: 927-280080) y Brígida (madre: 625-547542).Tenemos que saber si la familia estaría de acuerdo con ello. +++CEDEX: su Psiaquiatra no ha considerado oportuna la derivación hasta ahora. +++NO TIENE CONCIENCIA DE SU ESTADO DE SALUD, NO SE CUIDA EN ABSOLUTO: ha puesto peso y creen que come fuera del centro. +++SE relaciona sobre todo con Vicente R.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2018-10-05','(Pedro)Converscaión con Urbano (Infancia y familia). +++Los jurídicos tieenen la intención de recurrir la sentencia. Tienen de plazo hasta el 11 de octubre. +++La niña sigue con la familia de acogida ("que es estupenda..."). +++Seguirá informando a la Comisión. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con Mª Ángeles, Psicóloga de Plena Inclusión Llerena (924-870293). +++Le informo de la situación de Rocío.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2018-10-04','(Pedro).+++CONVERSACIÓN con Mª Ángeles (Psicóloga Plena Inclusión Llerena) +++Betariz no se quiere poner el inyectable (anticonceptivo) y sigue con deseos de tener otro bebé. +++Además, al parecer, ha inciado una relación con otro de nuestros tutelados, José Mª S. Al parecer, la relación la busca más él que a la inversa, por lo que se sospecha que pueda ser una relación muy desequilibrada. +++El deseo de maternidad de Betariz, unido a no querer ponerse el inyectable (cosa que no va a ocurrir) y la psoibilidad de una relación de pareja son indicadores de riesgo ante un nuevo y posible embarazo. +++++Solicito que elaboren un Informe con la valoración de la situación por parte del Centro, con las alternativas que consideren oportunas y nos lo envíen a la Comisión, por si fuera necesraio solictar al Juzgado autorización para un cambio de método anticonceptivo. +++OTRO TEMA: tenían previsto que Beatriz se marchase desde mañana, 05 de octubre hasta el 13 de octubre, con su padre. Dada la situación de La niña, la sentencia en la que le dan la custodia a la abuela (que no es firme) y que ello puede llegar a oídos de Beatriz si acude a casa de us padre, la Comisión considera que no es el momento oportuno para dicha salida y Mª Ángeles está de acuerdo con ello, por lo que se aplazará. Una visita en estos momentos podría suponer una desetabilización de Beatriz.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='MONTERO'and apellido2='VAZQUEZ'),'2018-10-04','(Pedro) Además, Irene comenta que desde nuestra visita la relación de Joaquín respecto de Cristofer ha mejorado, pero no a la inversa. +++En esta ocasión estaba fuera de sí, agrediendo a la G.Civil y Policía Local. +++NO quiere cambiar de vivienda. "Yo creo que el recurso en el que se encuentra le viene grande y quizá necesitase un cambio de perfil.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='CASQUERO'and apellido2='JAEN'),'2018-10-03','(Visita de Amalia y Pedro). +++PREOCUPACIONES DE ANTONIA: +++++¿Cuánto le queda de pagar de hipoteca? ¿Y cuanto tiempo?. +++++Le informamos de que en este momneto su situación económica es estable. +++Habla de su familia, queriendo estar más cerca de ella pero, a la vez, reconociemdo que no merece la pena porque ha tenido muchos problemas con todos ellos.Habla de Tamara, hija de su hermano Ángel, que es la que le suele llamar (tiene 21 años y discapacidad intelectual y física); de Margarita, su hermana que vive en Puebla de Obando; de su hermano Paco, que vive en Madrid, y que es el único que la ha ido a ver en una ocasión; de su padre (93 años) que vive con su segunda mujer, Mª Jesús (72años). +++POSIBILIDAD DE TRASLADO A CENTRO DE MAYORES: +++++Reconoce que ella necsita atención por lo que su idea de marchrase a un piso reconoce que en estos momentos es impenmsable. Inicialmente parecía aceptar esta posibilidad (Centro de Mayores), pero de una forma que fuese algo que los demás queríaqn hacer con ella y en lo que ella no podía opinar. Se le hace ver que tiene que ser ella la que opine al respecto y que se tome un tiempo para pensarlo. +++Animícamente se la ve muy decaída: NO ACEPTA SU SITUACIÓN ACTUAL DE DEPENDENCIA, cuando ella ha sido siempre una mujer que se ha valido por sí misma, ha tenido su cas, su trabajo y le está costando asimilar un cambio tan brusco en su vida. +++Quiere un móvil. Lo hablará con María y pedirá presupuesto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AQUILINO'and edp.apellido1='CAMACHO'and apellido2='ROMERO'),'2018-10-03','(Visita al CRR de Amalia y Pedro). +++SIgue con la idea de irse al CRR de Mérida con su "Isa". Es su pricipal petición. Se le dice que puede ir a verla de visita, para volver al CRR por la tartde como hacía antes. +++Al parecer hace meses que no se ven porque ambos están con problemas físicos: Aquilino tiene apnea del sueño y está en tratamiento por ello. +++SE queja de que le han reducido drásticamente la asignación, pero ha sido porque fumaba mucho. Además le han reajustado la medicación.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SEVERIANO'and edp.apellido1='TARANGO'and apellido2='DOMINGO'),'2018-10-03','(Visita al CRR de Amalia y Pedro). +++Respecto del terreno que quería para hacers euna casa y montar un huerto se informa de que no es posible, porque no hay terrenos próximos para ello. +++Comentan las compañeras que, si bien es muy colaborador y voluntarioso con los compañeros del piso, también es muy susceptible cuando se le cambia su rutina, lo que le provoca serios enfados.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANDREA'and edp.apellido1='DAZA'and apellido2='REGALADO'),'2018-10-03','(Visita al CRR de Amalia y Pedro). +++Ha tenido dos ingresos en UHB (junio y agosto). En opinión de las compañeras, poco tiempo para el que ella necesitaría. +++Se encuentra en un estado regresivo, se orina, etc. Ante determinadas circusntancias, su Psiquiatra determina su ingreso. +++Una hermana suya ha acudido a verla un día. +++Económicamente va a necesitar seguramente algo más de dinero para el tema de pañales, ropa, etc. +++HIJOS: "eS UNA FAMILIA COMPLICADA... Les cuesta seguir la indiccaciones del CRR porque Andrea los manipula , especialmente a su hija, más que a su hijo). Andrea es muy demandante. +++','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VICENTE'and edp.apellido1='MARQUEZ'and apellido2='CABEZA'),'2018-10-03','(Visita al CRR de Amalia y Pedro). +++La relación con él en el centro es muy buena. Es muy educado. Va a ver a su madre. +++Dice que con los 500€/mes no le llega. LO valorarán. +++Quiere ponerse euna dentadura fija.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SONIA'and edp.apellido1='VALCARCEL'and apellido2='VIDAL'),'2018-10-03','(Visita al CRR de Amalia y Pedro). +++Nada más entrar nos agradece todo lo que hacemos por ella. +++Quire que le suban la asignación diaria de 2 a 5 €. +++Acude a AEMIS.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='QUIROS'and apellido2='SAUCEDA'),'2018-10-05','(Pedro)Conversación con Victoria, T. Soc. H. Don Benito-Villanueva (924-386800). +++Prever, según el estado de salud y requirimiento de cuidados de D. José tras su opoeración, la posibilidad de que se le solicite plaza sociosanitaria. +++En función de los informes médicos y de que requiera mayores cuidados sanitarios, se valorará dicha opción.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2018-10-05','Correo-e de COCEMFE: +++He intentado hablar contigo esta semana para informarte que Tomás el lunes salió del centro sin permiso y se fue a casa de José Mª Tovar. Te lo informo por si Chema llama a la Junta para notificar esto. Si puedes me llamas y hablamos. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++(Pedro) Conversación con Julián (ver apuntes)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='MONTERO'and apellido2='VAZQUEZ'),'2018-10-08','-SIGUE INGRESADO EN LA UHB . LA DTA. QUIERE QUE SIGA EN MONTIJO HASTA VER SU EVOLUCION. DESDE EL CENTRO DONDE ESTÁ SU HNO . DE LA CRUZ BCA. QUIEREN VER LA OPCION DE QUE LOS HNOS. ESTEN JUNTOS.','2');
