insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='CACHO'and apellido2='GARCIA'),'2016-03-02','Hemos solicitado internamiento involuntario en centro (sociosanitario), ante su inminente excarcelación el 14/3/2016.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='CACHO'and apellido2='GARCIA'),'2018-10-11','(Pedro) Me comunica Mª José que se ha puesto en contacto con nosotros Blanca, T. Soc. del C. Penitenciario de Zaragoza (976-698426): +++D. Rafael se encuentra en estos monentos interno en la PRISIÓN de ZARAGOZA. +++FECHA DE EXCARCELACIÓN: ¿10 DE JUNIO DE 2019? +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Intento ponerme en contacto con el C. penitenmciario pero no lo consigo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARLOS ALBERTO'and edp.apellido1='VICENTE'and apellido2='CALDERERO'),'2018-10-15','-PLACEAT 927421950 , PREGUNTA POR LA DOCUMENTACION QUE ENVIARON, SE LE INFORMA QUE SE PUSO EN FIRMA , Y HABRÁ SALIDO EN CORREO . SE LE INFORMA QUE YA DÍ DE BAJA A LA PLAZA DE RAE , ELLOS TODAVIA NO LO HAN HECHO .','2');
