insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SAUL'and edp.apellido1='RODRIGUEZ'and apellido2='RAMOS'),'2018-10-17','(Pedro)Llamada de Julia,Directora de Includes Almendralejo (696-498420) desde el Hospital de Mérida. +++INGRESO EN INCLUDES ALMENDRALEJO: LUNES, 15 DE OCTUBRE DE 2018. +++Ingresó ayer sobre las 21h en el Hospital de Mérida por vómitos. Tiene hemorragia interna al parecer y necesitan el Consentimiento Informado para hacerle endoscopia digestiva. Reenvío el Consentimiento firmado vía Fax.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='CACHO'and apellido2='GARCIA'),'2018-10-15','(Pedro)Llamo al C. Pentenciario de Zaragoza. Blanca (T. Soc.) no ha acudido hoy a trabajar. +++Hablo con Orlinda, T. Soc: no lleva el caso y considera que es mejor que hable con Blanca que es quine lo conoce. +++Me comenta que está clasificado como 2ºgrado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CACHO'and apellido2='GARRIDO'),'2018-10-11','(Pedro)Llamada de Ana Pérez, Psiquiatra del CSS de Plasencia que atiende a D. Francisco. +++Llamaba porque D. Francisco carece de recursos económicos y se encuentra sin ropa. Pregunta si la Comisión tiene alguna partida presupuestaria para este tipo de contingencias, porque en estos moemtos no puede salir a la calle porque no tiene ropa ni calzado adecuado para la lluvia. +++Le informo de que los únicos recursos económicos con los que cuenta la Comisión son los propios de las personas tuteladas. +++Le propongo dirigirse a Cáritas para ver si ellos le podrían facilitar algo de ropa.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE PEDRO'and edp.apellido1='VILLEGAS'and apellido2='SERRANO'),'2018-10-11','(Pedro)Recibimos un correo de Futuex en el que se informa a la CTAEx de que Charo (Aux.de Hogar) se niega a atender a los hermanos este fin de semana (Fiesta del Pilar) si no se le paga lo que se le debe. +++Hablo con Charo y le digo que no siga atendiendo a los hermanos, porque vamos a contratar a una Empresa de Servicios. +++Hablo con Futuex para que hablen con la empresa que consideren más adecuada de entre aquellas con las que han contactado. Se realiza la contratación de la empresa "La Perla Del valle". +++INCIALMENTE y para cubrir este fin de semana, se les contrata hasta el jueves que viene, para así poder cxubrir este fin de semana y tener tiempo para valorar su continuidad y, en su caso, la ampliación del servicio.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE PEDRO'and edp.apellido1='VILLEGAS'and apellido2='SERRANO'),'2018-10-15','(Pedro)LLamo a EVA DOMÍNGUEZ, ENCARGADA de la Empresa "La Perla del Valle" (637-134807). +++JUANI (AUXILIAR DE HOGAR) le ha comentado que estos días ha "encajado" bien en la atención a los dos hermanos. El Jueves, llegó a las 14:15 a su domicilio y Cristina no estaba. La esperó y llegó a los pocos minutos. +++Pido a Eva que nos envíe un presupuesto para valorar la continuidad del servicio. +++Comenta que los periodos vacacionales y los domingos se cobra algo más por el Servicio. Le ruego que todo ello lo haga contar en el presupuesto. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Llamo a Puerto, Directora del Hogar de Nazaret, para saber su opinión sobre el estado en que José Pedro ha llegado estos días atrás al centro. +++Comenta que ha faltado algunos días y que cuando ha llegado iba en malas condiciones higiénicas. Le indico que desde el jueves hemos contratado una empresa de servicios: "Pues de estos últimos días no he hablado con Raque, la encargada del centro de Día que atiende a José Pedro."LE PIDO QUE HABLE CON ELLA Y ME INFORME. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++CORREO-e de Puerto: Me comenta Raquel, la encargada del Centro de Día, que el viernes, sábado y hoy, José Pedro ha venido puntual para el desayuno, Aseado y limpia la ropa. y contento. Sin ningún problema. Él le comentó que ya no iba Charo y era otra cuidadora. Parece que funcionan bien. Estaremos pendiente mañana y pasado. Un saludo, Puerto González Campo. Gerente. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++HORARIO DE D. JOSÉ PEDRO EN EL "HOGAR DE NAZARET": de 8:00 a 20:00h. DESAYUNA, COME y CENA EN EL HOGAR.','2');
