insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PETRA'and edp.apellido1='COSTA'and apellido2='RODRIGUEZ'),'2018-10-15','-HABLO CON PILAR BUENO , LA SEÑORA ESTÁ INGRESADA HACE MESES EN LARGA ESTANCIA. ESTABA EXENTA DEL PAGO PORQUE VIVIA CON SUS HIJOS. PILAR VA A COMUNICAR SI HAY QUE PAGAR Y CUANTO Y ESTABLECERÁ UN PTO. DE GASTOS.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MUÑOZ'and apellido2='MELCHOR'),'2018-10-15','(Pedro) Llanada de Mª Ángeles, hermana de Mª Isabel. +++Quiere saber cómo va el tema de asumir la tutela por su parte.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SAMUEL'and edp.apellido1='BARRADO'and apellido2='SANCHEZ'),'2018-10-16','(Pedro)Conversación con Adela (924-005995) sobre expediente de PNC nº 0425/I/2016. +++SE explica la situación: revocada la incapacidad. +++Se Envía dicha información por correo-e (adela.molina@salud-juntaex.es) y por correo ordinario con registro de salida de hoy, a las 10:12:52h y nº 2018278050005215','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SAMUEL'and edp.apellido1='BARRADO'and apellido2='SANCHEZ'),'2018-09-28','(Pedro)Hablo con Soraya sobre la situación surgida en relación a la recuperación de la capacidad por revocación de la incapacitación por parte de la Audiencia Provincial de Cáceres).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='BERNARDO'and apellido2='PIRIS'),'2018-10-16','Llama Dª Antonia solictando que pongamos una denuncia en su nombre por no estar de acuerdo con el diagnóstico que ha tenido por parte del forense. Estamos a la espera de que el juzgao nos indique si la sentencia es firma para poder aceptar el cargo o bien se ha recurrido la misma.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='CACHO'and apellido2='GARCIA'),'2018-10-16','(Pedro)Conversación con Blanca, T. Soc. del Centro Penitenciario de Zuera (Zaragoza). +++INGRESO EN C. PENITENCIARIO de BADAJOZ: 11 de JUNIO de 2018. +++++MOTIVO: ATENTADO CONTRA LA AUTORIDAD. 12 MESES DE CONDENA. +++++FECHA de EXCARCELACIÓN: 10 de JUNIO de 2019. +++INGRESO en el CENTRO PENITENCIARIO de ZUERA (ZARAGOZA): 18 de SEPTIEMBRE de 2018. +++++Solicitó el traslado por vinculación familiar con unas primas que dice tener en Gerona. +++++Su única petición cuando ingreso en Zuera fue que AL SALIR LE DIERAN UN BILLETE PARA IRSE A GERONA, AL "ALBERGUE de LA SOPA". +++++Durante el ingreso manifestó que era consumidor de alcohol (3 botellas de cerveza al día...no se sabe de qué cantidad). +++++Mencionó a su cuñada, Vanesa Morgado, con la que parece tener cierta confianza y les dió su número de teléfono: 659-272386.NO HARECIBIDO LLAMADAS NI VISITAS NI EN BADAJOZ NI EN ZUERA. +++DNI: se lo han renovado. Nos enviarán copia del mismo por correo-e junto con otra documentación: auto de prisión, cumplimineto de condena,etc. +++VISIÓN PROFESIONAL: Blanca cree que D. Rafael no quiere depender de nadie, que sabe cómo "buscarse la vida" y que es probable que durante su estancia en prisión tenga algún altercado que le lleve a la apertura de nuevos procediemientos. +++++Como nos dijo a Amalia y a mí en la visita que realizamos en el C.P. de Badajoz, no quiere pasar reconocimeinto de Cadex porque cree que si lo declaran incapacitado no va a poder encontrar trabajo en ningún sitio. +++UNA VEZ QUE BLANCA NOS ENVÍE LA DOCUMENTACIÓN, COMUNICAR AL JUZGADO DE 1ª INSTANCIA Nº 4 DE BADAJOZ LA LOCALIZACIÓN DE D. RAFAEL.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE PEDRO'and edp.apellido1='VILLEGAS'and apellido2='SERRANO'),'2018-10-17','(Pedro)Llamada de Julián (675-695571), hermano de José Pedro y Cristina. +++EStá muy contento con "...la chica que habéis puesto..." +++Manifiesta que tiene una deuda pendiente de una nave que alquiló y a la que debe tres mensualidades: "...el dueño ya me ha denunciado por no pagar. Y yo no puedo porque he metido mucho dinero en cuidar de mis hermanos y es que tengo que pagar esa deuda ya...". Creo que este es el interés real de esta llamada. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Llamo a Eva, de la empresa "La Perla del Valle", para que continuen con la atención a los hermanos y nos envíen el contrato para su firma, con la posibilidad de ampliar el número de horas de atención. Lo enviará mañana.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARGARITA SAGRARIO'and edp.apellido1='GARCIA'and apellido2='PECES'),'2018-10-17','(Pedro)Llamada de Pilar (Piso Supervisado de Proines)(924-805077). +++Margarita está preocupada porque, tras el fallecimiento de su madre el pasado junio, y haberle solcitado documentación (¿Pensión Orfandad?), no ha vuelto a saber nada. +++Margarita se encuentra cada vez más nerviosa y delirante, hasta el punto que se están planteando solicitar al ESM (Alberto es su Psiquiatra) su derivación a CRR. +++LLamar el próximo viernes.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MERCEDES'and edp.apellido1='PEREZ'and apellido2='PINNA'),'2018-10-17','(Pedro)Llama Pedro Bello, abogado del bufette de Granada (660-722009), donde también se encuentra Elena, la abogada que Merecedes dice ser amiga suya. +++Dice que les ha llegado la documentación que ella les envió y que lo que van a hacer con ella es remitirla a Hacienda para que desde alli nos la comuniquen a nosotros como cuaradores.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SAUL'and edp.apellido1='RODRIGUEZ'and apellido2='RAMOS'),'2018-10-18','(Pedro) Conversación con Julia. +++Saul permanece ingresado en el Hospital de Mérida. +++Endoscopia: detectó variós cólico y úlceras que provocaron una pérdida de sangre relativamente importante. +++Acompañamiento hospitalario: se le explica las circunstancias del mismo (le enviaremos carta). De momento se está quedando la familia con él.','2');
