insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DOLORES'and edp.apellido1='FERNANDEZ'and apellido2='BAEZ'),'2018-10-18','(Pedro)Visita programada de Dª Mª Dolores.Peticiones: +++Quiere marcharse a su casa, porque todavía es joven para una residencia. Cuando sea más mayor sí está dispuesta a irse. +++Quiere una mayor asignación diaria: actualemnte son 5€/día y querría que fueran 7 u 8€. +++Quiere marcharse un mes a su casa y administrar sus dinero. Le digo que parece mucho tiempo, pero que hablaré de ello para ver si cabe la posibilidad de estar un par de días seguidos. +++Quiere dinero para comprarse ropa y calzado. Lo hablaré también con el CRR.','2');
