insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONCEPCION'and edp.apellido1='ALEJANDRO'and apellido2='DIAZ'),'2018-10-19','(Pedro)Conversación con Mar, T. Soc. del ESM de Ciudad Jardín (41522) +++Confirma que Concepción está acuediendo al ESM. +++++PRÓXIMA CITA CON PSIQUIATRA (Dra.RÍOS): 15 NOVIEMBRE 2018 +++++PRÓXIMA CITA CON ENEFERMERÍA: ¿día? ENERO +++Desde que dejó el CRR ha estado en urgencias en numerosas ocasiones. +++MAR la citará para hablar con ella antes de que acuda al Psiquiatra.','2');
