insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SAMUEL'and edp.apellido1='BARRADO'and apellido2='SANCHEZ'),'2018-10-22','(Pedro)Conversación con Ana Álvarez, Asesora Jurídica de PNC (924-005991). +++Quería saber si el dinero de la pensión lo estaba utilizando la Comisión o bien era Samuel el que disponía de él, a los efectos de reclamar las cantidades indebidamente percibidas. +++Se le informa de que, según su última rendición de cuentas, esta persona no cuenta con ningún otro tipo de ingreso que esta Comisón conozca.','2');
