insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='BRUNO'and apellido2='SAAVEDRA'),'2018-10-23','-SE ENVIA POR CORREO ORDINARIO AL CENTRO EL CONTRATO DE ADMISION.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CRISTINA'and edp.apellido1='VILLEGAS'and apellido2='SERRANO'),'2018-10-22','(Pedro)De Eva, de la "Perla del Valle", nos informa por correo-e (21-10-2018) de que este sábado Julián ha llevado a su hermana al Hospital San pedro de Alcántara porque le ha notado un bulto en el vientre. +++Futuex: le hemos pedido que se acerquen al Hospital para conocer cuál es la situación.Nos informarán. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con Julián, hermano de Cristina. Comenta que le notó un bulto en el vientre y la llevó al Hospital. +++DIAGNÓSTICO: Tumor en riñón (que ha provocado una "masa abultada" que se podía coger con la mano abierta) con posible metástasis en el pulmón. Requiere ingreso e intervención para extirpar el riñón y administrar quimioterapia. +++INGRESO: en la sexta planta del Hospital. No sabe el nombre del Especialista que lo atiende. +++Llamar a Futuex y Hospital para confirmar diagnóstico y situación. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con Puerto, Directora del Hogar de Nazaret (927-416563). +++Plantaemos la posibilidad de que José Pedro, dadas las cirncunstancias, la premura de tiempo, la inmediatez de lo ocurrido y la imposibilidad de que José Pedro pueda quedarse solo en casa, pueda permanecer en el Hogar durante unos días hasta que le encontremos una solución a su situación. Aunque inicialmenmte no se considera viable, finalmente acceden a tenerlo allí durate dos o tres días. +++++Dado que se trata de una curatela, se le consulta a JoséPedro esta alternativa y, según comenta la Direcytora, no pone ningunba objección a ello. +++++Se quedará en la enfermería, donde hay una cama libre enb estos momentos. +++Dada la situación y la posibilidad de que finalmente requiera un plaza ressidencial, se plantea la posibiloidad de uqe sea en el propio hogar donde se pueda quedar tanto él como, llegado el caso, su hermana. En estos moemntos no hay plazas libres, pero ruego que si surgen nos lo comuniquen para tenerlo en cuenta. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Nueva conversación con Julián. +++Le informo que durante dos o tres días su hermano se va a quedar en el Hogar de Nazaret: "Me parece muy buena idea, porque así puedo estar pendiente de mi hermana sabiendo que él se encuentra atendido. Muchas gracias". Conversación con Eva, "La Perla del Valle". +++Le pido que sigan durante estos días con las tareas en la vivienda, aprovecxhando que no están ambos hermanos para poner orden y limpieza en la misma. Las cinco horas que hemos contratado, en estos momentos, no es preciso que las dividan en mañana (3) y tarde (2). Si lo consideran pueden hacerlas por la mañana. +++++Hablo con Julián para que esté en la vivienda a la hora que llegue la Auxiliar. No pone objección alguna. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ +++Llamo a D. José María,TAXISTA (616-012147), para decirle que en estos días no vaya a buscar a D. José Pedro dadas las circunstancias y hasta nuevo aviso. +++++DE acuerdo con la parte económica, se le pide que nos envíe una factura única con lo que se le debe a fecha 31 de octubre.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUISA'and edp.apellido1='REY'and apellido2='CAMPON'),'2018-10-23','-SE HA ENVIADO DOCUMENTACION SOLICITADA A PNC CC POR RGTO. ENTRADA. SE COMUNICA NUEVO Nº CUENTA DONDE INGRESAR LA PNC SOLICITADA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA TERESA'and edp.apellido1='NEVADO'and apellido2='MARTIN'),'2018-10-23','(Pedro)Llamada de Mª Jesús Nevado, interesándose por lo trámites de la herencia. Se le informa que está en manos del abogado de oficio. +++Se le aclara el concepto de tutela, porque creía que era Ángel el turor de su hermana.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUISA'and edp.apellido1='RODRIGUEZ'and apellido2='GRAGERA'),'2018-10-23','(Pedro)Visita de Dª Luisa. +++Quiere divorciarse de su marido, D. Juan Francisco Romo Serradilla (Calamonte),del que está separada "de hecho". +++Se le enseña el ingreso en su cuenta de la venta de la casa. +++Se le informa de los trámites de la herencia . +++Presupuesto clínica dental aprobado y se va a hablar con ella para consultar sobre el presupuesto. +++Se queja de su compañera de habitación. +++Dolor en rodilla. ¿Clínica privada?','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AGUSTIN'and edp.apellido1='RASTROLLO'and apellido2='BARRAGAN'),'2018-10-23','-PONGO EN REGISTRO ENTRADA A DEPEND AZUAGA EL PIA CON LA NO ACEPTACION DE 12H AL MES D PROMOCION DE LA AUTONOMIA . A.D.G. PONGO COPIA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CATALINA'and edp.apellido1='MIRANDA'and apellido2='ROSADO'),'2018-10-24','(Pedro)Llamada de Catalina (675-615145). +++Le han diagnosticado artrosis y está un poco asustada. le han puesto un tratamineto que acaba de inciar. +++Le preocupa qué hacer si se encuentra mal por la tarde y no puede contactar con nosotros. Le indico que, si puede , acuda a Urgencias de su Centro de salud o bien que llame al 112 y explique lo que le ocurre. +++Se palntea que cuando fallezca (¿?) que todo lo herede su hija.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='GARCIA'and apellido2='MORENO'),'2018-10-24','(Pedro)Se pone a la firma el consentimineto informado para colonoccopia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PETRA'and edp.apellido1='COSTA'and apellido2='RODRIGUEZ'),'2018-10-24','(Pedro). Llamada de Rosa, CSS de Plasencia. Me deriva al Dr. Fernando Domínguez (Med. General del CSS, 24132). Conversación con fernando: +++Ha derivado a Ginecología a Dª Petra por metrorragia. Al parecer en el Servicio no saben si continuar con las pruebas para conocer la causa. +++Frenando opina que se le debe hacer la autopsia para ello y la Comisión también si es indiccación médica. +++Hablará con Ginecología y nos enviará los consentimientos informados para su firma.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE PEDRO'and edp.apellido1='VILLEGAS'and apellido2='SERRANO'),'2018-10-24','(Pedro)Conversación con EVa ("La Perla del Valle"). +++Solicito presupuesto para acompañamineto en domicilio por la noche, en caso de que José Pedro no quiera ingresar voluntariamente en Residencia y deba volver a casa. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con Encarna, T. Soc. C.Salud. La pongo al día de la situación: +++Valorar plaza socio-sanitaria para Cristina y José Pedro. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con Raquel,Encargada del Hogar Nazaret: +++José Pedro se quiere quedar en el Hogar, no quiere ir a otro lugar. Está contentísimo. +++Le pongo al tanto de la situación de la hermana, y de la posibilidad de que le den el alta a finales de semana según resultados de las pruebas, con la finalidad de que puedan mantener a José Pedro en el Hogar hasta entonces. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con Julián, para ver su disponibilidad para atender a sus hermanos en caso de que tengan que volver a casa, dado que Cristina quedaría sola fuera de las horas en que trabaja la empresa de servicios. Estaría dispuesto, pero querriá COBRAR POR ELLO. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Convresación con Toni (FUtuex): ver correos-e del 24 de octubre (11:37 y 12:12)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE PEDRO'and edp.apellido1='VILLEGAS'and apellido2='SERRANO'),'2018-10-23','(Pedro)Conversaciones con: +++Fiscalía: hablo con José Manuel R.Le explico la nefasta situación económica en la que ambos hermanos se encuentran, la consideración de la Comisión de que en estos momentos no creemos que se den las circunstancias para solicitar una ampliación de la incapacidad de D. José Pedro Y de las alternativas de internamiento: si no accede voluntariamente NO SE LE PUEDE OBLIGAR. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ +++Toni (Futuex). Enviará informe sobre la información proporcionada por el Médico de Dª Cristina. +++++Pido que cuando vaya de nuevo Alicia, hable con José Pedro de la posibilidad de ingresar en otro centro, dado que en el Hogar su estancia es muy provisional y, dado que es una curatela, no podemos obligarle a un ingreso que el pueda no desear. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ +++Puerto (Hogar de Nazaret): +++++Nos ha dejado a todos sdorprendidos: ha pasado una buena noche, ha dormido estupendamente y se ha levantado muy animado. +++++Se plantea la posibilidad de que si se produce una vacante, pueda quedarse en ella. No obstante, al igual que a Futuex, se le reuega a Puerto que hablen con él para saber si aceptaría voluntariamente el traslado de Centro por las razones antes indicadas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='BRUNO'and apellido2='SAAVEDRA'),'2018-10-24','- HAY QUE SOLICITAR PNC ( YA TENGO TODA LA DOCUMENTACIÓN MENOS EL MODELO DE ALTA A 3º) ESTÁ EMPADRONADA EN OLIVENZA , PERO HE PEDIDO QUE LA EMPADRONEN EN BADAJOZ. HE SOLICITADO APROSUBA3 EL INFORME MEDICO PARA PEDIR DEPENDENCIA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MONTEVIRGEN'and edp.apellido1='GARCIA'and apellido2='SANCHEZ'),'2018-10-24','(Pedro)Conversación con Nuria, T. Soc. Hospital de Mérida (81041). +++Desde el pasado 21 de octubre Dª María está ingresada en el Hospital por un infarto cerebral. Consideran en neurología que no está para ingresar en Casa verde, por lo que van a pasar la herramienta para solcitar plaza T-3. Nos enviarán la solcitud para firma y devolución. +++Dado que hay un hermano que vive en Almendralejo que parrece ser el único que se preopcupa en cierta manera por ella, solcitar Almendralejo y las localidades más cercanas (hablo sobre ello con Blanca, del CSS Mérida). +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con Nuria, T.Soc. Hospital de Mérida. +++Dejamos las opciones abiertas en cunato a localidades donde solicitar plaza, aunque ruego que tenga en cuenta la proximidad a Almendralejo al haber familia en esta localidad (Antonio, su hermano de 84 años y la mujer de éste, también de 80 años). +++En estos momentos no hay plazas en Almendralejo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VICHO'and apellido2='ALFONSO'),'2018-10-24','(Pedro)Conversación con Rosa (CSS de Plasencia). Tras la misma, envía el siguinete correo-e: Hola Pedro: Tal como hemos quedado telefónicamente te informo sobre fuga del paciente. El pasado día 12/10/18, según recoge Informe Incidencias del Médico de guardia, en nota de las 18:00 h.: Tras pase de salida por el recinto del centro de 30 min., no regresa a su Unidad. Se avisa al Serv. de Seguridad para localización por el recinto del centro. No se encuentra. Se denuncia fuga a la Policía Nacional. En la mañana del día 13/10/18, es remitido desde el Hospital "Virgen de la Montaña" de Cáceres. Según el Informe del citado Hospital, ingresó en el mismo el día 12/10/18 (22:34 h.), "se había presentado en prisión demandando entrar allí". En entrevista con la Psiquiatra, José Mª. comenta que se fue a Cáceres en tren, acudiendo tras la llegada al Centro Penitenciario para cumplir la pena que puede "caerle" por la causa pendiente. Un saludo. Rosa Bravo. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Citado en el Juzgado Penal de Cáceres el 13 de noviembre (ver citación)por atentado contra la autoridad.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='MURILLO'and apellido2='DELGADO'),'2018-10-25','Decretan la apertura de juicio oral contra María en el Juzgado de Instrucción nº 3, de Badajoz. PA 1343/2017 delito de hurto. Le imponen en pago de una fianza de 200 euros.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2018-10-25','(Pedro)Solictan desde Plena Inclusión Llerena autorización para permitir la salida de fin de semana con su padre a Beatriz, para el próximo 2 de noviembre, aprovechando la visita a su hija Rocío ese mismo día pàra que su padre acuda allí a recogerla para pasar juntos el fin de semana. +++Intento hablar con Urbano, para saber si se ha recurrido la sentencia en la que se le daba la custodia a la abuela paterna, pero no están hoy. Le envío un correo haciendo esta consulta. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con Mª Ángeles (Plena Inclusión Llerena). +++Preocupaciones: la influencia de Antonio y su familia si se enteran de que está en Trujillo. +++Circunstancias: lleva muchos meses sin ir a su casa, a su entoreno y sin disfrutar de la compañía de su padre, por lo que cabe asumir el riesgo antes mencionado. +++PRECAUCIONES: informar a los SSB de la localidad de la estancia de Beatriz para el fin de smnena del 2 de noviembre y que alerten a la Polcicía Local para que, en la medida de lo posible, estén atentos a cualquier incidencia. +++++Hablar con el padre para que, dao el caso, avise a a Policía Local.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2018-10-25','(Pedro)Conversación con Pilar, T. Soc. del ESM de Cáceres. +++Quieren convocar una Subcomisión de Gestión de Casos para tratar el tema de José Manuel y consultan a quién creemos que se habriá de convocar. Propongo la Unidad de Programas (Salud Mental).','2');
