insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='FERNANDEZ'and apellido2='MERCHAN'),'2018-10-26','Solicitamos al Juzgado de Primera instancia nº 4 de Badajoz, testimonio del Auto de nombramiento de su madre fallecida, Teresa Merchán Pozo y aceptación del cargo, a los efectos de tramitar su herencia. Contactamos con el abogado Santiago Martínez-Carande Corral(2399@icaba.com, 600564938, 924232591) que llevó el caso en el año 2008, para registrar a nombre de Teresa su casa de Talavera la Real, que en Registro de la Propiedad no aparece a su nombre y en el catastro si.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2018-10-26','(Pedro). Conversación con Toni (Futuex). +++Valorar la salida de Betariz de fin de semana para el puente del 1 de noviembre con su padre, D. Tomás. +++++La recogería en el Punto de Encuentro el viernes 2 de noviembre y se la llevaría a pasar el fin de semana con él. +++RIESGOS: que Antonio (ex-pareja) sepa que está en Trujillo y le informe ( a su manera) de la situación de la niña o que quiera volver con ella...(ver incidencia anterior) +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Conversación con Urbano. +++Confirma que desde los Srvicio Jurídicos se ha recurrido la sentencia en la que se le daba la custodia de la niña a la abuela paterna. +++Con la familia actual, Rocío lleva ya un año, cuando el periodo de acogimeinto por urgencia es de 6 meses: al parecer la actual familia ha pedido cesár en el acogimineto. Afortunadamente tienen previsto plantear el acogimineto a otra familia, lo que en caso de ocurrir supondría cambiar el punto de encuentro. +++Respecto del recurso existe una previsión de que en cuatro meses esté resuelto, pero puede ser más probablemnete. Seguimos en contacto.','2');
