insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2018-10-26','-TEMA P.V.SAD : SE FIRMÓ PIA + MODELO ALTA 3º. QUÉ PASA CON EL CONTRATO DE LA EMPRESA ?? SE HA PEDIDO A FUTUEX QUE LO HAGA . EL CDO. DE CONVIVENCIA SE LO PIDIÓ DEPENDE. A ÉL DIRECTAMENTE. HAY QUE ENVIAR TODO A ANA ISABEL TEOMIRO QUE LO ESTÁ ESPERANDO . VER CORREOS EN EMAIL CTAEX. A.D.G.','2');
