insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE PEDRO'and edp.apellido1='VILLEGAS'and apellido2='SERRANO'),'2018-10-26','(Pedro)Copnversaciones con: +++Futuex: Critina se manietne ingresada durante el fin de semana al menos, valorando si continua tras la biopscia o se va a casa de alta. +++Hogar Nazaret (Puerto): se explican las circunstancias y, aunque todsos reconocemos que no es la solción más adecuada ni definitiva, José Pedro se mantenddrá unos días más en el centro hasta que se concrete la situación de su hermana. +++Eva (Perla del valle): se le inofrma de que este fin de semana no van a estra lo hermanos en el docmicilio: continuarán las tareas domésticas si son nevcesarias y si no se retoamraán el lunes (le pido que, si no trabajan el domingo, lo decsuenten para otros momentos en los que haga falta (sic). +++José Mª (Taxista): se le informa de que cuando se requieran de nuevo sus servicios se le comunicará. +++++Ha tratado de remitir la factura pero dice que no le permite el envío el correo. Envío dirección por correo-e.','2');
