insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='HIDALGO'and apellido2='ROMO'),'2018-10-29','LLAMA LA TS. DE PRISIÓN PARA COMENTAR QUE ANTONIO NECESITA UNA DENTADURA POSTIZA, DICE QUE LO PODEMOS PAGAR EN DOS O TRES PLAZOS, SON UNOS 600€. LE PIDO QUE NOS MANDE PRESUPUESTO Y CONSULTE CON EL DENTISTA SI PODEMOS PAGARLO EN TRES VECES YA QUE EN SU CUENTA HAY 800€ APROX.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO'and edp.apellido1='SUDON'and apellido2='HERNANDEZ'),'2018-10-29','En relación con la venta de la vivienda que tienen todos los hermanos en Badajoz, hablamos con Manoli, cuñada (mujer de Paco), para decirles que antes de la venta los hermanos deben abonar a Pedro los 9.805,26 euros en concepto de recibos de luz, agua, comunidad de la casa. No necesitamos autorización judicial para vender.','2');
