insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NURIA BELEN'and edp.apellido1='GARCIA'and apellido2='OLIVERA'),'2018-10-29','(Pedro)Conversación con Maribel Rivera, Directora Inclusive Villanueva de la Serena (924-842412), en relación a la autorización para la empresa Factoría Henneo, S.L. (de Zaragoza) para cederles todos los derechos de imagen y datos personales de Dª Nuria. +++No se va a firmar dicha autorización por suponer una cesión de derechos para cualquier actividad, además de la indicada, de cara al futuro. +++Maribe hablará con la Dirección de la Escuela de danza para formular una solcitud expresamente para la actividad concreta','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='QUIROS'and apellido2='SAUCEDA'),'2018-10-29','(Pedro) Conversación con Fausti, T. Soc. H. Don Benito-Villanueva. +++ALTA MÉDICA: para finales de esta semana o principios de la siguiente. +++D. José Antonio acepta voluntariamnete ingresar en un aresidencia de mayores durante su convalecencia. +++Cuidados requeridos: tercera persona para alimentación, higiene, no coger peso, curas, cambio de la bolsa, etc. +++Se valorará ingreso en plza privada en D. Benito o próxima a esta localidad: R. San Antonio (1350€/mes), R. santa Amalia (1200€/mes), R. La Salud de Vva. (1100-1200€/mes).','2');
