insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADRIAN'and edp.apellido1='ORTIGOSA'and apellido2='FUENTES'),'2018-10-30','(Pedro)Se recibe llamada telefónica del HIC (48081, Secretaria de Enfocrinología), sobre las 09:15h, comunicando que SE SUSPENDE LA CONSULTA DE ADRIÁN prevista para HOY por enefermedad del Endocrino, el Dr. Díaz Pérez de Madrid. +++SE insiste en la urgencia de la nueva cita dado que se está pendsiente de los resultados para comunicar al CADEX los mismos y establecer perfil para Centro. +++Lo comunico a Toni (Futuex) para que avise a Teresa. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Llamada de la Secretaria de Enfocrinología: NUEVA CITA: LUNES 05 DE NOVIEMBRE A LAS 11:05h. +++OTRAS CITAS: 12 de NOVIEMBRE ..............dni////16 de NOVIEMBRE.............Psiquiatría.','2');
