insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RICARDO'and edp.apellido1='ROCHA'and apellido2='BARCO'),'2018-10-30','En relación con la autorización de venta del piso de Ricardo, el Juzgado de 1ª. Instancia e Instrucción nº 1 de Mérida, nos cita a comparecencia el día 6/11/18. Enviamos escrito ratificándonos en la demanda presentada por el abogado. No tenemos que comparecer.','2');
