insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PETRA'and edp.apellido1='COSTA'and apellido2='RODRIGUEZ'),'2018-10-31','SE HA SOLICITADO EL CAMBIO DE DOMICILIACIÓN DE SU PENSIÓN A LA NUEVA CUENTA QUE SE LE HA ABIERTO EN LIBERBANK. UNA VEZ QUE EMPIECE A ENTRAR LA PENSIÓN EN ESTA CUENTA EMPEZARÁ A PAGAR EL CENTRO PORQUE HASTA AHORA NO HA PAGADO NADA. MJGH','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MONTEVIRGEN'and edp.apellido1='GARCIA'and apellido2='SANCHEZ'),'2018-10-31','(Pedro)Llamada de Nuria (T.Soc. Hospital de Mérida). No ha podido tramitar plaza T3 porque los compañeros estan de mudanza. +++Temporalmente ingresará esta tarde en el CSS de Mérida hasta que se gestione la T3','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONCEPCION'and edp.apellido1='ALEJANDRO'and apellido2='DIAZ'),'2018-10-31','(Pedro)Conversación con Mar, T. Soc. del ESM de Ciudad Jardín. +++Le envío por fax (924- 218332)informe enviado al Juzgado junto con el alta del CSS de Mérida. +++Valorarán ingreso en UHB.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARGARITA'and edp.apellido1='ANTICH'and apellido2='ARROYO'),'2018-10-31','EL JUZGADO DE 1ª INSTANCIA Nº 1 DE PLASENCIA ACEPTA LA INHIBICIÓN DE AVILA, LE HA CORRESPONDIDO EL PROCEDIMIENTO DE TUTELA 595/2018','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2018-10-31','(Pedro)Hablo con Mercedes (T. Soc. SSB de TRujillo). +++En realción a la salida de Beatriz al domcilio familiar, solicito se dé aviso a la Policía Local para que, en la medida de lo possible, estén atentos por si hubise algún problema con Antonio y su familia. +++Lo pondrá en conocimiento de la Policía Local. +++Una vez hablado con la P.LOcal, Merecedes me dice por correo que no es posible ese "control" por su parte, que es la fieasta de la cerveza ese fin de semna y que no se pueden hacer cargo. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Llamo a la Guardia Civil de Trujillo. Hablo con el Brigada Alberto Guillén (Comandante de Puesto) (927-321004). Le pongo en antecedentes . +++Aunque refiere que no tiene personal sufuieciente `para ello si me indica que toma nota de la situación y que, si se produce algún problema, el padre de Beatriz llame al 062 y pregunte por él, que estará al tanto. +++REspecto a Rocío, no entiende cómo se puede plantear siquiera la posibilidad de dar la custodia a la familia de Antonio. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Comunico estas gestoiones a Mª Ángeles, psicóloga de Plena Inclusión Llerena, para que hablen con el padre en los términos antes indicados.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CRISTINA'and edp.apellido1='VILLEGAS'and apellido2='SERRANO'),'2018-10-31','(Pedro/GESTIONES): +++Futuex/Perla del Valle: comunican el ALTA HOSPITALARIA de Dª Cristina en el día de hoy. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Hogar de Nazaret. Hablo con Puerto, la Directora, para ver la psoibilidad de que D. José Pedro permanezca en el centro durante más teiempo, para ver cómo evoiluciona Cristina en el piso. +++La Directora no pone objección a ello, todo lo contrario. +++Tienen en cuenta la posibilidad de reservar dos plazas, caso de que se produzcan las bajas correspondientes, para que puedan ser ocupadas por ambos hermanos. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Convresación con Julián, hermano. +++Refiere que su hermana está muy DÉBIL, QUE PRÁCTICAMENTE SE DECARTA LA OPERACIÓN por temor a que no pueda aguantar ni la anestesia y la intervención por su grado de invasividad. El pronóstico, según cuenta, es malo, a la espera de los resultados de la biopsia.VER INFORME DE ALTA EN EXPTE.) +++Le comunico que José Pedro permanercerá en el Hogar de Nazaret por un tiempo, para ver la evolcuión de su hermana. +++Él se va a encargar de no dejar a su hermana sola en nin gún momento, pero vuelve a hablar de los gastos que esto puedas suponer: quiere hablar con su mujer y el viernes me dirá qué cantidad puede ser (¿?) +++Se encargará de hacer la compra (de esta forma la Auxiliar se puede dedicar a las tareas domésticas y de aseo) y administrar medicación. Con la finalidad de no dejar sola a su hermana, dichas compras las realizará cuando la Auxiliar se encuentre en el docmicilio. +++SE le recuerda que ante cualquier síntoma de empeoramiento lo comunique al 112 para que su hermana sea atendida rápidamente. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con Eva, de la "Perla del Valle". +++DE momento seguirán con las cinco horas diarias, procurando concentrarlas en las horas de las comidas y cenas. Si considerasen necesraia cualquier modificación, nos lo harían saber. +++SE inofmra de los acierdos alcanzados con el hermano, y ruego que nos informen de cualquier circusntancia que consideren anómala en cuanto a su intervención con su hermana.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2018-10-31','(Pedro)Llamada de Julia (688-381229), madre de José Mª. +++Pregunta por la decisión del Juzgado. No sabemos nada todavía.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='BERGANTIÑO'and apellido2='GONZALEZ'),'2018-11-02','(Pedro)Llamada de Juan José (667-958878). +++Insistente en que quiere comprar un piso en Cáceres y que lo vayamos pagando poco a poco. Que sus hermanas están de acuerdo... +++Le hago ver que para él es mejor esperar al trasalado de CRR solcitado y seguir los planes que comentamnos en nla visita del 3 de octubre. +++Se muestra razonable y dice que seguirá esperando un poco más.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CATALINA'and edp.apellido1='MIRANDA'and apellido2='ROSADO'),'2018-11-02','(Pedro)Llamada de Catalina. +++Al parecer, ha visto esta mañana a su casero y le ha dicho que tiene un mes para dejar el piso, porque lo quiere ocupar él. +++Por si acaso, empezará a buscar alguna alternativa, pero se le advierte que no firme ni dé dinero alguno hasta que la Comisión tome una decisión.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SEGUNDA'and edp.apellido1='GARCIA'and apellido2='CARRILLO'),'2018-11-02','(Pedro)Visita de D. Gregorio. +++Consultas: +++++De nuevo la preocupación por los 90.000€ que hay en el banco de santander. +++++La cobertura de las necesidades que su hermana pueda tener en COMSER. Se le tranquiliza en el sentido de que cualquier necsidad que tenga nos será comunicada por la residencia y atendida por la Comisión. +++++La Declaración de la renta: se le comunica que no existe obligación de presentarla. +++++Recuerda el panteón que su hermana tiene en propiedad. +++++L epreocupa lo que pueda suceder en caso de fallecimiento de su hermana en día no laborable.También se le tranquiliza al respecto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL JESUS'and edp.apellido1='RODRIGUEZ'and apellido2='MURILLO'),'2018-11-02','(Pedro)Llamada de Ana, Psicóloga del CAMP Don Benito (20111). +++La madre de Ángel está ingresada en el H. Perpetuo Socorro. Al parecer, no tien un lugar donde vivir y está planteando allí solicitar el Módulo Familiar del CAMP por etá en este Centro su hijo Ángel, con quien no mantiene contacto alguno desde hace años (salvo alguno esporádico). +++Ana considera que esta convivencia no es posible y que podría ser contraproducente para el propio Ángel. +++En cualquier caso, al ser una persona (la madre) no incapacitada legalmente puede acudir a los servicios, tanto sociales como sanitarios, para valorar sus alternativas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='MELLADO'and apellido2='GUARDABRAZOS'),'2018-11-02','iciar Se envía por fax a ASociación Vera - 927 03 71 94, consentimiento informado para tratamiento odontológico.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CRISTINA'and edp.apellido1='VILLEGAS'and apellido2='SERRANO'),'2018-11-02','(Pedro)Conversación con Julián Villegas. +++Respecto de la cantidad de dinero para atender a su hermana comenta que no sabe qué decirme. Le pido que hable con Alicia, de Futuex, para elaborar un presupuesto en relación a la alimentación, limpieza de la vivienda, pañales y cualquier otra necesidad que pueda tener su hermana. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Correo de Toni (Futuex): +++Buenos días, adjunto el informe de alta de Cristina Villegas, escaneado para que se pueda ver mejor, que el otro día, que era una foto directamente hecha del informe físico. La delegada está allí ahora en la casa, ha llegado la auxiliar de ayuda a domicilio, tanto la auxiliar como Julián tenían una lista aproximada para lo que haría falta comprar para la casa, lo que está claro es que lo que presenta Julián es del todo inviable, dice que necesitaría 600-700 euros, esta cantidad es desorbitada, entendemos que con 200-300 se puede hacer una compra de alimentos frescos, carnes, pescado, fruta y verdura, y productos de limpieza e higiene, bastante aceptable. La lista que barajaba la chica de la empresa entendemos que se basaba solo en comida enlatada o productos preparados, no sabemos muy bien porque. Por otro lado Julián le ha comentado a nuestra compañera, que iba a comprar una cama eléctrica para Cristina, le hemos explicado que en ningún caso haga esta gestión por su cuenta, sin contar con la comisión, entendemos que no ha solicitado autorización y también que al comentarle que no puede hacer nada sin esta autorización ya que no se va abonar, que se estará quieto. Seria conveniente que Cristina saliera de la vivienda lo antes posible, la delegada la ha notado débil y realmente ahora necesita muchos mas cuidados que antes, a ver si la autorización judicial no tarda mucho!','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO MANUEL'and edp.apellido1='ALVAREZ'and apellido2='HIDALGO'),'2018-11-05','-LE PASO A ANGEL I.SOCIAL + DENUNICIA PARA QUE PUEDA SOLICITAR EL INGRESO .','2');
