insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MAXIMILIANO'and edp.apellido1='BAZAGA'and apellido2='CARRERA'),'2018-11-05','(Pedro) Informa Rosa (CSS de Plasencia) del FALLECIMIENTO de D. Maximiliano Bazaga, tras su ingreso en el Hospital el pasado sábado 3 de noviembre. +++Ya han comunicado a Caser el fallecimiento. +++Está la familia allí, porque habían venido de Barcelona. +++Va a ser incinerado y quedará en Plasencia. +++Efectos personales: harán una realción de todos ellos para firmarlo por los familiares y nos lo enviarán. +++Enviarán también desde el CSS Informe Médico del ingreso en el Hospital y toda la documentación referioda al fallecimiento.','2');
