insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MUÑOZ'and apellido2='MELCHOR'),'2018-11-06','Llaman del Juzgado nº 2 de Trujillo - Loli 927 32 00 85-. La juez debería haber visitado hoy a Dª Isabel Muñoz en la Residencia de Jaraicejo, de ello tiene conocimiento los Servicios Jurídicos de la Junta, pero le ha sido imposible. Plantean desde el Jzdo si fuera posible desplazar a Dª Isabel al Juzgado para que la vea la juez. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Confirmo con el Juzgado y con Futuex que la Jueza la verá el viernes, 9 de noviembre, a las 10:30h.','2');
