insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DOLORES'and edp.apellido1='FERNANDEZ'and apellido2='BAEZ'),'2018-11-06','(Pedro)Llamada de Manuel Porrón, Técnico del Ayto. de Almendralejo (679-158321), en relación con las obras mencionadas por Mariloli en el bloque de viviendas en el que tiene su piso. +++Se trata de un bloque de viviendas sociales que requieren refeormas por afectar a la vía pública y que han originado un expediente de Obras por Orden de Ejecución, en concreto dos: el 40/2017 y el 41/2017. +++Existe una Agencia que gestiona el bloque y que será la encargada de las mismas, pasando después a cada propietario la cuota que le cortreponda en furnción de su porcentaje de participación en la comunidad. En caso de que no lo ejecute la Comunidad, será el encvargado de hacerlo. +++NOS ENVIARÁ LA DSOCUMENTACIÓN AL RESPCECTO POR CORREO-e.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='AYALA'and apellido2='NUÑEZ'),'2018-11-06','(Pedro)Conversación con Toni (Futuex): +++Alicia a visitado a Francisco esta mañana. Se encuentra mejor. Ha ido al médico de cabecera por un problema en la pierna (dolor) para tratar de averiguar de qué se trata. +++También ha estado en el Psiquiatra, pero al parecer no le ha podido atender. +++Alicia, a petición de la Comisión, le ha planteado a Paco la idea de ir pensando en ingresar en una residencia, algo que de momento no se plantea, pero a lo que tampoco se ha negado rotundamente. Seguirán insistiendo en ello de aquí en adelante. Además, los compañeros del ESM también están haciendo su intervención en esa línea.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2018-11-09','(Pedro)Se recibe en la Comisión los siguinetes documentos del Juzgado de lo Penal nº 1 de Plasencia del P.A. 206/2018: +++Sentencia 340/21018 y Ejecutoria 0000643/2018 y 0000643/2018-3, solicitando lugar adecuado de internamiento para su cumplimiento. +++LIQUIDACIÓN DE CONDENA de la prohibición de aproximación y comunicación de: +++++Jorge F.C: INICIO 03-SEPT-2018....FIN 01-SEPT-2020. +++++Luis A. M.V: INICIO 04-SEPT-2018....FIN 30-JULIO-2019.','2');
