insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIPE'and edp.apellido1='BLANCO'and apellido2='GUISADO'),'2018-11-09','(Pedro)Llamada de Agustina, T. Soc. SSB de La Haba. +++Comunica que "La casilla" se ha caído y que hay una pared que hay que derribar, para lo que solcita nuetsra autoirización. Se le informa de que esa propiedad no es solo de Felipe y que para derribarla del todo neceitaráimos autorización judicial (inofrme técnico y fotos) y que el Ayto, creo, tiene autorizdad para tirarla sin autorización si considera que existe peligro para la población.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VICHO'and apellido2='ALFONSO'),'2018-11-09','(Pedro) Llamada de Ana Pérez Tejeda, psiquiatra de José María. Solicita autoriuzción para salida terapéutica. +++Le pido que envíe programa con las cararterísticas de estas salidas (está recogido en el expdte informatizdao). +++Hablar con Soraya sobre esta autorización.','2');
