insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='SOLANA'and apellido2='CHANCLON'),'2018-11-12','-SOLICITO CPTO. ATP , LO PONGO PARA FIRMA . TRAS SU ULTIMA RESOLUCION GRADO DISCAPACIDAD PASA A 75% Y TIENE G.II . AD','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUGENIA'and edp.apellido1='PACHECO'and apellido2='VICENTE'),'2018-11-12','En relación con la ETJ 35/2018, en el que aparecen como demandados Eugenia y Lino Luis Martín, les reclaman, 21.091,47 euros en concepto de principal y 6.327,44 en concepto de intereses. Según nos dice el Juzgado de Primera Instancia e Instrucción nº 3, de Plasencia, a Lino a fecha de hoy sólo han podido reclamarle 9,77 euros, por lo que el resto se lo van a ir reclamando a Eugenia. Hemos comunicado al Juzgado que Eugenia cobra un subsidio para mayores de 52 años, por importe de 430,27 euros, cantidad inembargable, a los efectos de tenerlo en cuenta para posibles reclamaciones.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADRIAN'and edp.apellido1='ORTIGOSA'and apellido2='FUENTES'),'2018-11-12','-HOY TRAIA TERESA ( FUTUEX ) EN SU COCHE A ADRIAN PARA RENOVAR EL DNI , HAN TENIDO UN ACCIDENTE EN LA CARRETERA DE OLIVENZA. NO LE HA OCURRIDO NADA A ÉL . AD','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AUGUSTO MANUEL'and edp.apellido1='DOS SANTOS'and apellido2='DOS SANTOS'),'2018-11-12','-PNC PARA REGISTRO DE SALIDA . LA ENVIARÉ , FALTA EL Nº SS QUE SE LE ENVIARÁ POSTERIORMENTE , ENVIARÉ AUTORIZACIÓN AL CTRO . DE LA LUZ PARA QUE SE LO PIDAN . ENVIAR LA PNC Y A SOLE LA AUTORIZACIÓN Y COPIA CON REGISTRO DE LA PNC.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VICHO'and apellido2='ALFONSO'),'2018-11-13','(Pedro)Asistencia de la CTAEx al Juzgado de 1ª Instancia e Instrucción nº 1 de Cáceres. +++MOTIVO: DECLARACIÓN EN CALIDAD DE INVESTIGADO (lesiones). P.A.0000209-2018. +++La vsita se había suspendido previamente sein avisar a la Comisión Tutelar.Por lo que la funcionaria me dijo, DESCONOCÍAN que José Mª estuviera tutelado. Al parecer lo iba a ver el forense para valorar su imputabilidad. +++Dejo en Registro del Juzgado escrito adjuntando sentencia de incapacitación y aceptación del cargo para su constancia en dicho procedeimiento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CACHO'and apellido2='GARRIDO'),'2018-11-14','- HABLO CON PNC PARA SABER COMO VA SU EXPEDIENTE , PERCIBIRÁ LA NÓMINA A FINALES DE DICIEMBRE CON ATRASOS . AD. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++(Pedro). Converscaión con Ana Pérez Tejada, Psiquiatra de Francisco (24172). +++Nos enviará presupuesto para dinero de bolsillo y pedirán extra para ropa. +++Solicita LIMITAR LA CUENTA y CONDICIONARLA al cumplimiento, por parte de Francisco, de asistir cuando se le indique al centro, que realice controles negativos de sustancias, etc. Nos enviarán dichos condicionantes lo antes posible para controlar la cuenta. +++Ana también valora la POSIBILIDAD de, llegado el caso, proponer una recuperación de la capacidad (parcial o completa) de Francisco: se le explica que ello requeriría un informe por su parte de que las circunstancias que motivaron la incapacitación se han reducido o, en su caso, desparecido. Entonces, basándoneos en los informes correspondientes, la Comisión solicitaría la apertura de un procedeimiento de amp`liación o recuperaciópn de la capacidad ante el Juzgado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CACHO'and apellido2='GARRIDO'),'2018-11-14','- NOS ENVIAN INFORME DESDE EL ESM , DESDE EL DIA 12 ESTÁ EN CENTRO ATEN TRANSEHUNTES + 2 DIAS EN CSS PLASENCIA , CON EL OBJETIVO DE PASAR A UN PISO DE VIDA AUTONOMO O CENTRO . AD','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2018-11-13','(Pedro)Me reuno con Julián, Gerente de Cocemfe en el centro: +++DIFICULTADES CON TOMÁS: +++++No entiende por qué tiene que estar en una silla de ruedas. +++++Aunque no ha vuelto a ocurrir, las autolesiones son su forma de presionar a los demás cuando no consigue lo que desea, sin ser consciente del daño que se inflige a sí mismo. +++++Están trabajando con él algunos episodios en los que se ha comprobado que ha sustraído dinero de sus compañeros. +++EN POSITIVO: está muy bien adpatadoa l centro y se hacer querer por todo el mundo. +++VALORAR ACOMPAÑAMIENTO en salidas una vez por semana (2h) y coste de las mismas asumible.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VICHO'and apellido2='ALFONSO'),'2018-11-14','(Pedro). Conversación con Rosa (CSS Plasencia) +++SE FUGA EL DOMINGO 11 y lo encuentran en la estación con intención de irse a Cañamero. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++(Pedro) Conversación con Ana Pérez Tejada, Psiquiatra de José Mª (24172):en relación a su solcitud de autorización de salidas terapéuticas, sin acompañamiento, como medio de motivarlo. +++Está muy preocupada por la situación de soledad y aislamienmto de José Mª, de su sensación de soledad y de no ser querido por nadie. Sentieminetos que le llevan a manifestar su deseo de volver a la cárcel, con el reiesgo que ello pude implicar de comportamientos tendentes a conseguirlo y, en casos extrempos, a la posibilidad de suicidio. +++Entiende que los riesgos que deberíamos asumir en caso de autorizardichas salidas son altos, no solamente para él, que quizá no tendría comportamientos no deseados frente a terceros, sino para estos últimos ante cualquier situación que José Mª entendiese como una provocación. +++Tras hablarlo con Soraya Masa, se le propone valorar que dichas salidas sean incialmente con acompañmineto, acompañamineto que no se realiza con ningún otro paciente y que él, en principio, tampoco acepta, aunque el hecho de hacerlo -le digo- también sería un punto a favor por su parte para ir ganando confianza en que su evolución sea positiva. +++También planteo la posibilidad de CONVOCAR SUBCOMISIÓN de GESTIÓN de CASOS. +++Hablará de todo ello con Soraya, la Directora, y valorarán la situación y la posibilidad de iniciar salidas con acompñamineto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN ANTONIO'and edp.apellido1='SANCHEZ'and apellido2='SANTIAGO'),'2018-11-14','-ESTA INGRSADO EN HOSPITAL DE LLERENA POR DESCOMPENSACION POR CONSUMO DE ALCOHOL DESDE HACE 10 DIAS.AD','2');
