insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LAZARO'and edp.apellido1='LUBIAN'and apellido2='SANTANO'),'2018-11-14','-COMUNICO NUEVO Nº CTA. A DEPENDENCIA . AD.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CRISTINA'and edp.apellido1='VILLEGAS'and apellido2='SERRANO'),'2018-11-13','(Pedro)Se envía por correo ordienario solcitud de plaza sociosanitaria T3 al Servivios de Atencvión de Mayores. +++A la vez, me pongo en contacto con Plácido, jefe de Servicio, para explicarle la urgencia de la situación y agilizar todo lo posible la adjudicación de la plaza. Se envía por correo-e la documentación anteriormente citada para darle curso lo antes posible. CORREO-e: residenciamayorescc@salud-juntaex.es','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CRISTINA'and edp.apellido1='VILLEGAS'and apellido2='SERRANO'),'2018-11-14','(Pedro)Llamada de Plácido, Jefe de Servicio (927-004261). +++Solicita datos económicos para calcular el coste de la plaza T3: +++++Coste inicial (según ingresos de Dª Cristina): 1122.92€ +++++Dicho coste se reduce al ser titular de préstamo hipotecario por el que pagan una cuota mensual de 1130.32€/mes. Dado que es COTITULAR con su hermano de dicho préstamo, se tiene enconsideración para el cálculo la mitad de la cuota.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='CALZAS'and apellido2='SANCHEZ'),'2018-11-15','(Pedro)Conversación con Toni (Futuex). +++Fallecimiento de D. Domingo el pasado domingo 11 de noviembre.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CRISTINA'and edp.apellido1='VILLEGAS'and apellido2='SERRANO'),'2018-11-15','(Pedro)Conversación con Toni (Futuex). +++Le informo de la solicitud de plaza sociosanitaria para Cristina. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Converscaión con la Unidad de Cuidados Paliativos del "Virgen del Puerto". Conversación con MIreia, T. Soc. de la Unidad (629-885824). +++Al tanto de la solcitud de plaza sociosanitaria. Se le explica la situación legal en la que se encuentra Cristina en relación con la CTAEx y la responsabilidad de esta a nivel legal. Su hermano Julián carece de capacidad de decisión al respecto. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE PEDRO'and edp.apellido1='VILLEGAS'and apellido2='SERRANO'),'2018-11-15','(Pedro)Conversación dcon Puerto, directora del Hogar de Nazaret. +++DE momento no han requerido la cama de enefermería que está ocupando José Pedro y él se encuentra muy bien allí: "...estoy en un hotal de cinco estrellas..." -dice-. +++Informo a la Directora que la Comisión espera que la situación de Cristina la podamos tener resuelta en cuanto a sui asistencia en unos días. +++Alternativas: +++++Si José Pedro se encuentra bien y hubiese plaza vacante en el Hogar, solicitaríamos esa plaza para él. +++++Si manifestara querer estar con su hermana, valoraríamos la idoneidad para él de ingresar en el mismo Centro que Cristina según la situación clínica en la que ella se encontrase.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CABEZON TERESA'and edp.apellido1='PLASENCIA'and apellido2='MAJADAS'),'2018-11-15','(Pedro)Llamada de Hortensia, T. Soc. de Cañaveral (927-300330) +++Pregunta sobre la herencia de Dª Teresa. +++Se le Informa de que la CTAEx ya no tiene competencia en el asunto y que serán los hijos los que tendrán que solicitar abogado para resover el tema de la herencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='SERRADILLA'and apellido2='CANO'),'2018-11-15','Se ha puesto en contacto con nosotros Ana Belén Sanromán Serradilla (609360824-anicassmi@gmail.com), que tiene el 25% del pleno dominio de la finca nº 9920 sita en Calle Casillas, s/n (hoy C/. Traseras Casilla, 16), de Logrosán, para agilizar la venta. El otro 25% lo tiene Raquel Sanromán Serradilla. Isabel el 50% restante. Tenemos la autorización judicial para venderla. Le comunicamos el valor mínimo de la finca a efectos del ITPAJD, 8.029,33 euros. Va a intentar hablar con algún familiar del pueblo para que empiece a mover la venta. Pedimos testimonio judicial del auto 59/2017, por que el que se autoriza la venta.','2');
