insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2018-11-16','Hemos recibido mail de la abogada de oficio Vanesas Durán con la sentencia, indicando que "Se le condeno a 4 meses de prisión, que ya tendría. Otros 4 meses de prisión y 9 meses de internamiento además de la orden de alejamiento". +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Hace dos días Nuria, del CSS de Plasencia, comunicó que tenía una medida de seguridad hasta el 04 de noviembre de 2019. Había sido trasladado a larga estancia.COMPROBAR EJECUTORIA DE LA MEDIDA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MUÑOZ'and apellido2='MELCHOR'),'2018-11-19','(Pedro)Llamada de Dª Mª Ángeles (648-829400), hermana de Isabel. +++Indignada porque su hermana le ha dicho que la llamo la Jueza y le dijo que para qué se quería ir a Plasencia si allí no tiene familia, que su familia ahora es la Comisión Tutelar. +++Quiere solicitar abogado de oficio, porque además, "...tampoco la jueza me ha llamado a mí...". +++En el Juzgado le han dicho que el procedimeinto ya estaba cerrado y que no la iban a llamar.','2');
