insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CANDIDO'and edp.apellido1='BAS'and apellido2='GONZALEZ'),'2018-11-19','-LA PFHC , VIENE DENEGADA PQ SU DNI NO ESTÁ EN VIGOR , CADUCADO DESDE EL 2016. ME INDICAN QUE CON LA PETICION DE CITA SERVIRÍA PERO EL PROGRAMA DE CITA PREVIA NO ME DA EL REPORTER . CUANDO SE LE HAGA EL DNI SE VOLVERÁ A PEDIR . NO NECESITA MÁS INGRESOS ACTUALMENTE , ESTÁ EN CSS MERIDA Y TIENE AHORRADO MÁS DE 30000€ . SE LO COMENTO A CSS MERIDA , CUANDO SEA POSIBLE QUE SE LE HAGA DNI NUEVO .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CANDIDO'and edp.apellido1='BAS'and apellido2='GONZALEZ'),'2018-11-20','-NOS LLAMA DEL C.O. DE ZAFRA , HA NECESITADO ACOMPAÑAMIENTO MEDICO EL FIN DE SEMANA Y SU PRIMA , QUE PERCIB 500€ POR MANTENERLA EN SU CASA SE NIEGA A ELLO . PARA LA PROXIMA VEZ SOLICITARAN ACOMPAÑAMIENTO . TIENEN PLAZA DE RAL PRIVADA POR UNOS 700€ DONDE PODRIA QUEDARSE Y TENDRIA MÁS CONTROLADA SU SALUD . LE PREGUNTARAN A ELLA SI QUIERE ACCEDER , ES CURATELA . A.D .','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONCEPCION'and edp.apellido1='ALEJANDRO'and apellido2='DIAZ'),'2018-11-19','Lllamada de Mar (ESM). +++Está con PIpí.Quiere 300€ para pagar los lamgostinos de Navidad que ya ha comprado. +++La han visto (sin cita) la T. Soc., Enfermera y Psiaquiatra (de manera informal). +++Vendrá mañana a las 10:00h poruque me quiere contar algo muy importante que no le puede decir a nadie más.','2');
