insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='YOLANDA'and edp.apellido1='CALDERA'and apellido2='MARTIN'),'2018-11-19','Enviamos vía fax al Juzgado de 1ª. Instancia e Instrucción nº 1, de Villanueva de la Serena, ratificación de la solicitud realizada por Inclusive de Villanueva de la Serena, de autorización judicial de internamiento involuntario de Yolanda en la UDAC. Se lo enviamos también a Félix, de Inclusive, por correo electrónico. Mañana día 20/11/18, está fijada la citación para proceder en sede judicial del examen de Yolanda por el Forense.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CRISTINA'and edp.apellido1='VILLEGAS'and apellido2='SERRANO'),'2018-11-19','(Pedro)llamada de la Gestoría JOCILES S.a., GESTORA DE LA COMUNIDAD DE VECINOS de los hermanos Villegas. +++CONTACTO: Dª NAVELONGA BUENO.////TELÉFONO: 927-411540. ///CORREO-e: inmuebles@jociles.com +++Los vecinos temen que ante la deuda generada en la Comunidad, la empresa de ascensores Schindler vaya a reclamar el pago al Juzgado y embarguen a la comunidad. +++El anterior Tutor, sr. Basquero, hizo un solo pago en diciembre de 2017: por parte de Dª Cristina, 526€ y por partede D. José Pedro 486€. +++++DEUDA PENDIENTE: Dª CRISTINA 4736€ (en dos pagos de 2368€ cada uno); D. JOSÉ PEDRO 4378€ (en dos pagos de 2189€ cada uno). +++La comunidad también solicitó a la Junta de Extremadura ua ayuda para el cambio de ascensor por uno nuevo, para cada uno de los propietarios de los pisos, pero no han recibido respuesta todavía. En caso de concederla, eso reduciría la deuda de ambos hermanos. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ (Pedro)Conversación con Encarna (T.Soc. C. Salud (74439). +++Julián NO quiere de ninguna manera que su hermana vaya a una residencia.Dice que él se puede encargar de cuidadarla como le prometió a su madre, seindo además que le queda poco tiempo de vida. +++NO ES POSIBLE EL TRANSPORTE SANITARIO para ir a la residencia asignada (debería estar previamente ingresada).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE PEDRO'and edp.apellido1='VILLEGAS'and apellido2='SERRANO'),'2018-11-19','Pedro)llamada de la Gestoría JOCILES S.a., GESTORA DE LA COMUNIDAD DE VECINOS de los hermanos Villegas. +++CONTACTO: Dª NAVELONGA BUENO.////TELÉFONO: 927-411540. ///CORREO-e: inmuebles@jociles.com +++Los vecinos temen que ante la deuda generada en la Comunidad, la empresa de ascensores Schindler vaya a reclamar el pago al Juzgado y embarguen a la comunidad. +++El anterior Tutor, sr. Basquero, hizo un solo pago en diciembre de 2017: por parte de Dª Cristina, 526€ y por partede D. José Pedro 486€. +++++DEUDA PENDIENTE: Dª CRISTINA 4736€ (en dos pagos de 2368€ cada uno); D. JOSÉ PEDRO 4378€ (en dos pagos de 2189€ cada uno). +++La comunidad también solicitó a la Junta de Extremadura ua ayuda para el cambio de ascensor por uno nuevo, para cada uno de los propietarios de los pisos, pero no han recibido respuesta todavía. En caso de concederla, eso reduciría la deuda de ambos hermanos. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2018-11-20','En relación con la Ejecutoria nº 643/2018, comunicamos al Juzgado de lo Penal 1, de Plasencia, que el centro médico adecuado para cumplir la medida de seguridad de internamiento sea el Centro Sociosanitario de Plasencia (Cáceres).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2018-11-20','(Pedro)Conversación con teresa, Directora de Asoc. Vera.927460598. Fax: 927037194 tras enviar el siguiente correo-e: +++++++Hola Pedro ,cómo está el problema de José Mª Morón Hernández , del Juzgado nos han informado que , os enviaron la Ejecutoria el día 05 de noviembre , están a la espera de vuestra contestación , entiendo que la Ejecutoria ha de resolverse rápido y, al parecer no hay comunicación por vuestra parte . José Mª , está inquieto y nervioso , anoche se metió con un compañero sin motivo ni razón y, estuvo a punto de ahogarle , cuatro personas necesitamos para separarle , un usuario de 149 Kg. , joven y con mucha fuerza , estamos expuestos a una desgracia anunciada . Se van a cumplir tres meses del juicio¿ Cúanto hay que esperar para que el traslado se lleve a efecto?Pedro por favor , Informarnos del proceso y, acelerar las cosas para que la Sentencia se cumpla Sabemos que este no es el Centro adecuado para Chema , estamos haciéndole flaco favor y, todos sufrimos las consecuencias Recibe un afectuoso saludo Buen día Teresa José A. Valverde Granado Asociación Vera Plena Inclusión ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Están muy preocupados con la situación y urge el traslado de José Mª. Al parecer no ha llegado al Juzgado el escrito de la Comisión proponiendo el traslado al CSS de Plasencia. Lo volvemos a enviar por fax.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2018-11-20','Enviamos a la Abogacía General la denuncia presentada por la Asociación Novaforma, ante la Fiscalía de Cáceres, contra D. José María Tovar y Dª. María José Pérez, por un posible delito regulado en el artículo 197 del Código Penal, para su estudio, por si procedieran interponer acciones civiles y penales como tutor y órgano que ejerce la protección, defensa y representación legal del incapaz D. Tomás Esteban Iglesias.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANGELES'and edp.apellido1='SANTOS'and apellido2='URBANO'),'2018-11-20','Se respeonde al correo de la Técnico PIA del pàsado 8 de noviembre (((((Buenos días, Dolores. Sí tenemos la tutela de Dª Mª Ángeles Santos Urbano (el primer apellido no es Santano, pero el DNI coincide). Por lo tanto, la negociación del PIA la debe realizar la Comisión Tutelar, por lo que te ruego que nos envíes la documentación al respecto para dicha negociación. Un saludo y que tengas buen día. El 08/11/2018 a las 10:49, Dolores Venegas Antequera escribió: > > Hola Buenos Días, me pongo en contacto con vocotros para saber si esta persona está tutelada por la Comisión , al parecer ha habido una revocación de la tutela del padre , el sr Antonio Santano , no he podido realizar la negociación del PIA , porque este señor dice " no querer saber nada , ni solicitar nada " , cuando podaís podeis mirarlo > Gracias , y buen día )))))) ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++No hemos recibido todavía respuesta del Juzgado sobre el expediente de jurisdicción voluntaria. Llamaremos para verel estado del tr´´amite. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Hablo con Toni (Futuex) para que realicen de nuevo visita a Dª Mª Ángeles.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CRISTINA'and edp.apellido1='VILLEGAS'and apellido2='SERRANO'),'2018-11-20','(Pedro)Se recibe el siguinete correo-e de D. JUlián Villegas, hoy a las 10:23h. ((((((habiendo sido informado por la trabajadora social del centro de salud Luis de Toro de Plaséncia Encarna Hurtado y de la trabajadora de Futuex, Alícia , de sus intenciones de trasladar a mi hermana María Cristina a una residencia para su cuidado y atenciones, les rogaría , que dado su estado de salud ,muy deteriorado por lo avanzado y extendido tumor que padece, QUE DESISTAN de hacerla efectiva, por que si como dicen y pronostican los médicos ,las expectativas de vida es muy corta, la familia y yo , como hermano y pendiente de ella las 24 horas del día, optamos y preferimos no movérla de su casa. Si en un momento determinado, su estado de salud precisa atención medica, tengo contratado el Servicio de Teleasisténcia de la Cruz Roja , así como la disponibilidad de los Servicios Médicos del Centro de salud que le corresponden. Trasladarla ya a un centro residencial ,fuera de su vivienda y entorno, la crearía angustia y malestar. Ella NO desea ni quiere ir a una residencia. Quiere que su hermano Julian siga atendiéndola. Mirando también por el tema económico , es mucho mas barato que siga atendida como hasta ahora, que el coste de una residencia. Con el servicio que esta recibiendo estos días , se cubren todas las atenciones necesarias que pueda necesitar. Espero entiendan nuestra petición y respeten su decisión de no sacarla de su domicilio . Para cualquier consulta o aclaración, pueden llamarme a mi telfono. Atte. Julian Villegas Serrano))))) +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Convresación con Toni (Futuex) sobre la opinión que tienen al respecto. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con Mireia de Cuidados Paliativos (629-885824. móvil corporativo). +++Fueron a la visita domiciliaria ella y Vicente, el Enfermero, (junto con Futuex) el pasado viernes, 16 de novimebre. +++CONCLUSIONES: Dª Cristina se encontraba mejor que en la visita del martes anterior: más animada, más espabilada y con mejor aspecto.LAS ÚLCERAS las examinaron y se nataba la mejoría al estar seindo tratadas por la Auxiliar de la empresa contratada. De todas formas, Vicente no solo las exámino sino que comprobó que el tratamineto se estuviese dispensando de manrea correcta, como así se verificó. +++++INGRESO: tanto Julián como Cristina refirieron que querían que esta permaneciese en todo momento en su domicilio y que no la sacaramos para llevarla a ninguna residencia. DEsde Cuidados Paliativos parece tener la opinión de que Julián se está ocupando adecuadamnet de su hermana, junto con el trabajo de "La Perla del Valle". +++++ASISTENCIA SANITARIA EN DOMICILIO: Miriam comenta que desde la Unidad de Cuidados Paliativos no se realizan ya visitas domiciliarias, salvo en ocasiones según su agenda. En caso de precisar dicha visita se tendrían que poner en contacto con ellos a través del Médico de Familia o, en caso de urgencia, a través del 112 si es fuera de horario. Hay siempore un médico de guardia en paliativos que puede ser avisado tanto por el médico de familia como desde el 112.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANGELES'and edp.apellido1='SANTOS'and apellido2='URBANO'),'2018-11-20','El Juzgado de 1ª. Instancia nº 2, de coria, dictó el 23/10 dictó el Auto autorizando el internamiento. Nos lo envían por fax.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VALLE'and apellido2='SIMON'),'2018-11-20','(Pedro)José María acude a la CTAEx, sin cita programada y con las siguintes demandas: +++Dinero para tabaco hasta que cobre a final de mes, porque se ha quedado sin dinero (se ha comprado unas gafas y un reloj). +++CIRCUNSTANCIAS: refiere que lleva más de dos días sin dormir y sin tomar la medicación. Ayer -dice- recorrió varios centros de salud para conseguirla y pidió que le ingresaran, pero no lo hicieron. +++++Refleja un aspecto muy desmejorado desde la última vez que acudió a la Comisión: pálido, muy delgado y falto de energía. +++PROPUESTA: se le hace ver el estado en que parece encontrarse y se le propone acompañarlo al Hospital para que lo valoren en la UHB. Acepta la propuesta, insisitiendo en que tiene que le demos dinero para tabaco.Ante su insistencia, le digo que una vez que le vea el psiquitra yo mismo le compraré ese paquete, como así hice después. +++EN EL HOSPITAL: la espera para ser atendido (que no fue excesiva) produjo en él una escalada de tensión que terminó obligando a la seguridad del hospital a intervenir. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con Agustina, Psiquiatra de UHB (81620): +++Ha pasado bien la noche pero con contención. +++Ha solictado la metadona al CEDEX poruqe cree que no la estaba tomando, que quizá le vendiera. +++También cree y la Comsión lo apoya, que debería estar en un centro..."pero la falta de recursos hace que se tarden menses en asignar plaza..." +++Trabajarán con él en esta dirección, la de que valore la posibilidad de ingresar voluntariamente en un centro. +++Prevé que se le dé el alta en unos días...y tendrtá que volver al piso. INSISTO en que traten de hacer todo lo psosible para que entre de nuevo en la red de salud mental. +++Mañana llamaré a Gema, T.Soc. (81638) para hablar del tema. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con Teresa, hermana de José Mª. Se le informa de lo tratatdo con la Psiquiatra.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2018-11-21','En relación con la Ejecutoria 231/2018 (procedimiento abreviado 155/2018) seguido en el Juzgado de lo Penal 1, de Cáceres, la abogada Verónica Moreno Durán, nos comunica que José Manuel ya ha pagado la multa de 150 euros impuesta. En cuanto a las cosas procesales no tiene que pagarlas al ser beneficiario de justicia gratuita.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='CALZAS'and apellido2='SANCHEZ'),'2018-11-21','Llama Sagrario de la Empresa de limpieza (tlf. 652 917 805) que va a casa de Mª Luisa, comenta que la chica que va al domicilio a limpiar ( Nunci 627 67 34 71) ve muy desmejorada y alterada a Mª Luisa, a las 5 de la mañana la ven deambular por Plasencia, no quiere ir a casa. Su hijo no se encarga de nada. Han desconectado un arcón congelador lleno de carne con lo que la vivienda huele a descomposición.','2');
