insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CONCEPCION'and edp.apellido1='FERNANDEZ'and apellido2='MUÑOZ'),'2018-11-22','(Pedro)Llama la hermana de Concepción diciendo que esta va a salir la semana que viene y quiere darle algo de dinero a la niña (sobrina) y que desde el CRR nos han mandado fax solcicitándolo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CRISTINA'and edp.apellido1='VILLEGAS'and apellido2='SERRANO'),'2018-11-22','(Pedro)Conversación con Vicente, enfermero del Equipo de Cuidados Paliativos (ecuipal)(78266). Tras la conversación, envío correo electrónico solcitando Informes Clínicos (ver expediente ordenador). +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++LLamada de Mireia (78175). +++Mañana acompañará al Psicólogo del Equipo para hacer una visita domiciliaria y valorar lo que en el informe solcitado se planteaba.Van a llamar a Alicia. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Pongo todo esto en conocimiento de Toni (futuex).','2');
