insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2018-11-26','En relación con la denuncia presentada por Novaforma, contra D. José María Tovar y Dª. María José Pérez y quienes pudiera resultar también implicados, por la comisión de un posibe delito tipificado en el artículo 197 del código penal, la Abogacía General de la Junta de Extremadura, nos indica que seamos nosotros quienes comuniquemos a Fiscalía que, tras la investigación del caso, se de traslado al Juzgado competente y en ese caso personarnos en defensa de los derechos de Tomás Esteban Iglesias. Enviamos escrito a Fiscalía.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='ROLLAN'and apellido2='SUAREZ'),'2018-11-26','(Pedro)Visita de Cristopher: +++Trae contrato de subrogación inter-vivos de la vivienda, pero hay un error en la rsolución que hay que subsanar. +++TELÉFONO DE CRITOPHER: 663-494324','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CRISTINA'and edp.apellido1='VILLEGAS'and apellido2='SERRANO'),'2018-11-26','- SE ARCHIVA LA DOCUMENTACIÓN ORIGINAL DE LA SOLICITUD DE PLAZA SOCIOSANITARIA, LO ENVIARON POR ADELANTADO POR EMAIL . ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Llegan (por fax 927-428343) los Informes Médicos, de Enfermería y Psicológico solicitados: ¿ES MÁS BENEFICIOSO PARA ELLA TRASLADARLA A UN CENTRO SOCIOSANITARIO O PERMANECER EN SU CASA HASTA QUE -COMO ELLA DICE- "...pase lo que tenga que pasar."?','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIO'and edp.apellido1='VAQUERO'and apellido2='PEREZ'),'2018-11-26','-SI HACEMOS EL CAMBIO PIA DE PRESTACIÓEN EN DEPENDENCIA , DEJAMOS LO DEL AYTO Y COGEMOS P.VINCULADA ÉL TENDRIA QUE ABONAR LOS PRIMEROS 6 MESES DE FORMA COMPLETA . A PARTIR DEL 6º MES ABONARIA COPAGO ENTRE 60 Y 90€ . TIENE 6000€ AHORRADOS PODRIA HACERLO . . TF DE JUANI AUXILIAR 666863893QUEDO PTE . CON ELLA QUE ME INDICARÁ SI FINALMENTE SE VA A LA EMPRESA Y EL PTO. DE ESTA LOS 6 MESES PRIMERO PARA SOLICITAR EL CAMBIO DE PIA. LA EMPRESA ES LA DE LA ASOCIOACION ONCOLOGICA TF 924207713/. PEDIR PTO. LE PIDO PTO. EL DIA 20 DEL 12 , ME LO ENVIARÁ AL EMAIL.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='ROLLAN'and apellido2='SUAREZ'),'2018-11-26','-HABLO CON NURIA VVDA. EL CONTRATO Y LA RESOLUCION VIENEN MAL , NOS LA ENVIARÁN CORREGIDA. ENTREGO LA DOMICILIACION BANCARIA A ALBERTO ( 23€ AL MES ) . - HAY UNA SENNTENCIA DEL JZDO PARA CITACION A JUICIO POR AMENAZAS A SARA Y SU PADRASTRO CON UNA NAVAJA. - VISITA CTAEX PARA SOLICITAR UN EXTRA , QUIERE IR A VER A SU HNA A MURCIA , ESTÁ INGRESADA EN EL HOSPITAL SEGÚN ÉL . A.D.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANDREA'and edp.apellido1='DAZA'and apellido2='REGALADO'),'2018-11-26','(Pedro) Tras recibir inofmración por parte de Ana Delfa y María Claros (directora y terapéuta del CRR de Badajoz)sobre la negativa de Dª Andrea parea ingresar en la UHB del HIC, hablo con ella para tratar de que entienda la conveniencia de dicho ingreso, tal como le recomendó su médico de Familia (aquejada de flebitis) y el Psiquiatra del ESM que gestionó su ingreo por Urgencias dado que él no podía tratar su xxxxxxxxxxx medicamentoso en medio ambulatorio, sino que tenía que ser tratado en medio hospitalario. +++Tras la conversación, Dª Andrea plantea esperar a ver como se encuentra en los próximos dos días, ya que tiene cita en el Médico de Familia el próximo miércoles 28.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MERCEDES'and edp.apellido1='PEREZ'and apellido2='PINNA'),'2018-11-26','-PERCIBE P.I.PTE.ABS DE 848€ , INCOMPATIBLE CON P.ORFANDAD . TENDRIA QUE OPTAR POR P.ORF +PFHC SI REUNIESE REQUISITOS . DE MOMENTO LA MANTEMOS CON LA QUE TIENE.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CRISTINA'and edp.apellido1='VILLEGAS'and apellido2='SERRANO'),'2018-11-27','(Pedro)ConverSación con Equipo de Cuidados Paliativos: +++Dra. Mª Ángeles Sánchez Pérez: en la visita realizada por el Enfermero y el Psicólogo el pasado viernes se pudo comprobar que Dª Cristina estaba muy bien atendida, orientada y manifestando su deseo de no irse a un centro. +++++Informe: "...que además de las dosis pautadas puede necesitar medicación extra a cualquier hora del día."Respecto a ello, D. Julián tiene instrucciones para darle 20 gotitas de Oloperidol como tratamineto de rescate. +++++En caso de que finalmente hubiese de ser trasladada, en caso de desorientación el tratamineto tambien sería con Oloperidol. +++++PRONÓSTICO: icialmente Mª Ángeles ha comentado que puede tener una esperanza de vida de poco más de un mes, pudiendo variar hasta unos pocos meses. En estas circunstancias, y salvo un empeoramiento brusco de las circusntancias tanto de salud como de atención, intentaremos mantenerla en su casa el mayor tiempo posible. +++Mireia (T. Soc.): hoy van a visitarla nuevamente ella y Vicente. Van a presentar a DOS VOLUNTARIOS (de la Plataforma del Voluntariado, a través de AOEx) para que vayan a estar con ella lunes, miércoles y jueves de 17 a 19h, liberando un poco a D. Julián durante este tiempo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2018-11-26','- LLAMOA A ADIEX ( EMPRESA SAD CACERES ) ACEPTO EL PTO. DE 195€ PARA 20 H EN CLAUSULA SUSPENSIVA , COPAGO 15€ . SOLICITO A LA EMPRESA CONTRATO A LA MAYOR BREVEDAD PARA MANDARLO A DEPEND.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='DELGADO'and apellido2='RODRIGUEZ'),'2018-11-27','-PIDO INFORMES A FUTUEX PARA VALORAR INGRESO , LA TS DEL SSB INDICA QUE LA SITUACIÓN ES INSOSTENIBLE EN EL DOMICILIO. AD','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAVID'and edp.apellido1='VITA'and apellido2='GIL'),'2018-11-27','Recibimos citación del Juzgado de 1ª. Instancia e Instrucción nº 1 de Zafra, para el día 5/12, a las 10:15. Solo es necesario que ese día le acompañe alguien del centro. El Juzgado le designa abogado de oficio.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PABLO'and edp.apellido1='GUTIERREZ'and apellido2='ALMARZA'),'2018-11-27','Se designa nuevo abogado en la ETJ 365/2004, seguida en el Juzgado de 1ª. Instancia e Instrucción nº 4, de Mérida. Juan Carlos Montalvo Frías.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SOFIA FLORENTINA'and edp.apellido1='COLLADO'and apellido2='ESTEBAN'),'2018-11-27','Autorizamos al Ayuntamiento de Guadalupe para que inspeccionen la vivienda sita en la Plaza de los Tre chorros, de Guadalupe, para que evalúen los daños de la vivienda y tomen las medidas oportunas para minimizar los daños. Le hacemos saber que Sofía dispone del 50% de propiedad, correspondiéndole el resto a Ana Esteban Guerrero (hermana de Cándida Esteban Guerrero, madre de nuestra tutelada), que según tenemos conocimiento era soltera y tuvo una hija, llamada Ana Esteban Guerrero, que a su vez tuvo dos hijos, Enrique y Ana Rabassa Esteban, esta última fallecida.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2018-11-27','(Pedro)Correo-e de Vera: +++Buenos días Pedro , termino de hablar con Eva , la chica del Juzgado , con relación al usuario José Mª Morón y , me comenta, que cómo le van a mandar al Complejo Sanitario de Plasencia , donde se encuentra luis ,el usuario que tiene orden de alejamiento Morón , han trasladado a Javier pero no a Luis , que son los dos usuarios que tiene orden de alejamiento , nuestro usuario Morón La notificación la tiene el Fiscal , pero está segura de que el Fiscal se va a negar a enviarle al Centro de Plasencia . Pedro , por favor , aclaradme el problema y, solucionemos de una vez este conflicto No dejemos que pase más tiempo Un abrazo Teresa Un saludo, José A. Valverde Granado Asociación Vera Plena Inclusión +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++A pesar de tener constancia del traslado de ambas víctimas a otros centros, llamo al CSS de Plasencia para confirmar el de D. Luis, como así me confirma Rosa que se efectuó el pasado 11 de octubre. +++Llamo a Teresa, Directora de Vera, y le confirmo que no existe motivo alguno para que José Mª sea trasalado al CSS de Plasencia cuando el Juzgado así lo indique.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CUEVAS'and apellido2='LOPEZ'),'2018-11-27','El CSS de Mérida comunican salida terapéutica el día 28 de noviembre, supervisada y organizada por el servicio de Laborterapia. Se ha comunicado desde el CSS al Juzgado Vigilancia penitenciaria nº 1 de Badajoz.','2');
