insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CRISTINA'and edp.apellido1='VILLEGAS'and apellido2='SERRANO'),'2018-11-27','Futuex comunica a esta Comisión que D. JUlián Villegas ha informado de que han coretado la luz en el docmicilio. +++En contacto con el banco nos informan de que no hay recibos pendientes de pago.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CRISTINA'and edp.apellido1='VILLEGAS'and apellido2='SERRANO'),'2018-11-28','+++Puestos nuevamnete en contacto con la entidad bancaria confirman que no existen recibos pendientes y que el último abonado lo ha sido el 13 de noviembre. +++En contacto con Iberdrola, nos informan igualmente que no se ha producido ningún corte de luz en dicho domicilio y que no existen recibos pendientes de pago. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Se contesta al correo-e remitido por los SSB de Plasencia, inofrmando de la situación y solcitando informes sobre ambos hermanos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CRISTINA'and edp.apellido1='VILLEGAS'and apellido2='SERRANO'),'2018-11-27','Futues comunica a esta Comisión que D. Julián le ha informado de que han cortado el suministro eléctrico en el docmicilio (también lo ha puesto en conocimiento de Servicios Sociales). +++Puestos en contacto con el banco nos informan de que no hay ningún recibo pendiente de pago.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CRISTINA'and edp.apellido1='VILLEGAS'and apellido2='SERRANO'),'2018-11-27','Futuex informa a última hora de que ha recibido comunicación de D. Julián respecto a un corte de suministrto eléctrico que se ha producido en el domicilio. +++En contacto con el banco, nos informan que no hay pendiente de pago ningún recibo ni tampoco devolución de ninguno.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RICARDO'and edp.apellido1='ROCHA'and apellido2='BARCO'),'2018-11-28','Enviamos a Curro, de Abogacía General, toda la documentación para que solicite autorización judicial de venta de inmueble.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CONCEPCION'and edp.apellido1='CANELADA'and apellido2='GARCIA'),'2018-11-28','(Pedro)Llamada de Amparo, Directora del Cuartillo. +++Al parecer, desde SSB están planetando la psoibilidad de que Dª Concepción pueda recuperar la capacidad perdida: quiere vivir con su marido, se maneja bien... +++SE le informa de que si los informes al respecto consideran que han desaparecido las causas que motivaron la incapacitación (en la sentencia se definen como permanente e irreversibles) y la fiscalía lo considera igualmente, se podría plantear dicho procedieminto . +++Dª Concepción, por otro lado, se encuantra perfectamente en al residencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN LUIS GUILLERMO'and edp.apellido1='REINA'and apellido2='GOMEZ'),'2018-11-28','(Pedro)Llama Ana, T. Soc. Hospital Tierra de Barros (89325). +++Le ha dicho que D. Juan Luis está tutelado por la Comiisón y necesita la firma de consentimento inofrmado para hacerle pruebas. +++Se le informa que la Comisión solamente está nombrada como Defensora Judicial para al Administración de Bienes, por lo que, legalmente, el tien cpacidad para dicha firma.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2018-11-28','(Ángel)Conversación con Eva, Juzgado Penal 1 de Plasencia. +++Esperar a la contestación del Juzgado tras informe positivo de Fiscalía, para ejecutar el traslado de José Mª al CSS de Plasencia. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++(Pedro) Conversación con Teresa (A.Vera): +++Reconocimiento Forenese solicitado por el Juzgado de 1ª Instancia e Instrucción nº 3 de Plasencia en las DPA 0000600/2018 (agresión).FECHA: 13 DE DICIEMBRE DE 2018. +++Traslado: como la vez anterior, intentaremos que sea Futuex quien lo acompañe al reconocimiento, si no se ha producido antes SU TRASLADO AL CSS DE PLASENCIA PARA CUMPLIMIENTO DE medida de internamineto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONCEPCION'and edp.apellido1='ALEJANDRO'and apellido2='DIAZ'),'2018-11-29','(Pedro)Llamada de Mar, T. Soc. ESM Ciudad Jardín(41522). +++Planteo las siguinetes alternativas: +++++Ingreso en Agudos: no existe motivo para ello. +++++Realizar Informe con incidentes y recomendación de recurso a palicar dirigido al Juzgado y a la CTAEx. +++++Convocar Subcomisión de Casos: Subdirección de Salud Mental, ESM, UHB de Badajoz, CRR de Mérida, Unidad de PP. Asistenciales (Sección de Salud Mental), Comisión Tutelar y cualquier otro servicio que se considere oportuno.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SAUL'and edp.apellido1='RODRIGUEZ'and apellido2='RAMOS'),'2018-11-29','En relación con la herencia de la madre, hemos enviado documentación a Notaría de Barcarrota para formalizarla.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CRISTINA'and edp.apellido1='VILLEGAS'and apellido2='SERRANO'),'2018-11-29','(Pedro)Llamada de Dª Flor Felipe Vega (927-413874 y 617-617-423) en respresentación de su padre D. José Felipe Prieto (propietario del Hostal "La Muralla"). +++Interesados en COMPRAR LA COCHERA de la C/ Esparrilla nº ¿3? de Plasencia. Al parecer, se han enterado por "...el abogado que les llevaba los papeles..." de que está en venta y sus padres están intersesados en comprarla. +++Anoto su interés en ello llegado el caso.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE PEDRO'and edp.apellido1='VILLEGAS'and apellido2='SERRANO'),'2018-11-29','(Pedro)Llamada de Dª Flor Felipe Vega (927-413874 y 617-617-423) en respresentación de su padre D. José Felipe Prieto (propietario del Hostal "La Muralla"). +++Interesados en COMPRAR LA COCHERA de la C/ Esparrilla nº ¿3? de Plasencia. Al parecer, se han enterado por "...el abogado que les llevaba los papeles..." de que está en venta y sus padres están intersesados en comprarla. +++Anoto su interés en ello llegado el caso.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VALLE'and apellido2='SIMON'),'2018-11-29','(Pedro)Acudo a la UHB de Mérida. Me reuno con Agustina (Psiquiatra) y con José Mª. +++Pide disculapas por su comporatmiento de hacxe una semana y me pide que borre esa imagen de él. +++Le entrego la llave del piso que nos ha proporcionado D. Pedro Herrera (676-597609) con las siguientes indicaciones: +++++Debe hacer una copia, probarla y después entregar en la Comisión una de ellas para devolverla al dueño. +++++Debe pedir al presidente de la comunidad copia de la llave de la puerta de la calle. +++DINERO: acudirá mañana al banco por extra de 70€ para el fin de semana y la semana que viene podrá sacar lo que le corresponde del mes. +++MÉDICO: el ALTA SE LA DAN MAÑANA, 30 DE NOVIMEBRE. Con el Informe de Alta tiene derivación al CEDEX y al ESM(con éste tiene cita el 14 de nero). +++++DEBE ACUDIR A SU MÉDICO DE CABECERA (URB. II) para control por orina en sangres. +++FUTUEX.aCOMPAÑARÁ A jOSÉ mª EN TODOS ESTOS TRÁMITES. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++TELÉFONO DE JOSÉ Mª: 644-896829','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CATALINA'and edp.apellido1='MIRANDA'and apellido2='ROSADO'),'2018-11-29','(Pedro)Gestiones sobre el alquiler de la vivienda. +++El alquiler que ya estaba pendiente de firma no se ha podido llevar a término por renunciar a ello la propietaria del piso. +++Intentamos alquiler con D. Aquilino, pero el otro piso que tiene está en Badajoz y ya alquilado. +++Hablo con el actual casero de Catalina para pedirle un aplazamineto para dejar la vivienda y, tras alguna reticencia, acepta retrasarlo hasta el martes que viene. +++Futuex acudirá mañana a ver otra vivienda que es posible se pueda alquilar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONCEPCION'and edp.apellido1='ALEJANDRO'and apellido2='DIAZ'),'2018-11-30','(Pedro)Llamada del HIC. Rubén, Enfermero (48759) Urgencias. +++Tiene allí a Concepción. Quiere hablar con la Comisión: +++++Quiere que el dienro que puede sacar del 1 al 15 se lo autoricemos a "su marido" para que ella se pueda tomar un café. +++++INGRESADA POR INSUFICIENCIA RESPIRATORIA desde hoy. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Hablo con Mª José, T. Soc. HIC: Ya era conocedora del ingreso. +++Le pido que intente, ahora que está ingresda, hacerle ver que su situación actual es mucho peor que cuando estaba en el CRR, que ya no es el primer ingreso que tiene por el mismo motivo y que debería volvber a vivir en un centro para estar bien atendida.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ABEL'and edp.apellido1='PEREZ'and apellido2='GARRIDO'),'2018-11-30','ARCHIVO Se archiva el expte. tras recibir la sentencia de apelación de la Aud. Prov., Secc. 1ª., de Cáceres. En ella se revierte la sentencia del Jzdo. de Instrucción, dejando sin efecto la incapacitación.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2018-11-30','(Pedro)José Mª fue trasladado en el día de ayer, 29de novimebre, al CENTRO SOCIOSANITARIO DE PLASENCIA por orden del Juzgado de lo Penal nº 1 de Plasencia. +++SE envía por fax la citación que el día 13 de NOVIemBRE, a las 10:00h, tiene en el Juzgado de 1ª Instancia e Instrucción nº 3 de Plasencia para RECONOCIMEINTO FORENSE.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VALLE'and apellido2='SIMON'),'2018-11-30','(Pedro)Alta Hospitalaria de UHB Mérida hoy, 30 de noviembre de 2018. +++INFORME DE ALTA ESCANEADO en su expediente. +++Han encontrado las pertenencias que le faltaban. +++Ha pasado por CEDEx tras venir a la Ctaex. +++Trato de localizarlo para decirle que pase a por sus cosas por el Hospital, pero una de las pertencias estraviadas era el móvil. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Acude Susana a la Comisión por otro caso. Se acercará a casa de José Mª e iran juntos al Hospital a por sus cosas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN ANTONIO'and edp.apellido1='SANCHEZ'and apellido2='SANTIAGO'),'2018-12-03','-NUEVO INGRESO EN UHB , DESCOMPENSACION ASOCIADO A CONSUMO DE ALCOHOL . LLAMA LA TS ( TONI ) CONSIDERAN NECESARIO IGRESO EN CTRO. RESIDENCIAL DE MAYORES . AL SER CURATELA NO PODEOS SOLICITAR INT. INV. SE LE PIDE INFORMES PARA SOLICITAR AUMENTAR SU INCAPACIDAD Y ASI SOLICITAR INTERN. LE PIDO A FUTUEX VALORACIAON DE LA SITUACION. A.D.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA'and edp.apellido1='DELGADO'and apellido2='ROMERO'),'2018-12-03','-LLAMA LA DTRA. DE ROSALBA Y TS. LA FAMILIA ESTÁ ALLÍ SOLICITANDO SUS PERTENENCIAS E INFORMACION DE LAS CUENTAS . LA RENDICION ANUAL PRESENTADA EN JUNIO NO ESTÁ APROBADA AÚN. LOS DERIVO AL JDO. SI TIENEN ALGUNA OBJECIÓN . AD','2');
