insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO'and edp.apellido1='MENDO'and apellido2='RODRIGUEZ'),'2018-12-03','-APROBADA P.ORFANDAD 200€ . DENEGADA LA DE ALEMANIA DONDE NO EXISTE ESTA PENSIÓN SUPERADOS LOS 27 AÑOS. APROBADA PFHC DE 570.20€ . SE PONE PARA FIRMA LA OPCION , ME QUEDO CON LA PFHC. -CON LA PNC ACTUAL SALE EN 7767€ -CON LA PFHC 6840+ P. ORF 2400= 9240€','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AURORA'and edp.apellido1='PAREJO'and apellido2='MORENO'),'2018-12-04','(Pedro)Se envía por fax al Juzgado de 1ª Instancia nº 1 de Villanueva de la Serena, contestación a la Comparecencia que Dª Aurora realizó el pasado 29 de noviembre ante ese Juzgado solcitada por éste en Diligencia de esa misma fecha.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUISA'and edp.apellido1='RODRIGUEZ'and apellido2='GRAGERA'),'2018-12-04','(Pedro)Llama su hermana Mercedes preguntando por los trámites de la herencia, si hermos recibido algo del Juzgado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUCIANO'and edp.apellido1='GARCIA'and apellido2='GARRIDO'),'2018-12-04','TRASLADO A URGENCIAS El 04/12/2018. "Se comunica a esa Comisión Tutelar de Adultos que el intero D. Luciano..., ingresado en este Centro (CSS de Mérida) y tutelado por esa Comisión, será trasladado al servicio de urgenias del HME, en fecha 04/12/2018."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2018-12-04','LIQUIDACIÓN DE CONDENA (Proc. de Origen 206/2018): +++2 años y 6 meses (910 días). +++++INICIO....: 29 DE NOVIEMBRE DE 2018 +++++FINAL.....: 26 DE MAYO DE 2021','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='YOLANDA'and edp.apellido1='CALDERA'and apellido2='MARTIN'),'2018-12-04','Correo-e de Apba. 9: Buenos días Pedro Por la presente te informo que la tutelada YOLANDA CALDERA MARTIN ingreso en la UDAC con fecha 28/11/18. El traslado lo realizó en compañía de Iván Garrido y Rocío Ruiz, psicólogo y cuidadora de referencia respectivamente. Con respecto a la actitud de Yolanda destacar que previamente conocía su traslado y el motivo e ingresó muy motivada y contenta. Atentamente Maribel Rivera Coordinadora del área residencial de Inclusives','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUIS MIGUEL'and edp.apellido1='MUÑOZ'and apellido2='SANCHO'),'2018-12-05','En relación con la responsabilidad civil relacionada con la condena que está cumpliendo en la cárcel de Madrid, hablamos con el abogado, Francisco Elías (606529869), debido a la preocupacion que le ocasiona a Luis Miguel por este tema. El abogado nos indica que al no disponer Luis Miguel de patrimonio ni de pensión superior al SMI, es insolvente. Será el Juzgado quien realice las averiguaciones oportunas para poder exigirle a Luis Miguel el pago de la responsabilidad civil, en el caso que viniera a mejor fortuna. La responsabilidad civil es solidaria, hay otro condenado. Nos comenta también que al irse a Madrid, el turno de oficio trasladó su expediente a Madrid y que el abogado designado dejó pasar el plazo para interponer el Recurso de Amparo, necesario para poder recurrir al Tribunal Europeo de Derechos Humanos, debido a que el abogado Francisco Elías, insiste en que la condena es excesiva.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='CANELADA'and apellido2='DEL RIO'),'2018-12-07','(Pedro)Acudo a Consultas Externas de Cirugía General, Servicio de Cirugía General y Digetsiva del Hospital "Nuestra Señora de La Montaña". +++Firma de consentimeinto informado para intrervención y laparoscopia. +++Entrego la siguiente documentación: Delegación de firma (queda copia en el expediente), Sentencia de incapacitación y aceptación del cargo. +++PENDIENTE: citarla para varias pruebas previas a la consulta de anestesista, a la que deberá nueavmente ir la Comisión para información y firmna de consentimineto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAIRO'and edp.apellido1='PUERTAS'and apellido2='MARTIN'),'2018-12-07','(Pedro) Conversación con Mariví, T. Soc. del CSS de Plasencia. +++La pretencisión de Jairo sobre la herencia de su abuela es otra de sus "fantasías". Conocíamos a su abuela y la mujer solamente tenía la casa que quemó Jairo y poco más. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Previa a la convesración comprobamos en el catastro las propiedaddes que figuran a nombrede la abuela: una casa de 36m cuadrados y una parcela de menos de 1/2 hectárea.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAIRO'and edp.apellido1='PUERTAS'and apellido2='MARTIN'),'2018-12-04','(Pedro)Conversación con Rosa (CSS de Plasencia). Jairo pregunta por la herencia de su abuela. +++Datos familiares: +++++ABUELA:Dª Esperanza Martín Cervigón (DNI: 7.453.990-N). Domicilio en C/ Medio 3 de Marchagaz. Fallecimiento: 22-01-2018 (Hospital de Coria). Vivía en la Residencia de Ancianos de Villasbuenas de Gata. +++++MADRE: Dª PIlar Puertas Martín. Fallecimiento: 05-10-2013. Lugar: Marchamaz.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE PEDRO'and edp.apellido1='VILLEGAS'and apellido2='SERRANO'),'2018-12-07','(Pedro)Convoco reunión con D. Francisco de Sales Villegas Serrano para el próximo miércoles, 12 de diciembre, a las 10:00h en las dependencias de la Comisión Tutelar.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CRISTINA'and edp.apellido1='VILLEGAS'and apellido2='SERRANO'),'2018-12-07','(Pedro)Convoco reunión con D. Francisco de Sales Villegas Serrano para el próximo miércoles, 12 de diciembre, a las 10:00h en las dependencias de la Comisión Tutelar. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con la Dra. Maite (33413), del Servicio de Cuidados Paliativos. +++En estos momentos Dª Cristina se encuentra muy estable. NO REQUIERE ACOMPAÑAMIENTO. +++Han hablado con D.Julián, su hermano, respecto a la necesidad de mantener ingresada a su hermana si él se encontraba desbordado. Ha reconocido que necesitaría más apoyo pero no se ha opuesto a la idea de que ingrese en un Centro. Sí pide que sea en Plasencia o Malpartida para poder ir a verla. +++En estos momentos, el pronóstico inicial en cuanto a esperanza de vida cabe considerar que ha mejorado dentro de la gravedad. +++HORARIO de VISITAS: por la tarde, de 17 a 20h. Hablaré con Puerto sobre la posibilidad de que D. José Pedro quiera acudir a ver a su hermana, ya que, según Maite, este sería un buen momento porque Dª Cristina se encuentra muy estable. +++Ruego que, dado que ya Dª Cristina refiere que con este nuevo ingreso supone que no va a volver al domcilio -según refier Maite- hagan todo lo posible desde el punto de vista psciológico para que dicha situación, un avez llegue, sea lo menos traumática posible. +++PLANTEAMIENTO ACTUAL: MANTENER EL INGRESO EN CUIDADOS PALIATIVOS HASTA SU TRASLADO A PLAZA SOCIOSANITARIA, tratando de agilizar todo lo posible dicho trámite. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con Pedro (927-004261)del Servicio de Atención a Mayores. +++Dª Cristina se encuentra la PRIMERA DE LA LISTA DE ESPERA para plaza T3 en todos los centros de la provincia de Cáceres, y, con las dificultades obvias para calcular plazos, es posible que la próxima semana se pueda producir el traslado. +++Ruego que, siendo prioritario dicho traslado, se tenga en cuenta la proximidad a Plasencia. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con Puerto, Directora del Hogar de Nazaret. +++PLAZA RESIDENCIAL: han hablado con D. José Pedro y está de acuerdo con quedarse en plaza residencial en el Hogar voluntariamente. La semana que viene pediré a Futuex que acompañe a D. José Pedro en la firma del contrato. +++VISITAS A SU HERMANA. Él nunca lo ha pedido, pero su hermano D. Julián sí que ha dicho que por qué no lo llevábamos a ver a su hermana. También la semana que viene plantearemos dicha visita con Futuex. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con Futuex. Alicia. +++Contrato: acudirá el martes para que D. José Pedro lo firme y lo remitan a a la Comisión. +++Visitas: acompañará también a D. José a ver a su hermana. Avisaremos al taxista para ello.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL MANUEL'and edp.apellido1='AGUADO'and apellido2='JIMENEZ'),'2018-12-07','(Pedro) llamada de D. José Mª Flores, de la Residencia "Los Olivos" de Mérida (924-310755). +++Les ha llegado la sentencia 179/2018 en la que nombran a la Comisión Tutora de D. Ángel (NO HA LLEGADO A LA COMISIÓN?) +++Refiere que tiene una hermana en Madrid de más de 80 años y unas cuñadas quie lo han dejado en la Residencia y se han marchado, sin dejar DNI, sin saber si tiene o no seguro de deceso, etc. +++Se le explica el funcionamineto de la Comisión Tutelar y los trámites iniciales que, una vez que nos llegué la sentencia, iniciaremos. +++T. Soc. de referencia: Cecilia Santander.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE PEDRO'and edp.apellido1='VILLEGAS'and apellido2='SERRANO'),'2018-12-07','(Pedro)Convoco reunión con D. Francisco de Sales Villegas Serrano para el próximo miércoles, 12 de diciembre, a las 10:00h en las dependencias de la Comisión Tutelar. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++(Pedro) Conversación con Puerto, Directora del Hogar de Nazaret. +++PLAZA RESIDENCIAL: han hablado con D. José Pedro y está de acuerdo con quedarse en plaza residencial en el Hogar voluntariamente. La semana que viene pediré a Futuex que acompañe a D. José Pedro en la firma del contrato. +++VISITAS A SU HERMANA. Él nunca lo ha pedido, pero su hermano D. Julián sí que ha dicho que por qué no lo llevábamos a ver a su hermana. También la semana que viene plantearemos dicha visita con Futuex. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con Futuex. Alicia. +++Contrato: acudirá el martes para que D. José Pedro lo firme y lo remitan a a la Comisión. +++Visitas: acompañará también a D. José a ver a su hermana. Avisaremos al taxista para ello.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO'and edp.apellido1='MENDO'and apellido2='RODRIGUEZ'),'2018-12-11','-OPTO POR PFHC , LO PONGO EN REGTO. ENTRADA CAISS MERIDA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIO'and edp.apellido1='VAQUERO'and apellido2='PEREZ'),'2018-12-11','-PONGO PARA FIRMA CAMBIO DE PIA. LA AUXILIAR ESTARÁ POR EL AYTO POSIBLEMENTE HASTA FEBRERO , LUEGO SE HARÁ EL CONTRATO CON LA EMPRESA DE AYUDA A DOMICILIO DE ASOCIACIÓN ONCOLOGICA. YA TENGO EL PTO . CON LAS 20H /MES Y SERIAN 210€.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2018-12-11','-VIENE A LA OFICINA EL DUEÑO DEL TORERO , ATI SALIÓ EL DOMINGO 9 DESPUES DE DESAYUNAR Y NO HA REGREASADO AL HOSTAL . SUS COSAS SIGUEN ALLÍ. AD','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='BERNARDO'and apellido2='PIRIS'),'2018-12-11','(Pedro) Llamada de Mariví, T. Soc. del CSS de Plasencia. +++Dª Antonia ha enviado un escrito a la Casa Real exponiendo su situación. +++Nos ha enviado por fax y por correo-e el acuse de recibo. +++Si se pide algún informe a la Comisión, SOLICITAR INFORME MÉDICO al CSS para adjuntar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2018-12-11','(Pedro) Se recibe del CSS de Plasencia CITACIÓN JUDICIAL del JUzgado de 1ª Instancia e Instrucción nº 3 de Plasencia, AUX. JUCICIAL NACIONAL 201/2018. +++Se le cita como investigado por un presunto delito de v. de g. +++Solicita el Auxilio Judicial el Juzgado de 1ª Instancia e Instrucción nº 4 de Mérida. DILIGENCIAS PREVIAS. D.P. 64/2018. +++++Teléfonos Mérida: 924-387374/75. Fax: 924-304313. +++CITACIÓN: 18 DE DICIEMBRE a las 10:10h. +++VIDEOCONFERENCIA. Llamo a ambos Juzgados para ver la posibilidad de que la Comisión pueda asistir también por videoconferencia desde Mérida. NO HAY PROBLEMA POR PARTE DE NINGUNO DE LOS JUZGADOS. +++++DEBEMOS COMUNICAR POR FAX que la Comisión se presentará en Mérida para asistir por videoconferencia. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con Mariví, T. Soc. del CSS de Plasencia, en realción con el siguinte correo-e: +++CORREO-E:En relación nuevamente con J. Manuel, ha solicitado permiso su hermano para que pueda pasar las navidades en casa, del 22/12/18 al 2/01/19. Como habrá que solicitar al Juzgado de Vigilancia dicho permiso, queríamos consultas con vosotros, tutores, si no existe inconveniente por vuestra parte. Desde el punto de vista clínico, el Psiquiatra considera que no existe problema. +++Pido a Mariví que nos envíe la autorización que comenta el correo-e, indicando en ella que desde el punto de vista clínico no hay ningún inconveniente en dicha salida y que es positiva desde un punto de vista terapéutico. En cualquier caso, para su firma o no ESPERAEMOS A QUE TENGA LUGAR EL JUICIO ANTES REFERIDO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2018-12-11','(Pedro) Llamada de Mariví, T.Soc. del CSS de Plasencia. +++Solicita por correo-e dinero de bolsillo para José María. Lo reenvío a Alberto y cosnulto con Belén (pendiente de extra de 80€).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALMUDENA'and edp.apellido1='CORREYERO'and apellido2='PAREJO'),'2018-12-11','(Pedro) Visita no programada de D. Antonio, padre de Dª Almudena. Plantea los siguintes temas: +++VESTIMENTA: en su última visita la ha visto muy desaliñada, calzando zapatillas de estar por casa. Cree que debería presentar mejor aspecto. +++PABELLÓN: considera que no está en el adecuado. Respecto a ello, son los médicos los que tienen que determinar cuál es el pabellón adecuado. +++HABLAR CON EL CSS sobre ambos temas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DOLORES'and edp.apellido1='FERNANDEZ'and apellido2='BAEZ'),'2018-12-11','(Pedro)Visita programada.Peticiones. +++Quiere 200€ para estas Navidades. +++No quiere gastar más deinero en su piso, sino venderlo y comperar una "casita para estar allí con mi hermano..." +++No tien suficiente con el dinero que tiene para sus gastos (32€/mes). Se le trata de hacer ver que ese dinero es para sus gastos, pero después de que no tiene que pagar ni alojamiento, ni manutención, ni agua, ni luz, ni impuestos, etc...como sería el caso si estuvies een su casa. +++Pongo a Gisela al tanto de la reunión.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2018-12-11','(Pedro)Visita programada.Peticiones. +++Quiere comparse unos botines que valen 60€ más o menos y en el Centro no le dejan. +++Se le hace ver que puede comprarlos de su asignación mensual, 350€, pero ella dice que eso es para sus gastos (café, desayuno, comida, etc.) +++Pongo a Gisela al tanto de la reunión.','2');
