insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='FAUS'and apellido2='LEMUS'),'2018-12-12','-LLAMA SU TIA ASUNCION ( 924109808/620436620) PARA COMENTAR QUE HA BUSCADO UN ABOGADO DE OFICIO Y UN PROCURADOR PARA QUE DEFIENDA A RAFAEL EN LA DENUNCIA QUE HA PRESENTADO AL QUE LE GOLPEÓ LOS DEDOS CON LA CATANA . - HA TENIDO UN JUICIO POR EL QUE LE SANCIONARON CON 3 MESES DE CÁRCEL PERO COINCIDIÓ CON LOS 15 DÍAS QUE HA ESTADO INGRESADO EN UN CENTRO DE DESINTOXICACION ( AGUADA DE ARCA DE NOÉ ) Y ELLA CREE QUE NO SE LO VAN A PEDIR . -ESTÁ PENDIENTE DE OTRA OPERACIÓN EN LOS DEDOS , EL DIA 20 VUELVE AL MÉDICO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2018-12-12','(Pedro) Llega a la Comisión Tutelar resolución de la D.G. de Políticas Sociales y Familia en relación al acogimineto familiar de la hina de Beatriz: +++Cese del acogimiento familiar de fecha 07-12-2017. +++Formalización de nuevo acogimiento de urgencia con nueva familia de acogida. +++SE cambia el punto de encuentro de Don Benito a Badajoz. (ya se comunicó al centro y a Futuex el pasado martes 4 de diciembre).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN ANTONIO'and edp.apellido1='SANCHEZ'and apellido2='SANTIAGO'),'2018-12-12','-NOS INFORMA LA TS DE LA UHB LLERENA Q J.A. NO PUEDE REGRESAR A CASA , NECESITA AYUDA PARA TODAS LAS AVD , ÉL VOLUNTARIAMENTE QUIERE INGRESAR EN R.MAYORES . LLAMO A COMSER ALMENDRALEJO , LA PLAZA SUBE A 1639€ COMPARTIDA . LLAMO A LA R.M . HOGAR DE SAN JOSÉ DE AZUAGA . TF 924890104 , FÁTIMA ES LA TS. ESTA SEMANA NO ESTÁ , HABLO CON LA MADRE SUPERIORA QUE ME DICE QUE SE ACERCARÁN AL HOSPITAL A VER A J.A. PARA VALORAR SU POSIBLE INGRESO .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='CONTADOR'and apellido2='MATEOS'),'2018-12-13','(Pedro) Correo-e recibido de Futuex. +++Adjunto un breve informe de Manuel Contador Mateos. Hemos recibido llamada de una de las hermanas (Mª José) para comunicar que no tenían noticias de él en todo el fin de semana. Cuando llegaron ayer lunes 10, por la mañana, se lo han encontrado tirado en el suelo y en lamentables condiciones. Ha quedado ingresado en UCI del hospital universitario de Badajoz. No saben el motivo exacto de que estuviera en el suelo y sin tomar líquidos, por eso está con una grave insuficiencia renal en estos momentos.Se le han realizado algunas pruebas y un TAC craneal y no tienen un diagnóstico. Que la vivienda estaba en malas condiciones de limpieza, nada de alimentación, solo latas en el frigorífico. Todo esto es algo que venimos observando, ya desde el inicio, se tenía la duda de que pudiera vivir solo. Ellas dicen que alcohol no bebe, pero es que con ellas solo come una vez en semana, como mucho. El resto del tiempo está solo y hace lo que quiere. No podemos constatar si continúa bebiendo, almenos mantenemos ciertas reservas, porque lo hemos encontrado alguana vez en Badajoz, en un bar en concreto, en un estado suceptible de interpretarse como que si estaba bebiendo. El inofrme adjunto está en el expediente de D.Manuel. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con Futuex sobre la situación. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con Mª José, hermana de Manuel (629-785581). En estos momentos está esperando hablar con el Médico. +++CIRCUNSTANCIAS: +++++Día 7 diciembre. Acude 4 veces a Urgencias: 3 al HIC y 1 al Perpetuo Socorro donde le ponen una inyección. Al llegar a casa se encuentra muy mal, pierde la conciencia. Mª José lo ha estado llamando durante el fin de semana pero al no contestar acude a su casa y lo encuentra en el suelo, donde al parecer ha estado desde hace tres días, con una tetraparesia y un elevado grado de obnubilación. +++Debemos interrumpir la conversación porque van a informarle de la situación de su hermano. +++Retomamos la conversación. +++++DIAGNÓSTICO: ENCEFALITIS AGUDA DISEMINADA que ha dado lugar a la tetraparesia. +++++Mañana le hacen una Resonancia y hoy parece que había recuperado algo de tono muscular y algo de fuerza.Seguirá en UCI. +++CORREO ELECTRÓNICO DE MARÍA JOSÉ: contador.mariajose@gmail.com','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALMUDENA'and edp.apellido1='CORREYERO'and apellido2='PAREJO'),'2018-12-13','(Pedro)Conversación con Blanca (24012) del CSS de Mérida sobre la reunión mantenida con el padre de Almudena. +++SE informará sobre los aspectos de ropa y calzado, que muchas veces están en función de la comodidad de los pacientes.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MINERVA'and edp.apellido1='MARTIN'and apellido2='BLANCO'),'2018-12-13','(Pedro) Conversación con Ana, T. Soc. de Aprosuba 7. +++Le pido que citen a D. Víctor mediante carta dirigida a él y que se la entreguen con Minerva cuando vayan a recogerla al Centro, indicando que la reunión será en el SEPAD, el miércoles 19 de diciembre a las 10:30h. +++Desde Comisión, acudirá Futuex al doimicilio para informa de dicha reunión personalmente. ( PEDIDO EL DIA 13 ) ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++NUEVOS TELÉFONOS DE D. VÍCTOR: 663-554068 Y 924-144473. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Hablo con su mujer y le indico día, hora y lugar para mantener la reunión. D. Víctor está acostado, convaleciente. Volveré a llamar. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++HABLO DIRECTAMENTE CON VÍCTOR Y LE COMUNICO EL LUGAR ,DÍA Y HORA DE LA REUNIÓN, insitiendo en la importancia de la misma.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MURILLO'and apellido2='ROMANO'),'2018-12-13','-SE ENVIA A PNC SENTENCIA Y ACEPTACIÓN DEL CARGO . TIENEN EXPTE PNC PERO NOSOTROS NO LO HEMOS INICIADO . QUEDO PTE. ENVIARLES EL MODELO ALTA 3º CON LA NUEVA CUENTA , LO HE PEDIDO A LA PARTE EC. ESTÁN PTES DEL INVENTARIO . A.D.','2');
