insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VANESA'and edp.apellido1='FERNANDEZ'and apellido2='GOMEZ'),'2018-12-13','-LE ENVIO SENTENCIA DE INCAPACIT. SOLICITADA. AD','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2018-12-13','(Pedro) Conversación con Mercedes Rubio y Mª Ángeles, de Plena Inclusión Llerena. +++La primera visita al punto de encuentro de Badajoz fue el viernes, y aunque se mosotró un poco preocupada porque la niña estaba un poco molesta del estómago después se puso muy contenta por estar con ella. +++Recibido correo de Urbano (DG de Infancia y familia) indicando que ya ha salido la sentencia en relación al recurso presentado por la Junta sobre la custodia de la niña, y al parecer le han dado la razón a la abuela. Informo de ello al centro, indicando que debemos recabar más información al respcto. +++VACACIONES DE NAVIDAD: plantean la posibilidad de que salga con su padre del 21 al 31 de diciembre, porque así podría ir con Futuex y volver con su padre. A la comisión le parece que son demasiados días, que con que fueran los día de Navidad (21-26) sería suficiente. también el centro lo cree y van a intentar que sea así. hablarán con el padre para vber si la puede llevar de nuevo al centro el 26 o 27.','2');
