insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONCEPCION'and edp.apellido1='ALEJANDRO'and apellido2='DIAZ'),'2018-12-14','(Pedro)Llama Mar desde el ESM de Ciudad jardín, donde ha vuelto a acudir Concepción. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ +++TELEFÓNO DE CONCEPCIÓN: 603-683476. +++La llamo nuevamente. Se autoriza extra de 100€ para el lunes 17 de diciembre.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CRISTINA'and edp.apellido1='VILLEGAS'and apellido2='SERRANO'),'2018-12-14','(Pedro)Llamada de Plácido. +++Hay plaz asociosanitaria en Sierra de San pedro Casas de Don Antonio. +++NO podemos rechazar la plaza en espera de otra (por cercanía) dado que ya dedse cuidados paliativos nos indoican que Dª Cristina está de alta y que en el hospital corre riesgo de coger alguna infección. +++Comunico a Mireia (ECUIPAL) la plaza vacante en espera de resolución.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DOLORES'and edp.apellido1='ALFONSO'and apellido2='GARCIA'),'2018-12-14','Llama Carmen TS de Cilleros para informar que Dolores es titular de una vivienda de promoción pública para que se tenga en cuenta en el caso de que pase a estar tutelada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MAXIMILIANO'and edp.apellido1='BAZAGA'and apellido2='CARRERA'),'2018-12-13','Se pone en contacto con la comisión (PEdro) el hermano Maximiliano (MIguel Ángel 93 381 52 94)para interesarse sobre herencia','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='LARA'and apellido2='SERRANO'),'2018-12-17','(Pedro)Llamada de Flor, T. Soc. del H Virgen del Puerto de Plasencia (78741). +++REquiere saber quién ha de firmar la solicitud de plaza sociosanitaria para D. José. Está allí su hijo, desesperado, porque su padre no puede ni deber volver a casa. +++SE le informa de que desconocemnos en estos moemtos la situación, porque estamos todavía en fase de inventario. +++Enviará la solicitud para plaza sociosanitaria.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='LARA'and apellido2='SERRANO'),'2018-12-17','Nos llama Raúl Lara Sánchez (605612560), hijo de José. Nos indica que su padre vive en su domicilio, junto a otro hijo, Miguel Ángel, 41 años, sin trabajo. Según nos cuenta, la vivienda se encuentra en mal estado de limpieza, muy sucia y con ratas. En su día intentaron ingresar a José en un centro, pero no lo consiguieron. Insiste en que le acompañemos a visitar la vivienda, para que podamos comprobar in situ lo que nos dice. José cobra una pnc.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JACINTO'and edp.apellido1='DIAZ'and apellido2='BOZA'),'2018-12-17','Hablamos con el Juzgado de Primera Instancia e Instrucción nº 1 de Zafra (924550130). Ya han designado el número del procedimiento, tras inhibirse el Juzgado nº 2 en ellos. Es el 487/18, pero aún no saben nada más. Está pendiente que el Juzgado lo distribuya entre los funcionarios y continúe la tramitación. Se ha designado al abogado Antonio Francisco Cháves Díaz (924909354 - 1046@icaba.com). Hablamos con él y le facilitamos el contacto de la anterior letrada, Mª. Guadalupe Mena Fernández-Huertas (653 992 131- guadalupemena@cmabogadas.com), que ya presentó el expediente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CASTILLO'and edp.apellido1='SOLIS'and apellido2='MELENDEZ'),'2018-12-14','(Pedro)Visita programada de D. Angel Collado Sierra (618-436443), marido de Dª Castillo. +++Tras la conversación mantenida con Asunción Cabrera, me reuno con D. Ángel para tratar la situación en la que se encuentra su mujer. Tanto Asun como él consideran que debe ingresar en el CSS de Mérida, pero ella no quiere hacerlo voluntariamente. +++Le propongo ir a su casa a verla en este mismo momento, pero me dice que tiene que volver al trabajo. Quedamos en que intentará venir con ella el próximo lunes a las 10:45h. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Hablo con Asun tras la entrevista y le pongo al tanto de la misma. +++Si firnalmente ingresa, hablará con la UHB para que tengan en cuenta la situación y promuevan el ingreso.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2018-12-17','(Pedro) Conversación con Mercedes: +++VACACIONES DE NAVIDAD: enviarán solicitud de autorización del 21 al 30 ó 31 de diciembre para pasarla con su padre. No podía ser menos tiempo porque de esta forma garnatizamos su traslado con Futuex el día 21 a Trujillo y la vuelta con su padre el 30 ó 31 (no puede otros días). ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++llamo a Beatriz para FELICITARLA POR SU CUMPLEAÑOS. +++Les decía en el centro que "... a ver si pedro se cuerda y me felicita..." -me dice Mercedes. +++Se ha puesto muy contenta al recibir la llamada. Se enceuntra bien el el Centro pero -dice- "...estaría mejor en mi casa..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='DELGADO'and apellido2='RODRIGUEZ'),'2018-12-17','Se envía al JDO de Fregenal informe social de José Antonio como nos había sido requerido.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='BERNARDO'and apellido2='PIRIS'),'2018-12-17','Llega el acuse de recibo de la Casa Real indicado en la incidencia anterior.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CRISTINA'and edp.apellido1='VILLEGAS'and apellido2='SERRANO'),'2018-12-17','(Pedro)Conversación con Mª Ángeles, Médico del ECUIPAL. +++LLama para informarnos de que el traslado a la plaza T· de Casas de Don Pedro se realizará mañana..."...salvo que D. Julián se oponga a ello como ha amenzado ya al saber el lugar en el que se le ha dado la plaza. Amenaza con ponerse delante de la ambulancia para impedir que su hermana se vaya...""Según él, su hermana no se quiere ir, pero nosotros hemos habaldo con ella le hemos explicado los motivos y los ha entendido y está dispuesta a marcharse a Casas de Don Antonio..." +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++(Pedro)Llamada de D. Julián, insistiendo en que su hermana no quiere irse tan lejos y que dado que su hermano Francisco le debe 6000€, que se lo pague y con ello se paga la plaza en malpartida de Plasencia...." +++Se le explica que, según evolucione su hermana, se podrá plantear un tralado más cerca de Plasencia, si su estado lo permitiera y no fues e negativo ni para ella ni para su hermano. +++Insiste en que enviarla allí, "en contra de su voluntad, va a suponer un trastorno para ella y para toda la familia..." argumento que repite varias veces y que da lugar a pensar que tiene esta opinión más en beneficio propio que en el del bienestar de su hermana.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JESUS'and edp.apellido1='DE LA OSA'and apellido2='DE LA OSA'),'2018-12-17','(Pedro)Llama la hermana de Francisco. +++Tras el fallecimiento de su padre, quieren arreglar la herencia. +++Enviará correo-e con los datos del fallecimiento. Al parecer, su padre dejó testamento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CASTILLO'and edp.apellido1='SOLIS'and apellido2='MELENDEZ'),'2018-12-17','(Pedro)No han acudido a la reunión que le planteé a D. Ángel el pasado viernes. Doy por enetendido que Dª Castillo se ha negado. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++(Pedro)Acudí al ESM para hablar con Esperanza, la T. Social (924-487229 y 85896). +++Castillo tiene cita el 20 de noviembre con el Dr. Adrés Simón (Psiquiatra).','2');
