insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JESUS'and edp.apellido1='DE LA OSA'and apellido2='DE LA OSA'),'2018-12-18','En relación con la herencia de su padre, D. Gabriel de la Osa Polo, hablamos con Paula para preguntarle si la escritura de herencia que se hizo y que nos ratificamos, la presentaron ante hacienda de la Junta de Extremadura, para que le pongan el sello de estar exenta de pagar Impuestos y así poder dirigirnos a las entidades Liberbank y Banco Santander, en la que exisen cuenas bancarias y recibir la parte que le corresponde a Francisco. Nos llama Paula cuando lo sepa.','2');
