insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIX'and edp.apellido1='GARCIA'and apellido2='AMBROSIO'),'2018-08-09','SALIDA El 09/08/2018. Realiza una salida a Coria para participar en el Mercado arteanal del Jueves Turístico en esta localidad.','2');
