insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MINERVA'and edp.apellido1='MARTIN'and apellido2='BLANCO'),'2018-12-18','(Pedro)En contacto con Bibiana, se suspende la reunión prevista para mañana con D. Víctor al estar este ingresado en el hospital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CRISTINA'and edp.apellido1='VILLEGAS'and apellido2='SERRANO'),'2018-12-18','(Pedro)Conversaciones, cronológicamente. +++ECUIPAL: Llama la Dra. Mª Ángeles: Julián está impidiendo el traslado de Dª Cristina a la Residencia "Sierra de San Pedro" en Casas de D. Antonio (927-383258). +++++JUZGADO de 1ª Instancia nº 4 de Plasencia: se informa de la situación e indican que desde los servicos médicos se llame a la Policía. +++++Nueva llmada a ECUIPAL: informo de la medida a tomar y antes de tomarla, Mª Ángeles comprueba en que situación está el traslado. La ambulancia va de camino y al parecer D. Julián va detrás. +++++Nueva llamada al JUZGADO nº 4. Informo de la situación y Toña me comenta que D. Julián ya está allí. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Toni (FUTUEX): +++Cambiarán cerradura, quedarán con "La Perla del Valle" para limpiar el piso, tirar productos perecederos, ordenar y poder dejarlo en condiciones dado que no se va a volver a ocupar. +++Facilitar las visitas de D. José Pedro a su hermana. +++++Eva, gerente de la "Perla del Valle". DE acuerdo con estas actuaciones finales. Tras la misma, nos enviarán la factura para rescindir el contrato. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con Puerto, Directora del Hogar de Nazaret. +++Consultará la posibilidad de que D. José Pedro pueda ir a visitar a su hermana durante las Navidades (La Delegada Tutelar está de vacaciones) +++Han enviado el contrato de la plaza residencial por "ventanilla única". Una vez nos llegue lo remitiremos firmado. +++NO pone ninguna pega a tener una llave del piso de ambos hermanos en el expediente de D. José Pedro (por si hubiese alguna incidencia en la vivienda). +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Vuelvo a hablar con Toni sobre las últimas gestiones con la empresa de servicios y con el Hogar de Nazaret. +++Plácido: nos enviara resolución de la plaza T3 tantyo a la Comisión como a ECUIPAL (Mireia). ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++(Pedro)Llamo a la Residencia "SIerra de San Pedro" (927-383258). Hablo con Modesto y me pasa con el dierctor, Isidoro. +++Dª Cristina ha pasado muy bien la noche, se ha levantado animada y parece contenta. +++D. JUlián se ha presentado allí con actitud poco colaboradora. SE inoforma sobre cómo han tranccurrido estos meses en relación con los familiares. +++HORARIO de MARÍA (T. Soc.): esta en la Residencia lunes martes y jueves.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='QUIROS'and apellido2='SAUCEDA'),'2018-12-18','(Pedro) Conversación con Oncóloga, la Dra. Elena Díaz Peña (86716) del Hospital Don Benito-Villanueva. +++Nos enviará el consentimiento informado para tratamineto de quimioterapia (explica telefónicamente las repercuisiones del mismo y considera necesario la aplicación del mismo dada la situación de D. José Antonio. +++EL TATAMIENTO CON quimioterapia ESTÁ SUPEDITADO a los resultados de la pruba del PET, para la que lo deben citar (a la residencia) desde el HIC, desde la Unidad de Medicina Nuclear. Si el resultado es positivo a la excistenci ade células tumorales, el tratamiento se debría retrasar 6 meses. +++TELÉFONOS DE MEDICINA NUCLEAR: 48471, 48473, (48095), 924-218095. LLAMAR para pedir que nos envíen el consetiomineto para la rueba.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='AYUSO'and apellido2='TENA'),'2018-12-19','(Pedro) Conversación con Carmen Ayuso (924-005458 y 650192996). +++El deseo de Dª Antonia Ayuso siempre ha sido SER ENTERRADA JUNTO A SUS PADRES EN EL NICHO QUE TIENE EN CAMPANARIO, voluntad que la familia quiere que se respete y que la Comisión Tutelar por supuesto va arespetar. +++Carmen hablará con el reponsable municipal del cemneterio para ver qué trámites habría que hacer para llevar el sepelio adelante una vez llegado el caso.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2018-12-19','-LLAMA URBANO DE MENORES CC, MAÑANA SE HARÁ ENTREGA DE LA NIÑA A LA ABUELA PATERNA CUMPLIENDO CON LA SENTENCIA. PREGUNTO SOBRE CÓMO SE REALZARÁN LAS VISITAS DE LA NIÑA CON SU MADRE , LA SENTENCIA NO ESTABLECE NADA , HAY QUE ACORDARLO CON LA ABUELA . ÉSTA NO PERCIBIRÁ PRESTACION EC. POR EL ACOGIMIENTO. NOS HAN ENVIADO LA SENTENCIA. LO COMUNICO A FUTUEX. A.D.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDREA'and edp.apellido1='GUERRERO'and apellido2='ZAMBRANO'),'2018-12-19','Remitimos documentación a la Secretaría General de la Consejería para que la envíe a la Abogacía General, a los efectos de solicitar autorización judicial para la venta de inmuebles de su propiedad.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VICHO'and apellido2='ALFONSO'),'2018-12-19','(Pedro) Conversación con Soraya (Directora CSS Plasencia). +++José Mª Todavía no ha iniciado las salidas porque están viendo la disponibilidad existente para su acompñamiento. Empezarán con salidas cortas de media hora para tomar un café. +++PROPONGO: contactar con la perrera municipal para ver la posibilidad, si a José Mª le parecierta bien y fuese posible, de realizar alguna actividad bien en la propia perrera, bien en el CSS (jardines), pudiéndose contar quizá con las asociaciones protectoras de animales para inciar una actividad de carácter terapéutico. VALORARÁN LA PROPUESTA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='AYUSO'and apellido2='TENA'),'2018-12-19','B','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NATALIA'and edp.apellido1='MEGIAS'and apellido2='MILLON'),'2018-12-19','(Amalia/Pedro). Reunión con Aprosuba Zafra: Ana (T. Soc.), Isabel (Terapéuta) y la Directora. +++Situación de Natalia. +++++COMPORTAMIENTO:alteraciones de consucta, manipulación de compañeros, conductas de carácter sexual con otros internos y aluna agresión a profesionales. En una ocasión se le denunció pero se retitó la denuncia. +++++ALTERNATIVAS: comunicar a la Sección de Recursos esta situación. Plantear UDAC o cambio de recurso +++Pendiente de INVENTARIO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2018-12-17','(Pedro)Acudí al ESM para hablar con Esperanza, la T. Social (924-487229). +++Ildefonso tenía cita con el Psiquiatra (Dr. Periañez) este mismo día pero no había acudido a la mimsma. +++Tiene cita en el CEDEX el 27 de diciembre con la T. Social y el 10 de enero con el Médico (Urbano) +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Estuvo en la Comisión: ha dejado el Hostal porque dice que allí no le daban de comer todo lo que él quería. Dice estar con unos "colegas".','2');
