insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='CONTADOR'and apellido2='MATEOS'),'2018-12-20','(Pedro)Conversación con Loli (T.Soc. del HIC. (31806)). +++Sigue en UCI y ha contraído un a neumonía durante su ingreso. +++El motivo del ingreso no ha sido psiquiátrico, por lo que a pesar de la conversación mantenida ayer con Asunción cabrera la posibilidad de que pasa a UHB es poco probable. +++ALTERNATIVAS QUE PLANTEA: +++iNGRESO EN REISENCIA CASER DE bADAJOZ. Las limitaciones a esta medida, informo a Loli son:Edad (51), voluntariedad (si no habría que pedir autorización judicial) e ingresos. +++En estos momentos no hay una previsión del tiempo que va a permanecer ingresado. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Llamao a su hermana Mª José pero no coge la llamada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE PEDRO'and edp.apellido1='VILLEGAS'and apellido2='SERRANO'),'2018-12-20','Correos del día de hoy. BUENOS DIAS: NO ESTOY DE ACUERDO DE QUE MIS HERMANOS ESTE LSEPARADOS. POR LO TANTO PRESENTARE SENDOS ESCRITOS A LOS JUZGADOS PARA SOLICITAR SER DON LADISLAO MARTIN ACOSTA ó UN SERVIDOR DADO QUE POR LEY ME PERTENECE DEBIDO DE SER EL MAYOR DE LOS HERMANOS- UN COORDIAL SALUDO. A LOS TRES. LO HAGO EN MIRAS DEL BIEN DE PEPE Y CRISTY (para que ambos esten justitos -cueste lo que cueste) y de toda la familia que es de sentido comun estemos a su lado. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ De: Comisión Tutelar de Adultos >ctutelar@salud-juntaex.es> Enviado: jueves, 20 de diciembre de 2018 7:58 Para: Francisco Villegas Asunto: Re: ASUNTO HERMANOS Buenos días, D. Francisco. Su hermano D. José Pedro se encuentra en Plasencia, en el Hogar de Nazaret, y su hermana Dª Cristina en la Residencia "Sierra de San Pedro" en la localidad de Casas de Don Antonio. En las conversaciones que he mantenido con ambos centros me han comunicado que sus hermanos se encuentran perfectamente, dentro de las limitaciones que cada uno tiene, contentos de estar donde están y con la certeza, por parte de la Comisión Tutelar, de estar recibiendo los cuidados y atenciones que cada uno precisa. Un cordial saludo. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ De: Francisco Villegas >pacovillegas123@hotmail.com> Enviado: jueves, 20 de diciembre de 2018 7:40 Para: Comisión Tutelar de Adultos Asunto: RE: ASUNTO HERMANOS BUENOS DIAS: DADO QUE ESTA MAÑANA A LAS 10 HORAS VOY A PLASENCIA-PARA SABER DONDE ESTAN MIS HERMANOS .Hazeme el favor donde se encuentra. Pues mi hermano, Julián solo me llamo la otra NOCHE disgustado con Vds. para que me uniera a él y a la familia, debido al traslado una Residencia de Ancianos a la localidad de Casas de Don Pedro. No he vuelto tener noticias de mis hermanos NO ME COGE EL TEL NI ME CONTESTA A LOS EMAILS QUE LE MANDO ESPERO SUS NOTICIAS. GRACIAS. DE PACO VILLEGAS.email de pacovillegas123@hotmail.com','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CRISTINA'and edp.apellido1='VILLEGAS'and apellido2='SERRANO'),'2018-12-20','Correos del día de hoy. BUENOS DIAS: NO ESTOY DE ACUERDO DE QUE MIS HERMANOS ESTE LSEPARADOS. POR LO TANTO PRESENTARE SENDOS ESCRITOS A LOS JUZGADOS PARA SOLICITAR SER DON LADISLAO MARTIN ACOSTA ó UN SERVIDOR DADO QUE POR LEY ME PERTENECE DEBIDO DE SER EL MAYOR DE LOS HERMANOS- UN COORDIAL SALUDO. A LOS TRES. LO HAGO EN MIRAS DEL BIEN DE PEPE Y CRISTY (para que ambos esten justitos -cueste lo que cueste) y de toda la familia que es de sentido comun estemos a su lado. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ De: Comisión Tutelar de Adultos >ctutelar@salud-juntaex.es> Enviado: jueves, 20 de diciembre de 2018 7:58 Para: Francisco Villegas Asunto: Re: ASUNTO HERMANOS Buenos días, D. Francisco. Su hermano D. José Pedro se encuentra en Plasencia, en el Hogar de Nazaret, y su hermana Dª Cristina en la Residencia "Sierra de San Pedro" en la localidad de Casas de Don Antonio. En las conversaciones que he mantenido con ambos centros me han comunicado que sus hermanos se encuentran perfectamente, dentro de las limitaciones que cada uno tiene, contentos de estar donde están y con la certeza, por parte de la Comisión Tutelar, de estar recibiendo los cuidados y atenciones que cada uno precisa. Un cordial saludo. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ De: Francisco Villegas >pacovillegas123@hotmail.com> Enviado: jueves, 20 de diciembre de 2018 7:40 Para: Comisión Tutelar de Adultos Asunto: RE: ASUNTO HERMANOS BUENOS DIAS: DADO QUE ESTA MAÑANA A LAS 10 HORAS VOY A PLASENCIA-PARA SABER DONDE ESTAN MIS HERMANOS .Hazeme el favor donde se encuentra. Pues mi hermano, Julián solo me llamo la otra NOCHE disgustado con Vds. para que me uniera a él y a la familia, debido al traslado una Residencia de Ancianos a la localidad de Casas de Don Pedro. No he vuelto tener noticias de mis hermanos NO ME COGE EL TEL NI ME CONTESTA A LOS EMAILS QUE LE MANDO ESPERO SUS NOTICIAS. GRACIAS. DE PACO VILLEGAS.email de pacovillegas123@hotmail.com ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con Modesto (Residencia "Sierra de San Pedro") y con D. Julián.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='QUIROS'and apellido2='SAUCEDA'),'2018-12-20','(Pedro) Hablo con Victoria, del H. Don Benito-Vva. (T. Soc.) +++Todavía no nos han enviado el consentimineto informado para su frima como quedé con la Dra. Elena porque no han recibido la cita de Medicina Nucleat del HIC. +++Hablo con Loli, T. Soc. HIC: consultará el trámite de la cita para el PET y el envío del consentimiento inofrmado corrrespondsienye.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2018-12-20','- ATI DEJÓ EL HOSTAL EL DIA 10 DE DICIEMBRE PQ QUIERE DESAYUNAR TRES VECES AL DIA Y COMER MÁS . EL DIA 15 ACUDIÓ A DEJAR LAS LLAVES PERO MANTIENE ALLI ALGUNAS PERTENENCIAS. ME HE REUNIDO CON ÉL Y COMENTA QUE VIVE CON OTRO CHICO EN UN PISO DE OCUPA , NO ME FACILITA MÁS INFORMACIÓN Y PIDE EN LA C/ SANTA EULALIA . LE INDICO QUE TIENE INGRESOS SUFICIENTES PARA NO LLEVAR ESA VIDA PERO CONSIDERA QUE ASÍ VIVE MEJOR . A.D.','2');
