insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2018-12-20','Se envía autorización de salida del 21 al 31 de diciembre para pasar las Navidades con su padre. Se envía por correo eléctrónico y ordinario. +++Hablo con Mª Ángeles, Psicóloga de Plena Inclusión de Llerena: le informo sobre la entrega de la niña a su abuela paterna y de las gestiones que estamos realizando para saber los derechos que com o madre le asisten, en especial el de las visitas a su hija. También si existe alguna acción posible a llevar a cabo como representantes de la madre así como si se va a hacer algún seguimiento de la custodia de la niña por parte de la abuela. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++CONVERSACIÓN CON LA GUARDIA CIVIL DE TRUJILLO (927-321004), con el cabo de Guardia. (el Brigada Alberto Guillén está de permiso). Solicito su colaboración durante la esrtancia de Beatriz con su padre para evitar posibles conflictos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='LARA'and apellido2='SERRANO'),'2018-12-20','(Pedro)Llamada de Miguel Ángel (hijo)(626-507318). +++Preguntando por las competencias de la Comisión Tutelar. +++Ofreciéndose por si necesitamos algo de él. +++Criticando la gesdtión de su otro hermano, anterior tutor de su padre: "...mi hermano lo que le daba de comer era mierda...Yo era el que estba realmente con él..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='MARFIL'and apellido2='MUÑOZ'),'2018-12-20','A través de Paulina (Madex) contyacta con nosotros nuevamente D. Javier San Andrés. Lo llamo, pero no se encuentra en el despacho en ese momento. La señora que coge el teléfono me pide un correo-e. Doy el de la Comisión. Se pondrá en contacto a través de este medio.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MEJIAS'and apellido2='DE LA MORENA'),'2018-12-20','(Pedro)Conversación con Mª del Cielo, T.Soc. CRPS-ZAFRA (924-555943). +++14 de diciembre: Beatriz sufre desmayo. Llaman al 112 y la trasladan a Llerena (no hay Psiquiatra en el ESM de Zafra). Queda ingresada en el Hospital de Llerena varios días en observación. DIAGNÓSTICO: NIVELES DE Li desajustados.De Alta el domingo 16 de diciembre. +++Desde el Lunes hasta ayer acude al Hospital de Zafra para controles. En observación en el Hospital. +++AYER, 19 de diciembre, queda ingresada en la Unidad de Medicina Interna del Hospital de Zafra. Los niveles de Litio no bajan (intoxicación). ESTA SUPERVISADA POR PSIQUIATRÍA. +++Llamo a Toni, T. Soc. del Hospital de Zafra (924-877000///34367) varias veces pero no consigo contactar con ella..','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='DELGADO'and apellido2='RODRIGUEZ'),'2018-12-20','-HABLO CON LA TS DE HIGUERA ( ROSA 924727001) NOS COMUNICA QUE HAY MUCHOS INCIDENTES Y CONFLICTOS FAMILIARES CON LA MADRE. VA A ENVIAR DILIGENCIAS POLICIALES. A.D.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE PEDRO'and edp.apellido1='VILLEGAS'and apellido2='SERRANO'),'2018-12-20','(Pedro)Llamada de D. Manuel Álvarez Delgado (Presidente actual de la Comunidad de Vecinos de la calle Sor Valentina Mirón nº 3 de Plasencia). TELÉFONO: 649-145165. +++Enviará recibo anual de la comunidad que dice haber entregado a JUlián y que no ha pagado (lo ha enviado por correo electrónico -dice-).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='FERNANDEZ'and apellido2='SALGUERO'),'2018-11-06','-NOS LLAMA DEL C.O. DE ZAFRA , HA NECESITADO ACOMPAÑAMIENTO MEDICO EL FIN DE SEMANA Y SU PRIMA , QUE PERCIB 500€ POR MANTENERLA EN SU CASA SE NIEGA A ELLO . PARA LA PROXIMA VEZ SOLICITARAN ACOMPAÑAMIENTO . TIENEN PLAZA DE RAL PRIVADA POR UNOS 700€ DONDE PODRIA QUEDARSE Y TENDRIA MÁS CONTROLADA SU SALUD . LE PREGUNTARAN A ELLA SI QUIERE ACCEDER , ES CURATELA . A.D .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CANDIDO'and edp.apellido1='BAS'and apellido2='GONZALEZ'),'2018-12-20','- SE LE HA RENOVADO EL DNI . POR EL MOMENTO LA PENSIÓN NO SE VUELVE A TRAMITAR ( PFHC ) TIENE AHORROS Y NO NECESITA MÁS MIENTRAS SIGA EN CSS . SE SOLICITÓ EN SU DIA LA PF PERO SS NOS PEDIA DOCUMENTACION SIN INDICAR DE QÚE USUARIO LO SOLICITABA , Y EL EXPEDIENTE SE ARCHIVÓ. AD','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='MATILLAS'and apellido2='JIMENEZ'),'2018-12-21','Teléfono de Mari Carmen:691692871','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MEJIAS'and apellido2='DE LA MORENA'),'2018-12-21','(Pedro)Conversación con Toni, T. Soc. del Hospìtal de Zafra. +++No requiere acompañamiento.Su madre está con ella. +++++PROBLEMA: discuten muchísimo y esto altera a Beatriz. Han hablado con la madre para que no esté tanto tiempo con ella o que no le haga caso para no alterarla.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='DELGADO'and apellido2='RODRIGUEZ'),'2018-12-21','SOLICITO A FUTUEX : en relacion a JOSE ANTONIO DELGADO RODRIGUEZ , ( Higuera la Real ) , nos han llegado informes policiales en los que nos solicitan intervención en su domicilio , se han agredido entre madre e hijo . La madre no quiere ingresar en residencia y él tampoco . Jose Antonio ha estado en la UHB LLerena el 17 diciembre pero le dieron el alta a las horas . He solicitado Informe de alta . Necesito informes de su ESM , desconozco si sigue acudiendo al CRPS de Zafra , hace años sí iba. Tiene por PIA , prestación vinculada a servicio con empresa privada , pero la TS del SSASB me dice que no facilitan la entrada a nadie , que no adminten SAD municipal ni ningún tipo de recurso. Dejan entrar a la auxiliar contratada por dependencia ?? Solicito visita domiciliaria y poder recabar información necesaria para valorar ingreso en centro . Si el ESM lo puede derivar a CRR o si solicitamos autorización judicial de ingreso en CSS . A.D','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN ANTONIO'and edp.apellido1='SANCHEZ'and apellido2='SANTIAGO'),'2018-12-21','-LLAMO A TONI , TS UHB LLERENA Y ME INFORMA QUE FUE TRASLADADO EL MIERCOLES AL HOGAR SAN JOSE.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2018-12-21','(Pedro) Conversación con Urbano (927-004355). +++POSIBILIDAD DE RECURSO: al parecer, la sentencia es firme y ya se ha entregado a Rocía a la abuela paterna. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ +++RÉGIMEN DE VISITAS: solicitar vía ABOGACÍA de la JUNTA que sea el Juzgado el que establezca el Régimen de Visitas de la madre, concretando LUGAR (la opción de la CTAEx es que Beatriz pueda estar con su hija en el propio Centro. Si esto no fuera posible, determinar punto de encuentro; concretando FRECUENCIA y concretando DURACIÓN de cada encuentro. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ +++SEGUIMIENTO DE LA TUTELA por parte de la Administración: acogiéndose al FUNDAMENTO JURÍDICO DÉCIMO de la Sentencia 513/2018 de la Sección 1ª de la Audiencia Provincial de Cáceres, adoptar las medidas que se consideren oportunas para el seguimiento de la situación de Rocío, garnatizando, entre otras cosas, su asistencia diaria a la guardería y en condiciones adecuadas, la asistencia a las sesiones de Atención Temprana que está recibiendo, la continuidad en la asietencia a las consultas de Neurología y todos aquellos aspectos que contribuyan al bienestar de la niña. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++CONTRADICCIÓN en la SENTENCIA: en el FUNDAMENTO JURÍDICO SEGUNDO (último párrafo) existe una contradicción fruto probablemente de un error en la redacción (¿o es decontenido?)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN ANTONIO'and edp.apellido1='SANCHEZ'and apellido2='SANTIAGO'),'2018-12-21','-HABLO CON LA TS DEL HOGAR SAN JOSÉ . HAY QUE ABONAR LA PENSION INTEGRA ( 380e/ MES ) EN 12 PAGAS . VA A SOLICITAR A LA PARTE EC. Nº CTA. POR EL MOMENTO MANTENGO EL PIA COMO ESTA CON P.V. PQ NO CREEN QUE SE QUEDE EN LA RESIDENCIA POR MUCHO TIEMPO . INGRESÓ VOLUNTARIAMENTE PERO SE QUIERE IR.LLAMO A PILAR LA CUIDADORA QUE ESTÁ EN SU CASA LE EXPLICO QUE POR EL MOMENTO VAMOS A MANTENER LA SITUACIÓN IGUAL PERO QUE ESAS HORAS Q NO VA A TRABAJRA CON J.A. PODRIA HACERLE UNA VISITA AL HOGAR JUNTO CON DIEGO , SE ABONARÁ EL TAXI DESDE AQUÍ . A.D.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='ARNEDO'and apellido2='LOPEZ'),'2018-12-21','(Pedro) Llamada de D. Gerardo (600-156460) del Juzgado de 1ª Instancia nº 4 de Granada. +++Hay un familiar interesado en adquirir algunas propiedades de D. Francisco. +++Le doy el correo de la Comisión para que la persona interesada se ponga en contacto con nosotros.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='LARA'and apellido2='SERRANO'),'2018-12-21','(Pedro) Llamada de Fernando, T. Soc. Hospital Virgen del Puerto de Plasencia (78206). +++Informa de la concesión de plaza sociosanitaria T3 en la Residencia "Sierra Pinar" de Zafra. Posiblemente el traslado sea hoy mismo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIO'and edp.apellido1='VAQUERO'and apellido2='PEREZ'),'2018-12-21','-CONTESTO A MAYTE A LO QUE SOLIICITA. BUENOS DÍAS AMALIA. SOY MAITE TRABAJADORA SOCIAL DE MONTIJO. TRAS LA CONVERSACIÓN TELEFÓNICA QUE MANTUVIMOS HACE UNOS DÍAS Y DONDE QUEDAMOS EN QUE COMISIÓN TUTELAR SE PONDRÍA EN CONTACTO CON AOEX,NECESITO QUE ACLAREMOS SI HABÉIS SOLICITADO YA EL CAMBIO DE PIA DE ESTE SEÑOR. EL NUEVO RECURSO SERÍA SERVICIO DE AYUDA A DOMICILIO VINCULADA AL SERVICIO DESDE EL 9 DE FEBRERO QUE ES CUANDO TERMINA EL CONTRATO CON ESTE AYUNTAMIENTO DE LA AUXILIAR QUE QUIEREN CONTRATAR Y QUE LE ATIENDE ACTUALMENTE A TRAVÉS DE SU RECURSO DE SAD PÚBLICO. YO YA VOY A SOLICITAR EL CAMBIO DE PIA DE ISABEL MOLINA, LA PAREJA DE JULIO AL MISMO RECURSO Y PARA QUE SEA ESTA MISMA AUXILIAR LA QUE LES ATIENDA A LOS DOS. UN SALUDO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='AYALA'and apellido2='NUÑEZ'),'2018-12-21','(Pedro)Comunican de la farmacia que D. Francisco se ha desplomado allí cuando acudía a por su medicación, llamando al 112 y requiriendo reanimación cardio pulmonar. +++Ingreso en UCI del Hospital Virgen del Puerto. +++++En contactos sucesivos con Fernando, T. Soc. (78206), informa finalemnte que D. Francisco va a ser trasladado al Hospital de Cáceres para realizar pruebas, dado que ha sufrido un infarto de miocardio. Cabe la posibilidad de que lo vuelvan a llevar al Hospitald e Plasencia una vez realizadas las pruebas. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ GESTIONES REALIZADAS PARA LA ATENCIÓN DE SU MASCOTA Y ADECUACIÓN DEL PISO EN CUANTO A CONDIUCIONES DE SEGURAIDAD Y HABITABILIDAD MINETRAS DURE EL INGRESO. +++POLICÍA LOCAL (Subinspector D. José A. Díaz///correo-e: jadiaz@aytoplasencia.es) y la empresa Grupo Gilsan (Víctor Gil Calvo, 654-072467): SE AUTORIZA A LA ENTRADA en el domicilio para que lleven al animal a la Protectora y la empresa revise el estado de la vivienda.La Policía avisará a un cerrajero porque las únicas llaves las tiene D. Francisco. +++La empresa se quedará con copia de la llave para que siga realizando su trabajo. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Contacto también con Toni (Futuex).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NATALIA'and edp.apellido1='MEGIAS'and apellido2='MILLON'),'2018-12-21','Teléfonos familiares Natalia Megías Millón * Pilar Mirón Román (abuela materna): 642536020 * Rubén Megías (Padre): 626974755 * Mª Del Carmen Millón (madre): 666764889/ 666898994 (en ocasiones llama desde este último teléfono, que parece pertenecer a una amiga) * Joaquín Millón (abuelo materno): 695463947 * Olga Millón (hermana de su madre): 656929694','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SARA'and edp.apellido1='VAZQUEZ'and apellido2='GILES'),'2018-12-26','Hablamos con Juan GAlán director de Plena Incluisón, nos comenta que el día 23 Saray se cayó y fue ingresada en el hospital, va a ser necesaria una operación. Se le ha buscado acompañamiento para estos días, no han podido contactar con la comisión al ser festivo. Nos deja el teléfono de la trabajadora social Almudena 646610633 (personal, solo en caso preciso).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SARA'and edp.apellido1='VAZQUEZ'and apellido2='GILES'),'2018-12-27','(Pedro)Conversación con Almudena 8T. Soc. Inclusives Zafra. +++Fractura de tibia y peroné por caida de tres escalones al ser empujada accidentalmente por otro usuario el pasado domingo.23 de dieiembre. +++Sigue ingresda en traumatología en el hopsitald de Zafra (HABITACIÓN 159). +++Acompañamineto: se le pide que se haga el estrictamente necesario y que una vez intervenida nos informe de los requerimientos para el mismo y tener en cuanta la capacidad económica para asumirlo. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Llamo al Hospital de Zafra (924-029200) para hablar con la T. Soc. (40335). No coge las llamadas. +++Intento hablar con Traumatología (40254). Me derivan a Atención al Paciente porque el CONSENTIMINETO INFORMADO que pido envíen a la Comisión Tutelar para su firma "...no podemos sacr del hospital ningún documento..." Explico la forma de trabajar de la Comisión Tutelar al respecto pero inisite en que hable con Atención al Paciente sobre ello. +++Llamo a Atención al Paciente pero no cogen la llamada. +++SE envía,firmado, consentimiento informado para intervención.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS MANUEL'and edp.apellido1='RAMOS'and apellido2='BARGON'),'2018-12-27','Se recibe en la Comisión Exhorto del Juzgado de lo Penal nº 2 de Cáceres pidiendo que en cumplimiento de lo indicado en el informe médico adjunto se acompñae a D. Jesús a las consultas copncertadas con el ESM de Cáceres. +++Hablo con Toni (Futuex): él no quiere que le acompañemos.Quedo en decirle la próxima cita en el ESM para que lo acompañen (la curatela es para el control del tratmiento médico y económico). +++Llamo al ESM: la última cita fue el 11 de noviembre (fue acompañado por Futuex) pero no tiene cita concertada en este momemto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='AYALA'and apellido2='NUÑEZ'),'2018-12-27','(Pedro) +++Conversación con Luli, T.Soc. del Hospital san Pedro de Alcántara (31621). NO conoce el caso. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ +++Conversación con el Dr. Ángel Pineda (Intensivista). Teléfono UCI del Hospital San Pedro de Alcántara (56430): +++D. Francisco sigue en las mismas circuntancias:con medicación para conservar la función cardíaca y respiración asistida. dado el tiempo que estuvo en parada cardíaca presenta también con mucha probabilidad daño cerebral. NO ESTÁ INDICADA INTERVENCIÓN ALGUNA y el pronóstico es muy desfavorable. +++Solo queda esperar a ver cuál es su evolución.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='CONTADOR'and apellido2='MATEOS'),'2018-12-27','(Pedro)Conversación con Juan José, T. Soc. del HIC (Loli está de vacaciones). +++Manuel ya no está en la UCI. Ingresado en la sexta planta en Neurología. Se inoformará de su estado y volveremos hablar. +++Nueva conversación: es posible que la semana que viene se le de el alta del Hospital, UN ALTA CON SUPERVISIÓN. Comento con Juanjo que la Comisión no tiene capacidad para esa supervisión y que, caso de darle el alta, debería volver a casa. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Llamo a Mª José, su hermana. Salta el contestador automático. Dejo mensaje para hablar con ella. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Hablo con Toni (Futuex). Expongo la situación.El próximo 3 de enero acudirán al HIC para ver si le dan el lata y tratar de supervisar la vuelta al domicilio (si esta es la opción).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CRISTINA'and edp.apellido1='VILLEGAS'and apellido2='SERRANO'),'2018-12-27','(Pedro)Conversación con Modesto, residencia Sierra de San Pedro. +++Cristina ha pasado estos día muy bien y contenta. ha recibido la visita de varias amistades y le han traído regalos. LOS FAMILIARES no han vuelto a venir desde la semana pasda en que tuviste conversacuión con Julián, cuando se presnetó en el Centro amenzando con tomar medidas drásticas. +++++MARÍA (T. Soc. de la Residencia). Se le inoforma de cómo actuar en caso de fallecimiento y se le envía copia de la póliza de deceso de ambos hermanos. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con D. Alfonso Cortés, Gerente del CERMI (646-771177), que ha llamado a la Gerencia del Sepad para que nos pongamos en cobtacto con él. +++++SE le explica la situación en aquellos aspectos que no vulneran el secreto profesional, básicamente que todas las actuaciones de la Comisión van encamindas al alcanzar el mayor bienestar posible de Dª Cristina y que a D. Julián ya se le informó de que, comprendiendo desde la Comisión su desacuerdo con las actuaciones de la misma, podía dirigirse al Juzgado para plantear allí dicho desacuerdo. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++','2');
