insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS MANUEL'and edp.apellido1='RAMOS'and apellido2='BARGON'),'2018-12-28','EJECUTORIA 16/2015 (Proced. origen 278/2014). +++MEDIDAD DE SEGURIDAD DE INTERNAMIENTO: DEL 09-12-2014 AL 28-09-2016. SE SUSTITUYE esta medida por SUMISIÓN A TRATAMINETO AMBULATORIO por Auto de 02-06-2015. +++PRIVACIÓN DE TENENCIA Y PORTE DE ARMAS del 14-01-2015 al 01-05-2022. +++PRIVATIVA DE DERECHO DE APROXIMACIÓN a MENOS DE 300m DE D. RAMOS SANTOS CANALES Y COMUNICACIÓN CON ÉL desde 14-01-2015 al 08-12-2017. +++PRIVATIVA DE DERECHO DE APROXIMACIÓN A Dª Mª ISABEL RAMOS BARGÓN Y RESTO DE HERMANAS Y COMUNICACIÓN CON ELLAS DESDE el 14-01-2015 al 08-12-2017.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MAXIMILIANO'and edp.apellido1='BAZAGA'and apellido2='CARRERA'),'2018-12-28','Vuelve a llamar el hermano de D. Maximiliano en relación con la herencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MINERVA'and edp.apellido1='MARTIN'and apellido2='BLANCO'),'2018-12-28','(Pedro)Visita no programada de D. Víctor, padre de Minerva y Jorge. +++Inssite en que haga fotocopias de los informes médicos que trae para justificar el no haber podido tener la reunión prevista. A pesar de inidcarle que no es necsario, insiste en ello. +++Solicita la extra de 200€/hijo pra estas fietas. +++Dice que se va jubiliar. +++PENDIENTE convocar la reunión aplazada. "Yop también tengo cosas que decir sobre el Centro que me cuenta mi hija...".','2');
