insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='AYALA'and apellido2='NUÑEZ'),'2018-12-28','(Pedro)Conversación con Víctor Gil Calvo (Empresa Gilsan). +++Finalmente cambiaron el bombín de la cerradura. Se quedaron una copia y dejaron otra a Elena, la farmacéutica. +++El perro está en la Protectora en concepto de adopción. +++Siguen con el trabajo de limpieza de la vivienda. La documentación que encuentren la apartarán y guardarán. +++Han solcitado una ampliación de las horas de dependencia. Hablar con clara para agilizar valoración. +++ALTERNATIVAS: VALORAR SOLICITAR AMPLIACIÓN DE LA INCAPACIDAD CON AUTORIZACIÓN PARA INGRESO INVOLUNTARIO (EN FUNCIÓN DE LA EVOLUCIÓN DE SU SALUD)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='AYALA'and apellido2='NUÑEZ'),'2019-01-02','(Pedro)Llamo a la UCI del Hospiatal san pedro de Alcántara (56430). Los médicos están en seseión clímnica. Llamar a paratir de las 10:30h. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con el Jefe de Servicio Dr. Basilio Sánchez. +++Están preparando para hoy el alta en la UCI y su ingreso en la planta de Cardiología. +++NO HAY PREVISTA fecha de ALTA HOSPITALARIA. Requiere rehabilitación. +++Pediré a FUTUEx visita en el Hospital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SARA'and edp.apellido1='VAZQUEZ'and apellido2='GILES'),'2019-01-02','(Pedro)Convresación con Almudena, T. Soc. de Plena Inclsión Zafra. +++Sara se encuentra bien, pero ha padecido una anemia que ha obligado a transfundir dos bolsas de sangre, al juntarse tambiénn con la menstruación. +++Tiene PREVISTA el ALTA pra HOY si todo va bien. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Llamada de Carolina, T. Soc. del Hosp. de Zafra: CONFIRMA EL ALTA PARA HOY DE Sara, que marchará al Centro en ambulancia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='MARFIL'and apellido2='MUÑOZ'),'2019-01-02','(Pedro)SE envía correo-e a D. Javier San Andrés en relación al borrador remitido para su presentación al Juzgado, en el que se plantea al mismo que sean los herederos de D. José Manuel los que recojan el dinero que se le debe.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='CONTADOR'and apellido2='MATEOS'),'2019-01-02','(Pedro)Conversación con Loli, T. Social del HIC (31806). +++ALTA: prevista para MAÑANA o PASADO MAÑANA. +++INFORMES MÉDICOS: tanto en NEUROLOGÍA como en PSIQUIATRÍA consideran que Manuel no puede vivir solo. Han hablado con él y ESTÁ DISPUESTO A INGRESAR EN CASER BADAJOZ VOLUNTARIAMENTE. Con Loli se insite en los siguinetes aspectos: +++++VOLUNTARIEDAD: ES IMPRESCINDIBLE. De no ser así no se le puede obligar y deberíamos solictar autorización judicial para ingreso involuntario. +++++COSTE DE LA PLAZA EN CASER: 1500€/mes. Se reitera que esto dara para 3 ó cuatro meses. Al parecer También la familia está de acuerdo en ello y es consciente de las dificultades económicas que ello puede suponer. +++++SE SOLICITAN A LOLI INFORMES DE NEUROLOGÍA Y PSIQUIATRÍA donde se indique el empeoramiento de Manuel y su imposibilidad de vivir solo, requiriendo ingreso residencial. Antes de esta conversación he estado hablando con Mª Luz sobre la lista de espera para pisos supervisados en al que Manuel está el número 17. Si los informes recogen el empeoramiento de su situación, esta posición pude variar a su favor. Además, en estos momentos, el acceso a Pisos Supervisados está sujeto al paso previo por el CRR, no siendo posible para personas que no se encuentren ingresdas en ellos. +++LOLI ENVIARÁ LOS INFORMES DE AMBAS UNIDADES PARA SOLICITAR PLAZA EN CRR.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA'and edp.apellido1='MARIN'and apellido2='LAUREANO'),'2019-01-03','RECIBIDO INFORME SEMESTRAL DE RESIDENCIA PADRE DAMIAN DE PLASENZUELA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2019-01-03','(Pedro)Conversación con Julián, Gerente de COCEMFE. +++Tomás debe acudir a revisión al Hospital de Parapléjicos de Toledo los días 8 y 9 de enero. +++El traslado se hará con ambulancia sanitaria. +++Han intentado que las pruebas se puidieran realizar en el mismo día pero no es posible. Las que quedaran por hacer no se le podrían realizar hasta abril. +++Necesita ACOMPAÑANTE para esos días y será con uno de los Cuidadores del centro que más conoce a Tomás. ENVIARÁN PRESUPUESTO DE GASTO DE ACOMPAÑAMIENTO. +++Respecto a NACE, no ha mostrado malestar alguno por no poder pasar estos días con ellos: lo ha nombrado, pero ya considera que COCEMFE es ahora su hogar y Julián "...su nuevo padre..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2019-01-03','En relación con la indemnización de 30.000 euros, el Servicio Común de Ejecuciones dictó la Ejecutoria nº 25/2018 (927620419). Está pendiente de reclamarle a Novaforma. Al parecer ha pedido un fraccionamiento. Una vez reciban las cantidades a pagar, lo comunicarán vía lexnet a la Abogacía General.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALBERTO'and edp.apellido1='RAMOS'and apellido2='BLANCO'),'2019-01-03','-SE RECIBE EMAIL DE SU ABOGADA , ENVIA LA SENTENCIA DEL JDO. PENAL 2 DE BADAJOZ , LE IMPONEN UNA MULTA DE 7 PAGOS DE 200€ +216€ + 4 MESES DE INTERNAMI.EN CSS. SE LO ENVIO AL CSS AL CORREO DE MARIBEL . SE LO PASO A LA PARTE EC. Y JURIDICA DE LA CTAEX PARA SU ABONO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALVARO'and edp.apellido1='GONZALEZ'and apellido2='ALVAREZ'),'2019-01-03','(Pedro)Llamada de D. José Javier Álvarez, Tío materno de D. Álvaro. POR RESUMIR: +++"Dado que Álvaro es heredero de su madre, debería contribuir con sus ingresos al mentemnimeinto de esta, ya que nadie de la familia está dispuesto a asumir las deudas de mi hermana -(Mª José, madre de Álvaro)-. ¿Podría la Comisión Tutelar contribuir como representante de Álvaro en estos gastos? Se le explica que la responsabilidad de la Comisión Tutelar es su sobrino y, como heredero de su madre, lo será cuando ella fallezca (La madre está ingresada en estos momentos, según inofrma su hermano, en la UME de Plasencia y, al parecer, el ingrteso va a ser largo...).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='PEREO'and apellido2='REBOLLO'),'2019-01-03','Se recibe en la Comisión Tutelar fax del CSS de Mérida indicando que D. Antonio hará una visita a su madre, residente en la Residencia "Felipe TRigo", mañana día 4 de enero de 2019 acompñado por personal del CSS de Mérida y en vehículo del propio centro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIO'and edp.apellido1='VAQUERO'and apellido2='PEREZ'),'2019-01-03','-CONTESTACION A LA EMPRESA DE SAD POR MI PARTE ( AOEX-924207713 ) , QUDO PTE. VALORARLO CON ALBERTO : BUENOS DIAS , RECIBIDO CORRECTAMENTE. ME REUNIRÉ CON LA PARTE ECONOMICA DE ESTA COMISIÓN PARA LA CONFORMIDAD DEL SERVICIO Y LE CONTESTARÉ EN BREVE . EL SERVICIO TENDRÍA QUE INICIARSE CUANDO JUANI ACABE EL CONTRATO CON EL AYTO. Y CREO QUE ES EN FEBRERO. UN SALUDO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIO'and edp.apellido1='VAQUERO'and apellido2='PEREZ'),'2019-01-03','-ACEPTO EL PTO. Y SOLCITO CONTRATO A LA EMPRESA.AD','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='CONTADOR'and apellido2='MATEOS'),'2019-01-04','Correo-e de Futuex (en relación a D. Manuel): Hola buenos días, feliz año ! Ayer realizamos visita al tutelado Manuel Contador Mateos, ingresado en hospital universitario de Badajoz en planta de neurología habitación 618. Se encuentra más recuperado, aunque todavía no al 100%. No puede hacer ningún esfuerzo ni siquiera movimientos de subir o bajar. Le hemos notado lento, en movimientos y en su lenguaje. Preocupado y triste por Todo lo ocurrido. Aceptando tranquilo, por ahora, irse a un centro residencial, Caser en Badajoz, en avenida del Guadiana, en Valdepasillas. Ha sido gestionado por sus hermanas, según nos comunican, y en contacto con la Comisión Tutelar, es lo que nos dijer ayer. Le han comprado ropa y preparado todo por si sale ya de alta. El diagnóstico a falta de alguna prueba es posible síndrome de guillain barre, trastorno del sistema inmunológico. Nos preguntan las hermanas y él mismo, que la vivienda ésta limpia y ordenada para entregar llave, pues no piensa regresar. Espero sean útiles estas informaciones, la próxima semana nos pondremos en n contacto +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con Loli (31806). +++ALTA HOSPITALARIA, AYER, 03 DE ENERO DE 2018. Ingresa voluntaria y directamente en Caser Badajoz. +++Remitirá los informes de Psiquiatría y Neurología solcitados. ón con Mª José, hermana de Manuel. De dicha conversación surgen las siguientes indicaciones para la parte económica: +++CONSULTA/GESTIÓN PARTE SOCIAL CTAEX TUTELADO/A, CURATELADO/A: D. MANUEL CONTADOR MATEOS MOTIVO: PISO DE ALQUILER. OBSERVACIONES: Tras hablar con su hermana Mª José (629-785581), la situación de su hermano hace imposible que vuelva al piso: • El piso está limpio y ordenado, “…para entregar”. • Hoy, 04 de enero, sacará de él las últimas pertenencias de D. Manuel. • He quedado que la semana que viene irá Futuex a ver el piso con ella y a recoger las lleves. • Llamar al propietario para informarle de que vamos a dejar el alquiler ya. Si en el contrato se recoge que hay que avisar con un mes de antelación, tratar de explicar las circunstancias que no lo han hecho posible antes (enfermedad) para que no cobre el mes de febrero y, a ser posible, solo la parte proporcional de enero. RESIDENCIA CASER BADAJOZ. • Tienen que enviar contrato para su firma. • Llamar para que envíen presupuesto de gastos al margen del coste de la plaza. • Revisar el reintegro permanente que tenía D. Manuel antes del ingreso en el hospital. FECHA: 04-01-2019 Jefe Sección CTAEX: Pedro Gracia López +++Mª José no ha enviado todavía el documento en el que planteaba todas las circunstancias que rodean a su hermano y que le animé a escribir para dejar constancia de ellas. Empezó, pero la tensión a la que ha estado sometida le aconseja "...redactar el escrito más en frío".','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='AYALA'and apellido2='NUÑEZ'),'2019-01-04','Correo-e de Futuex (en relación a D. Francisco): Escribo para comentar en primer lugar que a Paco Ayala le han subido a planta aunque estamos de días libres, avisaron ayer a delegada de Cáceres de que salía de la UCI por el momento es la única información que tenemos, pero entendemos es buena el q haya ya salido de la UCI y está en planta del hospital San pedro de Alcántara. Realizaremos visita próximo martes para ver q tal todo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2019-01-04','-PONGO PARA FIRMA EL PIA , MANTENIMIENTO DE PLAZA EN CRR , INFORMO DEL TRASLADO A PLASENCIA. ENTREGAR REGISTRADO A ESTHER TORRADO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='CONTADOR'and apellido2='MATEOS'),'2019-01-03','-PASA DEL HOSPITAL UNIVERSITARIO BADAJOZ DONDE HA PERMANECIDO INGRESADO A LA RESIDENCIA DE CASER EN BADAJOZ . LA PLAZA SON 1500€ GESTIONADA POR SUS HMAS. PAGAREMOS DE SU PENSION ( 900€) Y EL DINERO AHORRADO , TENDRÁ PARA ALGUNOS MESES. -PEDRO AVISARÁ A SU HNA. PARA QUE RECOGA SUS COSAS Y AL DUEÑO DEL PISO PARA DEJAR EL ALQUILER PARA EL PRÓXIMO MES . -PEDRO HA PEDIDO A LOLY OLIVERA INFORMES ACTUALIZADOS , TENGO QUE SOLICITAR REVISION GRADO. TIENE UN G.1 . INTENTAREMOS PEDIR PLAZA PUBLICA ADECUADA EN LA RED DE SALUD MENTAL O MAYORES. -PTE. VISITARLO EN LA RESIDENCIA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='AYALA'and apellido2='NUÑEZ'),'2019-01-04','-PASA EN EL HOSPITAL SAN PEDRO DE ALCANTARA , DE LA UCI A PLANTA . SE PEDIRÁN INFORMES ACTUALIZADOS PARA SOLICITAR REVISION GRADO . EL MARTES LO VISITARÁ FUTUEX , SE PODRIA PONER ALGO DE ACOMPAÑAMIENTO HOSPITALARIO CON LA MISMA EMPRESA DE AYUDA A DOMICILIO QUE VA A SU CASA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE PEDRO'and edp.apellido1='VILLEGAS'and apellido2='SERRANO'),'2019-01-04','-LA PLAZA DEL HOGAR DE NAZARET ESTÁ ACREIDTADA O ES PRIVADA ? PODRIAMOS OBTENER 175€ POR DEPENDENCIA . ES MUY POCO , SI CUBRIMOS CON SUS INGRESOS Y CON LA VENTA DE INMUEBLES PREFERIRIA QUE FUESE PLAZA PRIVADA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CRISTINA'and edp.apellido1='VILLEGAS'and apellido2='SERRANO'),'2019-01-04','-CIERRO EXPEDIENTE CON Mª CARMEN ( DEPENDENCIA ) . LE COMUNICO QUE NO SIGO CON LA RESIVION DEL GRADO NI CON LA NEGOCIACION PIA . POR DEPENDENCIA TENIENDO YA UNA PLAZA T3 NO LE VAN A DAR NADA MÁS , NO TIENE SENTIDO SEGUIR.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='GAMERO'and apellido2='GOMEZ'),'2019-01-04','(Pedro)Conversación con Almudena, T. Soc. del Centro Penitenciario de Zuera (976-770635 y 60270). +++D. Miguel está ingresado en la Unidad de Cirugía Plástica del Hospital "Miguel Servet" y necesitan la firma del consentimineto informado para intervenirlo. +++Solicito el teléfono de dicha Unidad y me pongo en contacto con ella. +++Ayer, D. Miguel, estando bajo sujección mecánica, prendió el colchón y quemó su habitación. La rápida intervenmción evitó malñes mayores: D. Miguel sufrió quemaduras en un a mano y ningún otro interno ni ningún profesional resultó afectado. +++SOLCITO INOFRMES SOCIAL Y MÉDICO (me indica que no es necesraio hacerlo por escrito) en los que se haga constar la evolución de D. Miguel en el centro y la opinión profesional de los profesionales que lo atienden en relación a cuál sería el recurso idóneo para él en previsión de su próxima excarcelación el próximo mes de junio. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Hospital "Miguel Servet" de Zaragoza.Unidad de Cirugía Plástica. 976-765654. +++Pido hablar con el Dr. Silva pero no está. Hablo con una de las enferemeras. +++No dan información de los pacientes por teléfono. +++Tras consultar con la supervisora, comenta que el Dr. Silva ya ha tomado una decisión y ha cambiado el tratamiento (no me puede edecir en qué consiste el cambio por teléfono. Le explico las circunstancias pero no es posible). En estos momenbtos NO ES YA NECESARIA LA FIRMA DEL CONSENTIMINETO PARA INTERVENIR. +++++A pesar de ello, al cabo de un rato envían por fax varios consentimientos para su firma de los servicios de Cirugía Plástica y del de Anestesiología y Reanimación, que se pasan a la firma y se envían por fax.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CONCEPCION'and edp.apellido1='FERNANDEZ'and apellido2='MUÑOZ'),'2019-01-04','En relación con la citación para el día 9/1/2018, en el Juzgado de Primera instancia e Instrucción nº 1, de Plasencia, con motivo de los Procedimientos F02 Faml, Guard, Custdo Ali. Hij Menor No Matri No C 723/2018 y F04 Pieza de Medidas Provisionales Coetáneas 723/2018, hemos enviado fax al Juzgado solicitando la SUSPENSIÓN y APLAZAMIENTO, hasta que solicitemos asistencia jurídica gratuita y se le designe Abogado y Procurador.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='AYALA'and apellido2='NUÑEZ'),'2019-01-04','(Pedro)Conversación con Juani, T. Soc. H. "San Pedro de Alcántara" (31621). +++Volver a llamar. Se informará de su estado una vez ha salido de UCI +++Nueva conversación: ¿NO ha salido de UCI? Lo confirmará.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='BERNARDO'and apellido2='PIRIS'),'2019-01-04','(Pedro) Una vez recibido del Gabinete del Consejero el escrito dirigido a él por Dª Mª Antonia, me pongo en contacto con el CSS de Plasencia por consierar que su contenido es significativo de cara a la valoración e intervención psiquiátrica que se está realizando a Dª Antonia. Trato de hablar con Mariví y Soraya, pero no lo consigo. Hablo con Rosa. +++Tras explicarle de que se trata, y en un anueva llamada, me confirma que ese escrito ya lo tienen en su expediente, pero mucho más extenso, por lo que pido nos lo envíen para tenerlo en su expediente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANGELES'and edp.apellido1='SANTOS'and apellido2='URBANO'),'2019-01-04','-AVERIGUO QUE SU ESM ES EL DE CORIA , PLANTEO A FUTUEX LO SIGUIENTE : Ya tenemos la autorización judicial de Mª Angeles Santos para el ingreso involuntario . Tiene un 71% grado discapacidad , sin embargo sólo grado 1 en dependencia. Su ESM es el de Coria ( tf 927149237 ) , su médico el Dr. Mora . Necesitamos que desde el equipo sea derivada a CRR ó Pisos Supervisados , pero tendría que acceder ella voluntariamente . En vuestros ultimos informes indicáis que no quiere irse del domicilio familiar. La otra opción ingreso en CSS Plasencia con la orden judicial . Tiene sólo 51 años y con patologia psiquiatrica , no creo que pudiera entrar en la Red de Residencia de Mayores. Según vuestras visitas , en qué recurso podría estar mejor ?? Un saludo. *en Pinofranqueado tiene un hermano , y si la derivamos allí ?','2');
