insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='AYALA'and apellido2='NUÑEZ'),'2019-01-11','-INFORMACION EC : - Saldo CCC a 10/01/2019: 45.236,47 €. - Ingresos mensuales: . PN ORF. ABS: 698,30 € X 14 PAGAS. . PRXH CARGO: 570,20 € X 12 PAGAS. . AYUDA VINCULADA: 75 € X 12 PAGAS. TOTAL INGRESOS SIN P. EXTRAS: 1.343,5 €/MES. IMPORTANTE: está abonando, en concepto "Servicio Ayuda Domicilio", a la empresa GRUPO GILSÁN, diversos importes. - Hay que dar de baja este servicio??? - Hay que renunciar a la ayuda vinculada???','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='AYALA'and apellido2='NUÑEZ'),'2019-01-11','Saldo CCC a 10/01/2019: 45.236,47 €. - Ingresos mensuales: . PN ORF. ABS: 698,30 € X 14 PAGAS. . PRXH CARGO: 570,20 € X 12 PAGAS. . AYUDA VINCULADA: 75 € X 12 PAGAS. TOTAL INGRESOS SIN P. EXTRAS: 1.343,5 €/MES. IMPORTANTE: está abonando, en concepto "Servicio Ayuda Domicilio", a la empresa GRUPO GILSÁN, diversos importes. - Hay que dar de baja este servicio??? - Hay que renunciar a la ayuda vinculada??? Vamos a esperar unos dias para ver cómo evoluciona y si finalmente ingresa en Ctro. Residencial. He pedido a Futuex que hable con la empresa SAD , la casa estaba fatal . Acudió a recoger ropa por si le daban el alta y la vió.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANGELES'and edp.apellido1='SANTOS'and apellido2='URBANO'),'2019-01-11','-MI RESPUESTA A LA TS DE CORIA , MARISA OLIVERA: he hablado con su hna . por tf , habia pasado unos días de vacaciones con la familia. Cree que Mª Angeles estaría dispuesta a ir a CRR siempre que se le permita tener salidas de fin de semana para ver al padre, que se podría hacer así. Incluso plaza en el piso asociado a CRPS si no hubiese en CRR plaza vacante . La derivación tenéis que hacerla desde ESM como un procedimiento normal , solicitándolo por emergencia social. Me indica Carmen Ferrer que si lo solicitáis en breve podría tener acceso a una plaza libre que hay en CRR Plasencia. Sería conveniente citarla con anterioridad para valorar la voluntariedad en el ingreso , si desiste con la sentencia judicial de internamiento involuntario tendría que ingresar en CSS Plasencia. Un saludo Amalia','2');
