insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='BERNARDO'and apellido2='PIRIS'),'2019-01-14','Se recibe el escrito anteriormente mencionado con fecha de entrada del 9 de nero de 2019.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIPE'and edp.apellido1='RODRIGUEZ'and apellido2='SOLIS'),'2019-01-14','(Pedro) Llamo a Toni, de Futuex, para que lo acompañen mañana al Juzgado de 1ª Instancia nº 1 de Trujillo, pero comenta que con este señor no han intervenido. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con Alejandro, C. O."EL Egido" de Miajadas. +++Hace tiempo que D. Felipe no acude por el C. Ocupacional. Intentarán localizarlo para comunicarle que mañana tiene que acudir al Juzgado de Trujillo para prestar declaración.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='CALZAS'and apellido2='SANCHEZ'),'2019-01-14','Llama Olga Rubio - T.S. del Centro de Salud de Plasencia Tlf.74523- nos comunica que María Luisa tiene cita en el Hospital de Plasencia, Consultas externas de Medicina Interna Dra. Ana Isabel de la Cruz, el jueves 17 de enero a las 11:45 h. Ella le solicitó la cita pero María Luisa seguramente no se acuerda por lo que nos solicita que alguien pueda ir con ella.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DOLORES'and edp.apellido1='FERNANDEZ'and apellido2='BAEZ'),'2019-01-14','(Pedro)Visita programada.Temas habituales: plaza residencial y hasta tenerla estar en un piso de alquiler, malestar en el CRR por los "continuos" confilctos que dice haber allí siempre...para finalizar pidiendo 350€.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LAZARO'and edp.apellido1='LUBIAN'and apellido2='SANTANO'),'2019-01-14','(Pedro) Llama su hermana (674-586675). +++Solicita certificado para cambiar la titularidad del suministro eléctrico de la vivienda en el que figura todavía su padre, ya fallecido, y le piden la autorización para ello de cada uno de los hermanos. +++Lo solcitarán por escrito.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='CACHO'and apellido2='GARCIA'),'2019-01-04','(Pedro)Conversación con Almudena, T. Soc. del Centro Penitenciario de Zuera (976-770635 y 60270). +++D. Miguel está ingresado en la Unidad de Cirugía Plástica del Hospital "Miguel Servet" y necesitan la firma del consentimineto informado para intervenirlo. +++Solicito el teléfono de dicha Unidad y me pongo en contacto con ella. +++Ayer, D. Miguel, estando bajo sujección mecánica, prendió el colchón y quemó su habitación. La rápida intervenmción evitó malñes mayores: D. Miguel sufrió quemaduras en un a mano y ningún otro interno ni ningún profesional resultó afectado. +++SOLCITO INOFRMES SOCIAL Y MÉDICO (me indica que no es necesraio hacerlo por escrito) en los que se haga constar la evolución de D. Miguel en el centro y la opinión profesional de los profesionales que lo atienden en relación a cuál sería el recurso idóneo para él en previsión de su próxima excarcelación el próximo mes de junio. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Hospital "Miguel Servet" de Zaragoza.Unidad de Cirugía Plástica. 976-765654. +++Pido hablar con el Dr. Silva pero no está. Hablo con una de las enferemeras. +++No dan información de los pacientes por teléfono. +++Tras consultar con la supervisora, comenta que el Dr. Silva ya ha tomado una decisión y ha cambiado el tratamiento (no me puede edecir en qué consiste el cambio por teléfono. Le explico las circunstancias pero no es posible). En estos momenbtos NO ES YA NECESARIA LA FIRMA DEL CONSENTIMINETO PARA INTERVENIR. +++++A pesar de ello, al cabo de un rato envían por fax varios consentimientos para su firma de los servicios de Cirugía Plástica y del de Anestesiología y Reanimación, que se pasan a la firma y se envían por fax.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='GAMERO'and apellido2='GOMEZ'),'2019-01-04','(Pedro)Conversación con Almudena, T. Soc. del Centro Neuropsiquiátrico del Carmen, en Zaragoza.(976-770635 y 60270). +++D. Miguel está ingresado en la Unidad de Cirugía Plástica del Hospital "Miguel Servet" y necesitan la firma del consentimineto informado para intervenirlo. +++Solicito el teléfono de dicha Unidad y me pongo en contacto con ella. +++Ayer, D. Miguel, estando bajo sujección mecánica, prendió el colchón y quemó su habitación. La rápida intervenmción evitó malñes mayores: D. Miguel sufrió quemaduras en un a mano y ningún otro interno ni ningún profesional resultó afectado. +++SOLCITO INOFRMES SOCIAL Y MÉDICO (me indica que no es necesraio hacerlo por escrito) en los que se haga constar la evolución de D. Miguel en el centro y la opinión profesional +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Hospital "Miguel Servet" de Zaragoza.Unidad de Cirugía Plástica. 976-765654. +++Pido hablar con el Dr. Silva pero no está. Hablo con una de las enferemeras. +++No dan información de los pacientes por teléfono. +++Tras consultar con la supervisora, comenta que el Dr. Silva ya ha tomado una decisión y ha cambiado el tratamiento (no me puede edecir en qué consiste el cambio por teléfono. Le explico las circunstancias pero no es posible). En estos momenbtos NO ES YA NECESARIA LA FIRMA DEL CONSENTIMINETO PARA INTERVENIR. +++++A pesar de ello, al cabo de un rato envían por fax varios consentimientos para su firma de los servicios de Cirugía Plástica y del de Anestesiología y Reanimación, que se pasan a la firma y se envían por fax.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BLAS'and edp.apellido1='GUERRERO'and apellido2='ASEGURADO'),'2019-02-21','Teresa: Valorada la situacion decimos no autorizar la salida ya que no tenemos apenas datos de la persona que se ha ofrecido a acompañarlo y vemos que puede ser un problem, se plantea que la salida las haga con el personar del centro. Se envía escritro a la residencia para comunicar la decision','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO'and edp.apellido1='VAZQUEZ'and apellido2='RODRIGUEZ'),'2019-01-14','(Pedro)Visita no programada del hermano, cuñada y sobrino de D. Pedro, reclamando justificación de los gastos realizados durante la tutela y, especialmente, de dos facturas de 1660 y 800€ aproximadamente del 07 de spetiembre de 2018. +++Se les infoprma de las competencias de la Comisión Tutelar y se les dirige al juzgado de 1ªinstanmcia nº 4 de Mérida.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2019-01-14','(Pedro)Visita no programada de Ildefonso. +++Acepta volver al Hostal. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con Antonio, del Hostal "El Torero" (924-371789): "No hay inconveniente en que vuelva aquí, porque ademas él nunca se comportó mal..." +++Le digo que si le pide algo de comer a media mañana o media tarde lo facture aparte. +++En viará correo confirmando asietncia al Hostal.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO TOMAS'and edp.apellido1='MURILLO'and apellido2='MATIAS'),'2019-01-15','(Pedro)Conversación con Blanca (CSS de Mérida). +++Estamos todavía en fase de inventario, de lo que el CSSes consciente, pero "...tememos su reacción cuando le digamos que está incapacitado totalmente. ´Quizá una curatela hubies esido más acertada, porque él se encuentra muy bien y, a pesar de que somos cosnientes de que no puede vivir solo, sí en un piso supervisado que ya le estamos tramintando..." +++Quieren que vaya a hablar con el médico, el psicólogo y con Blanca sobre el tema porque no saben como proceder...','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='CALZAS'and apellido2='SANCHEZ'),'2019-01-15','HAblo con Toni, acompañarán a Mª Luisa a la cita en el Hospital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2019-01-15','CORAL. Ildefonso, no se presento a la cicta de psiquiatria el 17/12/18, además anuló la que tenía en Zafra el 27/12/18 con lo cual o tiene pendiente ninguna sucesiva. El 17/12/18 si que asistió a la cita conla trabajadora social, no he podido hablar con ella aun, volveré a intentarlo mas tarde. Lo que si va cumpliendo es con el CEDEX, ultima visita hoy a las 8:30 de la mañana y tiene pendiente otra el 17/01/19 a las 8:55 y 14/02/19 a las 9:00. Encuanto al justificante de asistencia de enfermeria que entrego ayer, a nombre de otra persona, si que es correcto que asistió, ha sido un error adminstrativo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='FAUS'and apellido2='LEMUS'),'2019-01-15','Coral. Beatriz trabajadora social del centro penitenciario solicita dinero para Rafael, no habla de importe concreto dice una asignacion como otras veces. El nº de cuenta es ES23 0049 0373672910790309 BANCO SANTANDER, Avd/ Santa Marina de Badajoz.Con fecha de hoy se solicita Grado de discapacidad y DTF.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='HIDALGO'and apellido2='ROMO'),'2019-01-15','Coral. Ha llamado Maite trabajadora social del centro penitenciario donde está Antonio, dice que Mª José dejó aprobado el arreglo de la boca de este hombre y que han recibido los 200€ de diciembre, necesitan para el viernes 18/01/19 otros 200€ para el segundo pago y que falta un tercero. tf de contacto 927181407. Se lo ha trasladado a Alberto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIPE'and edp.apellido1='RODRIGUEZ'and apellido2='SOLIS'),'2019-01-15','(Pedro)Asistencia al Juzgado de 1ª Instancia nº 1 de Trujillo. +++D. Felipe no se ha presentado. +++La Jueza informa de que va a sobreseer el caso y solcita le mantengamos informada. +++Se inoforma a la Jueza de las dificulatdes inherentes a un ingreso en centro de forma involuntaria llegado el caso. +++ACTUACIONES: +++++Solicitar nuevamente al SSB informes de la situación actual de convivencia. +++++Solicitar también informes al C.O. "El Egido", de Miajadas. +++++Ver situación de Dependencia: Grado III Nivel 2 desde 2011. Actualmente con SAD. +++++Solicitar nuevamente visita de FUTUEx, a ser psoible junto a T. Soc. del SSB. +++++EN FUNCIÓN DE LOS INFORMES, solicitar cambio de PIA para plaza residencial. DE ser necesrio, solicitar Autorización Judicial de Ingreso Involuntario','2');
