insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='REMEDIOS'and edp.apellido1='CHAVES'and apellido2='MASERO'),'2019-01-16','-LA PARTE EC. ESTÁ ESPERANDO QUE EL BANCO LE FACILITE LOS DATOS DE LA NUEVA CUENTA. EN CUANTO LA TENGAN TENGO QUE HACER UN CAMBIO DE CTA. EN LA PFHC. LA ESTÁN ADMINISTRANDO LOS FAMILIARES , INCLUSO EL PAGO DE LA RESIDENCIA EN AP.3 Y SUS GASTOS DE ACOMPAÑAMIENTO HOSPITALARIO. AD.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='CONTADOR'and apellido2='MATEOS'),'2019-01-16','-INGRESADO NUEVAMENTE EN LA UHB DEL H.U. BJOZ , TRASLADADO DESDE CASER. LLAMO AL TS . DE CASER PERO NO PUEDO HABLAR CON ÉL . EMAIL DE FUTUEX : Recibida llamada telefónica de Mª José Contador Mateos para comunicar la situación de su hermano Manuel acontecida en estas últimas horas: Durante todo su ingreso hospitalario en servicio de neurología y los días que lleva en centro residencial Caser Badajoz, ha estado sin medicación psiquiátrica. Desde este fin de semana (días 5,6) han observado su inquietud y cambios en la conducta, aunque nada que registrara incidencia. En la noche de ayer lunes 14 enero, han llamado de madrugada a Mª José desde centro residencial para informar que Manuel estaba muy agitado, alterado e incluso ha agredido o intentado, a su compañero de habitación. Ella solicitó que llamaran al 112 y activaran protocolo, pero no sabe qué motivo no han acudido, por tanto ella misma se personó en el centro y pasó a ver a su hermano que tomo un Valium en el momento y pidió descansar. El martes 15 de enero tenía ya programada consulta de revisión con su psiquiatra doctor Francisco Javier Samino. Manuel le ha expuesto todo su proceso y la situación en la que ahora se encuentra. Por eso el doctor Samino ha ordenado su ingreso inmediato en la unidad de agudos del hospital Universitario de Badajoz. Ha ido con su hermana Mº José, sin más incidencias registradas, aceptando todo por voluntad. El doctor Samino solicita se le reajuste toda la medicación y reinicie la toma que ha estado interrumpida varias semanas, advirtiendo también que el centro residencial no es el lugar más adecuado para vivir. De hecho ha recibido la hermana, llamada del centro dónde parece ser ponen ya problema para su vuelta al centro. Con fecha miércoles 16 de enero se ha planificado encuentro con el dueño de la vivienda que ha tenido en alquiler Manuel Contador, D. Alejandro Ledesma para hacer entrega de las correspondientes llaves.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='AYALA'and apellido2='NUÑEZ'),'2019-01-16','- FUTUEX INFORMA DE SU PROBABLE ALTA, LES PIDO QUE PARA MAÑANA ME ASEGUREN SI QUIERE INGRESAR EN RESI PARA VOLVER A CONTRATAR LA PLAZA . Según informaciones médicas Francisco evoluciona favorablemente al tratamiento antibiótico intravenoso, por lo que con total seguridad y descartando nuevas complicaciones el próximo viernes 18 de enero será dado de alta hospitalaria. Paco por su parte a primera hora de la mañana expresaba su interés por pedir la alta voluntaria, por lo que ha sido necesaria la intervención de la delegada para generar conciencia de responsabilidad y hacerle entender que debe hacer caso a las indicaciones médicas, para evitar posibles recaídas en su estado de salud. Es importante destacar, por otra parte, que Paco llegó al hospital de Cáceres sin nada, ni siquiera ropa, puesto que llegó derivado del hospital de Plasencia. El pasado jueves 10 de enero, se acudió a su domicilio a recoger la ropa necesaria de cara a una posible salida del hospital, pero en ese momento no se recogieron más enseres porque Francisco se negaba a trasladarse a un centro, no obstante, está planificado acudir el próximo jueves 17 a recoger una maleta con algo más de ropa. No tiene documentación, ni dinero en efectivo, tan sólo la tarjeta sanitaria, en la visita que se realizó al domicilio no se encontró nada más. El solicita contar con una asignación para sus gastos aspecto que se puede llevar a cabo cuando este en el centro de mayores residiendo. Paco realiza la petición expresa de dinero, puesto que, como decíamos anteriormente, no tiene dinero en efectivo ni para poder comprarse una botella de agua. Podría ser conveniente dadas las circunstancias de estudiar las posibilidades de hacerle llegar a Francisco algo de dinero en efectivo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VALLE'and apellido2='SIMON'),'2019-01-17','-PENDIENTE DEVOLVER LA LLAVE ORIGIENAL AL PROPIETARIO , LE PREGUNTO A FUTUEX POR ELLAS : Buenos Días... No recuerdo si fue Iciar o Teresa quien quedó conmigo en devolverme la llave de la vivienda donde reside José Maria Valle Simón. Yo envié la que tenía porque él había perdido las suyas en el hospital. Ruego que me digan cómo hacemos la devolución, puesto que yo resido en Badajoz... Pedro Herrera 676597609','2');
