insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2019-01-15','(Pedro)Reunión en el ESM con Esperanza, T. Social. +++MÉDICO DE FAMILIA: Dra. Mª del Mar Álvarez Díaz (Urb I). +++PSIQUIATRA DEL ESM de Mérida: Dr. Periañez. +++Respecto a Ati, el pasado martes estuve en el Equipo de Salud Mental de Mérida y me confirmaron que no acudió a la cita que tenía de Psiquiatría el pasado 17 de diciembre. +++La última vez que acudió a Psiquiatría fue el pasado 02 de julio, en el ESM de Zafra, pero tampoco acudió a control de Enfermería el 05 de julio. +++Sí que está acudiendo a las citas de CEDEX (Mª Luisa, T. Soc.)y siguiendo el tratamiento. Última cita el 12-11-2019. +++Envío correo-e a Soraya sobre este tema, del que estuvimos hablando la semana pasada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2019-01-15','(Pedro)Conversación con Mercedes, T. Soc. Plena Inclusión Llerena. +++Según parace, la madre de Beatriz ha vuelto con su padre. Beatriz no ha dicho nada en el Centro hasta que, informadas por Susana (Futuex), le han preguntado por ello. +++LAS VACACIONES han transcurrido sin problemas, salvo porque al llegar a su casa con Susana le dijeron que su hija estaba con la abuela paterna, lo que hizo que se pusiese nerviosa. Susana habló con D. Andrés (padre) para pedirle que no volvieran a comentar nada sobre el tema con Beatriz. El resto de las vacaciones transcurrió con noremalidad y Betariz regresó al centro el día indicado. +++Merecedes comenta que, desde que regresó, parece haber perdido la confianza en ellas. +++RESPECTO DE LA MADRE: se dan las siguinetes indicaciones: +++++SALIDAS: mientras la madre esté con el padre, evitar las salidas de Beatriz a su loclaidad. +++++VISITAS: se realizarán en el Centro. Y si se trata de la madre serán supervisadas. +++++TELÉFONO: el centro valorará lo beneficioso de las mismas para Beatriz, pudiendo limitarlas o suprimirlas en caso que se considere necesario. +++RESPECTO A LA HIJA: +++++Se inofrma a Mercedes que está en manos de la Abogacía de la Junta para solicitar judicialmente el régimen de visitas al que ytiene derecho la madre y las condiones en que se desarrollen las mismas. +++++Se informa también de que desde la D.G. de Infancia y familia se hará el seguimineto de la ciustodia de la niña.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='CONTADOR'and apellido2='MATEOS'),'2019-01-18','(Pedro)Conversación con Loli, T. Soc. HIC. +++Manuel está en UHB del HIC desde el pasado 15 de enero. Psiquiatra Dr. Juan antonio Guisado. +++Bien porque la medicación no estuviera ajustada y pudiera tener un brote psicótico, bien por otrsa razones, en la residencia su comportamiento se caracterizó por una conducta en ocasiones grave, llegando a quitarle el pañal a su compañero de habitación. +++No pued evolver a la Residencia.','2');
