insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='MORENO'and apellido2='ACERA'),'2019-01-23','INCIDENCIA Ha bajado MAI preguntando quien tiene que hacer la solicitud para el centro de Dña. Joaquina. Venía con una providencia (guardada copia en su expte.). Se le informa que, al ser defensa judicial, sino viene taxativamente solicitado por el juzgado que seamos nosotros los que hagamos la gestión, no podemos hacer nada. Deben ser los SSB quienes lo hagan. Corresponden los de Plasencia','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='AYALA'and apellido2='NUÑEZ'),'2019-01-24','-LLAMO NUEVAMENTE A LA DTRA. DE LA R.M. DE JARANDILLA PAR QUE ME INFORME DE LO SUCEDIDO , LE REPITIÓ EL INFARTO ESTANDO ALLÍ EL SERVICIO MEDICO QUE NO PUDO HACER NADA. VA A ENVIAR FACTURAS DE LA ORTOPEDIA , UN CINTURÓN PARA QUE NO SE CAYERA DE LA CAMA , Y LOS DOS DIAS QUE OCUPÓ PLAZA . NO QUERIA COBRARLOS PERO LE HE INSISTIDO EN QUE PASE LA FACTURA. SOLICITO DE FUTUEX QUE RECOGA SUS COSAS DE LA RESI ?? ROPA , RELOJ , LLAVES ... YO DEJARIA LA ROPA Y EL CINTURON ALLÍ Y EL RESTO QUE LO ENVIEN Y LO REGOJA LA FAMILIA . AD. LO HABLARÉ PRIMERO CON PEDRO .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='CALZAS'and apellido2='SANCHEZ'),'2019-01-24','-LLAMA OLGA ,TS DEL CTRO SALUDUD PLASENCIA 1, 74529, Mª LUISA HA ACUDIDO A CITA MEDICA , TIENE DESNUTRICION , PESA 37KG ENTRE OTRAS PATOLOGIAS Y LE HA PEDIDO PRUEBAS MÉDICAS . MUY DIFICIL QUE ELLA ACUDA , SE NIEGA , LA DELEGAD T. Y SU HIJO INTENTAN QUE SE LAS HAGA. SALE A HORAS INTEMPESTIVAS A LA CALLE , VA SOLA , NO ACUDE A CASA DE SU HERMANA A COMER ... SOLICITO INFORMES SOCIALES A OLGA , HAY QUE MIRAR EN EL CORREO PQ BEATRIZ TS DEL SSASB HA ENVIADO I.SOCIAL Y SOLICITAR INTERN EN RESI MAYORES PQ VOLUNTARIAMENTE SE NIEGA. SE PODRIA VER HASTA RESI PRIVADA PQ TIENE DINERO . SE PIDIÓ TB POR PIA EN 2018 . EN CUANTO TENGA TODOS LOS INFORMES SE LOS PASO A LA P. JURIDICA. AD.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANDREA'and edp.apellido1='DAZA'and apellido2='REGALADO'),'2019-01-18','-LLAMA MARIA CLAROS , ANDREA SE HA ROTO UN BRAZO Y ESTO AÑADIDO A SUS PROBLEMAS DE MOVILIDAD HACEN QUE NO PUEDA ESTAR EN CRR. SOLICITAN QUE LA LLEVE A UNA RESIDENCIA DE MAYORES HASTA QUE SE RECUPERE ( A NIVEL DEFINITIVO TENDRÍAN QUE VALORARLO ) . HABLO CON PEDRO Y SORAYA QUE INDICA QUE TIENEEN QUE SOLICITAR DERIVACION A UME Y NO A RESIDENCIA DE MAYORES . LO QUE DETERMINAN ES QUE DESDE AP LA DERIVEN AL H.PERPETUO SOCORRO DONDE CONTINUA : Trasladaros que Andrea en el día de ayer y tras insistencia a AP fue derivada al Hospital Perpetuo, donde permanece ingresada en la actualidad. Esto se le traslado también a sus hijos dado las necesidades que presenta Andrea. Ana Delfa','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANDREA'and edp.apellido1='DAZA'and apellido2='REGALADO'),'2019-01-24','-TF HNA. TOÑI 609946574 TF HIJO JOSE Mª 605031241 HABLO CON LA HNA . ME CUENTA QUE SU HERMANA ESTÁ REGULAR Y PIDE QUE AL ALTA PASE A UN CENTRO RESIDENCIAL CERCA DE D.BENITO / VVA. LE EXPLICO QUE ACABO DE HABLAR CON ANA DELFA Y HEMOS QUEDADO EN QUE VAN A ESPERAR Y CUANDO LE DEN EL ALTA Y VUALVA AL CENTRO VALORARÁN SI PUEDE ESTAR EN CRR O TIENE QUE SER TRASLADADA A CTRO RESIDENCIAL . LA HNA ME DICE QUE DESDE EL CENTRO , MARIA LE DICE QUE NO VA A RESIDENCIA MAY. PQ LA COMISIÓN NO QUIERE ?? LE EXPLICO A LA FAMILIA EL PROCEDIMIENTO . HABLO CON MERCEDES , TS DEL HOSPITAL PERPETUO , LE PIDO QUE AL ALTA HOSPITALARIA VALORE LA OPCION DE PLAZA SOCIOSANITARIA . Y QUE PARA CONSENTIMIENTOS INFORMADOS LO ENVIEN POR FAX. AD.','2');
