insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSARIO'and edp.apellido1='MORENO'and apellido2='HERMOSA'),'2019-01-18','-REUNION EN EL EDIFICIO SARA CON LA TS DE GUADIANA INMACULADA( 924471014/663846587). SEÑORA MAYOR QUE VIVE SOLA , VIUDA SIN HIJOS CON SOBRINOS EN BARCELONA CON LOS QUE MANTIENE CONACTO TF 691440405 ( CONCHA ) . VIVE SOLA , VIVIDENDA EN BUENAS CONDICIONES , ACUDE AL CTRO DE DIA DE LUNES A VIERNES DE 9.00 A 16.00 H . EL RESTO DE HORAS DURNTE LA SEMNA MÁS EL FIN DE SEMANA COMPLETO LO HACE UNA INTERNA QUE PERCIBE 900€ Y LIBRA UN FIN DE SEMANA, ESTA SÑRA. ES INMIGRANTE IRREGULAR SE LE ABONA A UNA CUENTA DE UNA HIJA . LO CUBRE OTRA INTERNA QUE ES RUMANA Y QUE PERCIBE 65€/ MES . HABRIA QUE VER SI ESTA PERSONA PUEDE SEGUIR EN ESE TRABAJO , SOLICITA ADEMÁS EL MES DE VACACIONES , UNA SUBIDA DE SUELDO Y LIBRAR MÁS . UNA VECINA LE AYUDA CON LAS GESTIONES BANCARIAS Y VA A RETIRAR EL DINERO PARA SUS GASTOS TODOS LOS MESES . INGRESOS P. VIUDEDAD + P.VINCULADA SAD . AHORROS 30000€ HABRIA QUE IR SOLIICTANDO RESIDENCIA O ESPERAMOS HASTA AGOTAR UN POCO LO AHORRADO ES MUY MAYOR. PLAN DE INTERVENCIÓN: -PONERLO PARA SEGUIMIENTO FUTUEX .TIENEN QUE SOLICITAR INFOMRES PARA SOLICITAR REVISION DE GRADO EN EL CENTRO DE SALUD. QUE CONTACTEN CON LA TS. DEL PUEBLO. -VER TEMA INTERNAS -VER TEMA EC. LA TS YA SE LO HA ENVIADO A S. ECO. A.D.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AGUSTIN'and edp.apellido1='RASTROLLO'and apellido2='BARRAGAN'),'2019-01-25','REGRESO DE FUGA El 25/01/2019. "Se comunica a esa Comisión Tutelar de Adultos de que el interno Agustín..., ingresado en este Centroy tutelado por esa Comisión, ha regesado de fuga en fecha 25/01/2019". CSS DE MÉRIDA.','2');
