insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AGAPITO'and edp.apellido1='PAVO'and apellido2='TENA'),'2019-01-28','COMUNICACION Llamada recibida de la TS de Valle de la Serena preguntando para quién se hace cargo del entierro. Dispone de seguro de decesos. Se le comunica al alcalde y quedamos a la espera de su contestación.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='BUENO'and apellido2='FERNANDEZ'),'2019-01-28','GASTO EXTRAORDINARIO ESPOSA VARICES ESPOSA (MIGUEL) Comunicados con Juan Antonio Tierno en nombre de María Sta. Bazaga Lozano. Exmujer de n/ Tutelado, para preguntar el estado del Expte. Le comentamos que le llamaremos. Tras revisar el expte. no nos contsa la presentación por lexnet de la autorizacion para el pago de la intervención reclamada. El secretario del gabinete jdco. nos remite la autorización judicial. NO obstante, no nos consta el informe médico ni de la necesidad de intervención ni haber sido realizada la misma. Remitiré (Miguel) dicha autorización a Alberto para que resuelva al respecto y haga, si lo cree conveniente, la transferencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JOSEFA'and edp.apellido1='MORENO'and apellido2='RAMOS'),'2019-01-28','(Pedro)Visita de D. Antonio Peraita Moreno (640-635371) ,hijo de Dª Josefa. +++Se le explica en qué cosniste la tutela. +++SE ofrece a yaudar en lo que pueda, aunque con reservas en el tema económico si ello le va a afectar de alguna manera porque cobra muy poco dinero. +++Tenía el DNI de su madre, que se queda en la Comisión tras expliacarle los motivos de ello.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2019-01-28','(Pedro) Visita de Ildefonso. +++Dice que le han bloqueado la cuenta porque le piden laactualización de datos de Consolación y de su madre Araceli (a la cual no se pued eacercar por orden judcial). +++Acudió a su médica de cabecera el pasado por un callo que tiene en el pie derecho. Al parecer le pidió informe pero no se lo dió. Acudió a urgencias ese mismo día (21 de nero de 2019) para segunda opinión y le derivaron de nuevo a control por su médico de cabecera. +++++Llamo a Podólogo Sosa (924-313304) para que le vean el pie y le pongan tratamineto en su caso. Le dan cita para hoy, día 28 de enero a las 18:15h. Informo al Podólogo que debe emitir informe y factura a nombre de Ildefonso para su abono.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIO'and edp.apellido1='VAQUERO'and apellido2='PEREZ'),'2019-01-28','Llama Juani, de ayuda a domicilio, 666 863 893, el contrato termina el 8/2/19. Nos comenta que habrá que escribir un correo a la Sociedad Oncológica Extremeña para mostrar el consentimiento de la Comisión para que Juani continue yendo al domicilio de Julio.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE PEDRO'and edp.apellido1='VILLEGAS'and apellido2='SERRANO'),'2019-01-28','(Pedro) Conversación con Raquel, envargada de la Residencia del Hogar de Nazaret (927-416563). +++José Pedro se encuentra muy adapatado al centro y muy bien. "Dice que es un hotel de 5 estrellas...". +++Ya no pregunta tanto por su hermana y no recibe visitas de la familia (al menos por la mañana que es cuando está Raquel). Le pido que se entere de si recibe visitas o llamadas por la tarde.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CRISTINA'and edp.apellido1='VILLEGAS'and apellido2='SERRANO'),'2019-01-28','(Pedro) Conversación con Modesto e Isidoro, de la Residencia "Sierra de San Pedro" (927-383258). +++El próximo miércoles recibe una nueva visita de ECUIPAL. han ido a verla varias veces desde su ingreso. Llamo a ECUIPAl pero no cogen el teléfono. Volveré a llamar. +++Anímicamente tiene altibajos, pero en general se encuentra bien dentro de la gravedad de su estado (se encuentra en silla de ruedas). ültimamente se le veía un poco "apagada", creen que por la medicación para evitar el dolor (morfina): a petición de Enfermería en la última visita de ECUIPAL se le redujo esta medicación, siempre y cuando ello no suponga la aparición de dolor, para que Cristina esté más en "alerta". +++FAMILIA: +++++Nunca pregunta por su hermano José Pedro. +++++En una única ocasión vistaron a Dª Cristina sus dos hermanos, Julián y Francisco, juntos. Luego la han visitado y llmado por teléfono por separado. +++++Hace unos días acudió su hermano Julián con una amiga de Cristina con la intención, insisitente, de sacarla por fuera de la Residencia primero, después a comer, antes por el aparcamiento de la Residencia. Según refeier ISidoro (Director) con la clara intención de meterla en el coche y llevársela. +++++++Las visitas son siempre supervisadas, tanto dentro del Centro como en los paseos por su entorno. +++++++ESta terminantemente prohibido entrar en el centro comida del exterior y, por supuesto, que las visitas la ofrezcan a los residentes.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='AYALA'and apellido2='NUÑEZ'),'2019-01-28','(Pedro)Hablo con Toni (Futuex) sobre lo sucedido. +++Una vez dado de baja el alquiler, entregarán las llaves al propietario.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALBERTO'and edp.apellido1='RAMOS'and apellido2='BLANCO'),'2019-01-29','(MIGUEL)Tras conversación con Ana (hermana de Alberto)me indica que no está hecha la adjudicación de herencia y tras comprobar que somos competentes para la venta, la pido por email la documentación que por ahora pueden enviarnos a efectos de pedir autorización judicial para la venta','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2019-01-29','(Pedro)Ildefonso acude a la Comisión para entregar la factura del podólogo. +++No requiere más intervención. NO trae ningún informe sobre la atención o tratamineto requerido. +++SE ha podido también realizar el desbloqueo de su cuenta tras actualizar los datos solicitados.','2');
